-- Poems batch 99
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('30b0284d-dcb9-476c-b4c3-dcea7e7dd17c','頌古二十九首  其一四','釋師體','宋','宋诗','song-poetry','','[]','甘贄設白粥，南泉費鹽醋。',24,'全唐诗/poet.song.116000.json','["甘贄設白粥，南泉費鹽醋。", "彼此落便宜，至今斷來路。"]'),
('205c86f4-58be-4a46-8599-c3cfd4dcb431','頌古二十九首  其一五','釋師體','宋','宋诗','song-poetry','','[]','村婆暴富，誑諕閭閻。',20,'全唐诗/poet.song.116000.json','["村婆暴富，誑諕閭閻。", "趙州賣俏，矢上加尖。"]'),
('68823590-31f8-4793-a38a-901e6e956e88','頌古二十九首  其一六','釋師體','宋','宋诗','song-poetry','','[]','貧無所依，兩親相擊。',20,'全唐诗/poet.song.116000.json','["貧無所依，兩親相擊。", "旱地雷聲，青天霹靂。"]'),
('09831b54-028a-4f25-9966-b5363b90a714','頌古二十九首  其一七','釋師體','宋','宋诗','song-poetry','','[]','鑊湯無冷地，黄河輥底流。',24,'全唐诗/poet.song.116000.json','["鑊湯無冷地，黄河輥底流。", "金剛難插觜，腦後掛燈毬。"]'),
('3c25a611-50f1-4d0f-9ebb-4769fb367261','頌古二十九首  其一八','釋師體','宋','宋诗','song-poetry','','[]','之乎者也，雪月風花。',20,'全唐诗/poet.song.116000.json','["之乎者也，雪月風花。", "頭面各別，事同一家。"]'),
('6d960cb2-3233-4c38-b0a3-66a93b3c01f9','頌古二十九首  其一九','釋師體','宋','宋诗','song-poetry','','[]','佛是西天老比丘，星移斗轉水東流。',32,'全唐诗/poet.song.116000.json','["佛是西天老比丘，星移斗轉水東流。", "茫茫宇宙人無數，戶貫依前百草頭。"]'),
('fed9dc51-53eb-476b-9311-1a0ec87933dd','頌古二十九首  其二○','釋師體','宋','宋诗','song-poetry','','[]','投子下繩床，終非孟八郎。',52,'全唐诗/poet.song.116000.json','["投子下繩床，終非孟八郎。", "不摇三寸舌，未免鬼分贓。", "眼底欲條直，臨機爭探囊。", "裂破古今無面目，縱橫何處有關防。"]'),
('350647a6-236c-43e6-93a9-a272ddf51b66','頌古二十九首  其二一','釋師體','宋','宋诗','song-poetry','','[]','主賓會合風雲異，醉後添杯禮義全。',32,'全唐诗/poet.song.116000.json','["主賓會合風雲異，醉後添杯禮義全。", "棒打自家親骨肉，叢林扛鼓返成寃。"]'),
('ad65d969-c7b7-4bdb-8a6b-1f463b4572fb','頌古二十九首  其二二','釋師體','宋','宋诗','song-poetry','','[]','强盜遭逢惡抵家，賊贓纔敗別無他。',32,'全唐诗/poet.song.116000.json','["强盜遭逢惡抵家，賊贓纔敗別無他。", "山藤徹骨令甘伏，反與渠儂貼面花。"]'),
('afcdade4-5dcd-4d2c-9816-c408eff64307','頌古二十九首  其二三','釋師體','宋','宋诗','song-poetry','','[]','裂破古今沒窠臼，當機大闡血盆口。',32,'全唐诗/poet.song.116000.json','["裂破古今沒窠臼，當機大闡血盆口。", "脚尖趯出佛如麻，李四張三無路走。"]'),
('82987475-7f69-4f51-a6e7-db33d94d9d72','頌古二十九首  其二四','釋師體','宋','宋诗','song-poetry','','[]','先天後地本寥廓，撥草尋芳途路樂。',32,'全唐诗/poet.song.116000.json','["先天後地本寥廓，撥草尋芳途路樂。", "不得春風花不開，花開又被風吹落。"]'),
('dd6e8495-8852-425b-9e73-bb200aaf0bdb','頌古二十九首  其二五','釋師體','宋','宋诗','song-poetry','','[]','杖林山下竹筋鞭，憍梵鉢提舌拄天。',32,'全唐诗/poet.song.116000.json','["杖林山下竹筋鞭，憍梵鉢提舌拄天。", "羣黨元來諱空手，起家消息在荒田。"]'),
('a4c85a84-5f69-4d23-979d-d174e302ac67','頌古二十九首  其二六','釋師體','宋','宋诗','song-poetry','','[]','十分美麗誰家女，百倍聰明是馬郎。',32,'全唐诗/poet.song.116000.json','["十分美麗誰家女，百倍聰明是馬郎。", "堪笑金沙灘畔約，始終姻婭不成雙。"]'),
('af438a8c-cd1d-4c8e-85cf-8aa53293ac0c','頌古二十九首  其二七','釋師體','宋','宋诗','song-poetry','','[]','夜叉頭，菩薩面。',48,'全唐诗/poet.song.116000.json','["夜叉頭，菩薩面。", "鬼擣穀，佛跳牆。", "同門共戶不相識，邁古超今無寸長。", "燈心戳破石人脚，扁鵲盧醫爭主張。"]'),
('b47694fa-fd65-4f5a-bee5-445595ebcf2d','頌古二十九首  其二八','釋師體','宋','宋诗','song-poetry','','[]','昨夜發新雷，毒蛇離窟穴。',24,'全唐诗/poet.song.116000.json','["昨夜發新雷，毒蛇離窟穴。", "居常口不開，蹋著迸鮮血。"]'),
('9c201eb8-a95b-4efe-ba1a-579cc143585e','頌古二十九首  其二九','釋師體','宋','宋诗','song-poetry','','[]','兵行詭道，賊是家親。',20,'全唐诗/poet.song.116000.json','["兵行詭道，賊是家親。", "無功受祿，有理難伸。"]'),
('cddd0853-8b2f-47aa-88ac-393e968373a2','句  其一','王悅','宋','宋诗','song-poetry','','[]','鷄犬數聲雲一塢，春陽桃李渺成蹊。',16,'全唐诗/poet.song.116000.json','["鷄犬數聲雲一塢，春陽桃李渺成蹊。"]'),
('0d3e0ba9-db2f-4f53-9555-544b4c77b8a5','句  其二','王悅','宋','宋诗','song-poetry','','[]','觚稜脫脫風塵表，峭壁垂垂日月低。',16,'全唐诗/poet.song.116000.json','["觚稜脫脫風塵表，峭壁垂垂日月低。"]'),
('9a271789-2e72-46a4-8fcd-4266344ffb5c','遊九鎖','龍大淵','宋','宋诗','song-poetry','','[]','峯巒九鎖路縈盤，翠色沾衣作晚寒。',64,'全唐诗/poet.song.116000.json','["峯巒九鎖路縈盤，翠色沾衣作晚寒。", "日暮神仙歸洞府，雨餘星斗下天壇。", "人生何用千鍾貴，老去須求一室安。", "會得谷神元不死，世間何事可相干。"]'),
('6ae745cc-67ad-40bd-9629-a022f2da99f3','題金山','龍大淵','宋','宋诗','song-poetry','','[]','梵天台殿枕江流，形勝先推第一洲。',32,'全唐诗/poet.song.116000.json','["梵天台殿枕江流，形勝先推第一洲。", "不戰屈人當設險，樓船况有萬貔貅。"]'),
('d708726d-fd4e-447b-b469-92a60d02ef63','遊城山國清塘','鄭耕老','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湧金門外盡菰蒲，四月行人客上都。',32,'全唐诗/poet.song.116000.json','["湧金門外盡菰蒲，四月行人客上都。", "六月國清塘上望，依稀身更在西湖。"]'),
('5fa62728-3833-428c-b4de-ae0f95ff3ff6','木蘭溪書堂','鄭耕老','宋','宋诗','song-poetry','','[]','鄭子藏書處，柴門碧樹灣。',48,'全唐诗/poet.song.116000.json','["鄭子藏書處，柴門碧樹灣。", "開懷溪一曲，養拙屋三間。", "月色斜侵竹，鳥聲迥隔山。", "輞川多勝趣，何似此潺湲。"]'),
('d1866c26-02e5-4bf8-8bcb-6df87d4e464e','三聖殿','陳良翰','宋','宋诗','song-poetry','','[]','巨鎮標閩越，靈蹤肇晉齊。',48,'全唐诗/poet.song.116000.json','["巨鎮標閩越，靈蹤肇晉齊。", "空壇仙一去，古洞佛雙棲。", "化石龜猶在，燒丹井已迷。", "塵襟誰復悟，惟聽曉猿啼。"]'),
('aed8bf6f-7bdc-4817-867b-9dda7bba7a42','和敬夫斜川詩','劉芮','宋','宋诗','song-poetry','','[]','病著不任事，淹卧心自休。',120,'全唐诗/poet.song.116000.json','["病著不任事，淹卧心自休。", "經時不出門，况復斜川遊。", "每覿節物換，怳驚時序流。", "少年喜追逐，聚散水上鷗。", "沈舟枯木伴，風帆春樹丘。", "我病正爾許，懷念老朋儔。", "有酒不能飲，徒有獻與酬。", "故人酌佳日，亦復我念否。", "佳章寫懷抱，一讀寬百憂。", "吾君念遠民，歸計未易求。"]'),
('85d9207e-5476-4dc0-8705-ceae307b8549','題惠來驛  其一','龔茂良','宋','宋诗','song-poetry','','[]','十里平疇際遠山，土膏未動覺牛閑。',32,'全唐诗/poet.song.116000.json','["十里平疇際遠山，土膏未動覺牛閑。", "行人多謝晴相送，只恐妨農雨大慳。"]'),
('757b9515-262b-4f00-83cd-9eb6e1f3b50d','題惠來驛  其二','龔茂良','宋','宋诗','song-poetry','','[]','晴雲當午爭揮扇，曉霧生寒又着綿。',32,'全唐诗/poet.song.116000.json','["晴雲當午爭揮扇，曉霧生寒又着綿。", "此是嶺南春氣候，日中長有四時天。"]'),
('bf7b45b7-e532-4aaa-a24c-4454c5daeebf','靈源庵','龔茂良','宋','宋诗','song-poetry','','[]','遲回不忍去，復作抱衾留。',48,'全唐诗/poet.song.116000.json','["遲回不忍去，復作抱衾留。", "斷續雲間雨，蕭騷木末秋。", "勞生那有此，漸老欲相投。", "最愛千山暮，鐘鳴處處幽。"]'),
('ca08532e-a1db-4e06-bce5-27f9bf75799c','幽化院','龔茂良','宋','宋诗','song-poetry','','[]','晝寢招提最上頭，饑禽亡頼故喧啾。',64,'全唐诗/poet.song.116000.json','["晝寢招提最上頭，饑禽亡頼故喧啾。", "嶺雲西去欲成暮，山雨北來渾似秋。", "婉娩如今真是夢，經從似舊絕堪愁。", "昔年陳迹雞窗下，日落鐘鳴山更幽。"]'),
('52792c3f-41a7-4668-8632-e1dbebf66d92','木蘭陂','龔茂良','宋','宋诗','song-poetry','','[]','木蘭春漲與江通，日日江潮送曉風。',32,'全唐诗/poet.song.116000.json','["木蘭春漲與江通，日日江潮送曉風。", "此水還應接鄞水，爲誰流下海門東。"]'),
('fd6136c6-4494-4ba3-bbd0-0b2e3876bd80','詩一首','龔茂良','宋','宋诗','song-poetry','','[]','千章古木轉頭空，去與人間作棟隆。',32,'全唐诗/poet.song.116000.json','["千章古木轉頭空，去與人間作棟隆。", "未必真能庇寒士，不如留此貯清風。"]'),
('d6f6818a-b8bb-4758-aea8-688e07b1e42d','頌古四首  其一','釋仲安','宋','宋诗','song-poetry','','[]','法王法令沒周遮，一片虛凝絕點瑕。',32,'全唐诗/poet.song.116000.json','["法王法令沒周遮，一片虛凝絕點瑕。", "槌下不開諸聖眼，幾多騏驥困鹽車。"]'),
('bf90391b-b939-44f5-a243-d2a16ff7654b','頌古四首  其二','釋仲安','宋','宋诗','song-poetry','','[]','百丈堂前辨野狐，紫羅帳裏撒真珠。',32,'全唐诗/poet.song.116000.json','["百丈堂前辨野狐，紫羅帳裏撒真珠。", "誰家別館池塘裏，一對鴛鴦水上浮。"]'),
('9030eb44-6df6-4b07-be9b-609e617e04d7','頌古四首  其三','釋仲安','宋','宋诗','song-poetry','','[]','一段風光畫不成，洞房深處暢予情。',32,'全唐诗/poet.song.116000.json','["一段風光畫不成，洞房深處暢予情。", "頻呼小玉元無事，只要檀郎認得聲。"]'),
('878feb95-fdf4-46a7-aa23-56857a8df717','頌古四首  其四','釋仲安','宋','宋诗','song-poetry','','[]','解劈當胸箭，因何只半人。',24,'全唐诗/poet.song.116000.json','["解劈當胸箭，因何只半人。", "爲從途路曉，所以不全身。"]'),
('2a4b59ca-7e59-43cf-9670-45f7159b6086','偈','釋辯','宋','宋诗','song-poetry','','[]','毫釐有差，天地懸隔。',52,'全唐诗/poet.song.116000.json','["毫釐有差，天地懸隔。", "隔江人唱鷓鴣詞，錯認胡笳十八拍。", "欲得現前，莫存順逆。", "五湖烟浪有誰事，自是不歸歸便得。"]'),
('a5f407cc-2909-4bb1-9971-287f0a62855e','偈','釋智深','宋','宋诗','song-poetry','','[]','兜率降生，雙林示滅。',80,'全唐诗/poet.song.116000.json','["兜率降生，雙林示滅。", "掘地討天，虛空釘橛。", "四十九年，播土揚塵。", "三百餘會，納盡敗缺。", "盡力布網張羅，未免喚龜作鼈。", "末後拘尸城畔，槨示雙趺。", "旁人冷眼，看來大似弄巧成拙。"]'),
('3234ef29-fd4c-4101-9301-20d1f010ea18','頌古十二首  其一','釋智深','宋','宋诗','song-poetry','','[]','末後無端重漏泄，焦齒翁翁嚼生鐵。',32,'全唐诗/poet.song.116000.json','["末後無端重漏泄，焦齒翁翁嚼生鐵。", "玉鞭擊碎月明珠，累及兒孫揚醜拙。"]'),
('6bf37f57-f5e5-4580-9c42-a0fd2f6fd8d0','頌古十二首  其二','釋智深','宋','宋诗','song-poetry','','[]','吹毛劍首乾坤黑，臂墮山河掩日光。',32,'全唐诗/poet.song.116000.json','["吹毛劍首乾坤黑，臂墮山河掩日光。", "羣起須彌頭倒卓，方知兩兩不成雙。"]'),
('815623dd-9ff5-4125-aefe-8d36c4ccaec5','頌古十二首  其三','釋智深','宋','宋诗','song-poetry','','[]','古渡無風下直鉤，絲綸意在得鯨鰲。',32,'全唐诗/poet.song.116000.json','["古渡無風下直鉤，絲綸意在得鯨鰲。", "馬師言下揚家醜，千古兒孫草裏遊。"]'),
('92268eeb-e455-44f5-a130-cda984faf447','頌古十二首  其四','釋智深','宋','宋诗','song-poetry','','[]','裴公悟處絕譊訛，尺水能翻萬丈波。',56,'全唐诗/poet.song.116000.json','["裴公悟處絕譊訛，尺水能翻萬丈波。", "霹靂機中反活眼，鋒鋩句裏罷干戈。", "峯頭路，暫經過。", "濃綠萬枝紅一點，動人春色不須多。"]'),
('73b00221-e6e2-45e2-8d85-e73af28b038e','頌古十二首  其五','釋智深','宋','宋诗','song-poetry','','[]','崔顥曾題黄鶴樓，上頭春色少人遊。',32,'全唐诗/poet.song.116000.json','["崔顥曾題黄鶴樓，上頭春色少人遊。", "清香已逐殘春去，無限狂蜂戀不休。"]'),
('8d4e339a-cdb3-4be0-804f-c7d578c8917d','頌古十二首  其六','釋智深','宋','宋诗','song-poetry','','[]','菴主拳頭舉處親，趙州話魯指西秦。',32,'全唐诗/poet.song.116000.json','["菴主拳頭舉處親，趙州話魯指西秦。", "知音不在千杯酒，一盞空茶也醉人。"]'),
('845d6680-e8f7-466e-aded-74a00db0025f','頌古十二首  其七','釋智深','宋','宋诗','song-poetry','','[]','興化逐克賓，觀音戴鬼面。',24,'全唐诗/poet.song.116000.json','["興化逐克賓，觀音戴鬼面。", "靴裏動指頭，未免傍人見。"]'),
('e4dcb388-5efa-4189-97ec-04e6c7fd0ca3','頌古十二首  其八','釋智深','宋','宋诗','song-poetry','','[]','好手呈機不露鋒，慣將雙劍定雌雄。',32,'全唐诗/poet.song.116000.json','["好手呈機不露鋒，慣將雙劍定雌雄。", "忽雷迸出驚天地，華岳三峯倒卓空。"]'),
('0baa9de7-4314-4060-b27d-258674bb9d66','頌古十二首  其九','釋智深','宋','宋诗','song-poetry','','[]','笑裏憑誰眼豁開，龜毛須向火中栽。',32,'全唐诗/poet.song.116000.json','["笑裏憑誰眼豁開，龜毛須向火中栽。", "脚跟有路雲泥隔，千里區區謾往來。"]'),
('dd27c489-b29c-4cc9-b827-7a56fb17e2df','頌古十二首  其一○','釋智深','宋','宋诗','song-poetry','','[]','清波無透路，轉處少人知。',24,'全唐诗/poet.song.116000.json','["清波無透路，轉處少人知。", "斫却月中桂，清光付與誰。"]'),
('ad40e009-74a3-422d-aa47-1c875b2e1606','頌古十二首  其一一','釋智深','宋','宋诗','song-poetry','','[]','古木靈巢鶴夢迷，崑崙白象倒騎歸。',32,'全唐诗/poet.song.116000.json','["古木靈巢鶴夢迷，崑崙白象倒騎歸。", "魚鱗水漲舟橫岸，羊角風生花落溪。"]'),
('f4257c01-5139-4802-ac2f-6d1619e93ffe','頌古十二首  其一二','釋智深','宋','宋诗','song-poetry','','[]','新婦快騎馿，阿家引鞭走。',24,'全唐诗/poet.song.116000.json','["新婦快騎馿，阿家引鞭走。", "石筍夜抽條，面南看北斗。"]'),
('bf83ee3d-5cf2-4747-bab3-1531c901af5f','偈頌二首  其一','釋齊己','宋','宋诗','song-poetry','','[]','薦得是，移華兼蝶至。',96,'全唐诗/poet.song.116000.json','["薦得是，移華兼蝶至。", "薦得非，擔泉带月歸。", "是也好，鄭州梨勝青州棗。", "非也好，象山路入蓬萊島。", "是亦沒交涉，踏著秤錘硬似鐵。", "非亦沒交涉，金剛寶劍當頭截。", "阿呵呵，會也麽，知事少時煩惱少，識人多處是非多。"]'),
('6bfadcd3-ae9a-4175-9cff-63cd879d51a4','偈頌二首  其二','釋齊己','宋','宋诗','song-poetry','','[]','漸漸雞皮鶴髮，父少而子老。',104,'全唐诗/poet.song.116000.json','["漸漸雞皮鶴髮，父少而子老。", "看看行步躘蹱，疑殺木上座。", "直饒金玉滿堂，照顧白拈賊。", "豈免衰殘老病，正好著精彩。", "任汝千般快樂，渠儂合自由。", "無常終是到來，歸堂喫茶去。", "唯有徑路修行，依舊打之遶。", "但念阿彌陀佛，念得不濟事。"]'),
('f8fb3768-6384-4b31-9f5c-75251bce7c8a','偈五首  其一','釋覺阿上人','宋','宋诗','song-poetry','','[]','航海來探教外傳，要離知見脫蹄筌。',32,'全唐诗/poet.song.116000.json','["航海來探教外傳，要離知見脫蹄筌。", "諸方參遍草鞋破，水在澄潭月在天。"]'),
('ecefdf7e-6008-42a8-9fde-e50650948c29','偈五首  其二','釋覺阿上人','宋','宋诗','song-poetry','','[]','掃盡葛藤與知見，信手拈來全體現。',32,'全唐诗/poet.song.116000.json','["掃盡葛藤與知見，信手拈來全體現。", "腦後圓光徹太虛，千機萬機一時轉。"]'),
('644ce76c-dc5d-48f9-a998-307bf16928a5','偈五首  其三','釋覺阿上人','宋','宋诗','song-poetry','','[]','妙處如何說向人，倒地便起自分明。',32,'全唐诗/poet.song.116000.json','["妙處如何說向人，倒地便起自分明。", "驀然踏著故田地，倒裹幞頭孤路行。"]'),
('b204fbd1-ed30-4ef6-85ca-b7e7cad4edad','偈五首  其四','釋覺阿上人','宋','宋诗','song-poetry','','[]','求真滅妄元非妙，即妄明真都是錯。',32,'全唐诗/poet.song.116000.json','["求真滅妄元非妙，即妄明真都是錯。", "堪笑靈山老古錐，當陽拋下破木杓。"]'),
('55ba9352-333e-46b4-b4eb-d1578e94729e','偈五首  其五','釋覺阿上人','宋','宋诗','song-poetry','','[]','豎拳下喝少賣弄，說是說非入泥水。',32,'全唐诗/poet.song.116000.json','["豎拳下喝少賣弄，說是說非入泥水。", "截斷千差休指注，一聲歸笛囉囉哩。"]'),
('dcecb945-4301-4195-9efb-ba1d699b70e6','萍鄉道中','黄昇','宋','宋诗','song-poetry','','[]','路入萍鄉信馬行，野花香好不知名。',32,'全唐诗/poet.song.116000.json','["路入萍鄉信馬行，野花香好不知名。", "官卑無補公家事，時向田間問耦耕。"]'),
('2f2c485f-ed1b-4bc6-b1e7-db705045aede','題居室','夏龍五','宋','宋诗','song-poetry','','[]','用拙常存守道心，偷閑片片抵千金。',64,'全唐诗/poet.song.116000.json','["用拙常存守道心，偷閑片片抵千金。", "半簾梅影離離月，一澗泉聲曲曲琴。", "圖史燈前隨意檢，園蔬雨後不時尋。", "浮名自覺無多趣，五柳當年志已深。"]'),
('ecd69a99-1439-4792-a48f-ab83a969c95f','茅山書院謁侯處士像','巫伋','宋','宋诗','song-poetry','','[]','齋糧資講舍，遺像拜山中。',48,'全唐诗/poet.song.116000.json','["齋糧資講舍，遺像拜山中。", "不尚神仙術，特存儒者風。", "斯文真未喪，吾道豈終窮。", "爲憶皋比擁，庭前古木叢。"]'),
('d94a6f36-4abd-4a75-9329-3de625b2dc10','清隠院','張頤','宋','宋诗','song-poetry','','[]','古寺深山裏，高亭萬木叢。',48,'全唐诗/poet.song.116000.json','["古寺深山裏，高亭萬木叢。", "歸雲度疎牖，繡嶺倚晴空。", "澗草連階綠，岩花照檻紅。", "縱非塵世外，無異畫圖中。"]'),
('e12452ec-5e39-466b-b443-07343f66bd67','崇恩寺','彭舉','宋','宋诗','song-poetry','','[]','紺殿肇何年，古雅足幽賞。',96,'全唐诗/poet.song.116000.json','["紺殿肇何年，古雅足幽賞。", "嵌空結寶蓋，玲瓏如綺幌。", "誠哉運斤手，巍然閲今曩。", "丹碧浮霄漢，斑剝亦蒼莽。", "境界半村郭，清浄絕塵壤。", "諦聽萬籟寂，時聞松風響。", "盛夏此中憩，納爽思解網。", "聊以歷三匝，情想爲一盪。"]'),
('c0a9897b-0233-4162-b373-5de75a94c079','浄居寺','彭舉','宋','宋诗','song-poetry','','[]','攬勝棲真處，山窮境忽開。',48,'全唐诗/poet.song.116000.json','["攬勝棲真處，山窮境忽開。", "碧澄丹壑水，青疊翠屏苔。", "嶺樹宜高下，溪流當去來。", "聲光畫不得，臨此但低徊。"]'),
('c71a8e56-4aa6-462d-b261-c482abfebd2c','李忠定公挽詩  其一','吳岡','宋','宋诗','song-poetry','','[]','夢卜庸真相，艱難倚大儒。',48,'全唐诗/poet.song.116000.json','["夢卜庸真相，艱難倚大儒。", "英風起衰懦，直氣懾奸諛。", "琳館終高卧，燕然漫仕圖。", "哀榮看贈典，猶是慰寰區。"]'),
('5821d7de-d2c7-4984-944a-7ac0f423fe57','李忠定公挽詩  其二','吳岡','宋','宋诗','song-poetry','','[]','胡騎圍城日，諸生伏闕時。',48,'全唐诗/poet.song.116000.json','["胡騎圍城日，諸生伏闕時。", "公方扶病起，人遂有生期。", "日者猶如此，天乎不憖遺。", "傷心原上路，烟淡鼓簫悲。"]'),
('022d6be5-7e3d-4ef4-8840-ec7f168c9d2f','李忠定公挽詩  其三','吳岡','宋','宋诗','song-poetry','','[]','才大時難合，言深道轉艱。',48,'全唐诗/poet.song.116000.json','["才大時難合，言深道轉艱。", "去朝吾不負，巧譖爾何顔。", "袖手功名外，忘懷水石間。", "蒼生不知恨，猶望起東山。"]'),
('d0ce364d-7cb8-428d-9387-4a49d25be37b','中隠堂二首  其一','鮑同','宋','宋诗','song-poetry','','[]','當年早有菟裘意，歲晚塵埃尚困予。',32,'全唐诗/poet.song.116000.json','["當年早有菟裘意，歲晚塵埃尚困予。", "聞說龍江真可隠，欲將餘日寄僊居。"]'),
('a933603e-4512-4cc9-b21e-6af3e3fd5819','中隠堂二首  其二','鮑同','宋','宋诗','song-poetry','','[]','問舍知君困欲還，才高那得卧南山。',32,'全唐诗/poet.song.116000.json','["問舍知君困欲還，才高那得卧南山。", "由來甘井人爭汲，却恐心閑身未閑。"]'),
('51141f86-24a5-413e-b112-8559926ab352','姜山後巖洞','陳曦','宋','宋诗','song-poetry','','[]','春山多少雨，染出碧雲堆。',48,'全唐诗/poet.song.116000.json','["春山多少雨，染出碧雲堆。", "巖冷溜常滴，人閒洞自開。", "摘花香入袖，題石筆黏苔。", "茅屋在何處，桃花流水來。"]'),
('a1d9da88-d516-4bf4-91d6-2c3dc5053888','姜山前巖廟','陳曦','宋','宋诗','song-poetry','','[]','怪石嶄巖勢欲摧，洞門無鎖晝常開。',32,'全唐诗/poet.song.116000.json','["怪石嶄巖勢欲摧，洞門無鎖晝常開。", "此心不合神明者，到此應知嬾入來。"]'),
('1387380a-d309-4bc9-9a4c-1bc6eb9f3305','洗竹','陳巖肖','宋','宋诗','song-poetry','','[]','直幹解新籜，低枝蔽舊叢。',24,'全唐诗/poet.song.116000.json','["直幹解新籜，低枝蔽舊叢。", "芟繁留嫩綠，引月更添風。"]'),
('af8c06ac-2f36-451a-8b85-c549321741f2','題巾子山廣軒','陳巖肖','宋','宋诗','song-poetry','','[]','屹立雙峰入雲表，登臨聊爲小遲留。',64,'全唐诗/poet.song.116000.json','["屹立雙峰入雲表，登臨聊爲小遲留。", "四圍山色攙天碧，一曲波光抱郭流。", "身世欲違塵俗態，生涯宜與水雲謀。", "何當占斷層巒頂，一室煙霞百慮休。"]'),
('847de543-6864-4469-b299-4def9d3a265b','甘露','陳巖肖','宋','宋诗','song-poetry','','[]','負土築新阡，松楸手親藝。',108,'全唐诗/poet.song.116000.json','["負土築新阡，松楸手親藝。", "結廬居墓傍，猿鶴爲垂涕。", "屈指幾星霜，精誠動天帝。", "三宵神澤零，霏霏灑松蓋。", "曉看歲寒枝，厭浥滿蒼翠。", "初含紅日光，顆顆金珠綴。", "味分飴蜜甘，香奪芝蘭氣。", "亭午若凝脂，青絲繫千穗。", "赤城千里傳，冠蓋日相繼。"]'),
('76585621-6fc2-4ccc-8b42-ee0a52a765dd','題嚴子陵釣臺','陳貫道','宋','宋诗','song-poetry','','[]','足加帝腹似癡頑，詎肯折腰求好官。',32,'全唐诗/poet.song.116000.json','["足加帝腹似癡頑，詎肯折腰求好官。", "明主莫將臣子待，故人只作友朋看。"]'),
('8504f638-bf2e-4035-b22a-44fa7b6149f9','題涪江石魚','何憲','宋','宋诗','song-poetry','','[]','何年天匠巧磨礱，巨尾橫梁了莫窮。',64,'全唐诗/poet.song.116000.json','["何年天匠巧磨礱，巨尾橫梁了莫窮。", "不是江魚時隠見，要知田稼歲凶豐。", "四靈効瑞非臣力，一水安行屬帝功。", "職課農桑表勤惰，信傳三十六鱗中。"]'),
('fb1a9218-b511-40ab-95cc-873c9ea99b43','句  其一','何憲','宋','宋诗','song-poetry','','[]','人間正作雲霓望，天半忽驚霖雨來。',16,'全唐诗/poet.song.116000.json','["人間正作雲霓望，天半忽驚霖雨來。"]'),
('934cbeb7-736b-4313-8576-44b6014d1825','句  其二','何憲','宋','宋诗','song-poetry','','[]','鐵面金華誰氏子，要須相與嗣前塵。',16,'全唐诗/poet.song.116000.json','["鐵面金華誰氏子，要須相與嗣前塵。"]'),
('8e38dae7-d51b-4c40-9e7a-0cf373a80dc5','紹興戊午秋因觀畢氏所藏定武舊石本蘭亭因題','薛僊','宋','宋诗','song-poetry','','[]','無心工拙當閒暇，信手縱橫盡技能。',32,'全唐诗/poet.song.116000.json','["無心工拙當閒暇，信手縱橫盡技能。", "朱蠟謄摹猶若此，可憐真蹟殉昭陵。"]'),
('25cd4b52-adb0-4675-ad83-0f2583651597','䃜山道中','王崈','宋','宋诗','song-poetry','','[]','濺石韵寒泉，依稀言語處。',24,'全唐诗/poet.song.116000.json','["濺石韵寒泉，依稀言語處。", "回頭覺無人，又上前溪去。"]'),
('c56d829b-1c5b-4c44-8a83-cc6efbee5821','山樵','王崈','宋','宋诗','song-poetry','','[]','山樵竹裏居，略彴纔堪渡。',24,'全唐诗/poet.song.116000.json','["山樵竹裏居，略彴纔堪渡。", "落日澹平疇，牛羊點寒暮。"]'),
('b9f1a05c-30b0-4837-bf3d-a00f83df75de','送范道卿赴省試','晁公遡','宋','宋诗','song-poetry','','[]','君之先世真文雄，異時奏賦蓬萊宮。',128,'全唐诗/poet.song.116000.json','["君之先世真文雄，異時奏賦蓬萊宮。", "誰傳副墨過沙漠，至今猶稱長嘯公。", "芝蘭不乏後來秀，謂將褎然爲舉首。", "至音澹泊識者寡，遂令聲名落盧後。", "北風吹霜日隠山，綵鸞繡襦寧復寒。", "同車西歸信可樂，得意自忘行路難。", "明年春風紫宸仗，遥對清光九天上。", "長安花盡君亦歸，緩轡重來一相訪。"]'),
('c5f08878-edd3-4ffb-8b8a-bd8dc9a2e01d','凌雲寺','晁公遡','宋','宋诗','song-poetry','','[]','問途出青郊，踐勝得紺園。',120,'全唐诗/poet.song.116000.json','["問途出青郊，踐勝得紺園。", "始登十尋閣，敬禮兩足尊。", "仰觀碧玉螺，瑞光發面門。", "飛霞在指端，甘泉生耳根。", "屹爲江山壯，高揭日月存。", "念此未云大，法身滿乾坤。", "東望烏牛峯，突起如伏黿。", "少休白雲亭，遠見蒼煙村。", "晴波溢清輝，午樹增重昏。", "方袍無平叔，佳處莫與論。"]'),
('2ab434b4-7ba5-42da-b7f0-61d1c43a5f5e','中巖','晁公遡','宋','宋诗','song-poetry','','[]','久聞慈姥巖，今作巖中遊。',132,'全唐诗/poet.song.116000.json','["久聞慈姥巖，今作巖中遊。", "驚嗟未省見，入蜀今白頭。", "松道夾蕭森，石門閉清幽。", "蘚字崖壁古，蟲書山葉秋。", "突然起平地，劃若三神丘。", "其旁寶瓶峯，特立高岑樓。", "錯摩碧琅玕，刻削青琳球。", "周觀劍東西，孰得與此侔。", "尊者何方來，杖錫乃肯留。", "乞泉爲洗心，一飲吾無求。", "尊者默然許，勿忘早歸休。"]'),
('2e63f896-48cb-47fe-afb0-1c2d57dc76c1','自過犍爲山水益佳','晁公遡','宋','宋诗','song-poetry','','[]','客遊三十年，不出僰與巴。',120,'全唐诗/poet.song.116000.json','["客遊三十年，不出僰與巴。", "江惡崖石粗，十步九褒斜。", "自過頼里西，山水日夕佳。", "冥冥見遠樹，渺渺鋪平沙。", "兩岸何所有，鬰鬰皆桑麻。", "良疇散牛羊，支流入魚蛇。", "清絕益可愛，豈復憶漢嘉。", "怳如涉荆吳，是耶復非耶。", "兒女長硤中，老妻髮已華。", "茲來始及此，舉首亦驚嗟。"]'),
('feebc5c4-0d1c-4b91-8c3b-94656f940189','清晨坐堂上','晁公遡','宋','宋诗','song-poetry','','[]','清晨坐堂上，文書常滿前。',120,'全唐诗/poet.song.116000.json','["清晨坐堂上，文書常滿前。", "皆自公府來，徵發何紛然。", "不聞問養民，但聞橫索錢。", "按籍爲之課，獨求最多年。", "孰知人困窮，豈有力貿遷。", "商不願出途，農不願授田。", "居者轉溝壑，行者死道邊。", "此罪在郡縣，恩澤壅不宣。", "公府不我責，所貴爲貨泉。", "長使貨泉在，吏曹同晏然。"]'),
('ac9fafe0-501a-4a30-ac17-8c9a5730331c','池上','晁公遡','宋','宋诗','song-poetry','','[]','爛醉高陽池，長嘯辟疆園。',120,'全唐诗/poet.song.116000.json','["爛醉高陽池，長嘯辟疆園。", "當時自謂樂，主人豈無煩。", "方塘我所有，嘉木亦已蕃。", "盛夏每數來，天高衆星繁。", "露下蓮花香，風生荷葉飜。", "微月銜林端，光照癭藤樽。", "飲之心爲清，如洗濁水源。", "念此寧久居，行矣駕折轅。", "悽然仰屋歎，千載屹常存。", "閲人猶傳舍，過者誰可言。"]'),
('f3b7cf5d-40a3-4187-9a76-6e10a3b9a9a0','喜張仲景范與蔡仲見過','晁公遡','宋','宋诗','song-poetry','','[]','昔游房相湖，乃適與子逢。',168,'全唐诗/poet.song.116000.json','["昔游房相湖，乃適與子逢。", "迨其景將入，不盡湖所窮。", "今子聯翩來，二難復相從。", "散策破莓苔，循池詠芙蓉。", "子勿謂池小，託之儋耳翁。", "名重覺景勝，人賢增地雄。", "老夫實自慶，得爲使君公。", "飲食玻璃江，日汲水一鍾。", "洗我崑崙心，充我雲夢胸。", "巾車且少留，樂當與子同。", "徑幽木陰茂，土腴蓮實豐。", "凌波挽碧莖，剪房剝青蓬。", "吾兄猶在遠，按節臨瀘戎。", "吾亦思飄然，攝身乘清風。"]'),
('d2c02472-1901-4b59-b7bc-9f03c9f21119','比與鮮于柬之游池上已而辱三詩見示因次韻  其一','晁公遡','宋','宋诗','song-poetry','','[]','循行脩竹林，愛此晚色浄。',48,'全唐诗/poet.song.116000.json','["循行脩竹林，愛此晚色浄。", "蕭然抱清節，每見敢不敬。", "香聞遥風度，陰過微月映。", "渭川游未能，吁嗟子方病。"]'),
('36f304fb-131f-41f1-9701-0173e1bb2389','比與鮮于柬之游池上已而辱三詩見示因次韻  其二','晁公遡','宋','宋诗','song-poetry','','[]','好風如高人，于世豈求售。',48,'全唐诗/poet.song.116000.json','["好風如高人，于世豈求售。", "惟予招則來，怏出土囊口。", "臨風弄清泠，笑視月在手。", "吾州玻璃江，不減蒲萄酒。"]'),
('c09d5f41-7a56-4d5b-aec4-f0e2be0a7dc5','比與鮮于柬之游池上已而辱三詩見示因次韻  其三','晁公遡','宋','宋诗','song-poetry','','[]','資州有佳兒，賢哉青雲器。',48,'全唐诗/poet.song.116000.json','["資州有佳兒，賢哉青雲器。", "過我池上游，長嘯薄炎熾。", "折花愛欹紅，墮葉輕拾翠。", "風流良不凡，可用觀子志。"]'),
('1ba0638a-9a8a-4ada-9fbc-fafd3b7d3bbd','承親戚見過生朝賦此爲謝','晁公遡','宋','宋诗','song-poetry','','[]','冠者五六人，駕言款吾門。',108,'全唐诗/poet.song.116000.json','["冠者五六人，駕言款吾門。", "是日射蓬矢，請壽此山樽。", "吾方念初生，非止祭特豚。", "保母親食我，卜士負且言。", "劬勞曾莫報，喪亂乃僅存。", "愧子自遠來，戒婦具盤飧。", "草木皆華滋，春事亦嬋媛。", "如欲起我衰，豪氣薄乾坤。", "何用酌酒漿，斗柄可手援。"]'),
('a38490a8-f8b3-4e1a-bddb-568391ee6e87','外舅衛尉持節於此作盡心堂時與親戚會飲今三十年予復與衛尉內外屬置酒堂上不減當時喜賦一詩','晁公遡','宋','宋诗','song-poetry','','[]','衛尉築此堂，棟宇真傑立。',144,'全唐诗/poet.song.116000.json','["衛尉築此堂，棟宇真傑立。", "幾容五百坐，可飲三千客。", "府中省文書，堂上會親戚。", "金杯浪飜江，銅盤光吐日。", "侍女發清歌，華筵美遥夕。", "當時倏分散，回首遂陳迹。", "豈知吾繼來，復見少長集。", "雖誠慰濶絕，得無感疇昔。", "在者皆其孫，樂極悲且泣。", "歡娛殆不減，左右或太息。", "諒曾事衛尉，始壯今髮白。", "諸郎各勉旃，宗族期烜赫。"]'),
('f9c1debd-8ab6-4c4c-a9c5-1dafd278c0ee','於陵仲子','晁公遡','宋','宋诗','song-poetry','','[]','於陵有仲子，築室自躬耕。',48,'全唐诗/poet.song.116000.json','["於陵有仲子，築室自躬耕。", "辟纑以爲食，不肯從其兄。", "而況區中士，欲與並飛纓。", "高節固可嘉，由來無復情。"]'),
('14afd140-9edd-4845-8edf-849f28a4d082','桑大夫','晁公遡','宋','宋诗','song-poetry','','[]','漢朝議鹽鐵，發言實盈庭。',48,'全唐诗/poet.song.116000.json','["漢朝議鹽鐵，發言實盈庭。", "赫赫桑大夫，官高稱九卿。", "方斡山海藏，難以口舌爭。", "力微不自量，可笑茂陵生。"]'),
('90871d9b-940c-4294-99cc-9d96530b817b','羣荷','晁公遡','宋','宋诗','song-poetry','','[]','羣荷翳清瀾，不受明月光。',48,'全唐诗/poet.song.116000.json','["羣荷翳清瀾，不受明月光。", "明月每下照，但見露瀼瀼。", "炯如翠蓋中，珠璣爛熒煌。", "我起欲挹之，傾瀉入方塘。"]'),
('a77e0503-c513-4b92-8a12-77ea627cec22','秋日','晁公遡','宋','宋诗','song-poetry','','[]','秋日淡無光，晴雲閒不行。',48,'全唐诗/poet.song.116000.json','["秋日淡無光，晴雲閒不行。", "空中散白石，仰看天宇明。", "時聞敗葉下，摵摵微風生。", "季月當泛菊，栽培園中英。"]'),
('e04d3632-9053-4e56-9875-b72536f7e54f','幽園','晁公遡','宋','宋诗','song-poetry','','[]','幽園有嘉植，盛夏乃繁陰。',48,'全唐诗/poet.song.116000.json','["幽園有嘉植，盛夏乃繁陰。", "竹節見青眼，榴花開赤心。", "樓高可遐覽，地近無遠尋。", "時能卜勝地，於此盍朋簪。"]'),
('e7217a28-bb8f-444e-aa89-0b20a376300d','妻姪師如石同婦見過','晁公遡','宋','宋诗','song-poetry','','[]','古人重生孫，欲爲王父尸。',96,'全唐诗/poet.song.116000.json','["古人重生孫，欲爲王父尸。", "爾姑念爾祖，宰木今風悲。", "不得見爾生，況當逆婦歸。", "我獨賀迺翁，有婦能奉匜。", "食上調滑甘，寒煖視其宜。", "更致大夫食，迺翁喜可知。", "還家勤五經，進德要及時。", "他年懸旌節，門戶增光輝。"]'),
('0c21030c-04a6-42de-91ed-d661149cd4ed','王元才携家來過有詩見示因簡此作','晁公遡','宋','宋诗','song-poetry','','[]','我思見諸姑，正復如父存。',96,'全唐诗/poet.song.116000.json','["我思見諸姑，正復如父存。", "諸姑不可見，豈無若子孫。", "天涯忽爾逢，悲定喜且語。", "惟我之老姑，爾之外王母。", "真能似我家，炯然眉宇清。", "閒暇幸數來，慰此衰老情。", "今朝携婦至，兒女亦成行。", "富貴各勉旃，他時勿相忘。"]'),
('172a1f2d-d551-476d-ab13-46cffdbd3851','六月五日池上','晁公遡','宋','宋诗','song-poetry','','[]','蒼然暮色來，初月光尚微。',72,'全唐诗/poet.song.116000.json','["蒼然暮色來，初月光尚微。", "河漢亦不高，仰看天四垂。", "衆星一何多，粲若天圍碁。", "忽驚毛骨清，漙露霑我衣。", "放杯折荷花，中有千丈絲。", "織爲芙蓉裳，可作江湖歸。"]'),
('b3757aa8-7422-4909-a17f-c234fee0fa36','次韻鮮于晉伯三月病起二首  其一','晁公遡','宋','宋诗','song-poetry','','[]','桃李幾何春已闌，雜生蘼蕪與射干。',64,'全唐诗/poet.song.116000.json','["桃李幾何春已闌，雜生蘼蕪與射干。", "永夏碧瓦藏綠暗，凉秋青山吐白團。", "開花旋見槐著莢，解籜忽驚筍成竿。", "資州無事吾所羨，官居不殊澗谷盤。"]'),
('e52d8ff5-caba-477f-b8ce-8aadc8965c7d','次韻鮮于晉伯三月病起二首  其二','晁公遡','宋','宋诗','song-poetry','','[]','甘雨尚嗇風未闌，只今時清舞舜干。',64,'全唐诗/poet.song.116000.json','["甘雨尚嗇風未闌，只今時清舞舜干。", "山前四面雲欲渰，松上五鬣露已團。", "甚憎塵土願投幘，頗思滄浪去持竿。", "何當共作雞黍社，長者進酒少舉盤。"]'),
('d067100a-f355-44bb-9601-478761d352f9','張若虛乃予妻黨湯德翁外孫喜其來賦此','晁公遡','宋','宋诗','song-poetry','','[]','我昔見德翁，其人直且溫。',96,'全唐诗/poet.song.116000.json','["我昔見德翁，其人直且溫。", "共知懷抱清，宜使鄉黨尊。", "竟無蒲輪召，遂葬蒿里園。", "張子極季發，乃是外諸孫。", "謹厚甚似之，好修仍寡言。", "功名在少壯，簡編勤討論。", "剩觀書連屋，願聞策臨軒。", "方起甯氏宅，再興文紀門。"]'),
('c2a9f5ff-aaf8-4409-ba65-7ea2cefe2aa3','眉山史頤老秀才遣人寄詩用其韻答之','晁公遡','宋','宋诗','song-poetry','','[]','衰年臨滄江，華髮羞照映。',156,'全唐诗/poet.song.116000.json','["衰年臨滄江，華髮羞照映。", "人憐貌枯槁，水與心清浄。", "所居少席煖，況望有屋潤。", "但期牧雞豚，那得追駔駿。", "爲貧未歸田，投老聊爲郡。", "每行芙蓉湖，魚躍見於牣。", "自欣逢外平，兵木適無刃。", "願從賢者樂，俯同農夫慶。", "常令燔或炙，安敢驕且吝。", "使君非何武，弟子乃樂正。", "陳論翻犀革，宴語對麈柄。", "却思凌雲下，亦致賓客盛。", "暇時可數來，念此百里近。"]'),
('1db3dd64-5e52-4ea3-a701-cee7cc5b5f5d','中巖文老和予游字韻見寄用韻爲報','晁公遡','宋','宋诗','song-poetry','','[]','我雖券內士，常思方外游。',132,'全唐诗/poet.song.116000.json','["我雖券內士，常思方外游。", "未見夫鐵脚，況逢通钁頭。", "癯然祇樹老，隠此陰崖幽。", "脩竹不知夏，青松不知秋。", "甚欲效柳子，冉溪買西丘。", "又欲追白傅，香山尋石樓。", "忽開化人書，書中有鳴球。", "其鳴疑飛泉，清絕或可侔。", "乃是寄我詩，恨我昔莫留。", "觀者勿疵瑕，謂以聲音求。", "句法傳叢林，五言如湯休。"]'),
('e35a3239-cfa8-4a2f-a874-e500d16d9f02','師伯渾自通義來且出詩一軸爲之喜甚奉簡短作','晁公遡','宋','宋诗','song-poetry','','[]','通義固多賢，我昔守此邦。',96,'全唐诗/poet.song.116000.json','["通義固多賢，我昔守此邦。", "不肯入城府，私獨敬老龐。", "今誰念我去，帳空列麾幢。", "感子能遠來，香醪發春缸。", "共登煙雨樓，相對雲霧窗。", "贈貽詩五字，何啻璧一雙。", "詞源極峻潔，石齒潄琮琮。", "驚怪得爾清，中有玻璃江。"]'),
('c69a8282-7484-4d6a-8fa0-cf086a4bc9ef','送宇文安行如吳下','晁公遡','宋','宋诗','song-poetry','','[]','往者華陽公，熊軾始西還。',120,'全唐诗/poet.song.116000.json','["往者華陽公，熊軾始西還。", "不斷吳松江，但取江中山。", "千巖與萬壑，歸置函丈間。", "白雲生宴坐，青壁照蒼顔。", "高標可想見，逸駕難追攀。", "公孫喟然歎，顧我敢自閑。", "要興故老家，再立清朝班。", "結綬思登畿，棄繻行入關。", "嗟予忝父客，送子亦涕潸。", "願謹視風水，魚龍多神姦。"]'),
('c88d1e15-f5be-43a6-ba4a-999e2616b816','諸君以詩見壽用師伯渾韻爲謝','晁公遡','宋','宋诗','song-poetry','','[]','遠遊天台登玉霄，蓬萊仙人宜可招。',96,'全唐诗/poet.song.116000.json','["遠遊天台登玉霄，蓬萊仙人宜可招。", "君詩持此爲我壽，愛君學問皆富饒。", "有如翠駮與紫燕，穆王畫圖昔曾見。", "只今豈合地上行，霜蹄去曳吳門練。", "老夫惟思雲夢州，煙波渺渺非子愁。", "湖中卉木足驅使，歸求橘奴買千頭。"]'),
('526ecd4e-7f8b-44d2-9830-7479a94ccbfa','張君玉用伯渾韻見示次韻爲謝','晁公遡','宋','宋诗','song-poetry','','[]','瞿唐石城干雲霄，城中飛書頻見招。',96,'全唐诗/poet.song.116000.json','["瞿唐石城干雲霄，城中飛書頻見招。", "主公賢似晉重耳，兼如郇瑕地沃饒。", "此行華堂伴清燕，退食從容日相見。", "篇章卷舒文錦繡，光彩照映軍組練。", "子寧爲官滯一州，不須仰天歌四愁。", "主公早晚登鳳閣，子亦牽聯立螭頭。"]'),
('e47c23b2-9989-44fe-912c-c1d63f387845','樂敦仁用師伯渾見示句中作禪語禪不可不領話頭次韻爲報','晁公遡','宋','宋诗','song-poetry','','[]','江邊看雲望青霄，誰知隔江以扇招。',96,'全唐诗/poet.song.116000.json','["江邊看雲望青霄，誰知隔江以扇招。", "機緣句語無可錄，要如芝嶺居上饒。", "鎔鐵作牛石作燕，鳴亦不聞飛不見。", "凜然獨立紈綺中，大帛之冠衣大練。", "果能出世去九州，絕意著書爲窮愁。", "請來言下辨白黑，試觀海頭并藏頭。"]'),
('8f18e783-503f-4efe-a797-f299a846b380','麥','晁公遡','宋','宋诗','song-poetry','','[]','層雲挾雨來，四郊樹木蒼。',72,'全唐诗/poet.song.116000.json','["層雲挾雨來，四郊樹木蒼。", "東風吹春促，尚带花藥香。", "年華不可駐，倏見夏日長。", "近傳陵陂麥，宿昔青已黄。", "隣舍思煮餠，隔牆聞沸湯。", "里胥忽在門，先當輸官倉。"]'),
('583ee3b4-2549-494d-a5cf-ade82989dcca','三月二十日東山雲蜿蜒而上衆指曰龍也已而大雨','晁公遡','宋','宋诗','song-poetry','','[]','東山龍起風雨來，勢雖暴甚天無雷。',64,'全唐诗/poet.song.116000.json','["東山龍起風雨來，勢雖暴甚天無雷。", "蜿蜒氣上黑雲合，喧豗浪打蒼崖回。", "千林通體有膏澤，四郊畫時無塵埃。", "舊聞此地亦勝絕，夜夜神光如五臺。"]'),
('21d4a212-8c24-4014-a075-fc4851675715','湯子才凌雲山用予十四日韻見示且云衛尉頃登清音載酒二亭口占一聯清音見江來載酒送江去悵然感之','晁公遡','宋','宋诗','song-poetry','','[]','衛尉余樂廣，昔嘗侍蓬萊。',120,'全唐诗/poet.song.116000.json','["衛尉余樂廣，昔嘗侍蓬萊。", "暮年乃去國，持節此徘徊。", "時登清音亭，遥見江西來。", "悽然載酒地，復送江東回。", "崔嵬蒼龍闕，白首所仰懷。", "宅相實在傍，敬起酌公杯。", "公詩不敢忘，永藏十瓊瑰。", "我慚衛叔寶，繼領外行臺。", "每望凌雲山，尚想蓋世才。", "遺聲落巖壑，松風有餘哀。"]'),
('f607cc3c-39ee-4b0e-a582-ca1725ac83ad','范子庚見示長書','晁公遡','宋','宋诗','song-poetry','','[]','百川各分流，至海皆同源。',108,'全唐诗/poet.song.116000.json','["百川各分流，至海皆同源。", "儻于中道畫，潢汙無本根。", "子今始濫觴，如河發崑崙。", "勿作澗溪止，當規溟海尊。", "誰謂水至弱，蓋有剛者存。", "批巖仍抉石，萬里爭東奔。", "朝來示我書，此意固已原。", "可鄙棖也慾，奚爲丘之門。", "願子更踐履，豈云但知言。"]'),
('baa0bca7-4a2d-4cb9-96fe-639e235af587','正月十四日游凌雲寺','晁公遡','宋','宋诗','song-poetry','','[]','昔賢登茲山，逸氣凌清旻。',120,'全唐诗/poet.song.116000.json','["昔賢登茲山，逸氣凌清旻。", "誦詩懷太白，考易思景純。", "至今平羌水，常浸月半輪。", "追尋所鑿室，石古莓苔新。", "後豈無來者，倏忽迹已陳。", "壁間記歲月，刻劃如龍鱗。", "自非傳一世，爛若配三辰。", "姓名雖尚存，誰復知其人。", "我游方之外，久忘實之賓。", "但飲佛耳泉，永洗凡心塵。"]'),
('353c2752-2bea-4448-a16f-97578588f2ff','奉簡湯子和','晁公遡','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','衛尉女公子，始生在開封。',132,'全唐诗/poet.song.116000.json','["衛尉女公子，始生在開封。", "君來謁衛尉，見之文褓中。", "却後十五載，我乃卧廂東。", "與君初會面，脩髯鬰垂胸。", "席間致大斗，一舉酒輒空。", "相看每歎息，豪氣如元龍。", "今年凌雲下，訪我采蘋宮。", "老妻髮亦白，歲月猶轉蓬。", "人生能幾何，羨此江無窮。", "家有百壺泉，色作真珠紅。", "飲盡方可歸，廬山正春風。"]'),
('acc872a9-0ff9-4705-9641-f81119bcab79','望峨嵋山作','晁公遡','宋','宋诗','song-poetry','','["\u5ce8\u7709\u5c71"]','普賢大開士，神足靡不周。',120,'全唐诗/poet.song.116000.json','["普賢大開士，神足靡不周。", "世人妄指此，象馭昔所留。", "願觀百億身，奔走數十州。", "見者喜稱快，不見默懷羞。", "紛紛相矜夸，隠晦蓋有由。", "正如官肆赦，盡出繫中囚。", "豈其得預聞，皆可除愆尤。", "一方每驚動，千乘時往游。", "返爲斯民勞，實貽開士憂。", "我師寒山子，豐干非同流。"]'),
('f7fe2c12-27f0-47d7-a892-1a3dfd27c36d','師永錫家青神喜紅花堰興作詩因次韻','晁公遡','宋','宋诗','song-poetry','','[]','終歲辛勤農在野，邊頭亦聞軍茇舍。',176,'全唐诗/poet.song.116000.json','["終歲辛勤農在野，邊頭亦聞軍茇舍。", "指揮郡縣催輓輸，兼伐葦蒲收檿柘。", "諸將但思弧矢利，教我力耕誰暇議。", "兵多食少將奈何，請君往問司徒銳。", "秦人鑿渠開陌阡，坐臨關東常晏然。", "當時列國豈知此，楚王內府藏三錢。", "何須飛來黄鵠語，吾已得於褐之父。", "紅花堰廢今百年，不復秋成頌多稌。", "君看初未作此陂，夏無暑雨民怨咨。", "鍤聲殆合桑林舞，千夫斸荒汗如雨。", "道旁笑指堰復興，他日飽食勿忘今。"]'),
('3a5190a9-9749-4189-b551-e2678dee873a','送湯子才如吳下','晁公遡','宋','宋诗','song-poetry','','[]','俶裝理蜀柁，長嘯下吳天。',120,'全唐诗/poet.song.116000.json','["俶裝理蜀柁，長嘯下吳天。", "摩挲烏牛石，三繫春江船。", "結綬昨去國，力田未逢年。", "初看飛舄來，皆謂令尹賢。", "再看泥軾歸，日謁刺史前。", "抱才宜爲邦，鬰抑顧莫宣。", "遇合會有時，此行定騰騫。", "聖人坐齋居，羣公拱御筵。", "召見渤海龔，拜謝臚句傳。", "歸乘廄吏車，五馬應翩翩。"]'),
('f147abb2-0207-48d8-8eff-dcbe67f6e2d2','謝張文老餉酥','晁公遡','宋','宋诗','song-poetry','','[]','清晨坐堂上，忽得故人書。',132,'全唐诗/poet.song.116000.json','["清晨坐堂上，忽得故人書。", "近自玉壘州，遠餉金城酥。", "聞由笮都出，來與枸醤俱。", "開視靜如練，緘題投比珠。", "甚知故人厚，痟中憐老夫。", "豈惟減肺渴，兼可濡腸枯。", "因之想風味，更過酪醍醐。", "致此未足言，公才可時須。", "似傳滇池君，願獻汗血駒。", "高有八尺龍，次有一丈烏。", "論功當作頌，請歌馬斯徂。"]'),
('00e57c2e-4f1a-4d39-9a4c-cda772fcaf82','師永錫少出通義其歸携伯渾詩來因用其韻伯渾頃嘗相送至下巖也','晁公遡','宋','宋诗','song-poetry','','[]','益州古建國，遠自蠶叢來。',96,'全唐诗/poet.song.116000.json','["益州古建國，遠自蠶叢來。", "吾敢怪鼈靈，人有化牛哀。", "惟愛老翁井，蘇仙手所開。", "乘軺難少留，門前廄吏催。", "愧子遠相送，同把巖下杯。", "至今夢見之，石壁青崔巍。", "豈伊四座客，能屈一世才。", "去者不可招，至者不可推。"]'),
('e1ac41c8-93de-4f03-a4d4-fd16c18e756f','閻才元因程伯珍來寄近詩一軸不能盡和用師淮父韻奉簡','晁公遡','宋','宋诗','song-poetry','','[]','我思買蜀山，附田小崢嶸。',204,'全唐诗/poet.song.116000.json','["我思買蜀山，附田小崢嶸。", "家本冰氏子，室無孔方兄。", "爲郡非其樂，强顔聊此行。", "四夷幸兵休，萬邦喜時平。", "所嗟啟利源，開國始於荆。", "當年惟迂叟，乃如魯二生。", "高卧不肯起，彼方事交征。", "共兜自滔天，堯舜實聖明。", "至今天下士，語及涕縱橫。", "今王益神武，覽奏每歎驚。", "皇皇元首詩，主歌臣則賡。", "德音既屢下，美意誰能成。", "追懷符益州，積惡高陵京。", "老農扣頭泣，願聞徭役輕。", "故人佐太府，因君煩寄聲。", "艱難念吾土，慷慨見深情。", "歃血誓仁義，由來蓋同盟。"]'),
('3f2ca8f6-219a-40ad-b1c5-3ce53a18dacc','次韻劉安收惠詩二首  其一','晁公遡','宋','宋诗','song-poetry','','[]','此地冠蓋國，古來翰墨場。',96,'全唐诗/poet.song.116000.json','["此地冠蓋國，古來翰墨場。", "夜看蟇頤山，上干牛斗光。", "試酌老翁井，尚餘書傳香。", "想其居清華，漢閣千步廊。", "大字寫汗青，小楷書硬黄。", "仙去不可追，里人祀烝嘗。", "神兮肯下來，冠劍在帝傍。", "作詩遺里人，聞者當感傷。"]'),
('aa44f567-aee8-4d55-9c4d-cda978844a50','次韻劉安收惠詩二首  其二','晁公遡','宋','宋诗','song-poetry','','[]','耳悅齊王竽，莫聽蕢桴聲。',84,'全唐诗/poet.song.116000.json','["耳悅齊王竽，莫聽蕢桴聲。", "口甘秦人炙，莫采首陽苓。", "沈酣自壯歲，昏塞況暮齡。", "誰能悟此理，知幾如穆生。", "何須著胸中，雲夢一芥蔕。", "要當空所有，爲彼亦過計。", "惟思半嶺雲，野老肯分似。"]'),
('4b0aa886-3d06-43ae-aa92-1a018b70f9dc','勞劉子儀視作紅花堰','晁公遡','宋','宋诗','song-poetry','','[]','冽冽天北風，仰視寒雲繁。',132,'全唐诗/poet.song.116000.json','["冽冽天北風，仰視寒雲繁。", "蟄蟲亦坯戶，子獨在丘原。", "路人指此堰，嘖嘖相與言。", "堙廢將百年，故道今豈存。", "旁有蔣子池，沮洳無根源。", "耕者病夏畦，擁耒涕潺湲。", "念子不憚勞，塞茅手自掀。", "忽報故道出，萬鍤如雷喧。", "堰成爭來觀，矗若千丈垣。", "少壯始從仕，功績已可論。", "他時當不朽，名配謝公墩。"]'),
('ff1080fe-dc3e-4ba0-8a9b-1e247b519062','七月二十日雨中','晁公遡','宋','宋诗','song-poetry','','[]','浮雲淡高天，清雨灑廣庭。',96,'全唐诗/poet.song.116000.json','["浮雲淡高天，清雨灑廣庭。", "池館颯以凉，始知秋氣生。", "蒲荒葉亂委，荷折蓋已傾。", "微風經草木，獵獵有寒聲。", "炎蒸豈得久，四時相代更。", "當暑思折膠，纖絺不爲輕。", "冬復念裘褐，乃與寒暑爭。", "誰能安天運，傷哉世上情。"]'),
('4c70c4e4-a8e4-4eda-aeba-f72c2f324abb','喜湯子才永豐築室成','晁公遡','宋','宋诗','song-poetry','','[]','顔子在陋巷，端居亦何難。',120,'全唐诗/poet.song.116000.json','["顔子在陋巷，端居亦何難。", "家有郭外田，足以給一簞。", "今我客四方，衣食於縣官。", "罷則無所歸，奔走殊未安。", "聞君築室成，內熱自長嘆。", "近村爭相助，老幼常聚觀。", "斵者來運斤，圬者來持鏝。", "經始曾幾時，爛然皆雘丹。", "更須蓻嘉木，竹已青檀欒。", "藩籬護封植，勿令牛鬭殘。"]'),
('c5183144-a3f4-4252-921f-b046c7d52131','四月堰水甚小一雨灌田方足','晁公遡','宋','宋诗','song-poetry','','[]','岷江惟清流，涇水惟濁泥。',168,'全唐诗/poet.song.116000.json','["岷江惟清流，涇水惟濁泥。", "泥濁禾黍茂，流清稉稻宜。", "舊傳江發源，瀵涌出沈黎。", "老農望其來，未至龍尾西。", "今晨南山雲，蓊然忽朝隮。", "滂沱三尺雨，泛溢千步隄。", "積潦始北匯，餘波各東釃。", "茫茫黑壤潤，戢戢翠剡齊。", "亦復到邑里，溝澮爭交馳。", "往看芙蓉湖，微風綠生漪。", "似欲娛使君，豈減習家池。", "老農喜相語，歲晚可無饑。", "再拜勾龍社，配我靈星祠。", "更煩請天公，膏澤常及時。"]'),
('a7ab53fa-f0f5-4962-adeb-fd8abc143c03','石季野縣丞見示喜雨詩次韻爲謝','晁公遡','宋','宋诗','song-poetry','','[]','驕陽裂厚地，沃壤變焦土。',180,'全唐诗/poet.song.116000.json','["驕陽裂厚地，沃壤變焦土。", "野老呼蒼天，吁嗟擊雩鼓。", "三時農甚勞，一飽天宜與。", "自慙爲刺史，封內當鎮撫。", "有災累其人，無德及所部。", "是邦喜譏切，相語聞儔侶。", "不作傅說霖，空閔僖公雨。", "敢欺二三子，難長數百戶。", "徒知禱神祇，庶望救疾苦。", "如起乖龍卧，便覺商羊舞。", "坐令郡兩堰，豈減渠六輔。", "茲晨理衣冠，未暇掛神武。", "傷心念疲氓，稽首謝明主。", "豐年必可期，甘澤常順序。", "與君俱何幸，彼此德施普。"]'),
('c7373d53-5951-405e-a270-a196f525d17c','從宋憲登萬景樓','晁公遡','宋','宋诗','song-poetry','','[]','勝地開傑觀，大川壯重關。',156,'全唐诗/poet.song.116000.json','["勝地開傑觀，大川壯重關。", "使者領我來，共此須臾閒。", "玉節照綠野，銀瓶落青綸。", "酒酣望八極，氣豪吞百蠻。", "俯窺二江水，遠指三峩山。", "遂令蒼茫外，盡在顧盻間。", "崔嵬凌雲寺，繚繞含風灣。", "洲渚遞隠見，煙霞渺斕斑。", "靜看浮鷗沒，坐數昏鴉還。", "作者必磊落，後來莫能攀。", "不減鸛鵲樓，可想熊豹顔。", "下有安樂園，惜哉半荆菅。", "誰其爲起廢，歎息歲方艱。"]'),
('a0468233-78b4-4aa5-81cf-5e27fd54171c','師伯渾自所居東山來賦詩相示用韻酬之','晁公遡','宋','宋诗','song-poetry','','[]','東山鳴鳳在九霄，高翔千仞那可招。',96,'全唐诗/poet.song.116000.json','["東山鳴鳳在九霄，高翔千仞那可招。", "胡爲相顧肯下集，竹實醴泉吾用饒。", "春來淘河嚇飛燕，泉中老翁誰復見。", "崇桃炫晝爛明霞，穠李照夜舒素練。", "去年念我守此州，樽前歌者有莫愁。", "遥持一盃屬父老，日暮仰天搔白頭。"]'),
('09877224-cd3c-4f3c-9a61-10b4d8f03175','范仲芑惠詩次韻爲報','晁公遡','宋','宋诗','song-poetry','','[]','吾皇之居玄都秘，龍爲徼巡虎守衛。',128,'全唐诗/poet.song.116000.json','["吾皇之居玄都秘，龍爲徼巡虎守衛。", "太顛閎夭盡奔走，竇嬰灌夫敢睥睨。", "今年已徵虞公入，聖代豈有舜門閉。", "黄君近在承明庭，著作磊落垂一世。", "關子真宜校天祿，文采不減特進麗。", "劉郎聞亦對宣室，上陳三宗下七制。", "子當繼往螭頭立，我但願若龜尾曳。", "坐看指日清中原，同與老農歌樂歲。"]'),
('7ed26532-9ddf-4dee-91ab-ce6d6aae803f','王伯厚和予牆字韻因用其韻記五月八日同飲池上之作','晁公遡','宋','宋诗','song-poetry','','[]','蜀人工詞賦，作者司馬揚。',156,'全唐诗/poet.song.116000.json','["蜀人工詞賦，作者司馬揚。", "其聲中律呂，今有房中章。", "顧嘗評筆力，蓋可補詩亡。", "追思每歎息，浩歌徒慨慷。", "雖無銅水池，想見金芝芳。", "屬此樂大予，徧之署清商。", "是邦故俎豆，夫豈數樂浪。", "能唱襄陽曲，不減大隄倡。", "助我飲在泮，慙君並遊梁。", "臨波攬芙蓉，翠葉以爲觴。", "酌酒滿貯之，如挹白露光。", "放杯且勿遽，更當謀樂方。", "左右嗟未省，旁觀猶堵牆。"]'),
('f95a57a9-d914-492e-a89b-f927fd2872a3','比以酒餉師伯渾辱詩爲謝今次韻','晁公遡','宋','宋诗','song-poetry','','[]','荷花爲我衣，荷葉爲我觴。',120,'全唐诗/poet.song.116000.json','["荷花爲我衣，荷葉爲我觴。", "白露以爲醴，濯我冰雪腸。", "念君在東山，宛若天一方。", "想亦能自樂，飲菲仍食芳。", "及茲菰黍節，日吉辰甚良。", "笑攬北斗柄，安可挹酒漿。", "我有江南春，的皪猶竹光。", "傳呼急走送，兩足趼復僵。", "取君池中魚，酌此膾蜀薑。", "遥知快大嚼，饔子刀如霜。"]'),
('5a13878d-f4e1-4247-9dfe-c6c78768bf18','郭中行自漢中寄近詩來奉簡一首','晁公遡','宋','宋诗','song-poetry','','[]','憶始衿袂分，十載再相逢。',192,'全唐诗/poet.song.116000.json','["憶始衿袂分，十載再相逢。", "於時客益州，俱在行李中。", "不暇語衮衮，至今恨匆匆。", "惟昨一麾守，其守百乘同。", "乃翁持使節，顧予屬提封。", "君歸問寢門，遣書託風通。", "冀君或少留，解綬將往從。", "翻然先我去，劃若高飛鴻。", "經行武都間，古來多英雄。", "前弔大耳兒，追懷隆準公。", "壞道想流馬，深山埋卧龍。", "試尋所築壇，榛荒草蒙茸。", "詠歌意有託，嗤點昔未工。", "才大當盛年，氣豪念勇功。", "老夫猶少陵，志墮身亦窮。", "獨思百丈潭，俯臨衰病容。"]'),
('5d807ca7-114f-46f2-9327-b743b095fd7a','喜劉文潛來奉簡短作','晁公遡','宋','宋诗','song-poetry','','[]','吾州橫絕峨嵋陰，地勝無復俗塵侵。',64,'全唐诗/poet.song.116000.json','["吾州橫絕峨嵋陰，地勝無復俗塵侵。", "慈姥巖深不受暑，老翁井寒能洗心。", "子來觸熱可休駕，我起呼風令解襟。", "芙蓉池上更爽塏，仰看參天皆茂林。"]'),
('6c8b7ab0-1954-4d60-806d-d5d2ecf92cfd','喜三十二弟來','晁公遡','宋','宋诗','song-poetry','','[]','吾家全盛時，冠蓋靄雲屯。',144,'全唐诗/poet.song.116000.json','["吾家全盛時，冠蓋靄雲屯。", "上車入華省，下車趨里門。", "宗族百餘人，圭璋疊璵璠。", "胡塵暗河洛，分散各南奔。", "豫章老風霜，寧有枝葉繁。", "識者猶愛重，和爲千歲根。", "聞汝居沈黎，鄉黨頗見尊。", "尚蒙五世澤，勿鄙三家村。", "當令化箕子，所在誦文元。", "念汝今遠來，白首共盤飧。", "會合良亦難，亂離忍復言。", "少留無遽歸，同姓可不敦。"]'),
('aec8c291-090f-428f-b6f8-4ea209f5110d','薛郎遠以頌爲壽句法崛奇讀之喜甚賦此爲謝','晁公遡','宋','宋诗','song-poetry','','[]','家藏五世書，不減王銅川。',144,'全唐诗/poet.song.116000.json','["家藏五世書，不減王銅川。", "仕宦雖陸沈，文章則蟬聯。", "女歸逢其良，辭來亦粲然。", "胸次龜負圖，筆端驥奔泉。", "生朝遠壽我，細字書滿牋。", "手追淇澳詩，句法兩漢前。", "念昔昌黎公，嘗賦猛虎篇。", "南紀通古學，已難與並傳。", "況墮牛李中，百代莫洗湔。", "開尊笑謂婦，舉酒屬青天。", "愈也殆我愧，庶幾太史遷。", "更看敞夫人，叅語東廂邊。"]'),
('f9983c93-e5a0-48ad-b0d7-1647c1566234','簡梁子輔','晁公遡','宋','宋诗','song-poetry','','[]','比報趨魏闕，俄從三館游。',168,'全唐诗/poet.song.116000.json','["比報趨魏闕，俄從三館游。", "此地非人間，清絕乃瀛洲。", "時應陪羣仙，記帝蓬萊丘。", "中有白玉京，五城十二樓。", "胡爲憑熊軾，復泝巴江流。", "觀者盡驚歎，怪子不少留。", "無寧薄蓬萊，顧欲守一州。", "自云見帝所，侍御皆和柔。", "始知未鍊形，難與洪崖儔。", "不如在下土，爲民除瘡疣。", "屬予持漢節，夙夜愧且憂。", "日聞民呻吟，蓋甚魚掛鈎。", "幸子爲之主，其病往必瘳。", "何由使有邦，人人得賢侯。"]'),
('f2b67e98-cab9-4415-9417-91d7f6878fa7','自嘆','晁公遡','宋','宋诗','song-poetry','','[]','巴蜀久彫敝，傷哉遠朝廷。',156,'全唐诗/poet.song.116000.json','["巴蜀久彫敝，傷哉遠朝廷。", "大道舞狐狸，嘉穀困蝗螟。", "我嘗行其野，所在聞惟腥。", "歎息莫能救，熟視涕淚零。", "今年不自意，屬當按邦刑。", "平時語云何，敢遽忘生靈。", "擬於萬仞淵，撓以一寸筳。", "賢者相告戒，安坐看空囹。", "愚者顧之笑，謂我不自寧。", "我非惡靜樂，獨行苦伶仃。", "糜費廩中粟，奔走閤前鈴。", "恐如執金椎，而誦麥青青。", "果欲中世用，諸公乃儀型。"]'),
('ea5a3aa7-e6bb-4943-8844-b5afb9da31be','李仁甫除喪作詩問之','晁公遡','宋','宋诗','song-poetry','','[]','閉門讀喪禮，荒庭蓬藋深。',156,'全唐诗/poet.song.116000.json','["閉門讀喪禮，荒庭蓬藋深。", "愁雲聚隴首，悲風吹棘心。", "隣里昨甚憂，哭踴恐不任。", "近除二月禫，初御五日琴。", "雖復瘦欒欒，衆語喜見今。", "諒其念遺體，保此軀千金。", "顧無瘍可沐，髮脫未勝簪。", "稍當理衣冠，結綬且正襟。", "渠家符璽郎，實冠翰墨林。", "世業乏潤色，詔書行訪尋。", "紬繹須史遷，校讎得劉歆。", "再編中興詩，更載庭燎箴。", "暇時侍君側，祈招誦愔愔。"]'),
('48724876-976c-451d-a12d-2b10cb8f5d8b','中巖長老子文送羅漢松','晁公遡','宋','宋诗','song-poetry','','[]','駐車凌雲山，雖在官府中。',96,'全唐诗/poet.song.116000.json','["駐車凌雲山，雖在官府中。", "平生著幽禪，意與方袍同。", "已杖菩薩竹，更來羅漢松。", "天姿特高潔，厚葉非蒙茸。", "銅柯既夭矯，玉薤仍青葱。", "上有五百士，下笑十八公。", "皆披闍黎衣，如坐浮屠宮。", "勿謂默不語，說法聲摩空。"]'),
('77dd8c03-aea5-4cd3-a744-f47f5e1865a2','劉文潛來','晁公遡','宋','宋诗','song-poetry','','[]','虛亭布雨潤，高林來風聲。',72,'全唐诗/poet.song.116000.json','["虛亭布雨潤，高林來風聲。", "之子適過我，氣與秋爭清。", "胸次冰壺寒，舌端河漢傾。", "仰摩玉宇蒼，真是金天晶。", "使我簿書中，無復俗氛生。", "惜哉不可留，膏車明遂行。"]'),
('ed67b2af-6c9f-41bd-98d9-09d069acdc1e','與李紹祖劉文潛飲酒','晁公遡','宋','宋诗','song-poetry','','[]','劉子我所敬，未嘗言囁嚅。',132,'全唐诗/poet.song.116000.json','["劉子我所敬，未嘗言囁嚅。", "李子我所畏，氣豪才有餘。", "自昔得二子，重之比璠璵。", "喜今至是邦，乃與二子俱。", "劉子忽告行，具舟下東吳。", "念欲相挽留，佐我治文書。", "天台望其來，交章滿公車。", "李子復繼往，刺史親題輿。", "似云日延佇，正此州家須。", "二子古益友，終歲可與居。", "一朝捨我去，別淚濕襟裾。"]'),
('65339389-7e7a-4554-a207-65f75a911bc3','觀畫','晁公遡','宋','宋诗','song-poetry','','[]','菰蒲欹倒洲渚生，江流茫茫亦清平。',48,'全唐诗/poet.song.116000.json','["菰蒲欹倒洲渚生，江流茫茫亦清平。", "小舟擊汰如有聲，入眼初覺非丹青。", "便欲從之載酒行，忽怪四壁風濤驚。"]'),
('b49599ab-4330-42ac-9de7-22ef16f82ad8','鮮于大任自吳下來比與之飲大任自取毗陵惠山泉酌之色清而味勝蜀無有也喜賦詩','晁公遡','宋','宋诗','song-poetry','','[]','君從毗陵來，載酒與偕行。',108,'全唐诗/poet.song.116000.json','["君從毗陵來，載酒與偕行。", "釀以陸子泉，可使傖父驚。", "香味橄欖嚴，顔色蒲萄清。", "得非續玉漿，無乃挹金莖。", "固應壓白墮，亦未數烏程。", "老夫家巴蜀，華髮思南烹。", "飲此惟恐盡，酌之且徐傾。", "君如建吳檣，再見毗陵城。", "相煩送一車，救我枯腸鳴。"]'),
('a0fe04d0-1511-4f9e-af55-1b07d6aa921a','喜邵孟清見過','晁公遡','宋','宋诗','song-poetry','','[]','爾居泰定山，豈減獨樂園。',108,'全唐诗/poet.song.116000.json','["爾居泰定山，豈減獨樂園。", "但恨山中翁，奄忽歸九原。", "我來不及識，風流被後昆。", "見爾眉骨似，驚嗟翁尚存。", "借問昔手植，今應茂牆藩。", "高松垂雨鬣，大竹引霜根。", "種木在閭里，種德在子孫。", "家有三絕編，德乃一代尊。", "閉門勤讀此，勿使絕微言。"]'),
('b9232549-7045-42d3-b652-c653b86bb1dc','寄郭信可時假守忠州','晁公遡','宋','宋诗','song-poetry','','[]','君家老阿舒，抗論王公前。',144,'全唐诗/poet.song.116000.json','["君家老阿舒，抗論王公前。", "盍不託清靜，著書如子玄。", "愛君識此意，坐脫世糾纏。", "不復眉炙狂，惟應口談天。", "近假刺史節，名高黄潁川。", "無爲渠自化，多事豈所便。", "只今鳴玉溪，百尺來飛泉。", "秋風木葉下，想見清潺湲。", "凉波納華月，洗此白璧圓。", "借問掾曹內，得無從事賢。", "賞音不易逢，勝景那可捐。", "願因東轅使，寄我南樓篇。"]'),
('de2ad72d-3b2b-40c0-90bc-8eb23d78e84c','遠望','晁公遡','宋','宋诗','song-poetry','','[]','山近色未佳，山遠看始好。',108,'全唐诗/poet.song.116000.json','["山近色未佳，山遠看始好。", "我居巴硤內，所向苦奔峭。", "清晨望西南，忽盡牂牁徼。", "時於蒼茫外，寸岫出林表。", "雲來翳遥碧，眇眇沒飛鳥。", "方知勝絕處，畧已領其要。", "何必親躋攀，辛勤事幽討。", "平生謝康樂，往來永嘉道。", "此意當未知，躡屐空至老。"]'),
('8a9489e8-6d4f-41a6-8e39-4a0844b53232','過陳行之飲','晁公遡','宋','宋诗','song-poetry','','[]','陳郎見我江陽城，自起喚婦親庖烹。',128,'全唐诗/poet.song.116000.json','["陳郎見我江陽城，自起喚婦親庖烹。", "殷勤纖手爲袒割，始飲一盃和且平。", "一盃已盡催進酒，平頭奴子皆傳聲。", "幾州春色入此盎，陳郎調酒如調羹。", "我家東牀有孫子，亦得從容陪燕喜。", "門前有客不速來，笑說今朝動食指。", "陶然胸次吞渭涇，入口豈知醨與醇。", "從茲剩致百家酒，更可作意呼真真。"]'),
('a6503003-8e57-4322-8778-90f5102d67a2','陳行之二年三至寧江嘗有遊吳之興而尚不果','晁公遡','宋','宋诗','song-poetry','','[]','君如歷塊馬，萬里當霜蹄。',132,'全唐诗/poet.song.116000.json','["君如歷塊馬，萬里當霜蹄。", "今爲繞枝鵲，終夕未安棲。", "二年三見過，每至醉似泥。", "我貧觴豆薄，飯豆兼羹藜。", "汲碧雲雨硤，擷青風露畦。", "焉能效季倫，咄嗟辦䓑薺。", "君婦工烹調，刀几勞柔荑。", "昔嘗留我飯，鮮腴出中閨。", "慎勿笑粢糲，平生把鉏犁。", "朝來忽告別，復指巴渝西。", "借問王內史，何時游會稽。"]'),
('932906a2-c6ed-4c16-87ba-05fc7d7a7a70','謝曾子長分餉臨江軍黄雀','晁公遡','宋','宋诗','song-poetry','','[]','遠游旅食荒山裏，竹鼠山鷄污刀几。',192,'全唐诗/poet.song.116000.json','["遠游旅食荒山裏，竹鼠山鷄污刀几。", "鳴鞭走送來扣門，眼明忽見銜環子。", "江南今秋禾黍熟，場間啄穗驚不起。", "正緣一飽墮網羅，包裹頭顱行萬里。", "登盤始欣不負腹，下箸未及先染指。", "畧須沃酒助甘腴，更覺披綿愈豐美。", "使我轉憶江湖鄉，水珍海錯那可忘。", "十年不見尚能說，楚人未數鯉與魴。", "蛤蜊含漿自有味，蟹螯斫雪仍無腸。", "紅螺爲醤勝食肉，白𧍧作炙如截肪。", "江瑶石首最貴者，千金一枚誰得嘗。", "但願浮家老吳越，此生不願尚書郎。"]'),
('1cb8f58b-49ee-4939-b473-7e0b1ce42bf1','入硤行','晁公遡','宋','宋诗','song-poetry','','[]','吾家文物如崔公，向來世學工彫龍。',177,'全唐诗/poet.song.116000.json','["吾家文物如崔公，向來世學工彫龍。", "側理固嘗收會稽，陶泓不獨稱洪農。", "徂徠取煤如點漆，宣城束穎能藏鋒。", "焉知于今一禿翁，四寶委棄文房空。", "近時稍稍復尋訪，嗜好亦須隨土風。", "磁洞疏波鑿山骨，沙隴剔藪求毛宗。", "昌溪萬碓擣白楮，涪江千炬焚椅桐。", "不須更問在何記，已作僰叟從巴童。", "但看所有乃如此，亦足驗我良羈窮。", "君不見昔年平御史，初得巨璞三硤中。", "少陵酸寒真可笑，欲使起草明光宮。"]'),
('54a5de3b-a6de-418a-929b-b4c1d1d0197d','寧江僑人劉生徽宗時以畫供奉翰林中近過元汝功見其畫甚多皆劉生筆也','晁公遡','宋','宋诗','song-poetry','','[]','劉生待詔蓬萊宮，和鉛舐墨稱良工。',224,'全唐诗/poet.song.116000.json','["劉生待詔蓬萊宮，和鉛舐墨稱良工。", "自從八駿狩西極，萬里流落巴山中。", "老來摹寫益神妙，指麾草木回春風。", "時將一幅換斗米，千金舊價無由逢。", "漫郎手築江上宅，水鳥山麋森滿壁。", "問君致此何其多，答云嗜好今成癖。", "野人未嘗完袴襦，安得絹素充我娛。", "孰知世間皆畫囿，北盡汧瀧南衡廬。", "平生長嘯桓將軍，客持寒具輒怒嗔。", "細看粉繪託形似，豈若海岱開精神。", "我今丘壑隨所向，崖谷波濤入圖障。", "雲羅霧縠雖可憐，幻化紛紛徒自誑。", "請君閒暇來相從，翩然共跨高飛鴻。", "當使真形識五岳，老眼一洗丹青空。"]'),
('55344d2b-eebc-4368-b36a-0ce676f4d69d','曾夔州座右山水圖','晁公遡','宋','宋诗','song-poetry','','[]','華堂左右皆山川，登堂一見心茫然。',160,'全唐诗/poet.song.116000.json','["華堂左右皆山川，登堂一見心茫然。", "松林忽在素壁上，几杖却對陰崖前。", "百年老樹橫高枝，正當太古陰雲垂。", "近前細看纔拱把，生氣凜凜如十圍。", "尚想昔年初下筆，指顧江山生咫尺。", "梁棟已受長風吹，衣裘若濺洪濤濕。", "回山倒海不作難，此意誰能傳筆端。", "李成骨朽道寧死，況復鄭虔楊契丹。", "吾知此圖未易逢，頗思摹寫置座中。", "鵝溪生綃不難致，只恐今世無良工。"]'),
('02c006ed-031e-449e-a80b-93a7d69c2dce','鮮于大任自東南歸唐安遺予張安國所作水調歌墨本一軸且云明年復往吳下喜簡作此','晁公遡','宋','宋诗','song-poetry','','[]','去蜀游東吳，舉頭望赤霄。',168,'全唐诗/poet.song.116000.json','["去蜀游東吳，舉頭望赤霄。", "君之門九重，觚稜鬰岧嶤。", "是中盛文物，簪筆立漢朝。", "規摹覺地雄，氣象知天高。", "計其所從客，皆是夔與皋。", "平生聞張公，磊落一世豪。", "示我水調歌，奴僕可命騷。", "尚想揮翰時，淋灕宮錦袍。", "問子何歸來，遠指萬里橋。", "答云懷喬木，聊復訪衡茅。", "未嗟功名忤，非憚道路勞。", "不見廊廟具，乃對簿領曹。", "明年買扁舟，鼓枻出下牢。", "西府有故人，亦應遣弓招。"]'),
('4a5bd51b-510f-4588-83f3-f0c0721b2616','送李檢法赴夔州任','晁公遡','宋','宋诗','song-poetry','','[]','硤內如播州，曠絕誰與隣。',120,'全唐诗/poet.song.116000.json','["硤內如播州，曠絕誰與隣。", "君昔居其間，簿書良苦辛。", "捨之遂西游，五見岷峨春。", "屢爲帳下士，皆稱席上珍。", "昨聞乘軺使，去作觀國賓。", "雖歌馬離廄，肯效鷹著人。", "蹭蹬何所歸，復踏巴渝塵。", "手持太府書，仰推明主仁。", "約束狴犴吏，哀矜鱗介民。", "爲予語父老，今使子國新。"]'),
('e5357214-d46c-4e54-83d7-124296b5c37b','送李仁甫被召','晁公遡','宋','宋诗','song-poetry','','[]','天王覽萬事，日昃坐承明。',180,'全唐诗/poet.song.116000.json','["天王覽萬事，日昃坐承明。", "甚思得奇才，指望中原平。", "小吏與計偕，大夫招以旌。", "結綬聯翩來，屢聞開邇英。", "少卑著三館，高者登九卿。", "朝廷非不用，功業竟何成。", "豈其有所懷，閉口且吞聲。", "豈其有所畏，捩手恐覆羹。", "吾傷風俗衰，視此天下衡。", "莫計事可否，但隨意重輕。", "雖復建良法，因茲無由行。", "念予卧龍底，二年飽躬耕。", "世故已熟觀，見君勿屏營。", "要陳治安策，剴切如賈生。", "願無似揚雄，詞賦稱西京。"]'),
('3328d902-745e-4719-8774-c4f8c8760fcb','謝王元才見惠峨嵋山菩薩石','晁公遡','宋','宋诗','song-poetry','','["\u5ce8\u7709\u5c71"]','久聞光明山，下有太古雪。',132,'全唐诗/poet.song.116000.json','["久聞光明山，下有太古雪。", "大冬劇嚴凝，厚地愈融結。", "崢嶸成層冰，千歲終不滅。", "野翁因斸荒，得此走城闕。", "初非人磨礲，真是天剞劂。", "形模如圭長，顔色逾玉潔。", "巨細皆晶熒，表裏俱洞澈。", "或疑普賢化，誰得昆吾切。", "太陽一照曜，神光時發越。", "誠宜置宴坐，相伴修白業。", "可配寒露壺，清泠濯明月。"]'),
('28871e3b-734a-4033-9525-7290500219bd','今歲試士竟置酒起文堂延主司且作詩送之','晁公遡','宋','宋诗','song-poetry','','[]','吾州俗近古，他邦那得如。',168,'全唐诗/poet.song.116000.json','["吾州俗近古，他邦那得如。", "飲食猶俎豆，傭販皆詩書。", "今年屬賓興，詔下喧里閭。", "白袍五千人，崛起塞路衢。", "入門坐試席，正冠曳長裾。", "談經慕康成，對策擬仲舒。", "吟詩必二雅，作賦規三都。", "傳聞選主司，考閲須鴻儒。", "果然提權衡，未嘗謬錙銖。", "得者固驚喜，失者亦歡呼。", "鄉黨爲歎息，是事蓋久無。", "老守蒙此聲，增重西南隅。", "何以爲子謝，舉觴挽行車。", "少留盡一醉，歸駕且勿驅。"]'),
('73b30046-cfce-4dd3-b716-f9e48f0d79e1','次韻楊光父見贈','晁公遡','宋','宋诗','song-poetry','','[]','爲善惟不足，務德莫如滋。',120,'全唐诗/poet.song.116000.json','["爲善惟不足，務德莫如滋。", "古人行此道，名與星斗垂。", "是邦禿鬢翁，實乃古醜夷。", "區區豈云難，長者能折枝。", "上尋聲光遠，下感風俗衰。", "老夫强解事，曲學安所施。", "不見南海濱，舉世誰保持。", "吾言那可用，鄉黨笑脫頤。", "但皆指喬木，故園今在茲。", "喬木誠茂美，歎息將何爲。"]'),
('118ec887-baf0-4f04-a387-bc975d51fb1f','送杜時可歸太學','晁公遡','宋','宋诗','song-poetry','','[]','宴安不可懷，百年能幾何。',144,'全唐诗/poet.song.116000.json','["宴安不可懷，百年能幾何。", "況今五學開，皆以禮爲羅。", "既書內舍籍，天門近嵯峨。", "云胡久不歸，滯留蜀江沱。", "要須勇一往，行即中十科。", "君婦定復賢，相敦戒蹉跎。", "暫別德曜桉，勿操子犯戈。", "會看此里閭，高車再來過。", "路人笑指點，駟馬金盤陀。", "遠遊那足悲，所得蓋已多。", "罷酒當就途，執杯聽我歌。", "司業乃父兄，養材如菁莪。"]'),
('0bc50183-ba38-41a7-92c3-7a81b33c69ae','宇文叔介逆婦歸過通義爲置酒遠景樓餞之','晁公遡','宋','宋诗','song-poetry','','[]','夜雨洗綠野，平池磨青銅。',96,'全唐诗/poet.song.116000.json','["夜雨洗綠野，平池磨青銅。", "共登百尺樓，遂享萬里風。", "遠自木末來，大音中笙鏞。", "盛夏安得此，正是飛廉慵。", "爲我解炎蒸，舉觴謝天公。", "君行亦快哉，輕舟疾歸鴻。", "閨中當更喜，新凉入房櫳。", "可賡白頭吟，寫之以絲桐。"]'),
('2e2dca93-e730-4048-aa07-0e790fa0af98','寄宋嗣宗','晁公遡','宋','宋诗','song-poetry','','[]','蜀江自嶓冢，流惡及丘原。',120,'全唐诗/poet.song.116000.json','["蜀江自嶓冢，流惡及丘原。", "寧止數斗泥，乃有千丈渾。", "帝選高才郎，遠來乘輶軒。", "悽然在川上，會思澄其源。", "重部今何如，想無風水昏。", "激濁使之清，未覺禹功尊。", "我戚閭丘生，短衣方服轅。", "得爲經途尉，可致薄夫敦。", "何須讀刑書，顧欲多平反。", "但令吏不污，信是民無冤。"]'),
('3dbffceb-b8d2-45fb-9deb-3c5b41516790','李仁甫和予如字韻詩再用韻寄之','晁公遡','宋','宋诗','song-poetry','','[]','神州久陸沈，遂作蛇豕墟。',192,'全唐诗/poet.song.116000.json','["神州久陸沈，遂作蛇豕墟。", "諸公頗憤激，日上平邊書。", "覽書帝震怒，欲下雷霆誅。", "金城築三洲，戈船浮五湖。", "要令境土復，再似祖宗初。", "誰其爲民言，世獨無郇模。", "師克非在衆，正當戒不虞。", "討論惟甲兵，此豈戰所須。", "代思伊尹相，語憶皋陶都。", "皮亡毛安附，體肆心自舒。", "正宜詢褐父，難以訪綺襦。", "君今幸得用，出駕班輪車。", "爲民盍盡言，軒冕真塊蘇。", "區區但投劾，何貴於爲儒。", "春秋置桉上，開卷一軒渠。", "儻能遵伯禽，焉在獲僑如。"]'),
('484a8e8d-be43-4757-ba6c-ecac1d68135d','羅仲思送伯父以道帖','晁公遡','宋','宋诗','song-poetry','','[]','我家嵩山翁，平日慕迂叟。',96,'全唐诗/poet.song.116000.json','["我家嵩山翁，平日慕迂叟。", "斯文到蒼史，高節貫白首。", "至今遺翰墨，古意近科斗。", "世人規時好，娬媚無不有。", "寧知虞書渾，或笑夏篆醜。", "往年君家尊，得此蓋以厚。", "嘗從諸父游，於我實世舊。", "念昔盟可尋，與君期不朽。"]'),
('3a359e99-3d7a-4d30-8b1e-3ce1e56fa0f1','寄洪雅令孫良臣','晁公遡','宋','宋诗','song-poetry','','[]','志士居世間，要爲鶴鳴皋。',132,'全唐诗/poet.song.116000.json','["志士居世間，要爲鶴鳴皋。", "誰能如羊豕，料揀充豢牢。", "吾邦孫卿子，閉門長蓬蒿。", "慨然請治劇，不憚簿領勞。", "地雖百乘小，名與九頂高。", "老翁喜相語，得見今官曹。", "令行有盜奔，冬煖無兒號。", "君豈求人知，知亦未易遭。", "大哉龍伯國，乃欲舉六鼇。", "區區畢吏部，竟日把兩螯。", "且當置是事，痛飲讀離騷。"]'),
('2db53231-3961-4d5f-92a4-512d67dac9d9','謝張待制赴飲','晁公遡','宋','宋诗','song-poetry','','[]','我如沐猴冠，强佩刺史章。',192,'全唐诗/poet.song.116000.json','["我如沐猴冠，强佩刺史章。", "儻令入朝班，驚倒鴛鷺行。", "安敢延貴人，置酒登此堂。", "知公蓋超然，軒冕等粃糠。", "但逢臭味同，握手出肺腸。", "肯爲宣明面，貧賤乃遽忘。", "遠從三峽來，欲訪五畆桑。", "聞昨去郡時，送者傾城隍。", "皆言民疾苦，公見必慘傷。", "奏疏每建白，細書親貼黄。", "豈容廊廟具，而久滯一方。", "使民濟大川，行矣爲舟航。", "杖屨可少留，吉日辰甚良。", "歌公竹枝詞，舉我柏葉觴。", "勿辭飲之釂，不發寬饒狂。", "釀以老翁泉，中有班馬香。"]'),
('85b247a5-bfbb-4b41-a256-717cb844addf','贈羅仲思仲思今夏來試羣士八月予被朝命爲別試所考試仲思亦來','晁公遡','宋','宋诗','song-poetry','','[]','子初至我邦，受命蜀行臺。',132,'全唐诗/poet.song.116000.json','["子初至我邦，受命蜀行臺。", "羣士森如林，手自揀條枚。", "試席莫敢譁，棘門乃大開。", "知是諍臣鄉，所出非凡材。", "益州外南宮，將遣與計偕。", "詔書選主司，帝謂汝往哉。", "深喜與子逢，再持鈞石來。", "因得享成事，笑歌雜詼諧。", "秋風吹帽裙，白露入酒杯。", "飲我玻瓈江，瀉子瓊瑰懷。", "相看語不厭，預憂歸駕催。"]'),
('e6416c07-4ed8-442b-bc0f-65dfadfbaa2f','楊承父與予同在別試所聊戲之奉簡','晁公遡','宋','宋诗','song-poetry','','[]','近時文章衰，淺陋亦可憐。',144,'全唐诗/poet.song.116000.json','["近時文章衰，淺陋亦可憐。", "走趨王公門，書記爭翩翩。", "開讀令人慙，語吃意莫宣。", "今晨忽驚喜，贈我手一編。", "筆端吐虹霓，直上欲干天。", "樊南甲乙中，乃有猗那篇。", "如聽正始音，復回元祐年。", "借問安能爾，氣剛得其全。", "用爲良有司，吾實無間然。", "要知取士公，考閲外已傳。", "何由置漢朝，直柄遂當權。", "伏閣日論事，不減陽城賢。"]'),
('4f12643c-6376-4e4e-86a9-aac446e20a9f','楊周輔來考試刑法同在別闈剛直士也喜爲賦此','晁公遡','宋','宋诗','song-poetry','','[]','風俗嗟久衰，所見皆軟熟。',144,'全唐诗/poet.song.116000.json','["風俗嗟久衰，所見皆軟熟。", "今年客益州，得此一士足。", "古來豐鎬都，氣壓瀍澗卜。", "豈須和氏璧，自有藍田玉。", "琉璃非不佳，炯炯先奪目。", "只堪供把玩，彼脆寧受觸。", "愛君堅重質，坐閲世翻覆。", "來試法家流，因論廷尉獄。", "張湯善爰書，專亂漢約束。", "何嘗守律令，正爾舞桎梏。", "若人甚耿介，不待城旦讀。", "恨我無長風，送君騎鴻鵠。"]'),
('b7a666db-ff67-4679-b9cb-142c9c4c3429','題先主廟','晁公遡','宋','宋诗','song-poetry','','[]','天地收霸氣，丘原餘閟宮。',96,'全唐诗/poet.song.116000.json','["天地收霸氣，丘原餘閟宮。", "野人相指示，旁有若堂封。", "當時大耳兒，甚似隆準公。", "夫豈忘故都，崎嶇巴蜀中。", "劃然成三分，正爾阨兩雄。", "武侯抱遺恨，秦隴竟莫通。", "獨憐晉昌明，千載時始逢。", "坐看五胡亂，蕭條河洛空。"]'),
('02f6a5f9-a9e5-4273-a0ff-878c732ce82d','師永錫餽鹿','晁公遡','宋','宋诗','song-poetry','','[]','麋鹿愛豐草，羣行鳴呦呦。',72,'全唐诗/poet.song.116000.json','["麋鹿愛豐草，羣行鳴呦呦。", "自謂山林逃，可免刀几憂。", "于人亦何事，之死蓋有由。", "所入諒不深，竟爲羅網求。", "所以安期生，高舉崑崙丘。", "輟食爲歎息，吾其將遠游。"]'),
('8d086833-e36a-407f-b94a-e4a52fbcbcb9','鄉人欲開舊江相勉以詩','晁公遡','宋','宋诗','song-poetry','','[]','鄉人填然來，亦有雙眉厖。',108,'全唐诗/poet.song.116000.json','["鄉人填然來，亦有雙眉厖。", "讙言我東堤，夏潦所樁撞。", "舊時水流處，沙礫可手扛。", "請開百步洪，障以千石矼。", "不令近城郭，庶即回濤瀧。", "坐聞南堰民，籍籍口語嚨。", "深憂堰或壞，他日病此邦。", "二論堅相持，誰者肯屈降。", "老夫莫能决，君其問語江。"]'),
('4c134c6b-01f7-41dc-8241-8926f8d6e76a','詔除虛額錢計庭遣簡州通判王和叟再至謂考實未然也人日贈和叟一首','晁公遡','宋','宋诗','song-poetry','','[]','天王念遠民，哀此西南隅。',168,'全唐诗/poet.song.116000.json','["天王念遠民，哀此西南隅。", "主者按其籍，取之盡錙銖。", "掃地皆赤立，名獨存版圖。", "竭澤儻未已，來年恐無魚。", "明詔甚寬大，宿負當蠲除。", "主者慘不樂，何以充輓輸。", "刺史詎可信，殆將有爲無。", "遣官視故府，姑往考簿書。", "簿書亦難憑，緣絕或欺予。", "不如持明詔，却還桑大夫。", "跋涉君徒勞，兩駕泥軾車。", "所幸得一歡，莫辭留斯須。", "今晨屬挑菜，啗我園中蔬。", "蔬食君莫笑，郡縣誠空虛。"]'),
('4294093f-3eca-4f8d-8f76-a90b5a142792','予長女歸叔尚偕往江津作詩送之','晁公遡','宋','宋诗','song-poetry','','[]','薛郎吾嬌客，昨肯過彭濮。',144,'全唐诗/poet.song.116000.json','["薛郎吾嬌客，昨肯過彭濮。", "相從雖云久，一歲如轉燭。", "外堂忽有請，歸駕行當促。", "自稱先君子，嗣以病家督。", "焉能主烝嘗，我祭則受福。", "吾誠愛吾女，撫視長不足。", "人皆念其子，此事非我獨。", "敢欺泉下友，已拱宰上木。", "論情夫何遠，守墓亦所欲。", "老夫懷津鄉，山好田土沃。", "尋穿蜂窠硤，但種鴉鐵穀。", "先營五畝宅，仗爾今往卜。"]'),
('e893b523-0de0-4964-ae0b-63ef531965a3','四月十三日池上飲','晁公遡','宋','宋诗','song-poetry','','[]','圓荷受白露，可愛池上凉。',120,'全唐诗/poet.song.116000.json','["圓荷受白露，可愛池上凉。", "相將携筇來，羽衣颯飄揚。", "停觴待明月，少焉出西方。", "澄波照河漢，俯仰清茫茫。", "悠然望高天，邀月入我觴。", "肺肝聊一洗，吸此空中光。", "微風吹芙蕖，雜以草木香。", "豈復知有暑，踏冰挾飛霜。", "樂哉且勿歸，況乃夜未央。", "自疑非人間，今夕不可忘。"]'),
('c214cf16-0271-4009-83fd-557277762025','白宋瑞自益州和予池上詩來因用韻奉簡','晁公遡','宋','宋诗','song-poetry','','[]','文宗愛夏日，殿閣生微凉。',120,'全唐诗/poet.song.116000.json','["文宗愛夏日，殿閣生微凉。", "高帝思猛士，大風雲飛揚。", "五子歌洛汭，陶唐有冀方。", "誠懸未識此，古意墮淼茫。", "我欲起九原，釂以百罰觴。", "作詩豈徒然，日月要爭光。", "吾子堪校讐，行翻芸葉香。", "其師縉雲老，墓木已三霜。", "有懷不及展，往聽鑾聲央。", "子能償彼恨，下泉端不忘。"]'),
('7a4560e7-9ce5-4dac-a4c0-ab15d05ddd32','任季明見和池上詩再用韻奉簡且識予拳拳懷向之萬分也','晁公遡','宋','宋诗','song-poetry','','[]','甘泉洗心清，好風吹面凉。',120,'全唐诗/poet.song.116000.json','["甘泉洗心清，好風吹面凉。", "循池步漣漪，澹然波不揚。", "懷君佳弟兄，元方與季方。", "正茲阻會集，怳若限渺茫。", "顧欲煩飛廉，爲子飄羽觴。", "翔空浮河漢，上畧參井光。", "因思從之去，手攀蟾窟香。", "結以飛霜佩，衣以袍赤霜。", "俯問夜何其，未及庭燎央。", "自笑乃默存，蘧蘧真坐忘。"]'),
('85e6a0a9-d090-4be9-b3d2-2004e768c28f','師正二哥正三哥以詩賀雨次韻爲謝','晁公遡','宋','宋诗','song-poetry','','[]','漢家用牧守，斗酒得西凉。',120,'全唐诗/poet.song.116000.json','["漢家用牧守，斗酒得西凉。", "聖朝蓋不然，事舉或言揚。", "顧我誤見收，分符來一方。", "深知舜門闢，遠見禹迹茫。", "春秋祀百神，芒芒降嘉觴。", "昨者爲旱禱，紫檀燭神光。", "高天忽飛雨，未徹金爐香。", "潤得三日霖，穫待九秋霜。", "敬歸慈姥泉，導以旂旐央。", "天功及帝力，與爾俱敢忘。"]'),
('158d138a-6507-4c45-b4c1-4b61860ebeab','復用韻謝湯子才賀雨','晁公遡','宋','宋诗','song-poetry','','[]','亢陽乃爲災，正坐我德凉。',120,'全唐诗/poet.song.116000.json','["亢陽乃爲災，正坐我德凉。", "有雲輒復散，南箕端𥳽揚。", "舊聞江都相，亦有請雨方。", "星符久未下，天意終眇茫。", "齋居省愆尤，客至不敢觴。", "敬開紫函書，要近青黎光。", "電鞭煩列缺，雷車呼阿香。", "古人精誠感，六月猶降霜。", "夜來僅一洗，高澤未渠央。", "何時來賀我，有約君勿忘。"]'),
('f2fbd5bf-2f63-46e4-b1eb-9f734dd002c7','送邵仲象如吳下','晁公遡','宋','宋诗','song-poetry','','[]','乃翁昔爲校書郎，汗簡所載日月光。',64,'全唐诗/poet.song.116000.json','["乃翁昔爲校書郎，汗簡所載日月光。", "今看太史牛馬走，往見中朝鴛鷺行。", "南公聞名定傾蓋，西府念舊當外堂。", "儻思泰定山下路，肯來從我無相忘。"]'),
('c7350242-02a4-442f-82c8-5cbf5a939037','地行莫如馬','晁公遡','宋','宋诗','song-poetry','','[]','地行莫如馬，蹴踏千里空。',96,'全唐诗/poet.song.116000.json','["地行莫如馬，蹴踏千里空。", "西游到瑶池，豈止過崆峒。", "忽當涉江漢，載之樓船中。", "樓船誰能乘，御者須阿童。", "阿童亦何勞，八尺真毛龍。", "即將凌波濤，復恐挾雷風。", "或從琴高生，化作赤鯶公。", "徑去不可執，飄然朝河宗。"]'),
('780b7e76-8f6b-4823-8ed8-53494f78593a','病中','晁公遡','宋','宋诗','song-poetry','','[]','莓苔上車轍，病客方卧家。',48,'全唐诗/poet.song.116000.json','["莓苔上車轍，病客方卧家。", "不知春將歸，悵然感年華。", "雨砌粘落絮，風廊走飛花。", "坐久不知倦，林梢來暮鴉。"]'),
('5feb3fe5-3be3-4ba6-811a-6ead09933941','寄太府丞王能甫','晁公遡','宋','宋诗','song-poetry','','[]','君才雄萬夫，少也備文武。',168,'全唐诗/poet.song.116000.json','["君才雄萬夫，少也備文武。", "前年有疆事，假守在淮浦。", "小試三里城，已可因吾圉。", "諸公職獻納，見賢自當舉。", "雖聞對延英，尚屈丞太府。", "近往行芍陂，四顧多曠土。", "區區張全義，此老安足數。", "河南十八縣，髑髏相撐拄。", "猶能披荆棘，著手爲摩撫。", "朞年如承平，何但興百堵。", "封內我得爲，幸梁爲之主。", "況今天子聖，銳意思復古。", "若人果盡用，功利非小補。", "吾將以是卜，日望來告語。"]'),
('ec3639cd-3cbd-4d9a-8645-80632b066724','今年正月二十五日行園見羣花盡開悵然追思去年是日去江津縣親戚相送今一歲矣嗟歎不足情見乎辭','晁公遡','宋','宋诗','song-poetry','','[]','去年別津鄉，兩岸麥離離。',168,'全唐诗/poet.song.116000.json','["去年別津鄉，兩岸麥離離。", "親戚知我行，曉出相追隨。", "繫船五里沙，江水清漣漪。", "俯窺皆白石，綠色可染衣。", "何以謝送者，呼酒聊共持。", "放杯不忍去，看我船解維。", "至今念其處，歲月忽如馳。", "還復見薺麥，青青滿陵陂。", "桃李亦盡開，風吹總成泥。", "一歲春一來，少留能幾時。", "乃若遠行客，日夜只欲歸。", "正須勤往遊，步遶芳菲枝。", "釃渠引微流，浮萍已生池。", "無事但日飲，更賦涉園詩。"]'),
('7a4929ac-558f-4320-b2ab-1643c30a380a','寄瀘南子止兄','晁公遡','宋','宋诗','song-poetry','','[]','二年立王朝，忽然厭承明。',108,'全唐诗/poet.song.116000.json','["二年立王朝，忽然厭承明。", "受詔予印綬，復作江陽行。", "地當周五侯，秩視漢九卿。", "邊清塵不揚，主聖時自平。", "上堂簪履集，出門笳鼓鳴。", "想亦多宴樂，鼓瑟兼吹笙。", "吏民更相戒，豈敢煩敲榜。", "田間黄髮叟，聞此歎且驚。", "觸眼未嘗見，不毛今亦耕。"]'),
('a80b9386-f9d6-430e-8f08-7ea8000768ca','郡人請開舊江口因往視之而作','晁公遡','宋','宋诗','song-poetry','','[]','大江何時來，齧我千步隄。',192,'全唐诗/poet.song.116000.json','["大江何時來，齧我千步隄。", "居人念水至，前年拆鷄棲。", "浸淫勢未已，老圃憂夏畦。", "青青五畝蔬，素沙黄卷泥。", "一朝失此利，豈飽鹽與薺。", "紛然向我言，有叟其齒齯。", "使君幸靜聽，衆論信可稽。", "去城今幾許，坐視埤堄低。", "願移象鼻東，復瀉蟇頤西。", "匯爲沸白潭，不入流丹溪。", "焉敢費使君，畚插各自携。", "茲事蓋體大，更當訪扶犁。", "晨興聊出郊，浮雲渰凄凄。", "徐行見開塞，指點了不迷。", "得使負郭民，朝涉無過臍。", "肯辭他日勞，遠汲江玻瓈。"]'),
('eda8f883-889a-48ad-b89d-5455606441ea','前起居舍人何資深竹光酒法奇甚近得其法釀成以餉李仁甫','晁公遡','宋','宋诗','song-poetry','','[]','舊聞蜀酒濃，今乃舉此觴。',120,'全唐诗/poet.song.116000.json','["舊聞蜀酒濃，今乃舉此觴。", "可憐如甘言，難置烈士腸。", "近者營糟丘，始傳柱下方。", "青菽爲麴糵，碧蓼有微芳。", "調和火齊得，泉潔器甚良。", "釀成酌樽中，盎盎流瓊漿。", "味勝松醪春，色作竹露光。", "知君却奇溫，苫冷卧欲僵。", "五十不致毀，無徹桂與薑。", "强起爲我飲，季冬天雨霜。"]'),
('993e7805-40eb-4cc2-9c0b-2512e44d9baa','贈張文饒','晁公遡','宋','宋诗','song-poetry','','[]','乾坤五十策，巧歷莫能算。',204,'全唐诗/poet.song.116000.json','["乾坤五十策，巧歷莫能算。", "有如鈎其深，坐見太極判。", "文王所以王，此道乃一貫。", "即成靈臺附，豈畏羑里難。", "自從商瞿傳，訖至子雲贊。", "孰知幽明故，但樂文辭玩。", "遂令聖人情，亦同春秋散。", "堂堂張漢州，始屈諸侯泮。", "於時抱韋編，迨老識象彖。", "蓋將通晝夜，而況談治亂。", "昨初與我言，驚喜每竊歎。", "響應真無窮，圖畫皆可按。", "歸看所著書，略已思過半。", "屬今招弓旌，盍往執圭瓚。", "冰霜待春融，風雨催歲換。", "宜乘濤瀨平，快下赤澤岸。", "朝廷須君來，天下疑以斷。"]'),
('f4de646c-a896-468c-9014-39827578be88','懷浙中兄弟','晁公遡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昔游楚澤窺衡湘，飄然欲返川無梁。',304,'全唐诗/poet.song.116000.json','["昔游楚澤窺衡湘，飄然欲返川無梁。", "途窮問津西入蜀，十年一過如風狂。", "欲知滯留視草木，來時尺許今人長。", "石龜尚有懷海心，苟非達者寧無情。", "倦游于此豈不厭，況乃州縣徒勞人。", "官如敝屣端可捐，投劾徑去真欣然。", "只憂口紋有從理，一簪不著死道邊。", "近聞有客自吳至，試問龍化今何年。", "屬車南游今尚爾，翠華停停照江水。", "會稽久闕神禹朝，再喜吳兒識天子。", "徑山苕溪兩奇絕，鳳舞龍飛臨觀闕。", "宮中又起白玉城，丹樓如霞高嵽嵲。", "潮聲浩浩江風急，越水吳山動秋碧。", "霓旌玉弭有光輝，西湖蒲柳生顔色。", "氣象不與巴山同，年來聞此益欲東。", "但期生見翔鳳闕，豈敢望到明光宮。", "舉頭試望長安日，遥想烏衣淚霑臆。", "逢人寄書往問訊，流落猶爲帝城客。", "山川雖異風景同，勿作楚囚相對泣。"]'),
('ccf634d9-4975-48bf-a170-69161ac0f97b','單于行','晁公遡','宋','宋诗','song-poetry','','[]','單于連年壓吳壁，道路當時多阻隔。',192,'全唐诗/poet.song.116000.json','["單于連年壓吳壁，道路當時多阻隔。", "長安宮殿麋鹿游，目見銅駝在荆棘。", "一龍渡江已升天，妖氛夜衝牛斗躔。", "胡兒臨江飲胡馬，倉皇捐棄珊瑚鞭。", "蒲萄宮中日復日，長庚食月單于泣。", "邊馬心思塞草秋，吹笳淚落旃裘濕。", "豈知反覆十五年，靈光再見猶巋然。", "落南遺民喜相語，日欲歸理桑麻田。", "平生思歸今得歸，未歸悽愴獨先悲。", "闔廬傷指越未報，灌孟陷敵夫空回。", "念昔結纓在何所，遥想荒郊迷隴畝。", "他時抱劒哭野中，深目而髯當語汝。"]'),
('27ba5101-3c69-4197-ae2b-24dbef7fcb20','王才諒自行朝歸以進士題名示予愴然有感','晁公遡','宋','宋诗','song-poetry','','[]','先朝賜第白玉京，五世不出長安城。',368,'全唐诗/poet.song.116000.json','["先朝賜第白玉京，五世不出長安城。", "每聞三歲射策罷，諸生盛服趨天庭。", "禁門漏盡開九重，闕角髣髴晨光紅。", "衣冠是日集殿下，金支翠旗色相射。", "空雷隠隠車轉轂，鳴梢一聲禁籞肅。", "須臾雲開飛六龍，皇帝親御蓬萊宮。", "宮槐滿庭白日長，侍臣玉立分兩廂。", "衆星煌煌拱北極，龍顔負扆天中央。", "羽林虎賁擁仗立，霜交陛戟摩秋光。", "天風徐來雉扇舉，遥識重瞳似文祖。", "臚傳初罷日當午，起拜君恩謝明主。", "日斜天門隨仗出，車馬聯翩動阡陌。", "金錢賜宴上林苑，千花萬草生顔色。", "少年得意凌青雲，路人歎息家人迎。", "昔爲兒童親見此，當時仰望如天人。", "豈知生世逢艱難，流離憂患尤可憐。", "乘輿巡狩在江表，亮陰三年猶不言。", "詔令蜀都別選士，西游彈鋏秋風前。", "决科偶中太常第，意氣豈復如當年。", "臨安太守今爲誰，玉字能刻玻璃碑。", "曲江題名豈料見，摩挲墨本心傷悲。", "楚山聯綿越山遠，夢魂不到明光殿。", "一官留滯未得歸，北闕何時眼中見。"]'),
('af277093-ad4a-490f-b6a2-8294240469bf','樂溫道中','晁公遡','宋','宋诗','song-poetry','','[]','路經新峯驛，薄暮聊解裝。',144,'全唐诗/poet.song.116000.json','["路經新峯驛，薄暮聊解裝。", "頹垣生秋草，庭廡亦已荒。", "北風吹空林，崒崒葉隕廊。", "夜寒不能寐，起坐心彷徨。", "出看天欲明，疎星淡無光。", "征夫稍速駕，起拂車上霜。", "墟中始辨道，迢遞征途長。", "樹色共空濶，晨光尚蒼茫。", "雞鳴始知村，漸覺暾朝陽。", "青煙出林際，滯穗或在場。", "感茲田舍樂，慨然懷故鄉。", "黄金百鎰盡，失路徒悲傷。"]'),
('d8b67cf9-a31a-4dd1-bab3-53380535f715','脩竹二首  其一','晁公遡','宋','宋诗','song-poetry','','[]','虛窗倚脩竹，陰晴見佳景。',48,'全唐诗/poet.song.116000.json','["虛窗倚脩竹，陰晴見佳景。", "雨隙落餘滋，風櫺亂疎影。", "室幽境自閒，心遠地愈靜。", "丁寧護雲根，留伴歲寒永。"]'),
('93e62985-19e4-4510-8dcd-1fe951c0577a','脩竹二首  其二','晁公遡','宋','宋诗','song-poetry','','[]','脩林出夏筍，戢戢如牛毛。',48,'全唐诗/poet.song.116000.json','["脩林出夏筍，戢戢如牛毛。", "寧亡口腹味，所冀逃炎熇。", "露節半含粉，風篁微解苞。", "清陰日夜長，會見干雲霄。"]'),
('96af2738-b4be-480e-833b-16604487343c','送鮮于運使西歸','晁公遡','宋','宋诗','song-poetry','','[]','飛鳥避漢節，朔風揚旆旌。',288,'全唐诗/poet.song.116000.json','["飛鳥避漢節，朔風揚旆旌。", "光芒候躔次，始見入蜀星。", "父老喜公至，來臨此江濱。", "陽侯爲先驅，歸指唐安城。", "君恩解煩劇，劒履休殊庭。", "衆聞駟馬還，當爲故鄉榮。", "眷茲峽中郡，念昔德化深。", "民無暴歛困，士感銓衡平。", "自聞有行色，愁雲黯秋陰。", "已應江妃瑟，泠然作離聲。", "大江亦安流，不復洪濤驚。", "天水相與碧，雲山無限青。", "乃知盛德士，扶持有神明。", "但恨濟世具，遽起懷歸心。", "寧無北闕念，未忘東山情。", "君王正仄席，漏下開延英。", "如公藉甚久，名聞漢公卿。", "當賜宣室召，不但問鬼神。", "金印有斗大，錦衣無夜行。", "願言不俟駕，起焉慰蒼生。", "自嗟代舍客，蒯緱鬰悲音。", "久落糠粃後，日隨車馬塵。", "不意侍廣座，見謂非凡鱗。", "假之風雷勢，欲令化南溟。"]'),
('345afbcc-c0b3-4cf0-8d70-4f79633c4053','與鮮于茶幹','晁公遡','宋','宋诗','song-poetry','','[]','吾猶蠹書魚，豈能味斯文。',132,'全唐诗/poet.song.116000.json','["吾猶蠹書魚，豈能味斯文。", "但以性所嗜，頗與黄卷親。", "喜聞天下言，孝章有大名。", "苟得從其游，亦足慰此生。", "向來昌黎翁，始獲拜北平。", "停鸞與峙鵠，未見心已傾。", "朅來涪江上，適遇君遠行。", "我窮天所憐，特使見異人。", "令聞金石奏，暫破蟋蟀聲。", "相逢已定交，遽別寧忘情。", "謫仙不可見，空望江東雲。"]'),
('209fdf9a-74d7-49e8-8175-76db73372482','病中喜李仲霍王子載見過','晁公遡','宋','宋诗','song-poetry','','[]','春風餞餘寒，山雨留暝色。',192,'全唐诗/poet.song.116000.json','["春風餞餘寒，山雨留暝色。", "杜門正卧病，俯仰空四壁。", "庭空鳥雀至，窗破風雨入。", "擁爐意無聊，胸次百憂集。", "肉消時撫髀，嘯罷空抱膝。", "戶外雲氣昏，春泥汚阡陌。", "清晨履聲喧，不見車馬迹。", "忽傳高軒過，未知當何適。", "僕夫走告予，有客來問疾。", "起迎屐齒折，頗覺心悅懌。", "沈痾脫去體，陽氣滿大宅。", "坐聞枚叟言，汗復淟然出。", "平身拙自衛，外邪屢見襲。", "昔嘗倦賓至，束带難自力。", "今者乃不然，惟恐歸騎急。", "向來謝交游，正乏君輩客。"]'),
('d053a982-324d-4692-8230-ebb9572821e3','涪川寄蒲舜美桐煙墨來試之良佳因成長句','晁公遡','宋','宋诗','song-poetry','','[]','西風吹林秋日白，脩桐葉彫霣寒碧。',208,'全唐诗/poet.song.116000.json','["西風吹林秋日白，脩桐葉彫霣寒碧。", "霜餘結實鳳不至，野人取之出膏液。", "山中老翁頗喜事，買膏燃光歸照室。", "旋收輕煤下玉杵，陰房掩翳煙不出。", "澤麋解角麝薦香，嚴冬折膠天與力。", "律灰吹盡無裂文，外乾中堅介如石。", "故人憐我貧嗜書，遺我一丸欣有得。", "空堂無風塵亦靜，朝陽壓窗書繞壁。", "起臨墨池洗硯試，入手已怪光奪漆。", "蒼忙忽驚玄雲晦，罨靄頓失寒松色。", "徐嗟流落用失所，翰墨何由有勳績。", "從軍豪氣吾豈能，倚馬翩翩磨楯墨。", "傍人笑言君勿疑，著書固屬窮愁客。"]'),
('71c9d4fa-3170-4841-90fb-aee0d04faea2','送宋秀實罷官歸將有東南之行','晁公遡','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','遑遑魯東丘，結友得聃耳。',204,'全唐诗/poet.song.116000.json','["遑遑魯東丘，結友得聃耳。", "兩家千歲後，尚復通爵里。", "況予與先世，相去百年邇。", "常恨會面難，此意恐遂已。", "豈期官紵溪，君爲幕下士。", "不但見典型，自喜聞正始。", "獨嗟瓦礫後，不遑蒹葭倚。", "遽聞北海薦，當爲東山起。", "春風洞庭波，九澤彌空水。", "掛帆下中流，千里一日爾。", "東南即王都，分野乃星紀。", "宮殿芙蓉旗，玉佩白雲委。", "麒麟翳鳳皇，侍輦叅劒履。", "當知帝所樂，顧非俗吏比。", "良圖宜早遂，力行無遽止。", "今朝離亭柳，顔色已可喜。", "欲君早著鞭，折贈當馬箠。"]'),
('616544c5-bcab-4228-884f-7d26918b20b7','送譚廷碩司戶歸魚復','晁公遡','宋','宋诗','song-poetry','','[]','平生惜芳辰，每負止酒詩。',216,'全唐诗/poet.song.116000.json','["平生惜芳辰，每負止酒詩。", "不量井楣缾，安得如鴟夷。", "果中麴糵毒，抱病悔可追。", "雖無腐腸憂，乃有摏喉危。", "晚聞倉曹掾，巾車欲東歸。", "此君吾畏友，議論可質疑。", "相從未云久，白首已可期。", "莫陪諸公後，往聽陽關詞。", "羸然卧空舍，不得一語離。", "心旌無終薄，日夕風中飛。", "戶外雨連晝，水聲已鳴溪。", "行雲候歸蓋，花塵漲春泥。", "人知鄉閭近，自忘車馬疲。", "似聞五畝宅，止居瀼東西。", "傾倒稷下學，歡呼里中兒。", "嗟予久去國，流落天一涯。", "因君返枌榆，慘然起遐思。", "不惟消魂苦，益增游子悲。"]'),
('12c8b809-07a6-4303-b045-9633119be0e6','得東南書報亂後東都故居猶存而州北松檟亦無毀者','晁公遡','宋','宋诗','song-poetry','','[]','旄頭光垂北風起，胡沙漫漫暗天地。',384,'全唐诗/poet.song.116000.json','["旄頭光垂北風起，胡沙漫漫暗天地。", "翠華清曉巡朔方，咸陽宮殿生荆杞。", "胡兒解鞍留漢土，凝碧池頭日歌舞。", "一朝忽棄洪河南，來歸輿圖丞相府。", "當初亂離誰料此，南北中分指淮水。", "天暌地隔十五年，不知中原復何似。", "至今兵罷關泥開，始有北客中原來。", "歷言王侯故第宅，瓦礫半在高臺摧。", "最憐長楊與宣曲，樹木荒凉迷御宿。", "上林苑廢花自開，輦路春回草還綠。", "宮中千門萬戶空，獸扉凝塵生網蟲。", "遺民相對向天泣，耳冷不聞長樂鐘。", "外城白晝無人行，當道往往狐狸鳴。", "天陰日暮聞鬼哭，萬家經亂今一存。", "嗚呼上帝白玉京，繁華掃地令人驚。", "此生復識太平象，不及百年終未能。", "世人寧有金石堅，定恐不見全盛年。", "出門恍惚忘南北，故國何在山連天。", "豈意揚雄一區宅，城破蕭條尚如昔。", "閉門風雨長蓬蒿，榱桷多年亦傾側。", "戶牖尚带沙場塵，小兒猶學胡笳聲。", "四鄰半已易新主，存者無復當時人。", "城北凄凉九原路，往往停車不忍去。", "幸無樵牧犯松柏，那有鮮卑護置墓。"]'),
('0d1efe0d-3ed4-4e0f-88ad-93408b07f86c','尉廨無隙地不能蒔花竹之屬惟廳事前舊有柳一株予憐其獨也增植其七焉暮春之月大有生意可喜爲賦此','晁公遡','宋','宋诗','song-poetry','','[]','千林春入花梢紅，空庭無樹來東風。',195,'全唐诗/poet.song.116000.json','["千林春入花梢紅，空庭無樹來東風。", "手栽楊柳三尺許，芳意已在萌芽中。", "官居難期十年木，聊爾移根伴幽獨。", "雨催細葉相續生，眉峯爲誰出脩綠。", "君不見美人夢中春日長，翠簾風開捲春光。", "饑寒病叟寧有此，蒼苔破封對作行。", "游絲飛空日停午，乳燕巢成寂無語。", "柔條作陰未覆庭，影立東風不能舞。", "明年我亦未成歸，會見裊裊生新枝。", "清陰漸滿摇落日，度曲無力弓蠻垂。", "人生於世無定著，身與楊花共飄泊。", "他年莫忘桓將軍，漢南重來看摇落。"]'),
('95bbab9d-bb8b-4a97-b6af-9efd95431a21','晝寢','晁公遡','宋','宋诗','song-poetry','','[]','官曹無人吏休沐，杜門謝病車脫軸。',112,'全唐诗/poet.song.117000.json','["官曹無人吏休沐，杜門謝病車脫軸。", "門前經旬客不至，苔色侵階春更綠。", "書堂蕭然白日靜，黄蜂收聲蜜房足。", "楊花浩蕩天無風，簷端三丈朝陽紅。", "晴薰病眼煖欲醉，卧搔短髮如飛蓬。", "枕書睡熟呼不醒，黄粱正飯邯鄲翁。", "不知紛紜夢幾許，覺來煙際聞昏鐘。"]'),
('e71a9186-91f7-4c4f-a52e-6b49786f06ee','平都山硤中勝處余思欲一到而不能近得予弟書云今歲仲春嘗與外兄孫長文順流往遊焉聞之不勝悵然','晁公遡','宋','宋诗','song-poetry','','[]','沙痕夜漲春流生，微風不起波紋平。',128,'全唐诗/poet.song.117000.json','["沙痕夜漲春流生，微風不起波紋平。", "雲間眩轉失煙樹，輕舟直下鳬鷗驚。", "櫓聲欲出含風灣，舟人已指平都山。", "仙宮無人鎖春日，蒼煙漠漠松聲寒。", "謫仙賓天上寥廓，三百年來無此樂。", "知君此游殆奇絕，硤中山川豈云惡。", "昔年相期欲同往，流落空山阻清賞。", "興公雖不見天台，執筆猶能寄遐想。"]'),
('ee6dc6c6-af6b-4130-a873-d5d8514678b9','恭南道中有感','晁公遡','宋','宋诗','song-poetry','','[]','西風夜驚林，木葉下寒浦。',108,'全唐诗/poet.song.117000.json','["西風夜驚林，木葉下寒浦。", "大江未收潦，黄流尚奔注。", "起看曙光開，忽已暗煙霧。", "靄靄空谷雲，冥冥秋江雨。", "昏霾天際山，暝入雲間樹。", "跳波亂沸白，行旅皆斷渡。", "況復悲遠行，扶疾在道路。", "嚴程不可緩，端爲斗米誤。", "有田儻可歸，破甑誰復顧。"]'),
('f6f13b37-da14-4f9f-8fa5-a48c3903b9ae','雨中','晁公遡','宋','宋诗','song-poetry','','[]','冥冥雨脚來，巖谷生暝色。',108,'全唐诗/poet.song.117000.json','["冥冥雨脚來，巖谷生暝色。", "大江失洲渚，隠起煙霧白。", "微茫沙邊樹，坐覺雲氣隔。", "霖霪已經時，初不見天日。", "城中三尺泥，陌上無轍迹。", "秋田穫無時，農父相對泣。", "各言迫軍輸，督責甚峻急。", "今晨忽晴霽，曉日照屋壁。", "吾饑行可療，庶食明年麥。"]'),
('e2013255-102f-47a4-a76d-832a2318a38e','凝香堂','晁公遡','宋','宋诗','song-poetry','','[]','訟庭鞠茂草，圜扉生網蟲。',132,'全唐诗/poet.song.117000.json','["訟庭鞠茂草，圜扉生網蟲。", "政成胡不樂，酒肴可從容。", "人云倡優拙，公在宴寢中。", "翰墨以自娛，落紙驚游龍。", "壁間三大字，筆畫元自工。", "焚香日清坐，未覺塵事蒙。", "窗虛度清光，簾疎捲秋風。", "隠几衆山碧，題詩秋葉紅。", "脩篁發清籟，爲公奏笙鏞。", "坐客憮然笑，此興誰能同。", "但聞太守樂，焉知清靜功。"]'),
('7551b35d-ee2e-4876-8c03-54c8e524560b','有客自關外來頗道邊亭暴露之苦時子止兄方趨原上予因感而有作','晁公遡','宋','宋诗','song-poetry','','[]','平凉歃血不濡齒，奚車轔轔臨渭水。',128,'全唐诗/poet.song.117000.json','["平凉歃血不濡齒，奚車轔轔臨渭水。", "一丸未及封函關，已復胡歌飲都市。", "近聞移屯集岐下，戰聲日震長平瓦。", "兩軍相持久未决，將軍寶帳皆在野。", "野田秋深風力勁，邊雲日滿青泥嶺。", "三軍雨立甲裳重，諸將露宿旃裘冷。", "原頭霜落黄蘆乾，西風獵獵邊亭寒。", "從軍之樂今有幾，仲宣寄詩煩說似。"]'),
('8f9e5809-10aa-428a-aa1f-e7e6b988bb1b','題趙誠甫養恬軒','晁公遡','宋','宋诗','song-poetry','','[]','本朝流澤長，後世多宗英。',132,'全唐诗/poet.song.117000.json','["本朝流澤長，後世多宗英。", "故老稱先王，往往如咸平。", "及見後來秀，亦皆有典刑。", "辟疆好清靜，雖仕不近名。", "每笑黄須兒，鞍馬勤遠征。", "功成不過侯，彈雀良自輕。", "養恬一室內，尤見避世情。", "帝欲睦其族，賜祿恩甚榮。", "不煩親指呼，卧護鈴下兵。", "優游有餘樂，軒窗亦虛明。", "客來願置醴，庶無忘穆生。"]'),
('fbda2c8b-7d16-410c-9ece-04364413478e','遊仙都山','晁公遡','宋','宋诗','song-poetry','','[]','松環樓殿青，江遶石壁流。',48,'全唐诗/poet.song.117000.json','["松環樓殿青，江遶石壁流。", "清波天讓碧，月照無邊秋。", "風景自清好，江山難獨遊。", "舉觴聊一醉，放懷忘百憂。"]'),
('9b3adf04-4ec5-4202-a7ff-15cbf943f204','早起','晁公遡','宋','宋诗','song-poetry','','[]','晨煙生遠山，空翠蒙餘昏。',48,'全唐诗/poet.song.117000.json','["晨煙生遠山，空翠蒙餘昏。", "天容頗不佳，北風凄以寒。", "醉眠擁敗絮，方知有奇溫。", "夢餘忽驚悟，簷有鬭鵲喧。"]'),
('15f64f82-7af0-4b3c-8fe4-1b45792f2461','冬暮','晁公遡','宋','宋诗','song-poetry','','[]','風林委黄葉，寒烏噪枯枝。',108,'全唐诗/poet.song.117000.json','["風林委黄葉，寒烏噪枯枝。", "四山失其蔽，慘淡無奇姿。", "是時歲云暮，節物良可悲。", "邊馬嘶北風，塞垣草亦衰。", "傳聞西南戍，未敢休王師。", "不辭征行苦，頗念餽餉遲。", "遥憐持戟士，半是五陵兒。", "不知家存亡，辛苦臨邊陲。", "日暮裘褐單，誰當寄征衣。"]'),
('f9f42d1f-42a5-4631-8c8d-2132b2ef1dc6','歲晏','晁公遡','宋','宋诗','song-poetry','','[]','歲晏天益寒，短景殊未長。',120,'全唐诗/poet.song.117000.json','["歲晏天益寒，短景殊未長。", "曉日出愈遲，翳翳迷扶桑。", "微陽不破霧，髣髴光有芒。", "開門視屋瓦，北風吹朝霜。", "起坐擁寒爐，束带指已僵。", "灰中見宿火，晶熒無餘光。", "天寒不可出，墐戶宜深藏。", "朝衙不敢後，歛板趨公堂。", "歸來日正出，臨階負朝陽。", "茲晨暫自適，明朝殊未央。"]'),
('6d76c2c5-b6c4-4771-831d-405f65e0d08f','天寒','晁公遡','宋','宋诗','song-poetry','','[]','樹頭謖謖風聲來，木葉已盡吹黄埃。',112,'全唐诗/poet.song.117000.json','["樹頭謖謖風聲來，木葉已盡吹黄埃。", "是時霜飛萬瓦白，曉霧欲破晨光開。", "嚴天禦寒惟酒可，急喚江南鸚鵡盃。", "一盃未盡醉色起，紅入兩頰驚春回。", "惟愁見守不少貸，酒力未解還相催。", "遥瞻浮雲蔽北極，故鄉何在心悠哉。", "茂陵先帝儻見夢，敢不奏記通天台。"]'),
('19b7808c-aa0d-450a-8be8-c1d67db7ff3b','子兼行後一日作','晁公遡','宋','宋诗','song-poetry','','[]','平生每臨岐，輒作數日惡。',96,'全唐诗/poet.song.117000.json','["平生每臨岐，輒作數日惡。", "況當暮冬際，尤用感離索。", "千林已空枝，饑烏晚猶啄。", "北風殊未已，槭槭卷黄落。", "想當道里遠，窈窕復尋壑。", "霜寒清夜驛，月樹墮驚鵲。", "僕夫睡已熟，獨坐誰與樂。", "寄詩往問之，聊以慰寂寞。"]'),
('1dc455b9-8b15-4cd2-a1e9-e743dc95153a','馮萬州當可以洞庭春色遺王子載蓋用安定郡王遺法也子載招予飲爲賦之','晁公遡','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','秋風洞庭波，霜落洲渚出。',180,'全唐诗/poet.song.117000.json','["秋風洞庭波，霜落洲渚出。", "黄蘆半傾倒，江樹無復色。", "獨餘千木奴，后皇所嘉植。", "芳辛有餘味，不減玉斚瀝。", "可令披黄苞，以甘授歡伯。", "釀成無邊春，吞此雲夢澤。", "猶持陶家輪，斷取李衡宅。", "納之甕盎中，未覺宇宙窄。", "方當玉腴熟，溜溜糟床滴。", "尚带含霜容，未飲香滿室。", "味奪桑落醇，色輕蒲萄碧。", "夷考無前聞，疇能妙儀狄。", "流傳自王家，遺法後世得。", "不宜博凉州，時可餉賓客。", "輟餐茗戰罷，持用解水厄。"]'),
('470b0604-1c7d-4e27-8aa6-81fd0f8b3a95','飲兵厨羔羊酒','晁公遡','宋','宋诗','song-poetry','','[]','沙晴草軟羔羊肥，玉肪與酒還相宜。',83,'全唐诗/poet.song.117000.json','["沙晴草軟羔羊肥，玉肪與酒還相宜。", "鸞刀薦味下麴糵，釀久骨醉凝浮脂。", "朝來清香發甕面，起視綠漲微生漪。", "入杯無聲瀉重碧，僅得一醉夫何爲。", "君不見先王作誥已刺譏，後來爲此尤可悲。"]'),
('5e3520e2-8960-4110-bf67-d8a42031dc91','樂溫舟中作','晁公遡','宋','宋诗','song-poetry','','[]','密雲卷雨歸空山，暮林接翅昏鴉還。',160,'全唐诗/poet.song.117000.json','["密雲卷雨歸空山，暮林接翅昏鴉還。", "須臾水面明月出，滄江萬頃瑠璃寒。", "波平汗漫天無風，水光月色相爲容。", "臨流愛此無盡碧，乘月直下滄浪中。", "江心石出高崔嵬，水作鏡面無停埃。", "琉璃萬頃忽破碎，知是一葦橫江來。", "中流與月更媚嫵，湛湛無聲翠光舞。", "飄然長嘯順流下，櫂夫請留恐仙去。", "姑令結纜寒沙邊，月方正中光入船。", "洗杯索酒屬明月，今夕之樂寧非天。"]'),
('8c174a1f-4730-4824-b25b-f42692f0a26a','聞范道卿將赴試成都作此勉之','晁公遡','宋','宋诗','song-poetry','','[]','長來故倦游，車轍環天下。',288,'全唐诗/poet.song.117000.json','["長來故倦游，車轍環天下。", "艱難不吾容，虎兕適曠野。", "世方卧積薪，敢獨怨飄瓦。", "久荒小山桂，幾葬蒲圃檟。", "百罹生不辰，一死天所赦。", "故交贈綈袍，旅食悲冷炙。", "將索長安米，偶中澤宮射。", "倚楹日悲歌，魯國疑欲嫁。", "退慙一木微，安足支大厦。", "收聲就泯默，故意遂衰謝。", "二年游諸侯，彈鋏守代舍。", "地濕恐鵩來，常畏閼單夏。", "官慙司馬巧，學愧齊人詐。", "低回甘折腰，俯仰甚出胯。", "入遭妻孥笑，出畏官長駡。", "一官終無成，他日要稅駕。", "買山誅茅草，遶屋植桑柘。", "婦能躬井臼，時饁南畝稼。", "人皆見我窮，連蹇足悲咤。", "往往怪范君，何不老閒暇。", "不知驥伏櫪，風雲要凌藉。", "一日千里行，汗溝沫流赭。", "我方馭欵段，敢追王良靶。", "聞君近舉子，滿室光照社。"]'),
('e5303aa3-433e-4111-85fc-29bb8f03b6bd','今秋久雨至八月望夕始晴月色尤清澈可愛置酒月下作','晁公遡','宋','宋诗','song-poetry','','[]','玉斧琢月玻瓈聲，月中桂樹秋風驚。',224,'全唐诗/poet.song.117000.json','["玉斧琢月玻瓈聲，月中桂樹秋風驚。", "終年待此一輪滿，不憂蛙食憂鼉鳴。", "白鼉十日鳴空山，雨師乘雲呼不還。", "黄塵曉漲三尺潦，明河夜飛千丈瀾。", "廣寒不復觀霓裳，公子豈解歌秋陽。", "釜星未滅日已出，風櫺雨隙棲清光。", "須臾紺繒展秋碧，仰見西山銜半璧。", "青天冥冥星益疎，光芒寒溢千山白。", "今夕何夕誰與度，舉杯屬月當起舞。", "陶然相對影凌亂，不覺驚烏起庭樹。", "樹頭霏霏木葉墜，白露懸空斗垂地。", "雖無絲竹爲陶寫，亦有鳴蛙當鼓吹。", "向來悲歌子桑子，饑坐虛憂木生耳。", "安知上帝思澄清，要令六合無泥滓。"]'),
('5d37b8f7-c477-42c4-99f8-79a0ba74354c','十月晦日同一屬官劉司戶師教授孫司理游九頂山登萬景樓分韻賦詩得游字韻','晁公遡','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','今日當賜沐，幸同官屬休。',132,'全唐诗/poet.song.117000.json','["今日當賜沐，幸同官屬休。", "於時輿梁成，徑絕蒼江流。", "山靈念我來，遂使蒙雨收。", "林端膏澤滋，巖際陽光浮。", "倚杖送飛雲，列席俯滄洲。", "所携坐上客，不減枚與鄒。", "被服玳瑁簪，辭華珊瑚鈎。", "樽中瀟湘清，引滿更獻酬。", "欲觀南東畝，往登西北樓。", "其下島嶼出，凄然洞庭秋。", "將歸各賦詩，聊復記此游。"]'),
('b471461e-f567-457d-8816-f2c141760640','哭盤石墓下','晁公遡','宋','宋诗','song-poetry','','[]','種木已大拱，今年初一過。',48,'全唐诗/poet.song.117000.json','["種木已大拱，今年初一過。", "方持斗酒奠，其若下泉何。", "寒日墟中淡，悲風冢上多。", "一爲知己慟，淚濕石盤沱。"]'),
('600822f9-1973-4be9-af6b-435e2496858d','寄師會三郎','晁公遡','宋','宋诗','song-poetry','','[]','青松初生在澗阿，未聞託根附女蘿。',72,'全唐诗/poet.song.117000.json','["青松初生在澗阿，未聞託根附女蘿。", "女蘿弱質安足恃，奈此歲晚風霜何。", "我觀婦翁念汝婦，亦知阿翁昔念汝。", "阿翁之恩那可忘，明年歸守五畝桑，勿使父老祠桐鄉。"]'),
('8fc5054b-02ca-401c-9047-133eb26d26e7','聞稻有成','晁公遡','宋','宋诗','song-poetry','','[]','庭柯不摇綠蔽空，西風未回尚南風。',64,'全唐诗/poet.song.117000.json','["庭柯不摇綠蔽空，西風未回尚南風。", "香稻既收八月白，晚花能開百日紅。", "安排物色慰年暮，流落天涯嗟路窮。", "炎江熱石那可觸，少待征帆駕歸鴻。"]'),
('374bb850-c8ed-4ecd-8689-97e638ea91fd','竹醉日','晁公遡','宋','宋诗','song-poetry','','[]','塵埃蓬勃欲障天，畧無爽氣北牖前。',64,'全唐诗/poet.song.117000.json','["塵埃蓬勃欲障天，畧無爽氣北牖前。", "五月風炎竹尚醉，九衢日長柳亦眠。", "小兒畏熱書頗廢，老子罷食夢相牽。", "桂漿蔗飲不解渴，汲盡百壺冰井泉。"]'),
('58f26751-f051-4173-b144-f331029a2f86','贈師傳郎','晁公遡','宋','宋诗','song-poetry','','[]','盤石山深鳥相呼，常憂草木侵樵蘇。',96,'全唐诗/poet.song.117000.json','["盤石山深鳥相呼，常憂草木侵樵蘇。", "子孫存者亦牢落，安得上冢來鴻臚。", "憶初起家聲烜赫，翰林主人嗟莫及。", "只今若使翁不亡，再試南宮期第一。", "傳郎十四如我長，骨骼已似能文章。", "阿翁穿楊有舊箭，傳乎勉力不可忘。"]'),
('ae7d08ba-06f6-4f62-b4c3-55d712f00ab8','秋日送客梁山道中','晁公遡','宋','宋诗','song-poetry','','[]','白露下木末，寒蜩抱枝鳴。',120,'全唐诗/poet.song.117000.json','["白露下木末，寒蜩抱枝鳴。", "道旁幾官樹，稍稍棲烏驚。", "不知何爲爾，蕭瑟來秋聲。", "遥山歛暝色，凉月含空明。", "吾其及清夜，登車可徐行。", "露幘受新爽，風襟逐輕塵。", "兀兀寄殘夢，泠泠析餘酲。", "東行二十里，斗落參復橫。", "晨光明紫霞，銀潢淡疎星。", "吾行不可緩，曉復塵沙生。"]'),
('efb7f8c3-4255-4b38-81bb-cc6bce32e2e5','喜陳行之病起','晁公遡','宋','宋诗','song-poetry','','[]','閉門莓苔青，欹枕風雨秋。',180,'全唐诗/poet.song.117000.json','["閉門莓苔青，欹枕風雨秋。", "白日稍覺短，急景逝不留。", "鳴蟬尖舊響，高槐老新柔。", "弔古哀九辯，感今懷百憂。", "是時甫七月，大火方西流。", "陰麓懸暮色，停雲掛空愁。", "凉風颯然至，有聲在林丘。", "蕭蕭吹遊子，意已思良裘。", "隠几默不樂，讀書將安求。", "豈無三益友，共此百尺樓。", "陳郎漳濱卧，久闕過我游。", "朝來見顔色，厥疾云已瘳。", "自茲可來往，笑談更獻酬。", "不憂飯成糜，相約劒買牛。", "誰能與此世，顛倒同薰蕕。"]'),
('f5409492-2a16-4944-aaf3-174e33681480','西風','晁公遡','宋','宋诗','song-poetry','','[]','西風何時來，秋聲已蕭瑟。',108,'全唐诗/poet.song.117000.json','["西風何時來，秋聲已蕭瑟。", "卧聞庭前樹，終日鳴策策。", "雖云未摇落，慘淡損光澤。", "官槐脫高花，穉柏矜獨碧。", "感茲歲婉娩，客路尚行役。", "病骨感秋氣，瘧癘苦見迫。", "蝸牛猶自庇，狐兔亦有宅。", "抱病寄官舍，意氣非復昔。", "顧無揣摩才，胡爲諸侯客。"]'),
('b2285ecb-1703-4b8f-9ba6-3beb0f751f82','醉歌行贈閭丘伯有','晁公遡','宋','宋诗','song-poetry','','[]','昔別我髮青如葱，再來兩鬢真飛蓬。',192,'全唐诗/poet.song.117000.json','["昔別我髮青如葱，再來兩鬢真飛蓬。", "怪君五十面猶紅，答我有婦賢梁鴻。", "澹然意遠態甚濃，乃有謝家林下風。", "詩書圖史仍兼通，豈惟刀尺工削縫。", "入門不憂四壁空，要使我樂忘其窮。", "終朝舉桉歡笑同，方牀曲几陳座中。", "紙窗雲母明房櫳，華堂雖未掛桑弓。", "兩女雜佩琥珀龍，大女已能繡芙蓉。", "小女解唱風入松，事夫如賓顔色恭。", "歲時稱壽曲三終，自歌鵲巢詠阜螽。", "正須富貴報汝功，何時執戟明光宮。", "只今西州兵馬雄，盍往獻策西平戎。"]'),
('4767f5fa-9d0d-46ef-99fe-1326d7623790','燕閒','晁公遡','宋','宋诗','song-poetry','','[]','四無市聲身燕閒，更居高明益清安。',64,'全唐诗/poet.song.117000.json','["四無市聲身燕閒，更居高明益清安。", "銅缾水冷碧井凍，冰漿飯香白雪寒。", "味毋致和夏小正，仗當早歸漢從官。", "此身不願奉朝請，但願常甘藜藿盤。"]'),
('30242a0e-5309-4a40-8080-00b35ca5456c','合江縣舟中作','晁公遡','宋','宋诗','song-poetry','','[]','春江漲黄流，漸沒灘上石。',120,'全唐诗/poet.song.117000.json','["春江漲黄流，漸沒灘上石。", "是時三日霖，壠麥半腐黑。", "四顧雲氣昏，江樹生遠色。", "蒼茫何所辨，目盡千頃白。", "汗漫若無際，空濛如有覿。", "蕭蕭雨中帆，正此遠行役。", "馮夷喜我至，歸路風愈力。", "中流浪爲開，蕩漾放舟入。", "恍疑瀟湘游，白蘋了無迹。", "故人樓中望，天際應可識。"]'),
('f742fe01-aa50-415e-ab53-7dd2930057bd','三月二十九日舟中作','晁公遡','宋','宋诗','song-poetry','','[]','今晨天氣佳，晴光被茂草。',48,'全唐诗/poet.song.117000.json','["今晨天氣佳，晴光被茂草。", "草際含餘滋，粲然泫清曉。", "舟師催解纜，及此風色好。", "江神似相予，扁舟若輕矯。"]'),
('479f8e60-f7b7-4438-8cec-44a8d7ed1a53','病中一首簡陳行之','晁公遡','宋','宋诗','song-poetry','','[]','岡陵雖坡陀，其下水所積。',252,'全唐诗/poet.song.117000.json','["岡陵雖坡陀，其下水所積。", "山通巫硤雨，地類長沙濕。", "太陽豈不照，浸漬本膏脈。", "氣蒸柱礎潤，暗起窗戶黑。", "老屋生菌衣，陰牆上苔色。", "不知今何時，寒暑晝夜易。", "邑人安土風，特不宜北客。", "我初忽不戒，詩酒頗自適。", "艱難出一語，不博萬戶邑。", "竟坐傷天和，兩卧漳濱疾。", "急求三年艾，幾墮衆鬼域。", "自惟形羸甚，固易中膚革。", "昔年見君至，豪氣非我敵。", "謂將獨免此，不受瘴癘厄。", "胡爲亦效我，傾倒弄翰墨。", "吟哦彫肝腎，辛苦出鈎棘。", "邇來亦抱病，發作乃併日。", "滌胃無全功，徙薪有上策。", "意其水帝子，欲君更奇出。", "手掉芙蓉旗，聊爾一戲劇。", "庶聞譴瘧篇，相將還白石。"]'),
('8a66ed22-3afb-4ba7-bab1-c05eea7bc96c','雨','晁公遡','宋','宋诗','song-poetry','','[]','浮雲起層陰，空中薄爲霧。',72,'全唐诗/poet.song.117000.json','["浮雲起層陰，空中薄爲霧。", "簷端雨聲寒，客子念遲暮。", "祝融如昨日，白帝已更御。", "寒聲傍絡緯，秋意入庭樹。", "六龍疾其驅，歲月不吾與。", "婦子催授衣，荒城聞砧杵。"]'),
('94fe7784-4420-494c-85f8-fbec0d9d27ca','至漢嘉簡李悅夫','晁公遡','宋','宋诗','song-poetry','','[]','一別相望費歲時，盛山父老至今思。',64,'全唐诗/poet.song.117000.json','["一別相望費歲時，盛山父老至今思。", "才高方朔三千牘，名配韋郎十二詩。", "論薦久聞章奏上，推遷獨怪璽書遲。", "少留剩看平羌水，更繼風流太白詞。"]'),
('07982d1b-24cb-4b36-8e5d-b8613917b782','示犍爲李令君','晁公遡','宋','宋诗','song-poetry','','[]','悻直每疾惡，淹留無徙官。',48,'全唐诗/poet.song.117000.json','["悻直每疾惡，淹留無徙官。", "性雖與物忤，吾獨惜才難。", "垂老須聞道，爲邦貴在寬。", "君宜念此語，衰鬢各霜殘。"]'),
('f3e1ce5e-267f-4c8d-93d6-30cea59e8602','送梁子輔赴召  其一','晁公遡','宋','宋诗','song-poetry','','[]','始見擢高第，即當登赤墀。',48,'全唐诗/poet.song.117000.json','["始見擢高第，即當登赤墀。", "今聞一節召，已恨十年遲。", "聖主圖興造，諸儒合論思。", "此行宜努力，勿復負清時。"]'),
('dd3c44b5-fdea-4828-9b6f-ddb1f1055d08','送梁子輔赴召  其二','晁公遡','宋','宋诗','song-poetry','','[]','今日朝廷議，如聞少及民。',48,'全唐诗/poet.song.117000.json','["今日朝廷議，如聞少及民。", "諸侯無患楚，三戶可亡秦。", "但使誅求減，常令貢賦均。", "荒年免離散，率土盡王臣。"]'),
('8d275a76-57a9-4d80-85b9-3e6f0bb87a95','送梁子輔赴召  其三','晁公遡','宋','宋诗','song-poetry','','[]','漢廷日徵召，舟楫去紛紛。',48,'全唐诗/poet.song.117000.json','["漢廷日徵召，舟楫去紛紛。", "行路子所見，成功吾未聞。", "故人期此去，聖代用斯文。", "會使如椽筆，書勳繼典墳。"]'),
('8540cb0a-a1ff-4478-84ae-2b531a152fce','簡謝達夫','晁公遡','宋','宋诗','song-poetry','','[]','吾識宣城守，又違之一邦。',48,'全唐诗/poet.song.117000.json','["吾識宣城守，又違之一邦。", "相看知雅曲，必解賦澄江。", "溫厚氣無雜，衰慵心已降。", "舉觴喜見屬，親爲撥春缸。"]'),
('8813ee62-0674-42a0-a5d8-ac0e23dee3ab','寄李仁甫','晁公遡','宋','宋诗','song-poetry','','[]','守地難越境，弔生寧及哀。',48,'全唐诗/poet.song.117000.json','["守地難越境，弔生寧及哀。", "自傷轉蓬遠，莫致束芻來。", "慘日熙夏屋，悲風號夜臺。", "遥知倚廬處，流淚漬蒼苔。"]'),
('3d476596-7dd1-4654-bb03-46a2ff01bdc5','李悅夫劉文潛坐上醉歸作','晁公遡','宋','宋诗','song-poetry','','[]','將老尚逐食，相逢聊舉觴。',48,'全唐诗/poet.song.117000.json','["將老尚逐食，相逢聊舉觴。", "貧非原憲病，酒發次公狂。", "未至世臣國，先登君子堂。", "誰能更拘束，短髮已滄浪。"]'),
('56797fe6-22df-4384-9fc2-c6898276922a','贈張聽聲  其一','晁公遡','宋','宋诗','song-poetry','','[]','張子目盲心不盲，吾知胸次有人倫。',32,'全唐诗/poet.song.117000.json','["張子目盲心不盲，吾知胸次有人倫。", "眼光安用如巖電，白首王戎不識人。"]'),
('b6721d00-89ea-45f1-8828-9be5eb11887d','贈張聽聲  其二','晁公遡','宋','宋诗','song-poetry','','[]','論士平生妙入神，是誰無此耳輪囷。',32,'全唐诗/poet.song.117000.json','["論士平生妙入神，是誰無此耳輪囷。", "喚鍾作甕皆堪笑，自是渠儂聽不真。"]'),
('d6e2db0e-6974-4837-bcb8-2f5f7291f9f1','自恭州之眉陽相送者六客意不可忘以詩爲謝','晁公遡','宋','宋诗','song-poetry','','[]','所得乃三益，相從非一朝。',48,'全唐诗/poet.song.117000.json','["所得乃三益，相從非一朝。", "龍方卧隴底，魚肯似陽橋。", "月看玉奩滿，風吹金燼銷。", "少留吾亦住，不待楚詞招。"]'),
('143de69b-345e-4ccd-9a92-17afad8b15ee','贈朱師軻朱奎父','晁公遡','宋','宋诗','song-poetry','','[]','洛陽盛人物，喪亂亦南遷。',48,'全唐诗/poet.song.117000.json','["洛陽盛人物，喪亂亦南遷。", "今見大夫後，猶如翁子賢。", "端居送日月，秀句寫風煙。", "相遇何匆促，臨分重惘然。"]'),
('93b30a46-f09c-4b05-84ad-5adcb62913c6','置酒北郊外送張真甫還什邡','晁公遡','宋','宋诗','song-poetry','','[]','高木已在望，不妨寬作程。',48,'全唐诗/poet.song.117000.json','["高木已在望，不妨寬作程。", "相看愁饌徹，未用遽杯行。", "春暖姜肱被，川平雍齒城。", "遥知喜公至，雞犬亦歡迎。"]'),
('42ef689e-9579-4578-9d11-d6ba64757478','東津','晁公遡','宋','宋诗','song-poetry','','[]','東津草生花未開，西山雪消水欲來。',64,'全唐诗/poet.song.117000.json','["東津草生花未開，西山雪消水欲來。", "玻瓈江盡不受垢，蒲萄酒濃初醱醅。", "啄木喚君有扣戶，提壺勸我勤舉杯。", "春能幾何看即暮，一月杖藜須百回。"]'),
('ee12b28e-030b-479c-a1a3-c612f6690a00','龍爪灘','晁公遡','宋','宋诗','song-poetry','','[]','龍爪灘前江水平，蟆頤山下春草生。',64,'全唐诗/poet.song.117000.json','["龍爪灘前江水平，蟆頤山下春草生。", "白石既出細可數，雜花初開遠更明。", "日落盡見樓閣影，天晴易聞鐘鼓聲。", "至今回思三峽路，蛇退猿愁心甚驚。"]'),
('5665b127-3f3f-4cc1-853b-82b0ae3ded0e','十二月八日雪','晁公遡','宋','宋诗','song-poetry','','[]','桃杏顔衰不解紅，朝來飛雪舞回風。',32,'全唐诗/poet.song.117000.json','["桃杏顔衰不解紅，朝來飛雪舞回風。", "東風似與加湔拂，病葉枯枝一洗空。"]'),
('164a4d83-e329-428a-829e-899c5893a65b','登梁山縣亭','晁公遡','宋','宋诗','song-poetry','','[]','舉觴自起勸西風，吹盡千林木葉紅。',32,'全唐诗/poet.song.117000.json','["舉觴自起勸西風，吹盡千林木葉紅。", "遮斷前山渾不見，恐妨極目送飛鴻。"]'),
('8f84bd9f-2512-4d60-82d0-ab422f149fd0','感事三首  其一','晁公遡','宋','宋诗','song-poetry','','[]','中原耆舊老江東，淚灑軍前草木風。',32,'全唐诗/poet.song.117000.json','["中原耆舊老江東，淚灑軍前草木風。", "巫峽山高苦霜雪，附書那有北來鴻。"]'),
('3046a2e5-bd92-4a16-9d37-6cd959059012','感事三首  其二','晁公遡','宋','宋诗','song-poetry','','[]','長安摧堞有烏聲，草木猶蒙戰伐塵。',32,'全唐诗/poet.song.117000.json','["長安摧堞有烏聲，草木猶蒙戰伐塵。", "應念關中不忘漢，至今遺老願王秦。"]'),
('18e1dfe4-2f94-4500-85b4-355c632878bc','感事三首  其三','晁公遡','宋','宋诗','song-poetry','','[]','常恐東南驛騎疎，每逢人至問揚都。',32,'全唐诗/poet.song.117000.json','["常恐東南驛騎疎，每逢人至問揚都。", "深知白虜心輕漢，終倚黄旗運在吳。"]'),
('a5af4163-9dbb-4bb9-baf9-786ab9bedbf6','江上春漲','晁公遡','宋','宋诗','song-poetry','','[]','久坐思行樂，茲晨强出門。',48,'全唐诗/poet.song.117000.json','["久坐思行樂，茲晨强出門。", "菰蒲荒少岸，桑柘遠知村。", "波急春濤大，山晴午樹昏。", "每來成獨往，佳處與誰論。"]'),
('a9513c1f-608b-48e4-8ec0-875181ac3d37','送王師厚  其一','晁公遡','宋','宋诗','song-poetry','','[]','宿草丘邊手自耘，輟耘過我意良勤。',32,'全唐诗/poet.song.117000.json','["宿草丘邊手自耘，輟耘過我意良勤。", "可憐一語未深接，借問去來何見聞。"]'),
('d53f055d-8a3f-4b82-8e00-88b8c3960ef5','送王師厚  其二','晁公遡','宋','宋诗','song-poetry','','[]','季父高名映里閭，復欣千里識名駒。',32,'全唐诗/poet.song.117000.json','["季父高名映里閭，復欣千里識名駒。", "當令東海評清譽，他日還如二大夫。"]'),
('dc85a0a8-b8a4-469f-8791-becdc53fbd59','照上人去硤內游吳下十年而歸眉宇炯然無復瀘濮間氣喜作二解贈之  其一','晁公遡','宋','宋诗','song-poetry','','[]','幾年持鉢下瞿塘，踏遍東南古道場。',32,'全唐诗/poet.song.117000.json','["幾年持鉢下瞿塘，踏遍東南古道場。", "鄉里再來人不識，碧瞳白頰带湖光。"]'),
('234b2a33-f76f-4523-9374-b52977e73e05','照上人去硤內游吳下十年而歸眉宇炯然無復瀘濮間氣喜作二解贈之  其二','晁公遡','宋','宋诗','song-poetry','','[]','吳帆却入瞿塘硤，草樹連雲山四圍。',32,'全唐诗/poet.song.117000.json','["吳帆却入瞿塘硤，草樹連雲山四圍。", "想見同來木上座，怪君何苦復東歸。"]'),
('bd12f6ba-13d2-4623-a602-6b984353b365','過圓覺院簡照上人','晁公遡','宋','宋诗','song-poetry','','[]','一洗糟粕地，再聞鐘梵音。',48,'全唐诗/poet.song.117000.json','["一洗糟粕地，再聞鐘梵音。", "前身老東院，具體小西林。", "自昔知味少，于今無巷深。", "是中有妙理，直下試叅尋。"]'),
('7c39c55b-f91c-4ddf-8630-4feca4c64976','近承琮上人問訊甚勤老懶不能作書以偈答之  其一','晁公遡','宋','宋诗','song-poetry','','[]','食時持鉢乞諸隣，不用毗耶遣化身。',32,'全唐诗/poet.song.117000.json','["食時持鉢乞諸隣，不用毗耶遣化身。", "想見堂中慙此老，法輪未轉轉饑輪。"]'),
('bbfc51ae-eaa2-452c-b1eb-2dba5da67247','近承琮上人問訊甚勤老懶不能作書以偈答之  其二','晁公遡','宋','宋诗','song-poetry','','[]','世界猶如露電身，更於空裏聚微塵。',32,'全唐诗/poet.song.117000.json','["世界猶如露電身，更於空裏聚微塵。", "何時麥積崖邊路，說法重來要度人。"]'),
('76bccc0b-ec31-4c18-8c18-13d6e255d5f1','近承琮上人問訊甚勤老懶不能作書以偈答之  其三','晁公遡','宋','宋诗','song-poetry','','[]','十年不到吳溪上，聞道禪龕更斬新。',32,'全唐诗/poet.song.117000.json','["十年不到吳溪上，聞道禪龕更斬新。", "得見山中此松老，後來誰是住庵人。"]'),
('7e41b489-6014-4ce4-816a-dcb2005b285f','次韻謝石教授喜雨','晁公遡','宋','宋诗','song-poetry','','[]','天子齋居坐法宮，萬方都屬指揮中。',64,'全唐诗/poet.song.117000.json','["天子齋居坐法宮，萬方都屬指揮中。", "敢安無事思樂泮，方戒有司歸在豐。", "每念三農皆望歲，直期九月始休工。", "知君亦喜連宵雨，與漲詞源更不窮。"]'),
('4121f5d3-aad2-4b28-9102-b7603e8fb91a','次韻謝張德粹主簿','晁公遡','宋','宋诗','song-poetry','','[]','久知經籍總皆通，萬卷縱橫在腹中。',64,'全唐诗/poet.song.117000.json','["久知經籍總皆通，萬卷縱橫在腹中。", "占雨正當求管輅，藏冰更欲問申豐。", "每慚列爵來分土，未辦通商與惠工。", "君自還家歌樂職，大碑深刻示無窮。"]'),
('41aa0568-dfcd-4725-b6d7-c4484e3b9c12','雨中登披風榭望東山','晁公遡','宋','宋诗','song-poetry','','[]','岡嶺逶迤草木低，東山好處我能知。',32,'全唐诗/poet.song.117000.json','["岡嶺逶迤草木低，東山好處我能知。", "色濃意遠真堪畫，須在冥濛奄靄時。"]'),
('61cc3e37-e42e-46eb-a6e1-84775d4cd42f','方塘','晁公遡','宋','宋诗','song-poetry','','[]','清陰布幽徑，綠水溢回塘。',48,'全唐诗/poet.song.117000.json','["清陰布幽徑，綠水溢回塘。", "筍長露漬粉，蓮開風壞粧。", "坐多惟踵息，躁定自心凉。", "學道今始得，頤生真有方。"]'),
('8839fb1f-fd72-4021-b408-6aec10460ebd','年侵','晁公遡','宋','宋诗','song-poetry','','[]','年侵慵更甚，帙亂卷還舒。',48,'全唐诗/poet.song.117000.json','["年侵慵更甚，帙亂卷還舒。", "衰白愁看鏡，雌黄倦校書。", "臨風知地爽，映日愛窗虛。", "近報畬田粟，洿邪亦滿車。"]'),
('b3182d26-9714-4659-9dad-1fabf9478423','庭下荔子熟','晁公遡','宋','宋诗','song-poetry','','[]','脩枝密葉總扶疎，小摘登盤置坐隅。',64,'全唐诗/poet.song.117000.json','["脩枝密葉總扶疎，小摘登盤置坐隅。", "翠蓋高垂張葆羽，赤繒全皺裹明珠。", "不勞漢候十五里，可壓越人三百株。", "欲與銓量立題品，豈惟當使橘爲奴。"]'),
('f5a5c496-05ab-4a2d-93fd-65d5ecdc74ce','劉文潛以荔子并詩見寄','晁公遡','宋','宋诗','song-poetry','','[]','十里爲一候，奔騰南海來。',48,'全唐诗/poet.song.117000.json','["十里爲一候，奔騰南海來。", "封章伯游切，詩句少陵哀。", "異縣歲月改，前年霜雪摧。", "筠籠今遠寄，珍重手親開。"]'),
('4ffd58b5-daf9-42a6-9c46-10b54e03725b','侯革以詩見示次韻','晁公遡','宋','宋诗','song-poetry','','[]','少陵有幽事，止共阮生論。',48,'全唐诗/poet.song.117000.json','["少陵有幽事，止共阮生論。", "把酒與賢樂，爲邦慚主恩。", "欻傾賓客坐，知出聘君門。", "勝識中郎面，區區對虎賁。"]'),
('b180fde7-2612-4916-95f5-3392568b4596','送劉文潛如吳下','晁公遡','宋','宋诗','song-poetry','','[]','已聚糧三月，聊爲客數旬。',48,'全唐诗/poet.song.117000.json','["已聚糧三月，聊爲客數旬。", "吾難留逸駕，此去立通津。", "聖主坐中具，嘉謀思上陳。", "請言堯舜道，第一在安民。"]'),
('3ba27186-2d73-4afa-9267-a6e57082721b','隆州道中','晁公遡','宋','宋诗','song-poetry','','[]','冉冉晨霧重，暉暉冬日微。',48,'全唐诗/poet.song.117000.json','["冉冉晨霧重，暉暉冬日微。", "草黄迷犢卧，水白見鷗飛。", "在野樵牧少，閉關商旅稀。", "妻孥屬長至，遥想望吾歸。"]'),
('052adfb8-4fae-4fd9-879c-5e73f0c1dc63','送張君玉赴寧江幕府七首  其一','晁公遡','宋','宋诗','song-poetry','','[]','冠劔堂堂仁壽公，昨提金鼓去平戎。',32,'全唐诗/poet.song.117000.json','["冠劔堂堂仁壽公，昨提金鼓去平戎。", "惜君不往分一矢，共射佛貍江水中。"]'),
('f9b3aef9-2f87-4462-868c-c62036a30a14','送張君玉赴寧江幕府七首  其二','晁公遡','宋','宋诗','song-poetry','','[]','莫言地近嶲昆明，刺史題書筆不停。',32,'全唐诗/poet.song.117000.json','["莫言地近嶲昆明，刺史題書筆不停。", "解道澄江浄如練，空濛山水是昭亭。"]'),
('e0f9529b-0a99-403e-806b-338b19c1e4cf','送張君玉赴寧江幕府七首  其三','晁公遡','宋','宋诗','song-poetry','','[]','子去夔州頗自矜，舉杯大叫氣憑陵。',32,'全唐诗/poet.song.117000.json','["子去夔州頗自矜，舉杯大叫氣憑陵。", "新詩硤內流傳滿，今有高人王右丞。"]'),
('68a6a11b-27d9-4393-b31d-ad7c59573192','送張君玉赴寧江幕府七首  其四','晁公遡','宋','宋诗','song-poetry','','[]','來守劔西三里城，胸中豈止俗塵生。',32,'全唐诗/poet.song.117000.json','["來守劔西三里城，胸中豈止俗塵生。", "簿書堆案惟思睡，見此魁梧覺眼明。"]'),
('b3b64671-0400-49e5-a371-706d5b224c1c','送張君玉赴寧江幕府七首  其五','晁公遡','宋','宋诗','song-poetry','','[]','遠景樓高風月清，酒酣要看筆縱橫。',32,'全唐诗/poet.song.117000.json','["遠景樓高風月清，酒酣要看筆縱橫。", "山川有待君知否，可是東坡賦不成。"]'),
('8bc85721-b782-4c2d-94d5-47b943d64f44','送張君玉赴寧江幕府七首  其六','晁公遡','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','衆水爭流赴硤中，輕舟東下疾飛鴻。',32,'全唐诗/poet.song.117000.json','["衆水爭流赴硤中，輕舟東下疾飛鴻。", "流金不信人間熱，知有長江萬里風。"]'),
('f4168b0a-77f0-4ca7-95a7-39559c21021d','送張君玉赴寧江幕府七首  其七','晁公遡','宋','宋诗','song-poetry','','[]','江聲洶洶雷霆硤，山氣蒼蒼雲雨臺。',32,'全唐诗/poet.song.117000.json','["江聲洶洶雷霆硤，山氣蒼蒼雲雨臺。", "白髮拾遺吟不盡，分留物色待君來。"]'),
('5b3c65b3-8393-4bab-b55a-71001b98e1b8','鮮于東之晉伯之子贈詩次韻  其一','晁公遡','宋','宋诗','song-poetry','','[]','微風獵樹有佳聲，一榻無塵戶牖明。',32,'全唐诗/poet.song.117000.json','["微風獵樹有佳聲，一榻無塵戶牖明。", "已擘荔枝憐玉破，更開瓜碧嚼冰清。"]'),
('8e566bb9-34e2-4da7-b553-db1fb33daf39','鮮于東之晉伯之子贈詩次韻  其二','晁公遡','宋','宋诗','song-poetry','','[]','堂上詩書抵萬鍾，席間罇俎是千峯。',32,'全唐诗/poet.song.117000.json','["堂上詩書抵萬鍾，席間罇俎是千峯。", "蕭然更聽松風曲，喚起江東阮仲容。"]'),
('7a29d4f8-6953-4bf1-bbf3-a7ddb8f82630','鮮于東之晉伯之子贈詩次韻  其三','晁公遡','宋','宋诗','song-poetry','','[]','高簾不卷戶長開，須子時時著屣來。',32,'全唐诗/poet.song.117000.json','["高簾不卷戶長開，須子時時著屣來。", "一坐清風生白羽，九衢烏帽失黄埃。"]'),
('302f4626-1a16-44d4-9bd4-f065225fd2e8','鮮于東之晉伯之子贈詩次韻  其四','晁公遡','宋','宋诗','song-poetry','','[]','尊前每誦赤壁賦，如見當年禿鬢翁。',32,'全唐诗/poet.song.117000.json','["尊前每誦赤壁賦，如見當年禿鬢翁。", "誰謂流傳到喬木，果然遺響託悲風。"]'),
('6815ba89-a197-450d-97c2-91ac8d4fd294','鮮于東之晉伯之子贈詩次韻  其五','晁公遡','宋','宋诗','song-poetry','','[]','一掃浮雲萬里空，月華都在野航中。',32,'全唐诗/poet.song.117000.json','["一掃浮雲萬里空，月華都在野航中。", "葛巾藜杖勤相過，共賞芙蓉四面風。"]'),
('a9d40e47-996e-4cfe-8ba9-35841ff92c09','鮮于東之晉伯之子贈詩次韻  其六','晁公遡','宋','宋诗','song-poetry','','[]','資州太守知衰懶，日日倒床惟睡濃。',32,'全唐诗/poet.song.117000.json','["資州太守知衰懶，日日倒床惟睡濃。", "走送甘鮮三百顆，似君風味喜相逢。"]'),
('f28086cd-bb9c-4673-8038-0e73dae05938','寄查元章','晁公遡','宋','宋诗','song-poetry','','[]','一別三十載，再來聞未聞。',48,'全唐诗/poet.song.117000.json','["一別三十載，再來聞未聞。", "割鮮煩啗我，舉酒欲浮君。", "辯口霏木屑，醉顔生纈紋。", "相從能幾日，明發重離羣。"]'),
('47d88890-b96c-45fb-bf39-9b6377087115','喜見呂元錫聞往謁李仁甫奉簡短作','晁公遡','宋','宋诗','song-poetry','','[]','關塞三峨北，山川五渡西。',48,'全唐诗/poet.song.117000.json','["關塞三峨北，山川五渡西。", "喜逢連璧友，來自釣璜溪。", "先世施行馬，高才滯割雞。", "平生李元禮，好士必提携。"]'),
('59a4d10b-bfab-4be7-adf7-8ecd304a8e0b','王伯厚以詩招伯渾次韻同往邀之','晁公遡','宋','宋诗','song-poetry','','[]','憶昨歸來萬里遥，不能對策未央朝。',64,'全唐诗/poet.song.117000.json','["憶昨歸來萬里遥，不能對策未央朝。", "山林得計成長往，松石爲朋是久要。", "痛飲肯來同榼挈，小詩聊遣當弓招。", "請君莫學全椒老，澗下辛勤捨墮樵。"]'),
('9c2ca32d-6421-4967-ae31-b75fb48e2e17','師伯渾用韻復次  其一','晁公遡','宋','宋诗','song-poetry','','[]','束書歸隠不辭遥，庠序懶陪耆老朝。',64,'全唐诗/poet.song.117000.json','["束書歸隠不辭遥，庠序懶陪耆老朝。", "野外卜居無鬼瞰，山中誓墓以神要。", "暫來同作荔枝社，安可輕違桂樹招。", "已遣官奴理琴瑟，豈惟百戲但歌樵。"]'),
('0cd94bf7-ee4a-4dfe-8a08-5cbb5815aaaa','師伯渾用韻復次  其二','晁公遡','宋','宋诗','song-poetry','','[]','風俗相傳三近古，作成況自聖明朝。',64,'全唐诗/poet.song.117000.json','["風俗相傳三近古，作成況自聖明朝。", "藏家文字本蒼史，繼世子孫非黑要。", "近報漢廷頻詔下，時聞蜀士有旌招。", "怪君尚爾衣逢掖，獨向空山伴採樵。"]'),
('6c09b828-34db-42c0-ab31-9053e1105d57','師伯渾用韻復次  其三','晁公遡','宋','宋诗','song-poetry','','[]','背郭深通一徑遥，奔流坐看百川朝。',64,'全唐诗/poet.song.117000.json','["背郭深通一徑遥，奔流坐看百川朝。", "飛來黄鵠陂已復，歸去白鷗盟可要。", "益部官曹寧久處，津鄉書札近相招。", "此生若有躬耕地，白首甘心老負樵。"]'),
('2b32a90f-379e-4d72-956d-1ed294eefc93','師伯渾用韻復次  其四','晁公遡','宋','宋诗','song-poetry','','[]','古者諸侯今牧守，衰遲難强歲相朝。',64,'全唐诗/poet.song.117000.json','["古者諸侯今牧守，衰遲難强歲相朝。", "惟須稚子理簑笠，兼有老妻縫襋要。", "來歲定從田父去，飛書不待故人招。", "平生最愛津鄉聚，江小可漁山可樵。"]'),
('dc79b2c2-1c7e-420f-ad25-63464e4c14c8','師伯渾用韻復次  其五','晁公遡','宋','宋诗','song-poetry','','[]','東望行都絳闕遥，老來筋力倦趨朝。',64,'全唐诗/poet.song.117000.json','["東望行都絳闕遥，老來筋力倦趨朝。", "誰能作吏沈簿領，但欲買田書質要。", "雅意庶同高士傳，不才難望大夫招。", "津鄉舊有先賢宅，過者蒭蕘莫敢樵。"]'),
('645c2acc-7175-4bd7-a1a0-7571e21ea6c4','師伯渾用韻復次  其六','晁公遡','宋','宋诗','song-poetry','','[]','筋力何堪道路遥，難陪諸彥侍同朝。',64,'全唐诗/poet.song.117000.json','["筋力何堪道路遥，難陪諸彥侍同朝。", "初無計上三年最，況敢功思萬里要。", "北塞單于皆入貢，西山贊普不勞招。", "傳聞已卧清邊鼓，塹壘長閒守木樵。"]'),
('21d13b20-576d-47e8-b0d0-6d2e05960e1b','師伯渾用韻復次  其七','晁公遡','宋','宋诗','song-poetry','','[]','日飜蠹簡書齋裏，往往編摹自漢朝。',64,'全唐诗/poet.song.117000.json','["日飜蠹簡書齋裏，往往編摹自漢朝。", "雞距束毫來武信，馬肝琢硯出高要。", "時因撫事歌成相，更復懷人作大招。", "知子山中富吟詠，縱橫文力到孫樵。"]'),
('0fd8cb7d-8060-4f73-8279-dadaad3921ef','去通義按刑漢嘉至中巖師伯渾臨別於此因成二詩  其一','晁公遡','宋','宋诗','song-poetry','','[]','慚愧居士屩，遠來尊者巖。',48,'全唐诗/poet.song.117000.json','["慚愧居士屩，遠來尊者巖。", "深知煩露宿，徑爲落風帆。", "潭浄魚堪喚，花殘鹿罷銜。", "堂中有耆老，禪病說呢喃。"]'),
('3616a107-bc1c-4ead-90d3-750cccd953ca','去通義按刑漢嘉至中巖師伯渾臨別於此因成二詩  其二','晁公遡','宋','宋诗','song-poetry','','[]','相送自崖返，忍看騎馬回。',48,'全唐诗/poet.song.117000.json','["相送自崖返，忍看騎馬回。", "故情真獨厚，疊鼓未須催。", "此去無三舍，相留盡一杯。", "風林如惜別，摵摵暮聲哀。"]'),
('db84a55e-ca96-463f-8f92-6cadb2d701a9','次韻鮮于晉伯清明日過水南  其一','晁公遡','宋','宋诗','song-poetry','','[]','盈牋寄我送春詩，不減風流杜牧之。',64,'全唐诗/poet.song.117000.json','["盈牋寄我送春詩，不減風流杜牧之。", "覓句已應兒輩覺，論書那得外人知。", "如聞此上三年最，相過能成一段奇。", "況及霜天宜把酒，四郊物色勝花時。"]'),
('876cfb84-c667-4e93-b679-285eef4c0f0d','次韻鮮于晉伯清明日過水南  其二','晁公遡','宋','宋诗','song-poetry','','[]','又賦斜川五日詩，行將去此欲何之。',64,'全唐诗/poet.song.117000.json','["又賦斜川五日詩，行將去此欲何之。", "一年春事倉庚報，萬里鄉心杜宇知。", "筆力早衰無痛快，詞源漸老乏經奇。", "文章子駿惟君似，學到揚州刺史時。"]'),
('7bba2080-82ab-466a-9294-5121a8ba2ea6','歲盡','晁公遡','宋','宋诗','song-poetry','','[]','歲盡餘一候，年侵懷百憂。',48,'全唐诗/poet.song.117000.json','["歲盡餘一候，年侵懷百憂。", "人生漢南樹，節物劔西州。", "風榭梅花委，春杯柏葉浮。", "峨眉有佳色，領覽爲登樓。"]'),
('4b63c181-2b34-4122-8f3b-b65a9f0c0ff7','師襲卿來權攝峨眉縣祿東之來乃去送以詩乃元日也','晁公遡','宋','宋诗','song-poetry','','[]','白水諸山翠作堆，豈令飛舄著塵埃。',64,'全唐诗/poet.song.117000.json','["白水諸山翠作堆，豈令飛舄著塵埃。", "勿嫌屈子峨眉縣，正得同吾婪尾杯。", "淑日升堂迎晝永，和風排闥送春來。", "還家尚可爲親壽，柏葉清尊手自開。"]'),
('67b304cd-8a83-42aa-9aea-4e5c4591cf38','送湯子才','晁公遡','宋','宋诗','song-poetry','','[]','江湖此去水連空，萬賈連檣浩渺中。',64,'全唐诗/poet.song.117000.json','["江湖此去水連空，萬賈連檣浩渺中。", "帆影浸斜青草月，笛聲吹盡碧蘆風。", "未論魏闕功名近，不與巴山氣象同。", "更到臨平看輦路，沙堤十里軟塵紅。"]'),
('75fcb996-f0fd-4c85-b5f6-314d34fbbf87','聞虞參政至玉屏山  其一','晁公遡','宋','宋诗','song-poetry','','[]','宣室思賢久，鋒車促召還。',48,'全唐诗/poet.song.117000.json','["宣室思賢久，鋒車促召還。", "去調金鉉鼎，來別玉屏山。", "拱木雨露下，豐碑天地閒。", "九原凜如在，想足慰慈顔。"]'),
('74986ee0-56d0-446d-99ca-675a8eabadc0','聞虞參政至玉屏山  其二','晁公遡','宋','宋诗','song-poetry','','[]','鄉黨敬前輩，朝廷尊大儒。',48,'全唐诗/poet.song.117000.json','["鄉黨敬前輩，朝廷尊大儒。", "公無念丘墓，人自禁樵蘇。", "此去居衡軸，長留執事樞。", "求賢養邦本，深爲贊吁俞。"]'),
('6ad97979-2b94-4052-ae66-8943452cae4d','示中巖長老子文','晁公遡','宋','宋诗','song-poetry','','[]','我爲應真來，欲結無生緣。',48,'全唐诗/poet.song.117000.json','["我爲應真來，欲結無生緣。", "不食中巖飯，但酌中巖泉。", "莫言一杯水，實具五味禪。", "請師問應真，此語然不然。"]'),
('261b5802-73ba-4fe1-89f0-71fa515695f9','子雲','晁公遡','宋','宋诗','song-poetry','','[]','子雲世所賤，既死名乃傳。',48,'全唐诗/poet.song.117000.json','["子雲世所賤，既死名乃傳。", "至今讀其書，共言以爲賢。", "必待成丘壠，何如用當年。", "貴耳不重目，斯人真可憐。"]'),
('88bd0e70-d05d-4d3a-a3ba-eaeedf88e90e','蔡光祿','晁公遡','宋','宋诗','song-poetry','','[]','白頭蔡光祿，不肯拜司徒。',48,'全唐诗/poet.song.117000.json','["白頭蔡光祿，不肯拜司徒。", "滿朝愕相視，蓋是時所無。", "負乘初莫責，循牆乃當誅。", "古書若盡信，夫子實欺予。"]'),
('9c58403c-36fc-4d6b-af9b-3f424e4933d0','江行','晁公遡','宋','宋诗','song-poetry','','[]','瀘南道窮復劔西，桃花浪生行苦遲。',64,'全唐诗/poet.song.117000.json','["瀘南道窮復劔西，桃花浪生行苦遲。", "百丈牽舟上春水，三尺爲邦逢聖時。", "平蕪細麥綠相映，老樹雜花紅已衰。", "峨眉山月今始見，令人絕歎謫仙詞。"]'),
('38040807-5cf1-49e9-b8d6-d9cfeaadbee8','木犀花二首  其一','晁公遡','宋','宋诗','song-poetry','','[]','粟玉開花顔色新，秋光未覺減陽春。',32,'全唐诗/poet.song.117000.json','["粟玉開花顔色新，秋光未覺減陽春。", "蕭然不受風埃涴，知是高標可辟塵。"]'),
('8e3f2eb0-1198-4df5-8a5c-c19876d35ae8','木犀花二首  其二','晁公遡','宋','宋诗','song-poetry','','[]','滿貯彫盤可鎮帷，論花壓盡劔東西。',32,'全唐诗/poet.song.117000.json','["滿貯彫盤可鎮帷，論花壓盡劔東西。", "豈惟鼻觀遭渠惱，鄰舍聞香亦駭雞。"]'),
('35d1cf25-a5a9-4594-996e-f32c68aa9e93','楊參政挽章二首  其一','晁公遡','宋','宋诗','song-poetry','','[]','學海波瀾濶，人間爵齒尊。',48,'全唐诗/poet.song.117000.json','["學海波瀾濶，人間爵齒尊。", "南宮冠多士，東海起高門。", "請去三公府，歸休五畝園。", "何須篆幽石，天下有師言。"]'),
('e2b2678d-2c80-46f9-a2b1-58f8d717a707','楊參政挽章二首  其二','晁公遡','宋','宋诗','song-poetry','','[]','亟上疏封印，空馳會葬車。',48,'全唐诗/poet.song.117000.json','["亟上疏封印，空馳會葬車。", "山川渾不改，氣象比何如。", "德行太常議，功名惇史書。", "平生所薦士，豈復減嚴徐。"]'),
('e61fca22-bdc0-45e8-8675-6f94c133397a','清明','晁公遡','宋','宋诗','song-poetry','','[]','便覺近長夏，溫風蠶欲成。',48,'全唐诗/poet.song.117000.json','["便覺近長夏，溫風蠶欲成。", "冠欹知髮少，衣薄喜身輕。", "初荻青穿水，繁陰綠滿城。", "朝來試新火，茶鼎聽松聲。"]'),
('a48a2c35-5fe1-4728-a2f0-d76cbd91ef3a','晚望','晁公遡','宋','宋诗','song-poetry','','[]','遲日高樓上，江山引望長。',48,'全唐诗/poet.song.117000.json','["遲日高樓上，江山引望長。", "浮鷗輕浩渺，飛鳥滅蒼茫。", "洲渚蘋初白，陵陂麥未黄。", "流年太匆促，轉燭過春光。"]'),
('f4c7218f-c498-42fb-873f-9053171f3474','聞李士舉宿馬鞍山','晁公遡','宋','宋诗','song-poetry','','[]','入境封人報，飛書侍史還。',48,'全唐诗/poet.song.117000.json','["入境封人報，飛書侍史還。", "初聞虎節使，已至馬鞍山。", "霽野風煙麗，端居日月閒。", "此行吾所羨，脫屣簿書間。"]'),
('5710ba7f-cdbc-4584-8c6a-35f4ca559caa','江上','晁公遡','宋','宋诗','song-poetry','','[]','江淺晴沙見，山高細路分。',48,'全唐诗/poet.song.117000.json','["江淺晴沙見，山高細路分。", "老藤維墮石，遠樹掛殘雲。", "燕鴈遥難到，巴鶑暖遂聞。", "花飛少顔色，委地自紛紛。"]'),
('83ce5f95-ed37-4941-9b4b-19e6c109061a','春日','晁公遡','宋','宋诗','song-poetry','','[]','花發春連屋，山晴晝滿樓。',48,'全唐诗/poet.song.117000.json','["花發春連屋，山晴晝滿樓。", "所過皆異縣，何處是皇州。", "頏頡鶑銜逐，呢喃燕聚謀。", "物生各有累，於世孰無求。"]'),
('627d8a0f-9e8c-43ef-b600-39d36830b086','野亭','晁公遡','宋','宋诗','song-poetry','','[]','興發尋春去，寧知生路賒。',48,'全唐诗/poet.song.117000.json','["興發尋春去，寧知生路賒。", "簷牙啄晴漢，屐齒散平沙。", "風偃陵陂麥，雲垂間道花。", "芳菲看即過，留滯改年華。"]'),
('1d68fdc0-37a8-4859-b882-a083eb3000df','挈榼','晁公遡','宋','宋诗','song-poetry','','[]','挈榼吾何往，閒臨積水邊。',48,'全唐诗/poet.song.117000.json','["挈榼吾何往，閒臨積水邊。", "晚紅看落日，春碧愛晴川。", "蜂蝶低窺酒，鳧鷖狎近船。", "平生五湖興，見此一欣然。"]'),
('55b01fe1-eec2-4fd8-b11b-5a0924092ffd','出郭','晁公遡','宋','宋诗','song-poetry','','[]','出郭花相引，尋荒草欲迷。',48,'全唐诗/poet.song.117000.json','["出郭花相引，尋荒草欲迷。", "綠低憐獨卧，紅缺見鶑啼。", "溪石皆堪坐，山醪亦偶携。", "淹留送落日，直過石城西。"]'),
('660a1e8b-3aef-4a55-bb16-924f1a9d653c','合江舟中作','晁公遡','宋','宋诗','song-poetry','','[]','雲氣昏江樹，春流沒釣磯。',48,'全唐诗/poet.song.117000.json','["雲氣昏江樹，春流沒釣磯。", "如何連夜漲，似欲送人歸。", "亂石水聲急，片帆風力微。", "舟師且停櫓，鷗鷺畏人飛。"]'),
('cc793437-bebf-4b98-a75f-29c9a70cbdd3','江雨','晁公遡','宋','宋诗','song-poetry','','[]','江草被霜槁，江雲隨雨飛。',48,'全唐诗/poet.song.117000.json','["江草被霜槁，江雲隨雨飛。", "稍看霑徑濕，故作映空微。", "曉浪初吹浦，春泥未污衣。", "南征羨鴻雁，獨有故鄉歸。"]'),
('83ce9625-c381-4cf1-8ca3-e75c790f52e4','出郊','晁公遡','宋','宋诗','song-poetry','','[]','寒江多石出，危岸有沙摧。',48,'全唐诗/poet.song.117000.json','["寒江多石出，危岸有沙摧。", "短綠行穿麥，高紅仰嗅梅。", "故人能共往，勝日可頻來。", "春事從茲始，羣花次第開。"]'),
('3c677521-865b-4533-ae2f-049065137170','小立','晁公遡','宋','宋诗','song-poetry','','[]','小立臨洲渚，徐行過野亭。',48,'全唐诗/poet.song.117000.json','["小立臨洲渚，徐行過野亭。", "頹沙江沸白，穿徑草分青。", "秩酒近無給，窮途真獨醒。", "春來慰羈放，幽絕頼郊坰。"]'),
('3fa66a90-fe1b-43db-afe1-1fd112a857bb','梅','晁公遡','宋','宋诗','song-poetry','','[]','微陽回孤根，霜雪破餘凜。',48,'全唐诗/poet.song.117000.json','["微陽回孤根，霜雪破餘凜。", "顔紅發春鮮，膚粟憐夜永。", "輕風送幽香，缺月散清影。", "寒烏忽飛來，伴此一枝冷。"]'),
('6356efb7-5527-4e19-9e57-9b826be6f9d0','中巖十八詠 慈姥巖','晁公遡','宋','宋诗','song-poetry','','[]','棲巖既下集，賓天復上征。',24,'全唐诗/poet.song.117000.json','["棲巖既下集，賓天復上征。", "八子似荀氏，中當有慈明。"]'),
('8f4a2b77-76cd-437b-8c7d-906410f9c265','中巖十八詠 羅漢洞','晁公遡','宋','宋诗','song-poetry','','[]','釋迦行中國，設教周孔同。',24,'全唐诗/poet.song.117000.json','["釋迦行中國，設教周孔同。", "吾知諸子弟，不殊闕里中。"]'),
('1f579f69-21c8-4ba6-ad65-51fc3cd41da2','中巖十八詠 喚魚潭','晁公遡','宋','宋诗','song-poetry','','[]','潭水清見底，老僧來喚魚。',24,'全唐诗/poet.song.117000.json','["潭水清見底，老僧來喚魚。", "與渠同法食，持鉢施齋餘。"]'),
('6f40e45a-7ff2-4dfa-818f-9f2205803b9b','中巖十八詠 寶瓶峯','晁公遡','宋','宋诗','song-poetry','','[]','誰將巾瓶來，置此几席間。',24,'全唐诗/poet.song.117000.json','["誰將巾瓶來，置此几席間。", "不可喚木𣔻，試往問溈山。"]'),
('1563d1f2-42bd-4d06-9b97-87eae612875a','中巖十八詠 虎頭峯','晁公遡','宋','宋诗','song-poetry','','[]','山靈亦自喜，尊者乃吾師。',24,'全唐诗/poet.song.117000.json','["山靈亦自喜，尊者乃吾師。", "得與鷲嶺並，不作虎頭癡。"]'),
('eb1ac9ac-0fee-4ab0-a956-59d4f4cca458','中巖十八詠 盤陀石','晁公遡','宋','宋诗','song-poetry','','[]','飛廉日掃除，預知尊者過。',24,'全唐诗/poet.song.117000.json','["飛廉日掃除，預知尊者過。", "不令有塵垢，污此石盤陀。"]'),
('60e7885b-209a-4ace-a75e-088ef32fac59','中巖十八詠 風穴','晁公遡','宋','宋诗','song-poetry','','[]','有風地鳴籟，無風石抱雲。',24,'全唐诗/poet.song.117000.json','["有風地鳴籟，無風石抱雲。", "上人如宴坐，不可墮聲聞。"]'),
('6eeb8b31-9efe-4426-9477-0b229b4d1c71','中巖十八詠 瀑布泉','晁公遡','宋','宋诗','song-poetry','','[]','濺沫響空谷，分流清法筵。',24,'全唐诗/poet.song.117000.json','["濺沫響空谷，分流清法筵。", "元因卓錫地，今爲洗鉢泉。"]'),
('fa67aaa5-d418-4e7e-acba-948e03875f44','中巖十八詠 望江亭','晁公遡','宋','宋诗','song-poetry','','[]','偶來俯滄波，遥見生白蘋。',24,'全唐诗/poet.song.117000.json','["偶來俯滄波，遥見生白蘋。", "望望不得上，笑彼涉江人。"]'),
('64ef310b-4acb-4fd9-9748-b33427097e90','中巖十八詠 玉泉亭','晁公遡','宋','宋诗','song-poetry','','[]','徘徊立泉上，誰敢酌寒清。',24,'全唐诗/poet.song.117000.json','["徘徊立泉上，誰敢酌寒清。", "莫解金鑿落，且聽玉琮琤。"]'),
('86a7f54e-07c0-4a52-b484-9f617dbf0b47','中巖十八詠 松風亭','晁公遡','宋','宋诗','song-poetry','','[]','皎皎石上月，颼颼松下風。',24,'全唐诗/poet.song.117000.json','["皎皎石上月，颼颼松下風。", "清絕誰領會，倚杖送飛鴻。"]'),
('fcbd8f8e-1736-4b06-9ee7-612f43206ce1','中巖十八詠 應現亭','晁公遡','宋','宋诗','song-poetry','','[]','松道須雨灑，山扉遣風開。',24,'全唐诗/poet.song.117000.json','["松道須雨灑，山扉遣風開。", "塵念自起滅，至人無去來。"]'),
('5914d45a-ad42-4dfa-b2c3-7390a4a44428','中巖十八詠 寒峯軒','晁公遡','宋','宋诗','song-poetry','','[]','崖陰日慘慘，石潤露漙漙。',24,'全唐诗/poet.song.117000.json','["崖陰日慘慘，石潤露漙漙。", "何似藍田下，高並玉山寒。"]'),
('acf6ecf8-3b8d-4e8f-944c-dd849b364b02','中巖十八詠 碧筠亭','晁公遡','宋','宋诗','song-poetry','','[]','蕭然一叢竹，何當舉似人。',24,'全唐诗/poet.song.117000.json','["蕭然一叢竹，何當舉似人。", "不可妄認此，青青爲法身。"]'),
('3f9f225a-77c9-412e-a75f-a04ff2a01da1','中巖十八詠 石筍庵','晁公遡','宋','宋诗','song-poetry','','[]','奇峯如立筍，太陰生古苔。',24,'全唐诗/poet.song.117000.json','["奇峯如立筍，太陰生古苔。", "誰能此出入，咄咄金石開。"]'),
('8d3c326f-080d-4f1f-96eb-a3f430ac33dc','中巖十八詠 壁軒','晁公遡','宋','宋诗','song-poetry','','[]','卷書置案上，默坐初不看。',24,'全唐诗/poet.song.117000.json','["卷書置案上，默坐初不看。", "侍者空堵立，湛然惟壁觀。"]'),
('7f555850-023f-40e0-b926-ffcd57f3cd04','中巖十八詠 止庵','晁公遡','宋','宋诗','song-poetry','','[]','智者有所說，後生誰究明。',24,'全唐诗/poet.song.117000.json','["智者有所說，後生誰究明。", "韋編具此眼，時止復時行。"]'),
('23d47717-d52e-410b-b703-0f832c2a97f3','中巖十八詠 西方閣','晁公遡','宋','宋诗','song-poetry','','[]','官失學四夷，寂寥洙泗濱。',24,'全唐诗/poet.song.117000.json','["官失學四夷，寂寥洙泗濱。", "至此每再拜，西方有聖人。"]'),
('4f5b73e0-0185-4317-baa7-50ef86bb6ef8','前恩陽尉周邦舉出予兄激仲所書其父竹軒記求詩因題二解  其一','晁公遡','宋','宋诗','song-poetry','','[]','眼看數竿今白頭，高標直節氣橫秋。',32,'全唐诗/poet.song.117000.json','["眼看數竿今白頭，高標直節氣橫秋。", "果能似此孤竹子，何羨渭川千畝侯。"]'),
('f68e2f8e-867b-49dd-8ac1-c30b17fa3a70','前恩陽尉周邦舉出予兄激仲所書其父竹軒記求詩因題二解  其二','晁公遡','宋','宋诗','song-poetry','','[]','俗士胸中數斛塵，此君偃蹇不相親。',32,'全唐诗/poet.song.117000.json','["俗士胸中數斛塵，此君偃蹇不相親。", "當年曾識子猷面，大令今來是故人。"]'),
('f7d45327-9f04-48b6-9823-ef4698bb867b','園中二首  其一','晁公遡','宋','宋诗','song-poetry','','[]','南北東西極目天，看天不比下牢關。',32,'全唐诗/poet.song.117000.json','["南北東西極目天，看天不比下牢關。", "遥知前面山尤遠，直到飛鴉滅沒間。"]'),
('8f219d3b-9101-44ca-8714-e03c28951f2c','園中二首  其二','晁公遡','宋','宋诗','song-poetry','','[]','眇眇周垣總路平，森森夏木已陰成。',32,'全唐诗/poet.song.117000.json','["眇眇周垣總路平，森森夏木已陰成。", "却疑身在華軒上，翠幄中間曳杖行。"]'),
('c60c37c8-ea6b-41bf-bfba-fd6945b5de09','用薛郎所寄示詩三韻  其一','晁公遡','宋','宋诗','song-poetry','','[]','子勿誚毛穎，渠言何使余。',48,'全唐诗/poet.song.117000.json','["子勿誚毛穎，渠言何使余。", "遥知生白室，誰助殺青書。", "巴墨漆相似，蜀牋霜不如。", "殷勤遣分寄，吾汝與同車。"]'),
('55b191be-8169-4f27-8637-69e8b2a71757','用薛郎所寄示詩三韻  其二','晁公遡','宋','宋诗','song-poetry','','[]','阿傳議酒食，察貳更廉空。',48,'全唐诗/poet.song.117000.json','["阿傳議酒食，察貳更廉空。", "開甕鴨頭綠，磨刀魚眼紅。", "報功他日在，食淡暫時同。", "富貴行自致，聖時無道窮。"]'),
('46b0f5a8-3fca-4415-96a2-fc39a5b92d5a','用薛郎所寄示詩三韻  其三','晁公遡','宋','宋诗','song-poetry','','[]','薛君昔在日，才可齒諸任。',48,'全唐诗/poet.song.117000.json','["薛君昔在日，才可齒諸任。", "繼世能傳業，爲文有嗣音。", "千秋當却老，六籍更鈎深。", "何以壽吾子，高才無陸沈。"]'),
('653cd11d-ed53-420c-bd13-7cdf79da9dc5','請緣老住持象耳山有詩次韻  其一','晁公遡','宋','宋诗','song-poetry','','[]','朦朧兩眼著玄花，認取空中起滅華。',32,'全唐诗/poet.song.117000.json','["朦朧兩眼著玄花，認取空中起滅華。", "我是官曹老龐藴，終無瞎棒與盲枷。"]'),
('43be2d63-bf08-4b2c-a331-f10bc944f367','請緣老住持象耳山有詩次韻  其二','晁公遡','宋','宋诗','song-poetry','','[]','中巖尊者幸同堂，浪走諸方有底忙。',32,'全唐诗/poet.song.117000.json','["中巖尊者幸同堂，浪走諸方有底忙。", "若道渠儂棒可畏，新羅未過合思量。"]'),
('f94030bc-6202-43b5-97ef-eb686a867541','送王章赴長寧通判','晁公遡','宋','宋诗','song-poetry','','[]','仰事各黄髮，今爲閭里榮。',48,'全唐诗/poet.song.117000.json','["仰事各黄髮，今爲閭里榮。", "共看朱紱貴，更益綵衣明。", "泥軾幸小駐，羽觴當緩行。", "期君如石建，烜赫漢西京。"]'),
('20b4a561-fdb9-407d-96d2-18c7d6f94d31','次楊國材韻  其一','晁公遡','宋','宋诗','song-poetry','','[]','形模豈稱侍承明，不願簫韶聽九成。',32,'全唐诗/poet.song.117000.json','["形模豈稱侍承明，不願簫韶聽九成。", "但願豐年有高廩，千夫穫稻看秋晴。"]'),
('c568115d-5dd9-47f7-a0e9-46e4cf972785','次楊國材韻  其二','晁公遡','宋','宋诗','song-poetry','','[]','耆年何在隠牆東，常樂簞瓢陋巷中。',32,'全唐诗/poet.song.117000.json','["耆年何在隠牆東，常樂簞瓢陋巷中。", "白首可無知所自，宜歌帝力頌天功。"]'),
('130d7a69-cf31-4bff-8084-4af8e663df96','師廷珍以詩見惠因用其韻  其一','晁公遡','宋','宋诗','song-poetry','','[]','欲平靺鞨與堅昆，下詔旁求闢四門。',32,'全唐诗/poet.song.117000.json','["欲平靺鞨與堅昆，下詔旁求闢四門。", "吾子莫孤明主意，建隆開國聖雲孫。"]'),
('1a797afa-6356-4845-97a9-42e5b2bb7af1','師廷珍以詩見惠因用其韻  其二','晁公遡','宋','宋诗','song-poetry','','[]','蒼苔半蝕蔡邕碑，今日中郎有女歸。',32,'全唐诗/poet.song.117000.json','["蒼苔半蝕蔡邕碑，今日中郎有女歸。", "莫怪昏昏暗丘壟，浮雲淚濕不能飛。"]'),
('e5d9c46f-0c87-47d8-a6e8-0d9bdc8d2fa2','師廷珍以詩見惠因用其韻  其三','晁公遡','宋','宋诗','song-poetry','','[]','詩禮初聞衛尉旁，起家期擅蜀文章。',32,'全唐诗/poet.song.117000.json','["詩禮初聞衛尉旁，起家期擅蜀文章。", "快吟芍藥當階句，剩看芙蓉別殿香。"]'),
('4d407817-2943-4a5e-96e0-8ee38b884c41','王元才甥見過其弟元濟甥繼來有詩次韻','晁公遡','宋','宋诗','song-poetry','','[]','把酒悲歌望蜀天，感今懷昔重悽然。',64,'全唐诗/poet.song.117000.json','["把酒悲歌望蜀天，感今懷昔重悽然。", "道堅或謂如無忌，靈運還欣對阿連。", "他日鵬應自鵾化，此生蚿豈待夔憐。", "筆鋒剩淬猶錐利，明歲文場破兩甄。"]'),
('0545039b-53a9-4b66-bb5b-de7a004c5c22','宇文紹恭所藏其父德聞手書其祖家訓一卷','晁公遡','宋','宋诗','song-poetry','','[]','蜀士相與語，故家誰得如。',24,'全唐诗/poet.song.117000.json','["蜀士相與語，故家誰得如。", "千年令威宅，一紙伏波書。"]'),
('6330d0ef-950c-4273-99ad-87f4ecb6a6f6','曉望','晁公遡','宋','宋诗','song-poetry','','[]','城上高樓出女牆，遥看初日尚蒼凉。',64,'全唐诗/poet.song.117000.json','["城上高樓出女牆，遥看初日尚蒼凉。", "松邊淅瀝風成響，草際晶熒露有光。", "樂歲共歌羊考牧，新春不與雁還鄉。", "聖時願報收輿地，快自襄陽下洛陽。"]'),
('484fec92-9f7d-4869-a8ca-a13b87e0d67d','李士舉見寄次韻爲謝二首  其一','晁公遡','宋','宋诗','song-poetry','','[]','忽鼓硤中櫂，來從渝上城。',48,'全唐诗/poet.song.117000.json','["忽鼓硤中櫂，來從渝上城。", "何爲向南畝，本合侍西清。", "樹色行相引，灘聲鳴不平。", "青城有仙伯，往矣授長生。"]'),
('2ab5673f-0a7e-43a9-aa78-6862a890082a','李士舉見寄次韻爲謝二首  其二','晁公遡','宋','宋诗','song-poetry','','[]','想見山靈喜，如看柱史來。',48,'全唐诗/poet.song.117000.json','["想見山靈喜，如看柱史來。", "江清無急硤，野潤失飛埃。", "行攬孟博轡，再然安國灰。", "相過忍遽別，莫放錦帆開。"]'),
('cbbd387f-fc99-4963-90fa-72698067a0f6','師伯渾以詩告別次韻','晁公遡','宋','宋诗','song-poetry','','[]','閒居何不樂，非願世兼收。',96,'全唐诗/poet.song.117000.json','["閒居何不樂，非願世兼收。", "利乃庶人意，道惟君子憂。", "野花開北陌，官酒酌東樓。", "故里有書至，應言無久留。", "此去即鄉黨，子寧無友生。", "不堪今日別，真見故人情。", "杯覆葵花小，尊傾竹葉清。", "送行須盡醉，兼爲破愁城。"]'),
('e4d8797d-3ae2-4870-8b59-40fd78381cf7','楊復先寄荔子仍和予昨所贈二詩因次韻  其一','晁公遡','宋','宋诗','song-poetry','','[]','林間熟丹實，葉底綴紅雲。',48,'全唐诗/poet.song.117000.json','["林間熟丹實，葉底綴紅雲。", "並舍皆好事，絕甘能勸分。", "扣門知使至，登俎覺香聞。", "更與詩爭麗，紛披錦繡文。"]'),
('ec300c86-ed91-4226-a866-499b187210cb','楊復先寄荔子仍和予昨所贈二詩因次韻  其二','晁公遡','宋','宋诗','song-poetry','','[]','嘉果喜三嗅，名園思一游。',48,'全唐诗/poet.song.117000.json','["嘉果喜三嗅，名園思一游。", "駢頭丹殻皺，繞指玉漿流。", "味壓乾𦠆子，韻高蕭灑侯。", "安居日啗此，邊堠幸兵休。"]'),
('e71551f3-b58c-415d-af7f-a4a9fa398bf9','楊復先寄荔子仍和予昨所贈二詩因次韻  其三','晁公遡','宋','宋诗','song-poetry','','[]','遥想載酒客，時來從子雲。',48,'全唐诗/poet.song.117000.json','["遥想載酒客，時來從子雲。", "山高去天咫，日永惜陰分。", "秋稼田畝接，夏弦閭里聞。", "草堂無數出，猿鶴有移文。"]'),
('63560868-b905-4eb1-9d4c-04455f1728b6','楊復先寄荔子仍和予昨所贈二詩因次韻  其四','晁公遡','宋','宋诗','song-poetry','','[]','野色正如此，廢書時出游。',48,'全唐诗/poet.song.117000.json','["野色正如此，廢書時出游。", "山吞落日盡，硤束大江流。", "俗駕謝逋客，郊居如隠侯。", "愛君吐佳句，落紙不能休。"]'),
('14a68107-0c19-4abe-ab4c-90dd83e13f80','書齋','晁公遡','宋','宋诗','song-poetry','','[]','廷尉已執天下平，更出一節令循行。',64,'全唐诗/poet.song.117000.json','["廷尉已執天下平，更出一節令循行。", "時清斷獄歲大減，小臣何功君聖明。", "紙窗風破夜自語，瓦溝雨來寒有聲。", "官閒無事但宴坐，滿室惟對書縱橫。"]'),
('173c4dd7-4717-4a1d-87a1-5574d3829f8f','離南平','晁公遡','宋','宋诗','song-poetry','','[]','晨光慘慘雜微霄，寒水濺濺更斷橋。',64,'全唐诗/poet.song.117000.json','["晨光慘慘雜微霄，寒水濺濺更斷橋。", "風隕栗房開紫玉，煙蒙蘿幄疊青綃。", "官曹已畢三年考，客路深嗟萬里遥。", "從此揚舲下巴硤，新年當及未央朝。"]'),
('59320c9e-9457-4a2e-b2a4-cdb8956732b3','西山','晁公遡','宋','宋诗','song-poetry','','[]','萬州城西何所有，高山其下俯寒塘。',64,'全唐诗/poet.song.117000.json','["萬州城西何所有，高山其下俯寒塘。", "浮鷗藉草溪沙暖，飛鳥衝花野樹香。", "他日擬從南岳隠，平生尤愛北窗凉。", "道人爲我收松子，剩種清陰十畝長。"]'),
('51b482f1-0483-4ee8-afd3-2cf852c9f7ac','至日留滯荆渚同鄧氏兄弟飲酒','晁公遡','宋','宋诗','song-poetry','','[]','今日當長至，窮年尚遠行。',48,'全唐诗/poet.song.117000.json','["今日當長至，窮年尚遠行。", "野晴春草細，江晚夕陽明。", "衰病依僮僕，經過得友生。", "濁醪來近市，堅坐且徐傾。"]'),
('ef70bc16-72c6-483e-82f2-96bd6ae9df83','行李','晁公遡','宋','宋诗','song-poetry','','[]','路出蒼江上，雲生亂石間。',48,'全唐诗/poet.song.117000.json','["路出蒼江上，雲生亂石間。", "中年幸强健，今日試躋攀。", "湍硤寒鳴地，頹陽暮隠山。", "僕夫問行李，早晚遂東還。"]'),
('1da3aed0-1c1f-491c-a448-3af3a140a9ac','硤內','晁公遡','宋','宋诗','song-poetry','','[]','硤內收多雨，沙邊慘積陰。',48,'全唐诗/poet.song.117000.json','["硤內收多雨，沙邊慘積陰。", "龍吟殷地遠，虹飲入江深。", "不作山林去，非憂荆棘侵。", "經年困奔走，無力更登臨。"]'),
('4cdbba7a-5b1a-4259-a1f5-93592958109e','聞笛','晁公遡','宋','宋诗','song-poetry','','[]','落日卧郿塢，忽聞吹笛聲。',48,'全唐诗/poet.song.117000.json','["落日卧郿塢，忽聞吹笛聲。", "天清孤鶴唳，江浄蟄龍鳴。", "谷響風時下，山高月未生。", "誰能永今夕，呼酒與同傾。"]'),
('09880523-3db8-4486-81b5-042cd6776113','掃徑','晁公遡','宋','宋诗','song-poetry','','[]','掃徑通春屐，開林啟夕扉。',48,'全唐诗/poet.song.117000.json','["掃徑通春屐，開林啟夕扉。", "浮鷗避人去，輕燕引雛飛。", "尊俎深留客，風塵漸息機。", "不妨坐至晚，少待月同歸。"]'),
('3852bc25-b64c-4b62-bb65-e8ce2786b4a2','山行','晁公遡','宋','宋诗','song-poetry','','[]','白沙素石浄無泥，橘刺藤梢已不迷。',64,'全唐诗/poet.song.117000.json','["白沙素石浄無泥，橘刺藤梢已不迷。", "牛放遠山連鴈鶩，蛙鳴廢沼下鳧鷖。", "終年去國空彈鋏，盡日看雲且杖藜。", "久客諸侯成底事，幸逢寬政免推擠。"]'),
('a5f6229b-362a-48b2-b841-6da1b897c3f2','江邊  其一','晁公遡','宋','宋诗','song-poetry','','[]','素石寒沙共眇然，荒城古木暮雲懸。',64,'全唐诗/poet.song.117000.json','["素石寒沙共眇然，荒城古木暮雲懸。", "空山靜答鐘聲遠，落日晴隨樹影圓。", "屢報傳烽沈塞外，時來倚杖立江邊。", "東南耆舊今安否，欲寄新詩誰爲傳。"]'),
('d0eaf9e3-76dd-458f-9520-6f45d5fc9a8d','江邊  其二','晁公遡','宋','宋诗','song-poetry','','[]','江邊日日强登臺，越柁吳檣久不來。',64,'全唐诗/poet.song.117000.json','["江邊日日强登臺，越柁吳檣久不來。", "投迹東巴留萬里，側身南極望三台。", "公朝遣使丁年去，丞相疏恩甲第開。", "聖主得賢如作頌，微臣愧乏子淵才。"]'),
('c64faf28-5093-47ee-876e-f46dbdbc9551','郊外','晁公遡','宋','宋诗','song-poetry','','[]','草盡春泥綠，花乘晚照明。',48,'全唐诗/poet.song.117000.json','["草盡春泥綠，花乘晚照明。", "遥山先暝色，平野易風聲。", "歸沐休形役，深居感物情。", "據鞍聊一出，佳處得徐行。"]'),
('36b101cc-e736-4903-ab43-a83e6d5a5fff','春畦','晁公遡','宋','宋诗','song-poetry','','[]','水滿春畦白，雲連晚照黄。',48,'全唐诗/poet.song.117000.json','["水滿春畦白，雲連晚照黄。", "野花時結子，溪柳不成行。", "客禮容吾懶，酣歌與世忘。", "晚來得新句，吟罷立蒼茫。"]'),
('ae8f9fcd-cd6a-48c7-9a2d-ab6c669ba308','漢川','晁公遡','宋','宋诗','song-poetry','','[]','道路通襄野，風煙近楚天。',48,'全唐诗/poet.song.117000.json','["道路通襄野，風煙近楚天。", "地卑荒巨澤，山斷見平川。", "舟楫自此去，音書誰與傳。", "西南是巴峽，應盡落霞邊。"]'),
('54d61456-8312-4ccd-9b49-c1b2ce07e711','大冶縣見梅','晁公遡','宋','宋诗','song-poetry','','[]','客裏逢春色，江梅發故枝。',48,'全唐诗/poet.song.117000.json','["客裏逢春色，江梅發故枝。", "正應傷老大，似欲慰棲遲。", "雪樹真相引，風花莫倒吹。", "南來愧何遜，吾病不能詩。"]'),
('1564def0-e3d1-4334-801a-ad6762bcc66c','正月二日至九江過陳漢卿','晁公遡','宋','宋诗','song-poetry','','[]','行路傷徂歲，思家佇遠情。',48,'全唐诗/poet.song.117000.json','["行路傷徂歲，思家佇遠情。", "雲迷五尺道，春動九江城。", "耆舊無元亮，交游得仲卿。", "尊前見芳草，已似喚愁生。"]'),
('ad3827e0-429e-4af8-ab83-c3a94f17a832','夜','晁公遡','宋','宋诗','song-poetry','','[]','樹合春城暗，江鳴夜硤喧。',48,'全唐诗/poet.song.117000.json','["樹合春城暗，江鳴夜硤喧。", "艱難猶此地，漂泊更何言。", "冉冉輕煙集，輝輝列宿繁。", "巡簷望南斗，無路入脩門。"]'),
('a56a3245-4c33-4b6f-be41-0bbb92b496e7','官舍','晁公遡','宋','宋诗','song-poetry','','[]','雨徑蒼苔滑，風簾翠篠斜。',48,'全唐诗/poet.song.117000.json','["雨徑蒼苔滑，風簾翠篠斜。", "邑居藏萬室，驛道接三巴。", "曉堞調清角，春庭放早衙。", "歸休幸無事，隨意酌流霞。"]'),
('add4b6ed-11d4-4759-8a20-2bf0a69c40d3','晴野','晁公遡','宋','宋诗','song-poetry','','[]','草色熏晴野，溪痕上白沙。',48,'全唐诗/poet.song.117000.json','["草色熏晴野，溪痕上白沙。", "鳴鳩行哺子，晚樹續開花。", "多事真堪厭，浮生每自嗟。", "坐來歸興動，城郭欲吹笳。"]'),
('8252ecbf-919a-4cc2-9dbf-c6bedf0d3d51','偶作','晁公遡','宋','宋诗','song-poetry','','[]','官居復何有，幽事亦堪誇。',48,'全唐诗/poet.song.117000.json','["官居復何有，幽事亦堪誇。", "高樹行春蔓，疎篁上晚花。", "常年皆作客，隨地即爲家。", "尚想關山路，傷心故國賒。"]'),
('e83cae70-a558-4ee7-9308-e63fe5ec33da','雨中過祁門十里不能進宿旅次','晁公遡','宋','宋诗','song-poetry','','[]','今日祁門縣，衝泥怯遠行。',48,'全唐诗/poet.song.117000.json','["今日祁門縣，衝泥怯遠行。", "含風雲葉細，間雨雪花輕。", "溪晚白鷗下，草寒黄犢鳴。", "吾今更何往，漂泊愧平生。"]'),
('102ae344-ed12-4aa8-8369-eab86a90ef3b','旅宿','晁公遡','宋','宋诗','song-poetry','','[]','漠漠硤雲亂，冥冥汀露微。',48,'全唐诗/poet.song.117000.json','["漠漠硤雲亂，冥冥汀露微。", "鴉喧得食喜，鷗近畏人飛。", "旅宿天涯滯，心期歲暮違。", "滄江聞已漲，似欲勸吾歸。"]'),
('611c0376-d8be-49a1-bb05-0749268f46ae','歲暮','晁公遡','宋','宋诗','song-poetry','','[]','晴峽開寒祲，滄波逗遠光。',48,'全唐诗/poet.song.117000.json','["晴峽開寒祲，滄波逗遠光。", "年華已衰謝，春意尚微茫。", "久污功曹掾，終慙謁者郎。", "南方誠瘴癘，經月或無霜。"]'),
('ddd7a668-1ff6-41e5-b287-2b905a0756f3','沙寒','晁公遡','宋','宋诗','song-poetry','','[]','沙寒兼白石，瀼斷入青溪。',48,'全唐诗/poet.song.117000.json','["沙寒兼白石，瀼斷入青溪。", "硤霧連山暗，江雲出水低。", "遠游殊俗倦，歸路故鄉迷。", "日落荒原上，城烏已復啼。"]'),
('20c7700b-855f-4a38-a74a-eb339c177cb6','江流','晁公遡','宋','宋诗','song-poetry','','[]','江流日日上平蕪，細徑侵沙漸欲無。',64,'全唐诗/poet.song.117000.json','["江流日日上平蕪，細徑侵沙漸欲無。", "嫋嫋紫苞開露筍，森森青節亂風蒲。", "晴川默數千艘過，深硤遥看一水趨。", "傳道南檣有歸使，晚來失喜問揚都。"]'),
('28c87d9a-8f74-45d4-9812-5ca58900ce6f','偶成','晁公遡','宋','宋诗','song-poetry','','[]','離離樹影曉仍疎，寂寂禽聲暖自呼。',64,'全唐诗/poet.song.117000.json','["離離樹影曉仍疎，寂寂禽聲暖自呼。", "雨垤蓄粻來聚蟻，風簷壞網落懸蛛。", "十年空誦歸田賦，萬里試披輿地圖。", "老向人間定何許，只今湖海更南隅。"]'),
('4ba9076d-a74d-40cb-9b71-8c6749474e8c','李仁甫將至郭下以詩迎之','晁公遡','宋','宋诗','song-poetry','','[]','公館可休舍，良宵宜對床。',48,'全唐诗/poet.song.117000.json','["公館可休舍，良宵宜對床。", "肯汙白雲屨，來過碧瀾堂。", "置饌同三飯，開筵累十觴。", "凉秋當泛菊，小住擷微芳。"]'),
('eabb9260-3a60-4a02-a363-966784865ae7','次韻李仁甫','晁公遡','宋','宋诗','song-poetry','','[]','北牖厭高卧，西山思勝游。',48,'全唐诗/poet.song.117000.json','["北牖厭高卧，西山思勝游。", "詩人少題詠，物色盡分留。", "小憩青城夜，幽尋丹景秋。", "何人與同往，二老實風流。"]'),
('085c36b1-7b60-4d22-8fcd-3c5d93fd148f','中原','晁公遡','宋','宋诗','song-poetry','','[]','中原北望連虎牢，遺老畧皆死草茅。',64,'全唐诗/poet.song.117000.json','["中原北望連虎牢，遺老畧皆死草茅。", "腥臊千秋萬歲殿，塵埃四通五達郊。", "無人雄心肯出塞，何日戰骨與封崤。", "三軍歲歲費供給，但聞邊庭峙芻茭。"]'),
('73725e7c-43a3-4881-8a36-eb12c67079cc','節往','晁公遡','宋','宋诗','song-poetry','','[]','節往天始肅，地炎霜尚微。',48,'全唐诗/poet.song.117000.json','["節往天始肅，地炎霜尚微。", "靜聞木葉下，晴見荻花飛。", "積水蛤猶吠，並隣雞正肥。", "孤雲吾所羨，獨有故山歸。"]'),
('34d2b962-cf46-433e-97df-7022a8a06272','石判官惠詩用韻爲謝','晁公遡','宋','宋诗','song-poetry','','[]','吾宗衰謝尚斯文，長抱遺經教子孫。',64,'全唐诗/poet.song.117000.json','["吾宗衰謝尚斯文，長抱遺經教子孫。", "海內世家慚衛史，壁中編簡即齊論。", "交游幸得二三子，毀譽當如六四坤。", "肯爲清談飲一石，絕勝雜坐獨留髠。"]'),
('88c1129b-0db2-485a-9a3a-6054aa709f11','簡任季明府判','晁公遡','宋','宋诗','song-poetry','','[]','昔別嗟何往，今晨問始知。',48,'全唐诗/poet.song.117000.json','["昔別嗟何往，今晨問始知。", "茲爲泛舟役，端若赴襟期。", "夜雨霑桃葉，春風在柳枝。", "相逢不同醉，辜負豔陽時。"]'),
('3026c66d-d7cc-4eb5-be74-92ff4fac562b','遶樹','晁公遡','宋','宋诗','song-poetry','','[]','遶樹行百匝，臨池把一杯。',48,'全唐诗/poet.song.117000.json','["遶樹行百匝，臨池把一杯。", "白知茶蕊上，紅對燭花開。", "已作尋芳去，何辭盡夜回。", "惡風無藉在，明日滿蒼苔。"]'),
('093df05c-57a1-41bb-8144-1ddb45f699f0','游園','晁公遡','宋','宋诗','song-poetry','','[]','林陰忽忽已藏鴉，作急尋芳賞歲華。',64,'全唐诗/poet.song.117000.json','["林陰忽忽已藏鴉，作急尋芳賞歲華。", "尊每不空緣好客，席無何鄉爲隨花。", "開新合故從衣薄，度密穿深信帽斜。", "儻有歸休五畝宅，老夫著處便爲家。"]'),
('d6806a5f-4c24-4ec4-937c-3ad4d58affe6','他鄉','晁公遡','宋','宋诗','song-poetry','','[]','故國山川安在哉，他鄉今復見春來。',64,'全唐诗/poet.song.117000.json','["故國山川安在哉，他鄉今復見春來。", "蓬蒿並興草益茂，桃李不言花自開。", "催促年華似推轂，較量筋力試登臺。", "歸田尚可扶犁在，明歲當驅俗駕回。"]'),
('5fc78107-4613-427a-9f34-72754b2707bc','與官屬往江上觀淘江','晁公遡','宋','宋诗','song-poetry','','[]','郊原漸看薺麥繁，塵沙遠著榆柳昏。',64,'全唐诗/poet.song.117000.json','["郊原漸看薺麥繁，塵沙遠著榆柳昏。", "花光照眼暖自醉，江聲入耳清不煩。", "縣官作堨相地利，邦人防城釃水源。", "我將載酒勞掾史，酌言酬之兩山尊。"]'),
('d7549855-9e3a-4110-a5ff-9b556684e77d','丙戌元夕','晁公遡','宋','宋诗','song-poetry','','[]','刺史敢云樂，今非耆舊初。',48,'全唐诗/poet.song.117000.json','["刺史敢云樂，今非耆舊初。", "香醪秋露薄，膏火曉星疎。", "豈止君不足，誰能財有餘。", "近聞寬賦歛，明詔議虧除。"]'),
('14e092b3-25d3-4fa1-bf92-2fae86f6a52d','看花','晁公遡','宋','宋诗','song-poetry','','[]','春到人間得幾時，可堪鵯鳷趣春歸。',32,'全唐诗/poet.song.117000.json','["春到人間得幾時，可堪鵯鳷趣春歸。", "不辭日去千回看，便恐風飄萬點飛。"]'),
('ca2d9011-f00d-4ff3-870f-c5f1cdf8a537','布穀','晁公遡','宋','宋诗','song-poetry','','[]','南村北村布穀鳴，家家隴頭催出耕。',32,'全唐诗/poet.song.117000.json','["南村北村布穀鳴，家家隴頭催出耕。", "道逢田父喜相語，四十三箇春水生。"]'),
('f4d29b25-1545-42d2-808b-4ea31677b70d','視通濟堰二首  其一','晁公遡','宋','宋诗','song-poetry','','[]','野樹皆綠葉，清江初白蘋。',48,'全唐诗/poet.song.117000.json','["野樹皆綠葉，清江初白蘋。", "偶來無筮日，小出當行春。", "人頌勾龍社，恩沾佩犢民。", "橫江三百丈，遥見石嶙峋。"]'),
('60713f6b-4d7d-4c5d-93bd-41f4ad8699b0','視通濟堰二首  其二','晁公遡','宋','宋诗','song-poetry','','[]','往年初堰壞，樂歲亦民饑。',48,'全唐诗/poet.song.117000.json','["往年初堰壞，樂歲亦民饑。", "再見龍尾水，如興鴻却陂。", "名同召伯埭，人立許楊祠。", "祝史有祀事，歌予迎送詩。"]'),
('2447292d-6343-446d-8572-6aa8713a670c','細雨','晁公遡','宋','宋诗','song-poetry','','[]','細雨真宜麥，輕陰似養花。',48,'全唐诗/poet.song.117000.json','["細雨真宜麥，輕陰似養花。", "人烟隨土斷，村徑逐溪斜。", "大道能方軌，春泥欲濺車。", "歸來洗鞾袴，城郭未吹笳。"]'),
('2422c120-1735-474f-90f7-fe611ac9f7ad','新津道中','晁公遡','宋','宋诗','song-poetry','','[]','野綠平如案，松青潤更加。',48,'全唐诗/poet.song.117000.json','["野綠平如案，松青潤更加。", "兩岐惟有麥，一縣已無花。", "日色深迷霧，江流淺見沙。", "平生愛春事，忽復過年華。"]'),
('0f2c2fb2-b02b-4493-8a73-057333746e77','郡縣','晁公遡','宋','宋诗','song-poetry','','[]','郡縣紛紛數代更，循良少似漢西京。',64,'全唐诗/poet.song.117000.json','["郡縣紛紛數代更，循良少似漢西京。", "未聞子産能寬服，誰見翁歸有急名。", "所望家無空杼柚，常令天不害粢盛。", "打門不怕催科吏，願與君王竭地征。"]'),
('b1601432-8442-4754-91cd-c380155924a0','修覺寺','晁公遡','宋','宋诗','song-poetry','','[]','山遶象耳北，堰橫龍爪西。',48,'全唐诗/poet.song.117000.json','["山遶象耳北，堰橫龍爪西。", "遥瞻蜀玉壘，不減漢金堤。", "未合三江水，仍通百社溪。", "春流已可愛，散亂浴鳧鷖。"]'),
('19a800eb-7d61-470e-94f2-b3279e417603','池上與師伯渾飲酒','晁公遡','宋','宋诗','song-poetry','','[]','冉冉煙生樹，溶溶水滿池。',48,'全唐诗/poet.song.117000.json','["冉冉煙生樹，溶溶水滿池。", "藻寒魚不食，花暖蝶先知。", "相對飲鑿落，不妨歌接䍦。", "還山何用遽，同過艷陽時。"]'),
('b0547002-6857-42d3-abed-bc936e5a3476','寄李悅夫時監成都軍資庫茶馬司檄兼僚屬聞近治胥吏數輩','晁公遡','宋','宋诗','song-poetry','','[]','賓筵聊可樂，筦庫亦何勞。',48,'全唐诗/poet.song.117000.json','["賓筵聊可樂，筦庫亦何勞。", "近已尸鼠輩，果能清馬曹。", "晴郊堪挈榼，春事助揮毫。", "借問浣花水，只今深幾篙。"]'),
('2f7e4e48-108c-451c-9bd4-de1136314f5b','恭州報恩長老宣公以四偈見別用韻爲謝  其一','晁公遡','宋','宋诗','song-poetry','','[]','再到叢林得我驚，斬新花果自然成。',32,'全唐诗/poet.song.117000.json','["再到叢林得我驚，斬新花果自然成。", "種田更有僧祇戶，乞食何如舍衛城。"]'),
('631748d0-c37f-43d1-aa42-19961b6884f1','恭州報恩長老宣公以四偈見別用韻爲謝  其二','晁公遡','宋','宋诗','song-poetry','','[]','甑中炊米釜烹鮮，莫道巴兒不解禪。',32,'全唐诗/poet.song.117000.json','["甑中炊米釜烹鮮，莫道巴兒不解禪。", "日日扣門來乞火，箇中已有一燈傳。"]'),
('25708072-a80e-42d0-9b1f-2ee60390cc84','恭州報恩長老宣公以四偈見別用韻爲謝  其三','晁公遡','宋','宋诗','song-poetry','','[]','大地八風初不動，老夫自駕鐵船行。',32,'全唐诗/poet.song.117000.json','["大地八風初不動，老夫自駕鐵船行。", "莫憂船上不知曉，元有木雞來報更。"]'),
('ed432228-be61-429b-a86b-555a549c627e','恭州報恩長老宣公以四偈見別用韻爲謝  其四','晁公遡','宋','宋诗','song-poetry','','[]','海頭已白藏頭黑，老去心情總不堪。',32,'全唐诗/poet.song.117000.json','["海頭已白藏頭黑，老去心情總不堪。", "請唱德山歌一曲，却能打鼓似關南。"]'),
('612fb608-9028-44f6-8a52-6c339a1cc9cf','次韻杜主簿','晁公遡','宋','宋诗','song-poetry','','[]','平生有志欲歸休，老向殊方尚轉流。',64,'全唐诗/poet.song.117000.json','["平生有志欲歸休，老向殊方尚轉流。", "五畝桑今如卜宅，千章荻可比封侯。", "幾經峽口江水夜，往看峨眉山月秋。", "終恐官曹敗人意，不如一笠釣滄洲。"]'),
('84b2fc85-c05d-48a5-a167-7e5333bead4a','喜簡元輔兄二首  其一','晁公遡','宋','宋诗','song-poetry','','[]','元有不病者，君無嗟遽衰。',48,'全唐诗/poet.song.117000.json','["元有不病者，君無嗟遽衰。", "閉門謝餘子，扶杖看清時。", "野樹著花早，春江生浪遲。", "相過忍輕別，小立爲題詩。"]'),
('c07da9c5-0698-4049-955b-68b3f8bc75ab','喜簡元輔兄二首  其二','晁公遡','宋','宋诗','song-poetry','','[]','息女有所託，衰懷寬老翁。',48,'全唐诗/poet.song.117000.json','["息女有所託，衰懷寬老翁。", "通家猶孔氏，得婿似權公。", "奕世姻婭在，平生憂患同。", "追思九原友，宰木亦悲風。"]'),
('3070c548-6feb-4ef0-85e1-521f26e03688','白宋瑞','晁公遡','宋','宋诗','song-poetry','','[]','聖主思獻納，諸公專討論。',48,'全唐诗/poet.song.117000.json','["聖主思獻納，諸公專討論。", "吾生端有命，此去勿多言。", "往泛碧萬頃，歸來朱兩轓。", "江湖自可樂，不必上龍門。"]'),
('247ed3b3-a99e-4c08-9ef2-c49434910373','次師瓌韻','晁公遡','宋','宋诗','song-poetry','','[]','邇來才力愈衰遲，說向諸公笑脫頤。',64,'全唐诗/poet.song.117000.json','["邇來才力愈衰遲，說向諸公笑脫頤。", "來對老夫何所見，歸求文字有餘師。", "相期要作後彫柏，自獻當同前列龜。", "莫學一官今潦倒，白頭深愧伐檀詩。"]'),
('7c439107-aadf-4707-882d-726eeb8bcc7e','與客飲池上','晁公遡','宋','宋诗','song-poetry','','[]','脫畧簿書外，按行池籞中。',48,'全唐诗/poet.song.117000.json','["脫畧簿書外，按行池籞中。", "筍長風解碧，蓮浄雨欹紅。", "佳客常契濶，良宵難會同。", "巾車幸過我，取別莫匆匆。"]'),
('d97bf54f-674d-421b-8e3b-0763aa30a10a','次劉機將仕韻','晁公遡','宋','宋诗','song-poetry','','[]','承平玉燭四時和，處處惟聞擊壤歌。',64,'全唐诗/poet.song.117000.json','["承平玉燭四時和，處處惟聞擊壤歌。", "富國不須搜粟尉，勸民當應力田科。", "使君身似社樗老，故里賢如喬木多。", "今日九原誠可作，吾誰歸者有東坡。"]'),
('c92b3489-193c-4a33-8726-2d7364aee20f','六月八日雷雨大作喜呈張仲季孟','晁公遡','宋','宋诗','song-poetry','','[]','雲霧相纏暝不開，披衣衝雨獨登臺。',64,'全唐诗/poet.song.117000.json','["雲霧相纏暝不開，披衣衝雨獨登臺。", "風號曠野吹江立，雷擘蒼山震地來。", "從使郊原昏白晝，剩教草木洗黄埃。", "夜凉如此真堪飲，喜折圓荷作酒杯。"]'),
('bb3d07e7-5c9a-4679-9d55-291b019da52f','送李敞逆婦敘州乃予友悅夫之子也','晁公遡','宋','宋诗','song-poetry','','[]','初戲塗鴉壁，今升奠雁堂。',48,'全唐诗/poet.song.117000.json','["初戲塗鴉壁，今升奠雁堂。", "真堪當寢醮，已共乃翁長。", "歲月良易得，詩書宜自强。", "他時再相見，兒女即成行。"]'),
('d85d57b8-686f-4d3b-a8c6-664f0452881c','啗荔子戲作','晁公遡','宋','宋诗','song-poetry','','[]','已覺香皮腥染乾，漸憂熟顆鳥銜殘。',32,'全唐诗/poet.song.117000.json','["已覺香皮腥染乾，漸憂熟顆鳥銜殘。", "高攀上帝紅雲朵，笑撮仙人白玉丹。"]'),
('05516366-ec97-4116-a7e5-a4aaf64f83bb','寄瀘南子止兄','晁公遡','宋','宋诗','song-poetry','','[]','杖鉞知何處，看雲望欲迷。',48,'全唐诗/poet.song.117000.json','["杖鉞知何處，看雲望欲迷。", "真同阮南北，各寄蜀東西。", "峽嶮水增急，樓高山爲低。", "春來日行樂，桃李想成蹊。"]'),
('be2a4feb-04f5-4926-8118-b0a863c7e230','呂子山楊廷仲廷試歸','晁公遡','宋','宋诗','song-poetry','','[]','布席三峨見，升堂二妙來。',48,'全唐诗/poet.song.117000.json','["布席三峨見，升堂二妙來。", "端須置尊酒，一爲洗塵埃。", "翔雪吳江渡，薰風漢殿開。", "往還雖萬里，親得到蓬萊。"]'),
('290a2d1e-2d83-4cf6-81bc-1fef7de7e7f4','謝人惠生日詩二絕  其一','晁公遡','宋','宋诗','song-poetry','','[]','本將豪句慰衰遲，開卷寧知起我悲。',32,'全唐诗/poet.song.117000.json','["本將豪句慰衰遲，開卷寧知起我悲。", "獨對春風揮老淚，如聞人誦蓼莪詩。"]'),
('25af5574-23e3-44d5-b2c8-f3df7f5a9d47','謝人惠生日詩二絕  其二','晁公遡','宋','宋诗','song-poetry','','[]','壽我新詩意甚勤，此難專享要平分。',32,'全唐诗/poet.song.117000.json','["壽我新詩意甚勤，此難專享要平分。", "願從薊子摩銅狄，可謝蘇公贈鐵君。"]'),
('e06d7ee9-5cfc-4ce5-9214-6755dfbae646','夏夜','晁公遡','宋','宋诗','song-poetry','','[]','樹陰高下遶周牆，靜夜猶聞刻漏長。',32,'全唐诗/poet.song.117000.json','["樹陰高下遶周牆，靜夜猶聞刻漏長。", "斗轉未離天北極，參斜已近月西廂。"]'),
('565979ca-cc55-40a0-a1a0-0586b926a736','爲邦','晁公遡','宋','宋诗','song-poetry','','[]','壤畫東西劔，川分上下江。',48,'全唐诗/poet.song.117000.json','["壤畫東西劔，川分上下江。", "論才難塞職，逐食强爲邦。", "曉起雨南畝，晚來風北窗。", "幽懷得陶寫，頼有酒盈缸。"]'),
('7643b2e1-2114-4f65-8b29-33e85b246524','眉州燕游雜詠十首 碧瀾堂','晁公遡','宋','宋诗','song-poetry','','[]','清瀾深幾許，夏潦冬即空。',24,'全唐诗/poet.song.117000.json','["清瀾深幾許，夏潦冬即空。", "定非蛟龍宅，徒爲螺蚌宮。"]'),
('d972577f-a243-4378-94b1-f46547799f9c','眉州燕游雜詠十首 葵亭','晁公遡','宋','宋诗','song-poetry','','[]','杲杲東出日，萬方被照臨。',24,'全唐诗/poet.song.117000.json','["杲杲東出日，萬方被照臨。", "鸜鵒不踰濟，草木有常心。"]'),
('3b21caa6-7bc2-4de4-9d5b-d86bcdc5ee49','眉州燕游雜詠十首 臨風閣','晁公遡','宋','宋诗','song-poetry','','[]','舉扇謝風伯，排闥有清音。',24,'全唐诗/poet.song.117000.json','["舉扇謝風伯，排闥有清音。", "不可遣塵汙，但當開我襟。"]'),
('20a033c4-dffb-46a7-8c4b-514463400984','眉州燕游雜詠十首 晚賦園','晁公遡','宋','宋诗','song-poetry','','[]','雜樹畧就列，清晨時涉園。',24,'全唐诗/poet.song.117000.json','["雜樹畧就列，清晨時涉園。", "逢幽付鼻詠，懷新勞目存。"]'),
('a7b29a0f-6484-43e5-a733-eb48d2b93905','眉州燕游雜詠十首 披風榭','晁公遡','宋','宋诗','song-poetry','','[]','屏幛盡通徹，蕭然塵土空。',24,'全唐诗/poet.song.117000.json','["屏幛盡通徹，蕭然塵土空。", "不畏趙盾日，知有楚王風。"]'),
('4bcf16a2-5878-47f7-8b43-cfd0787f9161','眉州燕游雜詠十首 起文堂','晁公遡','宋','宋诗','song-poetry','','[]','天地有萬籟，中存韶濩音。',24,'全唐诗/poet.song.117000.json','["天地有萬籟，中存韶濩音。", "斯文未嘗廢，但見古猶今。"]'),
('85caea95-11de-4ecb-bdcb-772723528794','眉州燕游雜詠十首 野航','晁公遡','宋','宋诗','song-poetry','','[]','方牀客常滿，豈止兩三人。',24,'全唐诗/poet.song.117000.json','["方牀客常滿，豈止兩三人。", "誰可負之走，長留採白蘋。"]'),
('a4b78c11-dce7-4a18-a33d-b2df97a5e0d4','眉州燕游雜詠十首 芳菲亭','晁公遡','宋','宋诗','song-poetry','','[]','清陰夏可玩，秀色春可餐。',24,'全唐诗/poet.song.117000.json','["清陰夏可玩，秀色春可餐。", "桃李事且置，四時各有觀。"]'),
('74169ee1-414a-4f01-9da3-04036f449a29','眉州燕游雜詠十首 摇香亭','晁公遡','宋','宋诗','song-poetry','','[]','臨池可手攬，何似湘水中。',24,'全唐诗/poet.song.117000.json','["臨池可手攬，何似湘水中。", "冥冥望北渚，木末有芙蓉。"]'),
('c31cb2b5-3fa0-4963-9fee-f28b1518cb95','眉州燕游雜詠十首 遠景樓','晁公遡','宋','宋诗','song-poetry','','[]','山川未爲遠，在此軒楯中。',24,'全唐诗/poet.song.117000.json','["山川未爲遠，在此軒楯中。", "我覺千歲近，民今三代同。"]'),
('5c604736-0025-4687-afde-afc60e1dad18','送李紹祖通判寧江','晁公遡','宋','宋诗','song-poetry','','[]','此去夔州氣倍增，白鹽赤甲兩崚嶒。',64,'全唐诗/poet.song.117000.json','["此去夔州氣倍增，白鹽赤甲兩崚嶒。", "喜看司隸李校尉，往事高人王右丞。", "若使主公登紫殿，亦歸郎省卧青綾。", "老夫只擬安田畝，他日烝民頌中興。"]'),
('ddae89ce-dd00-4c03-bb6d-298f197df351','行役','晁公遡','宋','宋诗','song-poetry','','[]','胡爲行役尚殊方，已覺春容近艷陽。',64,'全唐诗/poet.song.117000.json','["胡爲行役尚殊方，已覺春容近艷陽。", "石齒潄江飜翠浪，蔣牙穿渚出青芒。", "艱難去國成淹泊，老大逢辰倍感傷。", "幕府吾歸具朋酒，兕觥猶及享公堂。"]'),
('cfab4d5a-60b8-49fd-8e88-ab4577fa4a28','樊口','晁公遡','宋','宋诗','song-poetry','','[]','林烏晴自語，水鶴暮知還。',48,'全唐诗/poet.song.117000.json','["林烏晴自語，水鶴暮知還。", "故國浮雲外，寒溪積雪間。", "東行臨赤岸，北望阻青關。", "石上漥尊在，吾將酌次山。"]'),
('0fc26285-590e-4677-8150-03b421928c5d','上都','晁公遡','宋','宋诗','song-poetry','','[]','晚歲辭荒塞，青春赴上都。',48,'全唐诗/poet.song.117000.json','["晚歲辭荒塞，青春赴上都。", "望雲君日近，犯斗客星孤。", "獻納看多士，衰遲失壯圖。", "功名吾已懶，歸擬著潛夫。"]'),
('9a1d4a12-d50b-4dda-8b6e-dab2a47f39ab','溪上','晁公遡','宋','宋诗','song-poetry','','[]','野老門前雲覆溪，雨晴雲氣亦霏微。',64,'全唐诗/poet.song.117000.json','["野老門前雲覆溪，雨晴雲氣亦霏微。", "水生蘆筍纖纖長，日暖楊花細細飛。", "得食慈烏皆反哺，卷簾乳燕自知歸。", "天涯物色堪行樂，況復淮西近解圍。"]'),
('af47be00-5523-47f4-89e1-b0633d84e646','春晚  其一','晁公遡','宋','宋诗','song-poetry','','[]','苔色侵階上，晴光度隙來。',48,'全唐诗/poet.song.117000.json','["苔色侵階上，晴光度隙來。", "庭花隨鳥下，池藻逐魚開。", "舊國悲銅雀，新詩擬玉臺。", "一春常道路，歸即送春回。"]'),
('dd1759e9-6f97-47f8-bd7f-62f39ff12ed5','春晚  其二','晁公遡','宋','宋诗','song-poetry','','[]','野樹交新葉，春江上晚潮。',48,'全唐诗/poet.song.117000.json','["野樹交新葉，春江上晚潮。", "花泥粘落蘂，麥隴散疎苗。", "輕籟因風發，游塵著雨消。", "遥憐小山桂，久負楚辭招。"]'),
('f40d1b5c-7f8b-4897-820a-99d0823e9e97','小築','晁公遡','宋','宋诗','song-poetry','','[]','小築何年隠，巾車得再臨。',48,'全唐诗/poet.song.117000.json','["小築何年隠，巾車得再臨。", "竹陰覆地薄，樹影入池深。", "雲日清暉動，山林暮景侵。", "南枝棲未穩，接翅有來禽。"]'),
('95afaf3d-ee46-4987-879c-f4e91ecd60d2','秋陰','晁公遡','宋','宋诗','song-poetry','','[]','出林雲未斷，入坐雨初霑。',48,'全唐诗/poet.song.117000.json','["出林雲未斷，入坐雨初霑。", "急點鳴高瓦，寒聲瀉壞簷。", "懸牆閒玉麈，散帙亂牙籤。", "誰道幽居勝，吾今吏隠兼。"]'),
('0d681b61-0871-46f9-baec-c38163db13fa','蜀江','晁公遡','宋','宋诗','song-poetry','','[]','蜀江楚硤鬰巉巖，雲霧中兼草木參。',64,'全唐诗/poet.song.117000.json','["蜀江楚硤鬰巉巖，雲霧中兼草木參。", "飛鶻飜空投霽野，游魚跳水亂澄潭。", "朝廷共仰辰之北，羈旅長留斗以南。", "更欲暇時求勝槩，每從隣叟恣窮探。"]'),
('7bfcd6e6-2a91-4551-b64f-163df3ee04f3','立春','晁公遡','宋','宋诗','song-poetry','','[]','我來佇立望晴空，目極蒼茫萬壑中。',64,'全唐诗/poet.song.117000.json','["我來佇立望晴空，目極蒼茫萬壑中。", "樹色昏昏酣霽霧，江紋細細織柔風。", "一行殊俗猶爲吏，三揖今年擬送窮。", "聞道東田耕帝藉，慙無賦奏大明宮。"]'),
('f491d762-bbdd-4140-9510-991bf8bc54d1','江上春事','晁公遡','宋','宋诗','song-poetry','','[]','春來江上解霜嚴，羣柏周廬筍出簷。',64,'全唐诗/poet.song.117000.json','["春來江上解霜嚴，羣柏周廬筍出簷。", "突兀貍頭蒙紫籜，參差龍甲長蒼髯。", "閒思井臼高人宅，懶傍車輿刺史幨。", "留滯殊方憂鵩入，今年試爲發書占。"]'),
('9d042fd3-8980-4a92-9dea-1037e5d510aa','春回','晁公遡','宋','宋诗','song-poetry','','[]','城郭初瞻北斗移，春回冰壑已流澌。',64,'全唐诗/poet.song.117000.json','["城郭初瞻北斗移，春回冰壑已流澌。", "石林背日垂寒旆，江藻舒風引細絲。", "物色徐看催歲換，形容先擬駐年衰。", "天涯草木雖無頼，亦復欣欣及聖時。"]'),
('f6556df7-3518-4481-be17-431355840e4a','巴城','晁公遡','宋','宋诗','song-poetry','','[]','比從關塞歷巴城，不復衣冠立漢庭。',64,'全唐诗/poet.song.117000.json','["比從關塞歷巴城，不復衣冠立漢庭。", "越巂江寒嗟獨往，瞿塘硤險駭初經。", "雙崖石立懸深翠，萬嶺排空送遠青。", "久抗塵容驅俗駕，往來吾亦愧山靈。"]'),
('6609bb58-b314-4ce3-b518-2b7886242f52','清秋','晁公遡','宋','宋诗','song-poetry','','[]','清秋獨立望殊方，粉堞遥瞻埤堄長。',64,'全唐诗/poet.song.117000.json','["清秋獨立望殊方，粉堞遥瞻埤堄長。", "水滿蒼江平巨硤，風交翠木亂寒塘。", "滯留晚歲違公府，準擬明年入帝鄉。", "多病早衰才不振，豫慙無賦奏長楊。"]'),
('dec53dca-19a1-4381-9fcf-bd4c5eb7ea79','潯陽','晁公遡','宋','宋诗','song-poetry','','[]','渺渺蒼江遶郭流，菰蒲杜若滿汀洲。',64,'全唐诗/poet.song.117000.json','["渺渺蒼江遶郭流，菰蒲杜若滿汀洲。", "山雲不動飛黄鶴，春水無邊沒白鷗。", "日落荒城聞戍鼓，天清絕浦見行舟。", "老夫舊有湘吳興，聊復今年作遠游。"]'),
('db7335c8-7ec3-41a5-8fa8-df4824195e32','郭外','晁公遡','宋','宋诗','song-poetry','','[]','脩林遶屋尚扶疎，紺葉樛枝老不枯。',64,'全唐诗/poet.song.117000.json','["脩林遶屋尚扶疎，紺葉樛枝老不枯。", "晴廡無風烏自語，秋場落日雉相呼。", "一區未有子雲宅，半世空看摩詰圖。", "終擬買田陽羨去，肯浮滄海遠乘桴。"]'),
('f231e210-f4c1-439c-9b28-7b31a1d545ae','趙主簿護貢篚至吳下有詩見示用詩爲謝','晁公遡','宋','宋诗','song-poetry','','[]','軸艫千里薄樅陽，未數當年漢省方。',64,'全唐诗/poet.song.117000.json','["軸艫千里薄樅陽，未數當年漢省方。", "勿爲催歸啼望帝，且看奉引駕乘黄。", "四邊每報風塵靜，萬國同瞻日月光。", "我願與民歌擊壤，求田當賣橐中裝。"]'),
('69e7c888-d826-40b6-bde5-3fb91cead225','觀雨','晁公遡','宋','宋诗','song-poetry','','[]','高閣前臨野外村，坐看急雨灑山根。',64,'全唐诗/poet.song.117000.json','["高閣前臨野外村，坐看急雨灑山根。", "黑雲合沓奔崖暗，白水崩騰赴硤喧。", "已快脩渠通草徑，稍清瘴土浄柴門。", "晚來更報滄江漲，津北津南沒舊痕。"]'),
('122ae317-3ad7-4398-b910-ce93c19abe4a','雨罷風大作','晁公遡','宋','宋诗','song-poetry','','[]','燕寢真宜雨，卧聞風有聲。',48,'全唐诗/poet.song.117000.json','["燕寢真宜雨，卧聞風有聲。", "莫驚無礙睡，寧爲不平鳴。", "折筍低行蟻，飛梅暗打鶑。", "最憐兩岐麥，欹倒亂縱橫。"]'),
('9a2264d6-a644-4cf3-9c03-946320edead9','江上','晁公遡','宋','宋诗','song-poetry','','[]','岸冷霜排草，川明月上梅。',48,'全唐诗/poet.song.117000.json','["岸冷霜排草，川明月上梅。", "清游誠可愛，深夜孰能來。", "不作尋山去，難成訪剡回。", "此生慙野老，過往只田萊。"]'),
('5749760e-ecc5-4f67-85d5-20939177ec9f','白日','晁公遡','宋','宋诗','song-poetry','','[]','白日寒無色，黄流漲未平。',48,'全唐诗/poet.song.117000.json','["白日寒無色，黄流漲未平。", "雲低催夕暝，江濁污秋清。", "尚覺物多累，敢期詩有聲。", "窮愁今至骨，書或似虞卿。"]'),
('9a9ac85e-e47f-4050-aff3-c97196d4a4d7','次韻程愿以十詩見示篇中多及故起居舍人程子山老懶姑取其一用韻答之','晁公遡','宋','宋诗','song-poetry','','[]','故鄉喬木莫知年，聞道端居似玉川。',64,'全唐诗/poet.song.117000.json','["故鄉喬木莫知年，聞道端居似玉川。", "勿謂魯侯吾不遇，試言衛政子奚先。", "傳家學問三冬足，插架文書四庫全。", "頗復因君懷柱史，當時高會有羣賢。"]'),
('761e6b04-3e56-47de-919a-3336ef00dcec','費子範以予銘其父墓持錦物相餉盡歸之姑留洮州綠石研一作詩謝之  其一','晁公遡','宋','宋诗','song-poetry','','[]','大費家聲星斗垂，乃翁名蹟世人知。',32,'全唐诗/poet.song.117000.json','["大費家聲星斗垂，乃翁名蹟世人知。", "平生於此辭無愧，不減東京有道碑。"]'),
('c886c7af-d96a-41a7-942d-af3b6ebad024','費子範以予銘其父墓持錦物相餉盡歸之姑留洮州綠石研一作詩謝之  其二','晁公遡','宋','宋诗','song-poetry','','[]','訟牒裝懷塵滿胸，少無筆力老尤慵。',32,'全唐诗/poet.song.117000.json','["訟牒裝懷塵滿胸，少無筆力老尤慵。", "洮州綠石堪爲礪，聊與衰翁淬筆鋒。"]'),
('bffe2f21-a9f4-4db4-badb-2bc4f8dff298','王才諒歸自臨安備道羣從內集之樂感而有作','晁公遡','宋','宋诗','song-poetry','','[]','豈料高陽里，于今復舊游。',48,'全唐诗/poet.song.117000.json','["豈料高陽里，于今復舊游。", "風塵兩地隔，江海一身留。", "夢斷烏衣夜，魂傷白帝秋。", "臨平江上柳，早晚繫歸舟。"]'),
('bd777988-d81e-40b1-8f5f-9141872e5e2e','病中','晁公遡','宋','宋诗','song-poetry','','[]','官冷經過少，門寒亦懶開。',48,'全唐诗/poet.song.117000.json','["官冷經過少，門寒亦懶開。", "雨餘苔及榻，病起研生埃。", "客淚隨猿落，家書想雁來。", "似聞溪上柳，一一報春回。"]'),
('c914d12c-41cc-4ece-8a33-c113ce02e602','立春有感','晁公遡','宋','宋诗','song-poetry','','[]','歲盡無人訪汴州，東風應到未央樓。',64,'全唐诗/poet.song.117000.json','["歲盡無人訪汴州，東風應到未央樓。", "荒垣草沒牛羊入，廢苑春生雉兔游。", "萬里艱難炊劔首，十年流落夢刀頭。", "一官何事不歸去，空戴南冠泣楚囚。"]'),
('09adedee-1b93-4c07-bc89-a7631087f6f6','感事','晁公遡','宋','宋诗','song-poetry','','[]','征衣消盡洛陽塵，泣向東風拭淚痕。',32,'全唐诗/poet.song.117000.json','["征衣消盡洛陽塵，泣向東風拭淚痕。", "不及青春歸有信，一年一別樂游園。"]'),
('672841d9-ae74-4f35-9717-a0b7a41a4950','木櫪觀','晁公遡','宋','宋诗','song-poetry','','[]','離離荒草滿遺宮，羽化無人殿閣空。',32,'全唐诗/poet.song.117000.json','["離離荒草滿遺宮，羽化無人殿閣空。", "白鶴亦應天上去，獨餘枯櫪起秋風。"]'),
('3dc39bed-a8c1-4f64-8981-7f335d0d9da3','層樓','晁公遡','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','獨立層樓上，遥看衆壑中。',48,'全唐诗/poet.song.117000.json','["獨立層樓上，遥看衆壑中。", "山頭冠落日，谷口吸長風。", "雲霧吳天接，江湖蜀柁通。", "只今洞庭岸，白浪沒青楓。"]'),
('644b0a85-c862-416d-a90c-a1b02e2d6658','溪上尋梅','晁公遡','宋','宋诗','song-poetry','','[]','凍雨霏霏不濕山，冰溪淺淺欲生瀾。',32,'全唐诗/poet.song.117000.json','["凍雨霏霏不濕山，冰溪淺淺欲生瀾。", "我來問訊無消息，笑倩東風與破寒。"]'),
('f6085977-1b43-4089-b0a0-da33c470207e','病酒','晁公遡','宋','宋诗','song-poetry','','[]','遣愁自笑筆無功，醉覺花梢入眼紅。',32,'全唐诗/poet.song.117000.json','["遣愁自笑筆無功，醉覺花梢入眼紅。", "本擬消磨付杯勺，不堪中酒過春風。"]'),
('9b80bcb8-751a-4265-bfd8-58ccaf924cb6','喜雨簡仲霍行之','晁公遡','宋','宋诗','song-poetry','','[]','久晴風暖紵溪城，陌上輕埃欲汙人。',64,'全唐诗/poet.song.117000.json','["久晴風暖紵溪城，陌上輕埃欲汙人。", "不惜春泥三日雨，且消烏帽十分塵。", "霏微著柳空添色，浩蕩欺花便減春。", "擬作郊居雌霓賦，故人今日有王筠。"]'),
('4933e1b8-1c7c-4f4e-acd6-04986a5e4265','簿書','晁公遡','宋','宋诗','song-poetry','','[]','楊梢飛雪滿城風，暖日催花爛熳紅。',32,'全唐诗/poet.song.117000.json','["楊梢飛雪滿城風，暖日催花爛熳紅。", "詩興消磨渾欲盡，一春心事簿書中。"]'),
('a07f10f2-9de1-4cf7-937a-7d5fa778d205','春晚','晁公遡','宋','宋诗','song-poetry','','[]','花輸落蘂歸蜂室，風約疎簾納燕泥。',32,'全唐诗/poet.song.117000.json','["花輸落蘂歸蜂室，風約疎簾納燕泥。", "見此令人思故里，山門搔首忘東西。"]'),
('b2bbba76-40b8-4db2-bb3c-75da8554d2c1','二月  其一','晁公遡','宋','宋诗','song-poetry','','[]','只知流落倦飄蓬，豈識朝回合殿風。',32,'全唐诗/poet.song.117000.json','["只知流落倦飄蓬，豈識朝回合殿風。", "二月春容山色裏，五更歸夢雨聲中。"]'),
('5858492b-55a0-4204-b3ef-ed3f95707d90','二月  其二','晁公遡','宋','宋诗','song-poetry','','[]','門外春寒數日風，登樓聊恃醉顔紅。',32,'全唐诗/poet.song.117000.json','["門外春寒數日風，登樓聊恃醉顔紅。", "水浮渺莽春畦外，山在冥茫暮雨中。"]'),
('d2390b63-69a1-4d1d-b684-a73a5a16c554','去八月同張文饒考試始遂言集執經問道至今不敢忘因成二詩  其一','晁公遡','宋','宋诗','song-poetry','','[]','屬者俱被命，敕書黄札光。',48,'全唐诗/poet.song.117000.json','["屬者俱被命，敕書黄札光。", "同將舜權量，與較蜀文章。", "投分雖已晚，傳經何可忘。", "對床風雨地，長記此升堂。"]'),
('485d7d4a-3e1c-463d-bdb8-8904a23930ec','去八月同張文饒考試始遂言集執經問道至今不敢忘因成二詩  其二','晁公遡','宋','宋诗','song-poetry','','[]','通變莫如易，韋編存至今。',48,'全唐诗/poet.song.117000.json','["通變莫如易，韋編存至今。", "如傳仲尼手，盡見伏羲心。", "此去被清問，豈惟蒙賞音。", "要通天下志，觀象得惟深。"]'),
('404b3b7b-a20e-44f6-adfb-6ca50c585720','二十七叔父書來說東都故居如昔','晁公遡','宋','宋诗','song-poetry','','[]','吳蜀相望萬里程，經年書到說都城。',64,'全唐诗/poet.song.117000.json','["吳蜀相望萬里程，經年書到說都城。", "御溝猶泛宮花出，春草還依輦路生。", "京洛衣冠皆去國，東南父老亦傷情。", "鄭公鄉里聞如故，誰道胡兒解弛兵。"]'),
('bf18e522-6b13-4d29-8b0e-0eae2b4e8ea8','讀江南諸公詩','晁公遡','宋','宋诗','song-poetry','','[]','吟盡江南草木春，只今臺閣有詩人。',32,'全唐诗/poet.song.117000.json','["吟盡江南草木春，只今臺閣有詩人。", "漢廷安用滄浪句，容我持竿詠白蘋。"]'),
('ced706bb-bfce-49c1-b519-d98f0b457894','午睡','晁公遡','宋','宋诗','song-poetry','','[]','漸覺銅壺刻漏遲，捲簾花日弄晴輝。',32,'全唐诗/poet.song.117000.json','["漸覺銅壺刻漏遲，捲簾花日弄晴輝。", "午窗睡美無人喚，夢逐游絲自在飛。"]'),
('66a59119-a540-4f86-8753-58b7f5fbb8ad','南州','晁公遡','宋','宋诗','song-poetry','','[]','久矣吾人愧白鷗，塵埃無路入南州。',64,'全唐诗/poet.song.117000.json','["久矣吾人愧白鷗，塵埃無路入南州。", "愁橫蜀嶺何年斷，夢繞吳江盡日流。", "病骨本無軒冕相，微官端爲稻粱謀。", "與君共約東歸日，江總還家要黑頭。"]'),
('903b1118-2823-4a44-8948-e24b16afd57c','官舍','晁公遡','宋','宋诗','song-poetry','','[]','得閒誰更傍人門，且喜深居少送迎。',64,'全唐诗/poet.song.117000.json','["得閒誰更傍人門，且喜深居少送迎。", "楊柳春風垂地影，芭蕉夜雨隔窗聲。", "病寬束带圍應減，愁攪枯腸睡苦輕。", "明日公庭有官事，又須持板候雞鳴。"]'),
('43576797-4014-4dac-bfdf-b02278738c32','止酒','晁公遡','宋','宋诗','song-poetry','','[]','卧病經旬不舉觴，胸中無復少年狂。',64,'全唐诗/poet.song.117000.json','["卧病經旬不舉觴，胸中無復少年狂。", "春心已逐飛花盡，午夢還隨白日長。", "塵事無窮那可了，詩情常在不能忘。", "閉門覓句無餘事，書策紛紛正繞牀。"]'),
('3326ddf2-f78a-437c-a2f2-a51e86a737e3','即事','晁公遡','宋','宋诗','song-poetry','','[]','故國邊聲靜鼓鼙，依然宮闕淚沾衣。',64,'全唐诗/poet.song.117000.json','["故國邊聲靜鼓鼙，依然宮闕淚沾衣。", "端門曉日烏聲樂，別殿春風燕影歸。", "目斷楚天嗟樹隔，夢回梁苑逐雲飛。", "里中父老今誰在，聞說比隣半是非。"]'),
('3d7152b4-1e10-48a2-b184-ef361be7f353','寄子兼弟時聞有平都之游','晁公遡','宋','宋诗','song-poetry','','[]','春風殿閣百花香，欲去題詩細作行。',32,'全唐诗/poet.song.117000.json','["春風殿閣百花香，欲去題詩細作行。", "聞爾東游有佳句，只應先我賦靈光。"]'),
('9017ebfb-2356-413b-ac3d-d5ed43398cbc','遣愁','晁公遡','宋','宋诗','song-poetry','','[]','白盡汀蘋老，黄彫岸草秋。',24,'全唐诗/poet.song.117000.json','["白盡汀蘋老，黄彫岸草秋。", "西風正蕭瑟，何處不堪愁。"]'),
('c58eca12-4579-48d2-99f0-ac221aac9337','巴江','晁公遡','宋','宋诗','song-poetry','','[]','巴江暮秋末，霜降千林空。',48,'全唐诗/poet.song.117000.json','["巴江暮秋末，霜降千林空。", "山色不改碧，蓼花無數紅。", "木葉感湘浦，蓴羹憶江東。", "艱難志當壯，吾未怨途窮。"]'),
('e9f70670-007f-424c-aee9-bb9b16cc6af9','懷子兼弟時在寧江赴試  其一','晁公遡','宋','宋诗','song-poetry','','[]','霸國山河在，秋風草樹疎。',48,'全唐诗/poet.song.117000.json','["霸國山河在，秋風草樹疎。", "羈游今幾日，旅食定何如。", "夢想池塘句，愁消鴻雁書。", "細思治安策，勉力獻公車。"]'),
('90d9debf-98f7-4d29-8472-fd87f81ad519','懷子兼弟時在寧江赴試  其二','晁公遡','宋','宋诗','song-poetry','','[]','江晚微收潦，乘流久已歸。',48,'全唐诗/poet.song.117000.json','["江晚微收潦，乘流久已歸。", "沈郎正多病，水帝有餘威。", "鴻雁幾時到，脊鴒相背飛。", "題書問行李，東望獨依依。"]'),
('62b1d1c6-efc7-403b-a4cf-b645ff41282e','予己未十月二十有二日去涪上越明年八月二十有八日以事再來觀山川之勝無異於昔而予之幽憂抑鬰亦自若也','晁公遡','宋','宋诗','song-poetry','','[]','重來閒曳杖藜行，白帽依前似管寧。',64,'全唐诗/poet.song.117000.json','["重來閒曳杖藜行，白帽依前似管寧。", "風雨只如當日恨，江山不改故時青。", "天寒未夕窗先暝，霜晚無聲葉自零。", "詩罷時爲洛生詠，醉吟聊使故人聽。"]'),
('34bda4aa-bd23-4028-918c-3ee4186abb92','送王和甄竇公瑞歸魚洞','晁公遡','宋','宋诗','song-poetry','','[]','壁掛凝塵榻，苔生嘯月樓。',48,'全唐诗/poet.song.117000.json','["壁掛凝塵榻，苔生嘯月樓。", "喜聞佳客至，能爲故人留。", "雨積山川暝，風傳鼓角秋。", "沙邊晚相別，留眼送歸舟。"]'),
('1b58116e-83e9-40ff-9061-a7d8aef6ce64','秋江','晁公遡','宋','宋诗','song-poetry','','[]','秋江水清不勝綠，還與漢江顔色同。',32,'全唐诗/poet.song.117000.json','["秋江水清不勝綠，還與漢江顔色同。", "望中白鳥忽飛去，落日丹楓相映紅。"]'),
('de0ae00c-ea60-4b3a-9574-59005e535f10','和郭安道','晁公遡','宋','宋诗','song-poetry','','[]','水落灘聲急，風來樹影移。',48,'全唐诗/poet.song.117000.json','["水落灘聲急，風來樹影移。", "懶窮千里目，空誦四愁詩。", "白帽何妨隠，黄粱未遣炊。", "要令鄉國夢，暫向枕中遲。"]'),
('555c954e-7fde-4a72-8cbc-148037c83121','雨晴','晁公遡','宋','宋诗','song-poetry','','[]','西風送殘雨，吹盡簷際滴。',48,'全唐诗/poet.song.117000.json','["西風送殘雨，吹盡簷際滴。", "稍稍江流清，湛此千頃碧。", "雲收天倚蓋，山靜月銜壁。", "秋容日夕佳，真欲慰北客。"]'),
('235bc3ce-e739-4612-9e0a-6b10fcd6da98','別郭安道盧能甫','晁公遡','宋','宋诗','song-poetry','','[]','客路悲秋落木邊，江流滾滾尚連天。',64,'全唐诗/poet.song.117000.json','["客路悲秋落木邊，江流滾滾尚連天。", "病來懶著登山屐，歸去聊乘下瀨船。", "回首關河嗟去國，傷心風雨送殘年。", "相逢又作怱怱別，擬續陽關第二篇。"]'),
('1ced0912-b85b-4b5d-9be3-c96292ab5367','偶題懷子兼弟','晁公遡','宋','宋诗','song-poetry','','[]','秋色丹楓畔，愁心白雁邊。',24,'全唐诗/poet.song.117000.json','["秋色丹楓畔，愁心白雁邊。", "東來又相失，更擬待明年。"]'),
('c96630a8-e6eb-4bd3-8912-82a4a1d3eb08','夢中作','晁公遡','宋','宋诗','song-poetry','','[]','舉鞭重到故都行，予亦咨嗟恨不勝。',32,'全唐诗/poet.song.117000.json','["舉鞭重到故都行，予亦咨嗟恨不勝。", "心與隴雲留漢苑，目隨煙樹遶秦陵。"]'),
('07a02da1-99a1-445f-9b50-87d8720c2a4f','尋梅花尚未有開者','晁公遡','宋','宋诗','song-poetry','','[]','問訊溪頭樹，如何殊未春。',24,'全唐诗/poet.song.117000.json','["問訊溪頭樹，如何殊未春。", "亦應心老大，不逐世陳新。"]'),
('4811b598-00a9-4085-92fd-8feea3bc054b','有感','晁公遡','宋','宋诗','song-poetry','','[]','不見罘罳闕，于今已十春。',24,'全唐诗/poet.song.117000.json','["不見罘罳闕，于今已十春。", "素衣不忍棄，爲有洛陽塵。"]'),
('973c6f9f-3300-456a-8b54-2c75ed8100b5','雨中觀庭下梅二首  其一','晁公遡','宋','宋诗','song-poetry','','[]','霏霏凍雨細無聲，解洗梅花花上塵。',32,'全唐诗/poet.song.117000.json','["霏霏凍雨細無聲，解洗梅花花上塵。", "似與橫枝借顔色，故應添我一分春。"]'),
('ad740389-d19f-4828-82e1-f285fe2ecba6','雨中觀庭下梅二首  其二','晁公遡','宋','宋诗','song-poetry','','[]','春近梅梢著意紅，留花不發待東風。',32,'全唐诗/poet.song.117000.json','["春近梅梢著意紅，留花不發待東風。", "籬邊一樹最佳處，半在冥濛煙雨中。"]'),
('5c908d20-6e2e-47a8-bc85-908c4b18d230','詠銅缾中梅','晁公遡','宋','宋诗','song-poetry','','[]','折得寒香日暮歸，銅缾添水養橫枝。',32,'全唐诗/poet.song.117000.json','["折得寒香日暮歸，銅缾添水養橫枝。", "書窗一夜月初滿，却似小溪清淺時。"]'),
('556b83b6-7aa9-4d2d-a3bf-f449417dd863','喜雨','晁公遡','宋','宋诗','song-poetry','','[]','提封爲國守，樂歲見天心。',48,'全唐诗/poet.song.117000.json','["提封爲國守，樂歲見天心。", "與此一年食，賜之三日霖。", "打荷看急點，歷竹有清音。", "上帝嗟何遠，昭昭寔汝臨。"]'),
('fcda1899-497e-4616-8f9a-344fa17cc935','三月晦日舟中','晁公遡','宋','宋诗','song-poetry','','[]','平生每欲惜芳菲，人事還多與願違。',32,'全唐诗/poet.song.117000.json','["平生每欲惜芳菲，人事還多與願違。", "卧病不常同客醉，作詩才及送春歸。"]'),
('207e8a94-5214-4827-a1bf-806fc504fffc','四月一日舟中','晁公遡','宋','宋诗','song-poetry','','[]','渺渺無風浪自平，順流乘曉放舟行。',64,'全唐诗/poet.song.117000.json','["渺渺無風浪自平，順流乘曉放舟行。", "汀蘋不與春同老，池草能隨夢復生。", "山色向人元不改，年華轉景未須驚。", "故人相會無多日，有酒何妨爲我傾。"]'),
('f8844534-f982-487f-8977-3d80dc26c177','師安撫生日','晁公遡','宋','宋诗','song-poetry','','[]','鼻祖貽謀遠，承家積慶長。',288,'全唐诗/poet.song.117000.json','["鼻祖貽謀遠，承家積慶長。", "青箱元不墜，玉樹久逾芳。", "氣驗三嵎秀，祥占五世昌。", "向來蜀父老，久憶漢文章。", "試問風騷將，誰登翰墨場。", "浮雲玉壘變，秋草墨池荒。", "大雅淪金石，斯文厭秕穅。", "九成方命舜，三變必興唐。", "東壁初觀象，南箕果降光。", "終當薦清廟，始驗出崑岡。", "世喜韶音在，人皆肉味忘。", "遥聞望帝國，重立鄭公鄉。", "議論看前輩，春秋守素王。", "談經追服杜，下筆逼班揚。", "價重連城璧，功高治水航。", "詞源傾灧澦，才刃劇干將。", "思涌辭穿月，文成字挾霜。", "高明齊日觀，豪健敵風檣。", "不但垂金薤，方期兆玉璜。", "徑宜排稷下，不用奏阿房。", "退草三千牘，深窺數仞牆。", "多聞正科斗，博識辨商羊。", "鄉黨尊王烈，交游說鄭莊。", "絃歌化鄒魯，文物見成康。"]'),
('a892f59a-ac38-4136-891c-7f5d84b68926','范令人生日','晁公遡','宋','宋诗','song-poetry','','[]','文正垂芳久，風流八葉蕭。',264,'全唐诗/poet.song.117000.json','["文正垂芳久，風流八葉蕭。", "名傳慶歷頌，功冠寶元朝。", "人物追三代，儀刑正百僚。", "後來登玉筍，故自有霜條。", "配德皆乘鳳，生賢必珥貂。", "賦高梁苑雪，聲振浙江潮。", "已慶生金社，俄聞夢紫霄。", "飈車度弱水，絳節下陽寥。", "溫潤珠無纇，清修玉不雕。", "成家自褵結，高節陋琴挑。", "靈匹期河漢，仙槎近斗杓。", "擇夫得溫嶠，傳業繼班昭。", "比物能吟絮，逢辰解頌椒。", "早遵王吉儉，久去少君驕。", "絳帳詩書在，朱絃律呂調。", "行皆圖史應，步節珮環摇。", "林下風姿遠，閨中禮法饒。", "翟衣嚴象服，彤史嗣英飈。", "夙御魚軒駕，和鳴鳳管簫。", "清標矜竹潤，盛德頌桃夭。", "八桂知同秀，三芝等後彫。", "他年看洗髓，終不羨雲翹。"]'),
('82e3a49e-65f2-47d5-afb8-4cfaca374013','偶成  其一','晁公遡','宋','宋诗','song-poetry','','[]','鸞鑑無塵月影圓，不須朱粉污紅顔。',32,'全唐诗/poet.song.117000.json','["鸞鑑無塵月影圓，不須朱粉污紅顔。", "待傳京兆眉膴樣，剩寫春容入遠山。"]'),
('ea99c356-a607-47a8-b979-1625aa9c38df','偶成  其二','晁公遡','宋','宋诗','song-poetry','','[]','臉上桃花春自開，眉邊柳色日全回。',32,'全唐诗/poet.song.117000.json','["臉上桃花春自開，眉邊柳色日全回。", "遥知弄粉粧成晚，應待溫郎玉鏡臺。"]'),
('4e2d396a-9dab-4b27-a6ea-ded5d30e6973','偶成  其三','晁公遡','宋','宋诗','song-poetry','','[]','樓上東風簾幕垂，纖纖春筍弄粧遲。',32,'全唐诗/poet.song.117000.json','["樓上東風簾幕垂，纖纖春筍弄粧遲。", "玉籠鸚鵡知人意，催報花梢日影移。"]'),
('6770c1c7-1454-4895-80c8-24640693eed0','偶成  其四','晁公遡','宋','宋诗','song-poetry','','[]','深深小閤夜籠香，日上珠簾逗曉光。',32,'全唐诗/poet.song.117000.json','["深深小閤夜籠香，日上珠簾逗曉光。", "爲喚羅帷春睡起，翠盆添水試新粧。"]'),
('8946a801-6a84-4c55-935c-5744616ff352','九日','晁公遡','宋','宋诗','song-poetry','','[]','霜林木葉未全紅，疎雨蕭蕭不滿空。',64,'全唐诗/poet.song.117000.json','["霜林木葉未全紅，疎雨蕭蕭不滿空。", "萬里黄花欺病眼，十年烏帽怯秋風。", "可憐望遠身能健，愈覺追歡歲不同。", "便欲題詩問鄉國，不堪回首失飛鴻。"]'),
('9d8e915d-02cb-47db-b8d2-0af868c16ad3','答鮮于晉伯再用游卧龍山詩韻見贈之什','晁公遡','宋','宋诗','song-poetry','','[]','康成名已滿山東，復見談經鄭小同。',64,'全唐诗/poet.song.117000.json','["康成名已滿山東，復見談經鄭小同。", "卧病向來嗟髀減，誦詩多謝愈頭風。", "休隨賓客游梁苑，合有文章動漢宮。", "如我空疎已何用，一生丘壑坐奇窮。"]'),
('20c0bc3e-5dbf-4159-927a-cfc763944cc0','喜王志夫來','晁公遡','宋','宋诗','song-poetry','','[]','懶觀南土化，歸勒北山銘。',48,'全唐诗/poet.song.117000.json','["懶觀南土化，歸勒北山銘。", "蠟屐乃相過，巾車何不停。", "復回千里駕，去食五侯鯖。", "想見知君到，傳呼閤下鈴。"]'),
('b1fb7be2-7d97-42aa-8437-5845c7ef9e54','恭州教授宋師民有詩次韻','晁公遡','宋','宋诗','song-poetry','','[]','但聞兩廡讀書聲，學館無塵地更清。',64,'全唐诗/poet.song.117000.json','["但聞兩廡讀書聲，學館無塵地更清。", "歲久緇林皆木拱，春來泮水有芹生。", "剩令龍虎登高第，再賦鳧鷖美太平。", "我老循行才不稱，愧君刻畫與虛名。"]'),
('2596bb90-c8e8-4a7e-bf72-7a2e0a23f99c','聞伯初兄從周宣諭往兩京','晁公遡','宋','宋诗','song-poetry','','[]','聞道西從使者車，殷勤問訊武侯廬。',64,'全唐诗/poet.song.117000.json','["聞道西從使者車，殷勤問訊武侯廬。", "卧牛已去多新冢，化鶴重來失舊居。", "草木久荒門外逕，塵埃應化壁中書。", "遥知流落歸無處，未免悲歌問孟諸。"]'),
('dee96872-dad3-4379-a225-fb09de38cba9','句','晁公遡','宋','宋诗','song-poetry','','[]','天風夜半剪冰花，三十六峯如玉立。',16,'全唐诗/poet.song.117000.json','["天風夜半剪冰花，三十六峯如玉立。"]'),
('66ad1fb5-2ade-43c7-949b-9904b3555c1e','次韵鄭夾漈題林時隠霆芹齋詩','方翥','宋','宋诗','song-poetry','','[]','鄧侯牽挽政難留，六十年來亦倦游。',64,'全唐诗/poet.song.117000.json','["鄧侯牽挽政難留，六十年來亦倦游。", "至竟眼高無俗韵，不因人喚始回頭。", "江湖白鳥緣應熟，塵土烏靴心少休。", "可笑山翁癡未已，欲成吏隠更何由。"]'),
('c9f67150-c704-4a86-aec8-7548958cb6b3','仙篆石','方翥','宋','宋诗','song-poetry','','[]','何人登眺睨絕頂，一樹一石探幽奇。',32,'全唐诗/poet.song.117000.json','["何人登眺睨絕頂，一樹一石探幽奇。", "蟲文鳥篆不可識，如讀岣嶁神禹碑。"]'),
('3c391753-1650-4e8a-be42-f0fb3625235e','粘蠔石','方翥','宋','宋诗','song-poetry','','[]','纍纍蠔山着石面，此非所有能無疑。',64,'全唐诗/poet.song.117000.json','["纍纍蠔山着石面，此非所有能無疑。", "細看大石深孔竅，舟人撐篙跡猶遺。", "乃知此山千載前，洶湧尚作海渺瀰。", "蛟龍魚鼈占窟宅，不省造化能密移。"]'),
('9aaed7ea-72c3-488b-9635-7b3549ea46d4','家有白雞蓄之三年矣馴熟可愛謙之讀書山中一日相過偶道庵僧所闕遂送謙之以遺之','方翥','宋','宋诗','song-poetry','','[]','羽儀潔白如自脩，風雨晦冥那失曉。',128,'全唐诗/poet.song.117000.json','["羽儀潔白如自脩，風雨晦冥那失曉。", "沙頭鷗鳥不馴熟，雪裏鷺絲太孤皎。", "山寒夜半落葉深，閉門垂荑偎重衾。", "聞雞而起竟何事，我老看書不入心。", "久無鬭志形如木，世上癡兒能舍肉。", "白雞之肉不可食，無勞斷尾亦爲福。", "山僧窮獨老無妻，想見愛養如嬰兒。", "得地羽毛愈應好，天年全得山中老。"]'),
('1f191f9d-b234-4cbd-a5fa-9660f0f1e7e6','次韻時瑞見寄','方翥','宋','宋诗','song-poetry','','[]','吟詩夜半霜月白，胡床夢作乘槎客。',128,'全唐诗/poet.song.117000.json','["吟詩夜半霜月白，胡床夢作乘槎客。", "醉中入月捉玉兔，手摵桂枝鳴策策。", "風吹天河銀浪高，月邊星宿相周遭。", "五色機頭索雲錦，天孫一笑顔如桃。", "天河下接武陵溪，重覓仙源路却迷。", "五更波上回煙棹，半空飛雨落凄凄。", "羽衣稚子雙瞳方，伴我清江老嚴光。", "落日還收釣筒去，蘆風起處暮天長。"]'),
('5cb02e9d-c299-4428-a0fd-3f519a10e17a','跋漁村晚景瀟湘夜雨圖','方翥','宋','宋诗','song-poetry','','[]','雲昏雨暗黄蘆渚，沙磧風高人斷渡。',64,'全唐诗/poet.song.117000.json','["雲昏雨暗黄蘆渚，沙磧風高人斷渡。", "一葉扁舟忽下來，落日還收釣筒去。", "收盡沙頭白鳥飛，蒹葭暮雪滿蓑衣。", "千門萬戶擁被卧，獨釣寒波人未歸。"]'),
('8df02fcb-64ee-4f06-b0fd-ffabf071b8f2','除夜寄謙之','方翥','宋','宋诗','song-poetry','','[]','去年雪暗江南路，日暮踟躕無宿處。',96,'全唐诗/poet.song.117000.json','["去年雪暗江南路，日暮踟躕無宿處。", "今年坐見故園春，梅花已過桃花新。", "東皋薄田纔數畝，依方旋造逡巡酒。", "嗣宗痛飲是吾師，萬事否臧勿掛口。", "循環三百真超忽，誰向空濛問巢窟。", "愚癡聰慧一冥冥，不如且進杯中物。"]'),
('34a96173-3082-4630-bfeb-fda85c02ce50','虞美人','方翥','宋','宋诗','song-poetry','','[]','生犀百萬環帳立，漏聲未殘楚聲急。',96,'全唐诗/poet.song.117000.json','["生犀百萬環帳立，漏聲未殘楚聲急。", "拔山男子心轉柔，夜倚芙蓉秋露泣。", "帳中別酒苦如荼，不是嬋娟害覇圖。", "勦人憤死愁雲氣，呂氏田頭見老夫。", "漢宮三萬六千日，得意蛾眉亦陳迹。", "至今一曲唱虞姬，恨草摇摇向春碧。"]'),
('cb976f2e-86c4-497a-9f89-3a1e9f8504ca','與鄭國叔司法山行','方翥','宋','宋诗','song-poetry','','[]','策筇山下路，未省盡幽尋。',24,'全唐诗/poet.song.117000.json','["策筇山下路，未省盡幽尋。", "回首見桑柘，始知墟落深。"]'),
('35f45aa8-6e6d-4437-b9c2-0362e53ba9f1','無題','方翥','宋','宋诗','song-poetry','','[]','暗雨落漫漫，山中五月寒。',24,'全唐诗/poet.song.117000.json','["暗雨落漫漫，山中五月寒。", "大江渾不覺，溪壑有驚湍。"]'),
('513e47ff-0c54-4d53-8c11-124410f20877','再過幾先姪齋中','方翥','宋','宋诗','song-poetry','','[]','樹連平野濶，深夜易高風。',48,'全唐诗/poet.song.117000.json','["樹連平野濶，深夜易高風。", "星月迷濛外，乾坤鼓蕩中。", "山窗寒未白，宿炭曉能紅。", "抱被論詩句，長長與子同。"]'),
('619bca3f-48ab-4ea9-970a-2c652ae1eef2','元日','方翥','宋','宋诗','song-poetry','','[]','又見增年齒，謀身事事非。',48,'全唐诗/poet.song.117000.json','["又見增年齒，謀身事事非。", "時難逢歲飯，日暖換春衣。", "新莽姦猶在，懷王殯未歸。", "中原久離絕，感節淚頻揮。"]'),
('509749af-b2a4-4e86-bc93-d6f9d9a17c66','讀易','方翥','宋','宋诗','song-poetry','','[]','晝出陽關已斷腸，那堪真別更凄凉。',32,'全唐诗/poet.song.117000.json','["晝出陽關已斷腸，那堪真別更凄凉。", "癡人刻水方求劍，一息舟行過夜郎。"]'),
('849e3b54-e5f8-458f-940f-4f9437cbb40c','讀易 乾','方翥','宋','宋诗','song-poetry','','[]','蕩蕩春風野老家，欲尋蹤跡隔煙霞。',32,'全唐诗/poet.song.117000.json','["蕩蕩春風野老家，欲尋蹤跡隔煙霞。", "洞中携出小桃核，種作碧雲千樹花。"]'),
('c2876537-d2e9-4893-a783-bd127a6448f8','讀易 元','方翥','宋','宋诗','song-poetry','','[]','雨過前村湖水平，魚頭戢戢逐波生。',32,'全唐诗/poet.song.117000.json','["雨過前村湖水平，魚頭戢戢逐波生。", "隣家籃裏收雞子，昨夜分明報五更。"]'),
('db7380a7-b706-4ff2-9aab-0498b4a2987f','讀易 亨','方翥','宋','宋诗','song-poetry','','[]','洛邑舟中萬里均，舟車白浪與紅塵。',32,'全唐诗/poet.song.117000.json','["洛邑舟中萬里均，舟車白浪與紅塵。", "微掀衣角凉生面，不是清風動白蘋。"]'),
('78cbd7a4-c812-4d74-9563-29a2d30d642f','讀易 利','方翥','宋','宋诗','song-poetry','','[]','江上柴門照夕陽，牧童蓑笠下牛羊。',32,'全唐诗/poet.song.117000.json','["江上柴門照夕陽，牧童蓑笠下牛羊。", "明朝依舊山前路，溪北溪南花草香。"]'),
('7fad64ef-c099-4d6f-a33e-5697442457f2','讀易 貞','方翥','宋','宋诗','song-poetry','','[]','牛背穩如千斛舟，斜烟細雨任遨遊。',32,'全唐诗/poet.song.117000.json','["牛背穩如千斛舟，斜烟細雨任遨遊。", "春風草綠江南岸，祇見輕寒不見牛。"]'),
('85c9e101-e834-4cad-80a1-362018b61a90','次韻鄭漢仲講書','方翥','宋','宋诗','song-poetry','','[]','鄧侯牽挽政難留，六十年來亦倦游。',32,'全唐诗/poet.song.117000.json','["鄧侯牽挽政難留，六十年來亦倦游。", "至竟眼高無俗韻，不因人喚始回頭。"]'),
('d4065f39-442e-44ba-86c7-2400fcd18b07','宿釣溪','方翥','宋','宋诗','song-poetry','','[]','茅簷寂寞住人稀，落日逢迎宿酒旗。',32,'全唐诗/poet.song.117000.json','["茅簷寂寞住人稀，落日逢迎宿酒旗。", "夢覺五更山月上，溪邊人語釣船移。"]'),
('d2f6f672-1e3d-4114-86c4-a4903182deaa','過華嚴謁陳季若同年','方翥','宋','宋诗','song-poetry','','[]','老僧方丈倚雲巖，窘束公私百不堪。',32,'全唐诗/poet.song.117000.json','["老僧方丈倚雲巖，窘束公私百不堪。", "雖有此泉無此耳，留君旬日駐征驂。"]'),
('33b329f2-c630-4451-a8da-8bbf665ba8d4','立秋','方翥','宋','宋诗','song-poetry','','[]','星光如月映長空，驚起愁眠夜向中。',32,'全唐诗/poet.song.117000.json','["星光如月映長空，驚起愁眠夜向中。", "殘暑不妨欺枕簟，隔窗鳴葉是西風。"]'),
('cb3853f3-f1d0-4d27-8c74-cc668a62d935','癸酉冬赴部除夜宿信州客舍','方翥','宋','宋诗','song-poetry','','[]','隔屋青燈一點明，卧聽簷雨落三更。',32,'全唐诗/poet.song.117000.json','["隔屋青燈一點明，卧聽簷雨落三更。", "無因作得還鄉夢，門外兒童爆竹聲。"]'),
('6cccb7ff-afb1-4541-a9e4-2b90d2eddcec','臨安江上','方翥','宋','宋诗','song-poetry','','[]','來時雪片楊花落，今見楊花作雪飛。',32,'全唐诗/poet.song.117000.json','["來時雪片楊花落，今見楊花作雪飛。", "獨立暮江心似醉，羨他一葉釣船歸。"]'),
('a4384ed9-35b1-4e78-96ff-a6a4961e583d','離武林','方翥','宋','宋诗','song-poetry','','[]','大江東接海漫漫，海氣江風吹雨寒。',32,'全唐诗/poet.song.117000.json','["大江東接海漫漫，海氣江風吹雨寒。", "纔出國門三十里，便成回首望長安。"]'),
('cf163a4c-5f05-444d-abc8-5e77bbbfb98a','讀老子','方翥','宋','宋诗','song-poetry','','[]','且柅流沙青犢車，葱葱佳氣滿城閭。',32,'全唐诗/poet.song.117000.json','["且柅流沙青犢車，葱葱佳氣滿城閭。", "白頭不解家人語，狂學司空城旦書。"]'),
('98ee133d-674b-4ce2-9ddf-bb565091d09e','甲戌除夕','方翥','宋','宋诗','song-poetry','','[]','兒女歡喜羅酒漿，夜深笑語火爐傍。',32,'全唐诗/poet.song.117000.json','["兒女歡喜羅酒漿，夜深笑語火爐傍。", "如何去歲聽風雪，身在江南夢故鄉。"]'),
('171f84b2-56aa-4373-a6ef-dbad3806a256','病起','方翥','宋','宋诗','song-poetry','','[]','淡蕩光風尋戶牖，迷濛宿霧浄園林。',32,'全唐诗/poet.song.117000.json','["淡蕩光風尋戶牖，迷濛宿霧浄園林。", "春深燕子來無數，雨後桃花落不禁。"]'),
('8f727114-32d9-4f18-beca-21b23e438b87','送虞仲房監倉歸臨安','方翥','宋','宋诗','song-poetry','','[]','宿命須同一洞天，相逢孰處故依然。',32,'全唐诗/poet.song.117000.json','["宿命須同一洞天，相逢孰處故依然。", "不知墮落青衫底，何日塵泥是了緣。"]'),
('0663f98c-a397-4a49-a83e-df4d1f6edd25','宿尊勝庵二首呈謙之  其一','方翥','宋','宋诗','song-poetry','','[]','天寒古寺往來希，門掩柴爐晝共圍。',32,'全唐诗/poet.song.117000.json','["天寒古寺往來希，門掩柴爐晝共圍。", "細雨無聲潛自落，開簾時復見霏霏。"]'),
('aeb52170-9647-457c-adff-c9182e69bb4c','宿尊勝庵二首呈謙之  其二','方翥','宋','宋诗','song-poetry','','[]','陣陣山風遞雨來，夜深飄損滿庭梅。',32,'全唐诗/poet.song.117000.json','["陣陣山風遞雨來，夜深飄損滿庭梅。", "未應一等成摇落，知有人家花未開。"]'),
('2d65fa8d-9844-4573-bb5c-eceaf65b8a05','百丈漈','方翥','宋','宋诗','song-poetry','','[]','斷崖日夕自撞舂，未近先看氣象雄。',32,'全唐诗/poet.song.117000.json','["斷崖日夕自撞舂，未近先看氣象雄。", "萬壑不停雷隠隠，一川長覺雨濛濛。"]'),
('090913ac-0fd6-4c5b-8f79-d6443ffa12c4','紫微','方翥','宋','宋诗','song-poetry','','[]','學得天文夜睡遲，雲籠月照恨星稀。',32,'全唐诗/poet.song.117000.json','["學得天文夜睡遲，雲籠月照恨星稀。", "而今病眼都無力，猶向簷邊認紫微。"]'),
('df3f70c1-2cc8-4db0-853f-e04b70ec41df','再至北鄉幹歸路中作','方翥','宋','宋诗','song-poetry','','[]','遠山馬首尚相隨，近岸迎人勢却迴。',32,'全唐诗/poet.song.117000.json','["遠山馬首尚相隨，近岸迎人勢却迴。", "鸜鵒食殘松子落，虹霓飲過水聲來。"]'),
('2126a65a-262f-473e-ba03-3f3843c78c24','謂柔立兄','方翥','宋','宋诗','song-poetry','','[]','雞犬還家自識村，重營生理長兒孫。',64,'全唐诗/poet.song.117000.json','["雞犬還家自識村，重營生理長兒孫。", "時平戰地逢華屋，歲久他鄉是故園。", "別後塵埃如我老，歸來耆舊幾人存。", "雁行疇昔從游者，莫話凋零恐斷魂。"]'),
('9c94141b-3a9e-494e-b102-2852b65c754d','出戶','方翥','宋','宋诗','song-poetry','','[]','出戶春光刮眼明，遠雲遲日慶初晴。',32,'全唐诗/poet.song.117000.json','["出戶春光刮眼明，遠雲遲日慶初晴。", "偶來傍樹尋梅子，時聽新蟬葉底聲。"]'),
('8616e1d8-58e8-449e-ac25-600d1a42295e','詩一首','方翥','宋','宋诗','song-poetry','','[]','江山入眼昔無殊，只有人事堪嗟歔。',136,'全唐诗/poet.song.117000.json','["江山入眼昔無殊，只有人事堪嗟歔。", "權門雜沓行苞苴，屠兒販客紆青朱。", "梵儀膜拜參浮屠，癡兒嬌子不識書。", "淫坊博塞爲歡娛，金章下堂揖老胥，老胥分庭抗士儒。", "身裹道衣臂佛珠，歲時入謁何易于。", "羊肩斗酒清而腴，酬酢偃蹇以字呼。", "官家赤子元何辜，一毫枉直憑青蚨。", "十八年前此事無，作詩一笑君應呼。"]'),
('c8c3967c-00b3-478c-842a-b43f79b456c0','寺中別林謙之兼寄諸鄭','方翥','宋','宋诗','song-poetry','','[]','遊從忘朝晡，尊酒輕招呼。',96,'全唐诗/poet.song.117000.json','["遊從忘朝晡，尊酒輕招呼。", "笑語恣玩狎，翻覆雲雨疎。", "我友數君子，古心相與娛。", "每見輒賓敬，衣裳儼而趨。", "惡石寓規誡，美疢疾佞諛。", "深山足風雨，零落梅花株。", "亭亭巖上松，霜姿一何孤。", "感茲各努力，勿以歲事徂。"]'),
('49fecf14-c38b-4cfb-a9ff-6289cec7797e','冬夜憶謙之','方翥','宋','宋诗','song-poetry','','[]','忽憶夫君阻笑言，出門南望欲飛翻。',64,'全唐诗/poet.song.117000.json','["忽憶夫君阻笑言，出門南望欲飛翻。", "孤誠隔水初浸夜，畫角因風自入村。", "短句有時隨意得，古心近日與誰論。", "未除習氣君應哂，月冷梅香易斷魂。"]'),
('98830cd0-b08c-4ed9-a2e3-3f79cd3b9384','句  其一','方翥','宋','宋诗','song-poetry','','[]','秋明河漢外，月近南斗旁。',12,'全唐诗/poet.song.117000.json','["秋明河漢外，月近南斗旁。"]'),
('fc2af456-4505-4e1d-8fba-b44040be5ae7','句  其二','方翥','宋','宋诗','song-poetry','','[]','瀨寒隠魚鼈，廟古動龍蛇。',12,'全唐诗/poet.song.117000.json','["瀨寒隠魚鼈，廟古動龍蛇。"]'),
('3fa35822-8c1e-4a16-8d12-c063a96ac38e','句  其三','方翥','宋','宋诗','song-poetry','','[]','山寒一杯酒，歲晚兩窮人。',12,'全唐诗/poet.song.117000.json','["山寒一杯酒，歲晚兩窮人。"]'),
('0c9c95de-4d6f-48be-b110-3b50cee9c73e','句  其四','方翥','宋','宋诗','song-poetry','','[]','可惜聽泉夜，還當殘月時。',12,'全唐诗/poet.song.117000.json','["可惜聽泉夜，還當殘月時。"]'),
('400d9523-14f7-444f-b8e7-1ae24162ed66','句  其五','方翥','宋','宋诗','song-poetry','','[]','上書北闕妨何事，笑殺孤寒孟浩然。',16,'全唐诗/poet.song.117000.json','["上書北闕妨何事，笑殺孤寒孟浩然。"]'),
('14bd80e3-be67-4b7c-b94b-09a03debc11e','句  其六','方翥','宋','宋诗','song-poetry','','[]','無端正踏江南路，暮雪蕭騷滿客衣。',16,'全唐诗/poet.song.117000.json','["無端正踏江南路，暮雪蕭騷滿客衣。"]'),
('cec24f91-ea02-4534-98c8-fe7774a935a2','仙霞道中阻雨','黄公度','宋','宋诗','song-poetry','','[]','薄暮雨霏霏，歸心恨不飛。',48,'全唐诗/poet.song.117000.json','["薄暮雨霏霏，歸心恨不飛。", "客程三日阻，家舍半年違。", "澗澀水爭道，山空雲觸衣。", "憑誰洗光手，取出太陽輝。"]'),
('212f6800-39a4-426f-bef5-8ce11d162e8a','題金沙驛','黄公度','宋','宋诗','song-poetry','','[]','閩越飽溪山，何如蜀道難。',48,'全唐诗/poet.song.117000.json','["閩越飽溪山，何如蜀道難。", "驛行仍怯嶺，舟駛復憂灘。", "行李三秋杪，居民百戰殘。", "今宵投宿處，茅店倚層巒。"]'),
('206c02fe-aec1-408e-9b47-a51ab98d13e8','過使華亭悼七友','黄公度','宋','宋诗','song-poetry','','[]','惡石亂崢嶸，胡爲君此行。',48,'全唐诗/poet.song.117000.json','["惡石亂崢嶸，胡爲君此行。", "功名成底事，舟檝誤平生。", "天遠寧容問，灘流本自鳴。", "林猿如會意，故作斷腸聲。"]'),
('596f1376-a9ec-46cc-b591-adf3a4a3c022','奧村晚望','黄公度','宋','宋诗','song-poetry','','[]','山逐寒雲斷，天隨暮靄低。',48,'全唐诗/poet.song.117000.json','["山逐寒雲斷，天隨暮靄低。", "稻畦迷上下，樵徑自東西。", "故國存書劒，他鄉尚鼓鼙。", "涓埃期補報，未敢卜幽棲。"]'),
('1d9320dd-7b18-4a8b-824f-54dbccea732c','初秋夜坐','黄公度','宋','宋诗','song-poetry','','[]','納凉北窗下，景象有餘清。',48,'全唐诗/poet.song.117000.json','["納凉北窗下，景象有餘清。", "林暝惟螢影，庭幽但竹聲。", "語闌驚坐久，露重覺衣輕。", "不寐饒詩思，徘徊參斗橫。"]'),
('53608e1d-49e1-4c2a-9eb0-6209107d4f8f','久雨阻西郊之遊','黄公度','宋','宋诗','song-poetry','','[]','忽忽春將半，冥冥雨未休。',48,'全唐诗/poet.song.117000.json','["忽忽春將半，冥冥雨未休。", "過從喧屐齒，追賞負觥籌。", "詩句那排悶，鶑聲巧喚愁。", "晴郊饒勝槩，何日許同遊。"]'),
('68c756d7-bfab-4560-a25b-18dcabad8b4b','和宋永四兄集句','黄公度','宋','宋诗','song-poetry','','[]','時事干戈裏，年光卷帙中。',48,'全唐诗/poet.song.117000.json','["時事干戈裏，年光卷帙中。", "有懷憂社稷，無力靖華戎。", "世路日多梗，齋扉晝掩蓬。", "悲歌撫長鋏，爽颯氣摩空。"]'),
('109d0b5d-3395-44bc-9749-e5639992fcf3','會同年共樂臺','黄公度','宋','宋诗','song-poetry','','[]','蘭省三千士，莆陽十五人。',48,'全唐诗/poet.song.117000.json','["蘭省三千士，莆陽十五人。", "此時鄉曲會，異日廟堂身。", "名塞乾坤隘，恩沾雨露新。", "天邊三鴈遠，回首獨凝神。"]'),
('ef0f0a11-34e4-4c84-a42d-a6215fba8c88','賀孫使君','黄公度','宋','宋诗','song-poetry','','[]','文宿動三吳，于門應大儒。',72,'全唐诗/poet.song.117000.json','["文宿動三吳，于門應大儒。", "中秋寒律近，九葉瑞蓂敷。", "錦被棲郎舍，朱幡鎮海隅。", "金鰲淹從橐，銅虎暫分符。", "德蔭紛桃李，仁風暖袴襦。", "祝公椿壽永，千歲贊蘿圖。"]'),
('37b5bb25-59af-4286-a446-077d187fb54a','次韻宋永兄傷時二首  其一','黄公度','宋','宋诗','song-poetry','','[]','舉目江河異，傷心漢闕低。',48,'全唐诗/poet.song.117000.json','["舉目江河異，傷心漢闕低。", "未聞胡折北，誰復將征西。", "志苦甘嘗膽，身先願執鼙。", "時惟王事急，六月尚棲棲。"]'),
('fe874cce-d116-4aaa-b468-b5d7b8826755','次韻宋永兄傷時二首  其二','黄公度','宋','宋诗','song-poetry','','[]','目斷吳天遠，魂飛楚塞低。',48,'全唐诗/poet.song.117000.json','["目斷吳天遠，魂飛楚塞低。", "六龍巡漠北，萬騎遶淮西。", "寒月籠烟燧，霜風遞曉鼙。", "征夫蝴蝶夢，休傍故園棲。"]'),
('7f719e33-90dd-4410-b23c-f5cf6e81afac','和徐子由題晝寂軒','黄公度','宋','宋诗','song-poetry','','[]','木落孤城迥，苔封古寺深。',48,'全唐诗/poet.song.117000.json','["木落孤城迥，苔封古寺深。", "結廬依近地，隠几愜幽心。", "細草秋仍綠，脩篁晚更陰。", "紅塵門外路，六轡漫如琴。"]'),
('671d7da9-2ae1-4fec-979b-cb1d6f59d899','戲集老杜句再和','黄公度','宋','宋诗','song-poetry','','[]','背堂資僻遠，要路亦高深。',48,'全唐诗/poet.song.117000.json','["背堂資僻遠，要路亦高深。", "未負幽棲志，回看不住心。", "寒花隠亂草，飛鳥度層陰。", "獨遶荒齋徑，新詩近玉琴。"]'),
('8b3427e5-e427-41f2-b909-2147603ca997','次方咨謀韻賀鄭宋英弄璋','黄公度','宋','宋诗','song-poetry','','[]','渥漥産龍種，筦簟兆熊禧。',164,'全唐诗/poet.song.117000.json','["渥漥産龍種，筦簟兆熊禧。", "木星光芒舒紫焰，玉出崑山珠出隋。", "徐卿憂何有，于門高可期。", "啼聲已識是英物，成立行看少壯時。", "瓦盆盛酒醺四座，我獨不許陪宗支。", "眼穿難望葱牙鏹，吻燥不沾荷葉巵。", "涓滴於人甘分絕，枯腸强索祝兒詩。", "祝兒效張良，熟讀韜鈐爲帝師。", "祝兒效陳平，磊落胸中吐六奇。", "天驕捧首遁漠北，豈容郊壘尚纍纍。", "勿效文章致身者，畫餠虛名天下知。"]'),
('c50cd34e-b675-4a9c-a4fc-4506840fe5de','松峰菴即席示同年','黄公度','宋','宋诗','song-poetry','','[]','才子連鑣俯近坰，霜風散逐馬蹄輕。',64,'全唐诗/poet.song.117000.json','["才子連鑣俯近坰，霜風散逐馬蹄輕。", "芳樽屢約同年會，要路行看異日情。", "境僻却嫌絲管沸，坐闌轉覺笑談清。", "松峰自此宣高價，不使慈恩獨擅名。"]'),
('b457bb58-6839-426a-bb33-8f004598450e','徯諸同年和章久之無耗再用前韻','黄公度','宋','宋诗','song-poetry','','[]','勞君携酒出郊坰，强緝巴詞醉墨輕。',64,'全唐诗/poet.song.117000.json','["勞君携酒出郊坰，强緝巴詞醉墨輕。", "我輩詎能捐習氣，伊人底事寡詩情。", "漫令抆目朝朝望，無復揮毫字字清。", "冷淡生涯殊不惡，想應著意諱窮名。"]'),
('573b20bb-2413-4ae5-9931-1a9100b6b7fc','庚申元日','黄公度','宋','宋诗','song-poetry','','[]','繭足度殘臘，回頭又一年。',48,'全唐诗/poet.song.117000.json','["繭足度殘臘，回頭又一年。", "文書疎病眼，事業付高眠。", "盥櫛從朝懶，衾裯覺夜便。", "南隣競春色，車馬日喧闐。"]'),
('63629ecf-33cd-4bef-97d7-05bae92c249d','陪孫使君宴歸路口占呈應求宋永二兄','黄公度','宋','宋诗','song-poetry','','[]','五馬風流在，昇平笑樂空。',48,'全唐诗/poet.song.117000.json','["五馬風流在，昇平笑樂空。", "時難寸心異，歲晚一樽同。", "畫角寒雲外，籃輿暮雨中。", "歸來狎兒女，殘燭耿紗籠。"]'),
('27093a9f-9610-4ad7-9735-502e6f3d180d','早春紅梅盛開有感  其一','黄公度','宋','宋诗','song-poetry','','[]','不與雪霜分素艷，却隨桃杏競芳辰。',32,'全唐诗/poet.song.117000.json','["不與雪霜分素艷，却隨桃杏競芳辰。", "自知孤潔羣心妒，故著微紅伴早春。"]'),
('851c5e5b-51ec-483a-92be-fe1603952e04','早春紅梅盛開有感  其二','黄公度','宋','宋诗','song-poetry','','[]','少年桃李競青春，回顧寒梅已丈人。',32,'全唐诗/poet.song.117000.json','["少年桃李競青春，回顧寒梅已丈人。", "强欲施朱追俗好，誰知翻是失天真。"]'),
('c5850a29-1045-418f-b5ce-ca7a98aa5f52','正月晦日寄宋永兄','黄公度','宋','宋诗','song-poetry','','[]','萬事縈心空歲月，一分春色已塵埃。',64,'全唐诗/poet.song.117000.json','["萬事縈心空歲月，一分春色已塵埃。", "簷前雨脚何時斷，陌上遨頭幾日來。", "寒束幽花如有待，風延啼鳥苦相催。", "明年此會各南北，趁取官閒共酒杯。"]'),
('114ad8a6-9441-407a-a913-06c1d674129d','和陳應求韻兼呈方次雲','黄公度','宋','宋诗','song-poetry','','[]','策蹇衝泥到野扉，故人相對破愁眉。',64,'全唐诗/poet.song.117000.json','["策蹇衝泥到野扉，故人相對破愁眉。", "話因別久卒難盡，情逐杯深那更辭。", "十里雲山乖素約，一番桃李負幽期。", "蕭蕭半夜空階雨，亂滴枯腸百斛詩。"]'),
('87615d54-8c54-49d0-99c7-26700f1fff18','次雲見過留宿有詩因賡其韻二首  其一','黄公度','宋','宋诗','song-poetry','','[]','茅舍囂塵外，青燈笑語中。',48,'全唐诗/poet.song.117000.json','["茅舍囂塵外，青燈笑語中。", "相逢今夕欵，忽憶去年同。", "瓶澀傾無綠，爐寒撥更紅。", "卧聞窗雨響，簷溜受斜風。"]'),
('e5778b1a-44ce-4cf7-baeb-c357a054ff26','次雲見過留宿有詩因賡其韻二首  其二','黄公度','宋','宋诗','song-poetry','','[]','惜別情無頼，狂吟意有餘。',48,'全唐诗/poet.song.117000.json','["惜別情無頼，狂吟意有餘。", "琴尊閒院落，花柳暗村墟。", "行樂真聊爾，論交莫後予。", "裹糧山下約，來往未應疎。"]'),
('e2bc4257-d53b-42af-9d1c-0e4d55afdbc6','家僮歸得王慶長消息知留浙中秋舉','黄公度','宋','宋诗','song-poetry','','[]','倦僕去復返，憐君歸未能。',48,'全唐诗/poet.song.117000.json','["倦僕去復返，憐君歸未能。", "吟餘幽砌月，夢破短檠燈。", "地僻人稀到，書成雁莫憑。", "秋風霜翮健，天末看飛騰。"]'),
('0f31a52e-8809-4ba0-80ef-15cc38170746','春日懷王慶長','黄公度','宋','宋诗','song-poetry','','[]','夜雨纔霑地，朝暉已照牆。',48,'全唐诗/poet.song.117000.json','["夜雨纔霑地，朝暉已照牆。", "潤畦舒菜甲，暖樹拆茶槍。", "胡虜潛沙磧，關河息戰場。", "王孫緣底事，萍迹久他鄉。"]'),
('b942a043-e418-4310-af6a-373b38893352','久不得浙耗','黄公度','宋','宋诗','song-poetry','','[]','獨酌澆愁酒，慵翻信手書。',48,'全唐诗/poet.song.117000.json','["獨酌澆愁酒，慵翻信手書。", "折腰行俗吏，投足且吾廬。", "歲月鶑聲老，江湖雁影踈。", "依棲五侯第，旅食近何如。"]'),
('18351d9c-5649-421b-bb0a-25a803c76c02','贈弟稚圭別','黄公度','宋','宋诗','song-poetry','','[]','行色動高蓋，題詩寄短箋。',48,'全唐诗/poet.song.117000.json','["行色動高蓋，題詩寄短箋。", "離亭春草外，吉水暮雲邊。", "鵰鶚摶霜翅，驊騮受玉鞭。", "槐黄須努力，好語及秋天。"]'),
('4172ce27-f236-4384-9ad2-fe2d268da0e4','寄呈察推二兄廷直','黄公度','宋','宋诗','song-poetry','','[]','尺素書憑雁足傳，側身吟望楚江邊。',64,'全唐诗/poet.song.117000.json','["尺素書憑雁足傳，側身吟望楚江邊。", "關山去我仍千里，風月思君閲二年。", "蓮幕宦情今好在，莆川春色故依然。", "相逢若問官閒事，爲道粗裘飽晝眠。"]'),
('16a89b76-f149-4131-a7f2-f857702dde88','漫成','黄公度','宋','宋诗','song-poetry','','[]','時事含胡裏，年華轉燭間。',48,'全唐诗/poet.song.117000.json','["時事含胡裏，年華轉燭間。", "利名多噂沓，貧賤覺安閒。", "致主知無術，歸休幸有山。", "茅堂一尊酒，時得慰愁顔。"]'),
('c4bff849-a1c1-4c44-882c-c76a5ac7262d','千里共明月','黄公度','宋','宋诗','song-poetry','','[]','僊掌露初凝，高空月迥明。',72,'全唐诗/poet.song.117000.json','["僊掌露初凝，高空月迥明。", "雪霜千里色，關塞一時情。", "永夜驚烏鵲，中原有弟兄。", "清輝憐獨對，良會苦難并。", "目斷一天遠，愁隨兩地生。", "倚樓何處笛，凄切送殘聲。"]'),
('d37d2cad-a704-48df-aa6e-ec44a644a4aa','鳥影度寒塘','黄公度','宋','宋诗','song-poetry','','[]','秋色滿瀟湘，天寒玄鳥忙。',72,'全唐诗/poet.song.117000.json','["秋色滿瀟湘，天寒玄鳥忙。", "數聲離疊嶂，片影度橫塘。", "風翮摶寥廓，烟蹤入渺茫。", "乍隨萍荇沒，還共水雲長。", "冷浸千尋碧，斜侵兩岸霜。", "凝眸西塞遠，踈點带殘陽。"]'),
('96869762-63c8-497c-886d-3d1de34631c0','和余子美即事二首  其一','黄公度','宋','宋诗','song-poetry','','[]','昏昏午汗浹桃笙，醒眼清詩仗友生。',64,'全唐诗/poet.song.117000.json','["昏昏午汗浹桃笙，醒眼清詩仗友生。", "俘馘遥傳泮水捷，琴書初解杏壇盟。", "開尊頼有論文酒，舍肉應無遺母羹。", "好種桑麻歸杜曲，行藏休更問君平。"]'),
('c511b172-9b46-4ea7-bb3c-dda319f7e7b3','和余子美即事二首  其二','黄公度','宋','宋诗','song-poetry','','[]','黌堂歸去葛衣輕，怪底形容太瘦生。',64,'全唐诗/poet.song.117000.json','["黌堂歸去葛衣輕，怪底形容太瘦生。", "抖擻慳囊償酒債，安排嶮韻主詩盟。", "妖韶梅老自餘態，滋味韓休薄大羹。", "强策駑駘追逸駕，不堪才力但平平。"]'),
('f336f364-d4b9-4cc6-8dbb-e1364512ea79','夏日陳應求見訪','黄公度','宋','宋诗','song-poetry','','[]','酷暑避脩竹，繁陰侵短楹。',48,'全唐诗/poet.song.117000.json','["酷暑避脩竹，繁陰侵短楹。", "形骸方枕簟，車馬忽柴荆。", "對酒情無極，哦詩韻更清。", "昏鴉催別急，天末片雲橫。"]'),
('139a171e-e7e8-4025-9968-54bdc2e69083','苦熱','黄公度','宋','宋诗','song-poetry','','[]','玉井晨不冷，茅簷午欲焚。',48,'全唐诗/poet.song.117000.json','["玉井晨不冷，茅簷午欲焚。", "月摇看畫箑，榴吐認紅裙。", "迥野都如火，奇峰空自雲。", "衣巾負芒刺，曝背有人耘。"]'),
('9a1caa73-c1c6-4a4d-ba8f-38316d99a039','秋興二首  其一','黄公度','宋','宋诗','song-poetry','','[]','秋入蒹葭霜正威，數聲歸雁塞痕微。',64,'全唐诗/poet.song.117000.json','["秋入蒹葭霜正威，數聲歸雁塞痕微。", "欺人白髮蕭蕭得，未老丹楓故故飛。", "胡虜乾坤多戰骨，江湖風雨一蓑衣。", "百年粗飯從衰朽，萬事塵寰有是非。"]'),
('b5c40216-d7bb-4348-8abc-da31709bcb91','秋興二首  其二','黄公度','宋','宋诗','song-poetry','','[]','牙叉老木抱江城，城古江寒相對清。',64,'全唐诗/poet.song.117000.json','["牙叉老木抱江城，城古江寒相對清。", "雲雁不逢音信杳，沙鷗無數往來輕。", "露華今夜凝僊掌，詞藻他年動帝京。", "淮海一身猶卧病，關河千里未休兵。"]'),
('0f419580-0f2f-4343-bc3f-e8b8800fd7c7','和宋永兄詠荔支用東坡刑字韻四首  其一','黄公度','宋','宋诗','song-poetry','','[]','枝頭血色萬年萍，錯落橫天粲彗星。',64,'全唐诗/poet.song.117000.json','["枝頭血色萬年萍，錯落橫天粲彗星。", "昔日楊姬勞走驛，一時王姥欲俱刑。", "浪傳石蜜來他域，巧似珊瑚出漲溟。", "僊種世傳工益壽，飽嘗端勝衛生經。"]'),
('21d7cafc-61ed-46fb-b66b-f68a375164b2','和宋永兄詠荔支用東坡刑字韻四首  其二','黄公度','宋','宋诗','song-poetry','','[]','蜜甜誰數楚江萍，枉道偷桃是歲星。',64,'全唐诗/poet.song.117000.json','["蜜甜誰數楚江萍，枉道偷桃是歲星。", "長夏日烘憐國色，去年霜薄赦秋刑。", "侯堂舊許祠南海，使驛曾勞走北溟。", "名種尚堪重品第，未甘陸羽著茶經。"]'),
('5c031ee4-1b4c-4f36-aa66-7f5790027efa','和宋永兄詠荔支用東坡刑字韻四首  其三','黄公度','宋','宋诗','song-poetry','','[]','脩竹繁陰覆綠萍，壓牆朱實鬭星星。',64,'全唐诗/poet.song.117000.json','["脩竹繁陰覆綠萍，壓牆朱實鬭星星。", "明珠落掌驪龍睡，丹殻歸盤白馬刑。", "曾指畫圖誇北客，至今漬蜜動南溟。", "可憐傖父流涎久，何日烏山始一經。"]'),
('c5637cc1-b1de-4b18-9293-f470c727b2d3','和宋永兄詠荔支用東坡刑字韻四首  其四','黄公度','宋','宋诗','song-poetry','','[]','一時紅紫逐飄萍，風雨殘枝尚綴星。',64,'全唐诗/poet.song.117000.json','["一時紅紫逐飄萍，風雨殘枝尚綴星。", "西國葡萄甘僕隸，白家躑躅强儀刑。", "誰移僊種從丹府，不使靈荄遍八溟。", "大業豪華今寂寞，佳名空著海山經。"]'),
('2e358006-e93e-49c1-a514-c7b4ca0378f8','寄林謙之','黄公度','宋','宋诗','song-poetry','','[]','冰壺玉麈逼人寒，忽漫過逢豁肺肝。',64,'全唐诗/poet.song.117000.json','["冰壺玉麈逼人寒，忽漫過逢豁肺肝。", "千載有人扶古道，一時傾蓋盡儒冠。", "不妨我輩詩腸在，要取他年酒量寬。", "萬卷白頭成底事，販屠之輩任艱難。"]'),
('4ed0aae1-2a0c-46c6-9048-6c56b9ebbf9a','方次雲伏枕久不入城獨宿知稼堂有懷','黄公度','宋','宋诗','song-poetry','','[]','吹笛清宵何處聲，隔窗斜月聽人行。',64,'全唐诗/poet.song.117000.json','["吹笛清宵何處聲，隔窗斜月聽人行。", "夢回案上青熒火，魂斷城頭長短更。", "三伏故人憐卧病，百年薄宦任浮生。", "春風尚憶茅堂話，相對哦詩天未明。"]'),
('7faa2095-bc8e-4e1c-9f38-53a28b580e04','贈日者黄明遠','黄公度','宋','宋诗','song-poetry','','[]','幅巾別我五周星，今日相逢眼暫明。',32,'全唐诗/poet.song.117000.json','["幅巾別我五周星，今日相逢眼暫明。", "一第男兒身自致，曾將蹤跡問君平。"]'),
('ef5ec29e-4336-4046-8e86-f545f6386cbb','迓泉守晚宿囊山','黄公度','宋','宋诗','song-poetry','','[]','山木轉斜暉，秋風動客衣。',48,'全唐诗/poet.song.117000.json','["山木轉斜暉，秋風動客衣。", "露華侵坐冷，星宿傍簷稀。", "樓迥鐘聲隠，更長燭影微。", "年來倦奔走，早覺利名非。"]'),
('2f2794fe-8251-47e9-91bf-545d993295fd','慈竹','黄公度','宋','宋诗','song-poetry','','[]','慈竹陰初合，新梢翠欲流。',48,'全唐诗/poet.song.117000.json','["慈竹陰初合，新梢翠欲流。", "晚摇千尺影，冷撼一堂秋。", "笋迸苔痕拆，葉蒙山色幽。", "鳳凰棲息穩，端爲此君留。"]'),
('b7b09b4d-b2fc-42da-9029-48162efcba7d','返照','黄公度','宋','宋诗','song-poetry','','[]','返照隠西山，烟村一水間。',48,'全唐诗/poet.song.117000.json','["返照隠西山，烟村一水間。", "路長人自急，林暮鳥知還。", "楓巷秋常掃，蓬門夜不關。", "風塵猶劇盜，歲月但催顔。"]'),
('688127dd-1edc-4536-ad11-1b08b9e97011','倚薄','黄公度','宋','宋诗','song-poetry','','[]','茅簷供倚薄，藜杖費扶携。',48,'全唐诗/poet.song.117000.json','["茅簷供倚薄，藜杖費扶携。", "天入平蕪濶，山含宿靄低。", "樹聲風便旋，野色晚凄迷。", "容易營生事，秋田稻欲齊。"]'),
('22c84817-72d0-4c11-b69c-9ef2945e4a95','迓楊守宿九峰','黄公度','宋','宋诗','song-poetry','','[]','木落閩山暮，雲深野寺秋。',48,'全唐诗/poet.song.117000.json','["木落閩山暮，雲深野寺秋。", "寒花空照眼，濁酒不禁愁。", "宦拙羞奔走，時危且滯留。", "迥廊供徙倚，萬慮寄冥搜。"]'),
('d6b4d7ad-5ac2-4498-a032-d0dfe9218f39','偕方次雲餞孫守月下同歸戲成','黄公度','宋','宋诗','song-poetry','','[]','北陌爭迎丞相車，南郡新分刺史符。',160,'全唐诗/poet.song.117000.json','["北陌爭迎丞相車，南郡新分刺史符。", "弩矢紛紛夾道趨，旌旗獵獵照通衢。", "一時冠蓋事奔走，車馬不許停斯須。", "賢愚貴賤俱物役，始覺名利真區區。", "我亦年來忝簪紱，苛禮羈人日湮汩。", "往來叨沐主人恩，陶母不恪千金髮。", "平明聯轡逐西風，歸路三更踏明月。", "解貂野店貰濁酒，醉罷高譚偃溟渤。", "風塵薄宦君勿悲，猶勝低回場屋時。", "烏帽白袍青竹榻，短檠終夜照紅蠟。"]'),
('709c3064-f12e-4007-be14-99d7af8bb1f2','奉別王宰先之','黄公度','宋','宋诗','song-poetry','','[]','畫角城頭繞怨音，秋風握手別杯深。',64,'全唐诗/poet.song.117000.json','["畫角城頭繞怨音，秋風握手別杯深。", "三年故國相從地，萬里青雲欲別心。", "醉罷林霜催菊老，夢回江月轉棠陰。", "預愁曉色離亭外，衰草撩人思不禁。"]'),
('a97ad5f5-2ec1-4eaa-bc75-44649e6c0ef7','醉中別李元泰','黄公度','宋','宋诗','song-poetry','','[]','同雲幕幕暗前山，急雨颼颼釀小寒。',64,'全唐诗/poet.song.117000.json','["同雲幕幕暗前山，急雨颼颼釀小寒。", "桃花欲開尚羞澀，梅梢已老半闌珊。", "話別一尊休草草，丈夫相識期歲老。", "綈袍萬一未忘情，春風莫惜歸來早。"]'),
('a70ebf89-5394-4fcf-8e49-9c7082cf8389','和陳應求春日見寄','黄公度','宋','宋诗','song-poetry','','[]','滿目繁春事，題詩寄所思。',48,'全唐诗/poet.song.117000.json','["滿目繁春事，題詩寄所思。", "輕寒欺酒力，宿雨褪花姿。", "經世知無術，追歡要及時。", "郊原賸晴景，莫負去年期。"]'),
('9572cd06-c79b-4439-80a0-975f148c6515','和余子美春日緩步','黄公度','宋','宋诗','song-poetry','','[]','道屈時危且茹藜，不妨去魯儘遲遲。',64,'全唐诗/poet.song.117000.json','["道屈時危且茹藜，不妨去魯儘遲遲。", "一軒容膝分藍宇，十里携筇闖麥岐。", "杜老皓頭真可惜，陶潛知命更奚疑。", "干戈淮上無消息，愁絕南山獨步時。"]'),
('3b6b7abc-0333-41d3-a839-ec0a00024137','山行即事二首  其一','黄公度','宋','宋诗','song-poetry','','[]','落石奔沙岸，頹雲擁樹根。',48,'全唐诗/poet.song.117000.json','["落石奔沙岸，頹雲擁樹根。", "牛羊千古道，雞犬數家村。", "風遞隣舂急，春歸農事繁。", "生涯隨處樂，翁嫗話柴門。"]'),
('ae12dcca-fee1-4170-997a-e5a77ffcd594','山行即事二首  其二','黄公度','宋','宋诗','song-poetry','','[]','席改尊猶在，心閒屐自遲。',48,'全唐诗/poet.song.117000.json','["席改尊猶在，心閒屐自遲。", "角巾欹短樹，風带罥踈籬。", "作難憂胡羯，全生混野麋。", "晚來幽意愜，歸路恐多岐。"]'),
('819dbbb5-0d5d-4086-9c9e-04dbfcdb6e42','宿鷲峰菴題壁兼呈林孚卿諸友','黄公度','宋','宋诗','song-poetry','','[]','抱被招提聽晚鐘，昔遊回首七春風。',64,'全唐诗/poet.song.117000.json','["抱被招提聽晚鐘，昔遊回首七春風。", "斬新花木軒窗外，依舊樓臺烟靄中。", "永夜篝燈元自照，故人尊酒偶然同。", "明年此日看騰踏，先數班楊賦律工。"]'),
('41845eba-6933-410c-a532-4f7b6627beba','和龔實之聞虜人敗盟','黄公度','宋','宋诗','song-poetry','','[]','請纓未係單于頸，置火須然董卓臍。',64,'全唐诗/poet.song.117000.json','["請纓未係單于頸，置火須然董卓臍。", "列郡奔馳喧羽檄，聖朝哀痛下芝泥。", "盟寒關隴無來使，春晚江淮有戰鼙。", "十載枕邊憂國泪，不堪幽夢破晨雞。"]'),
('b50dd60b-43cb-4558-bd76-339c227f1141','和宋永兄春日閒居','黄公度','宋','宋诗','song-poetry','','[]','負郭濃春事，高齋闢曉關。',48,'全唐诗/poet.song.117000.json','["負郭濃春事，高齋闢曉關。", "晴雲浮越嶠，芳草接荆蠻。", "祿薄難長飽，才微分久閒。", "年華兵甲裏，吁駭鏡中顔。"]'),
('95c4391e-a3de-40c7-88f0-ef2adecbaef5','喜雨','黄公度','宋','宋诗','song-poetry','','[]','皇天嗇甘澤，爲農生理休。',72,'全唐诗/poet.song.117000.json','["皇天嗇甘澤，爲農生理休。", "哀哉桑麻瘁，得意蓬蒿稠。", "一夜溜簷雨，曉屋喧鳴鳩。", "驚濤注空壑，秀色溢平疇。", "田舍無宿儲，及此寬百憂。", "陌上誰家郎，惟恐阻春遊。"]'),
('90f8c186-c752-4749-ae7d-9669b5d0b662','偕徐子由余子侯陳應求游虎丘巖偶題壁韻叶因分字聯句','黄公度','宋','宋诗','song-poetry','','[]','一室函滄海，羣公半列侯。',48,'全唐诗/poet.song.117000.json','["一室函滄海，羣公半列侯。", "放懷追許謝，洗耳笑巢由。", "花暖蜂相趁，泥香燕自求。", "杖藜窮勝境，染筆記春遊。"]'),
('88a896e1-378e-4c31-9172-a7aad1060e66','題翠峰寺西軒','黄公度','宋','宋诗','song-poetry','','[]','寂寂春葩映短牆，半山松竹奏笙簧。',32,'全唐诗/poet.song.117000.json','["寂寂春葩映短牆，半山松竹奏笙簧。", "無情幽鳥背人去，不慣村童笑客狂。"]'),
('8d7fd86a-db39-439a-a0af-83e8fc213045','送龔實之赴官南安十韻','黄公度','宋','宋诗','song-poetry','','[]','氣合論文地，魂銷惜別筵。',120,'全唐诗/poet.song.117000.json','["氣合論文地，魂銷惜別筵。", "離亭芳草外，飛蓋落花前。", "北闕舊通籍，南州先著鞭。", "郤詵丹桂早，萊子綵衣鮮。", "側耳聆佳政，成名及妙年。", "因風能見憶，得句會須傳。", "筮仕聊棲棘，駑才阻泛蓮。", "交情期歲晚，會面數秋天。", "莆水浮春樹，桐城際暮烟。", "龔黄真忝竊，末路共騰騫。"]'),
('1bc3a357-dfdf-4db9-ba9c-71b62dbf4f9e','暮春山間','黄公度','宋','宋诗','song-poetry','','[]','緩步春山春日長，流鶑不語燕飛忙。',32,'全唐诗/poet.song.117000.json','["緩步春山春日長，流鶑不語燕飛忙。", "桃花落處無人見，濯手惟聞澗水香。"]'),
('5ba347dd-2a0c-4e06-bcaa-bbcbfccdf984','閒居','黄公度','宋','宋诗','song-poetry','','[]','一水遠能白，羣山陰更青。',48,'全唐诗/poet.song.117000.json','["一水遠能白，羣山陰更青。", "靜憐風細細，閒任雨冥冥。", "春色供多病，時情畏獨醒。", "平生憂國意，客至問朝廷。"]'),
('52718e62-26d8-4ecf-bacd-932960ea8d74','次韻余子侯遊石泉','黄公度','宋','宋诗','song-poetry','','[]','竹杖椶鞋意自便，蘚牆莎徑色相鮮。',64,'全唐诗/poet.song.117000.json','["竹杖椶鞋意自便，蘚牆莎徑色相鮮。", "平疇漲麥雲連海，絕壁蟠松蓋倚天。", "竟日虎巖延眺矚，何時蟹井費攀緣。", "歸來幽獨不成寢，山月侵廊鐘韻圓。"]'),
('3f60b3de-ff43-4b08-8052-1561c02e88d7','秋日晚晴懷南山舊遊','黄公度','宋','宋诗','song-poetry','','[]','霽色孤城外，秋聲獨樹邊。',48,'全唐诗/poet.song.117000.json','["霽色孤城外，秋聲獨樹邊。", "烟雲澄遠嶼，風月渺平川。", "寇盜休何日，登臨憶去年。", "吾曹得踈放，醉墨灑層巔。"]'),
('0cf75e15-441f-465b-a02f-4761e99f1052','寄方次雲','黄公度','宋','宋诗','song-poetry','','[]','近有清源信，官期報早秋。',48,'全唐诗/poet.song.117000.json','["近有清源信，官期報早秋。", "時危從薄宦，情在惜同遊。", "簪笏趨新幕，琴書別故邱。", "君能訪茅宇，尊酒話離愁。"]'),
('e28d50ed-4ad9-4463-b16d-2c0fc392a5b1','悲秋','黄公度','宋','宋诗','song-poetry','','[]','萬里西風入晚扉，高齋悵望獨移時。',64,'全唐诗/poet.song.117000.json','["萬里西風入晚扉，高齋悵望獨移時。", "迢迢別浦帆雙去，漠漠平蕪天四垂。", "雨意欲晴山鳥樂，寒聲初到井梧知。", "丈夫感慨關時事，不學楚人兒女悲。"]'),
('a1ddfa53-81ff-4822-ab65-f07aed9f98a2','和鄭叔友題真如','黄公度','宋','宋诗','song-poetry','','[]','南郡趨新幕，微官愧野人。',48,'全唐诗/poet.song.117000.json','["南郡趨新幕，微官愧野人。", "客懷投寺晚，歸夢到家頻。", "歲月看蓬鬢，塵埃聽葛巾。", "相隨一杯酒，且慰百年身。"]'),
('e967594c-9eeb-4aa7-8d61-f99075eae835','和方次雲至日作','黄公度','宋','宋诗','song-poetry','','[]','至日空相憶，何時復此來。',48,'全唐诗/poet.song.117000.json','["至日空相憶，何時復此來。", "素書煩蠟炬，往事付寒杯。", "夢破風驚竹，詩成雨綻梅。", "江城低婺女，回首亦勞哉。"]'),
('3834d58c-4b35-4fd6-80d2-fa5fbae06662','上汪內相生日','黄公度','宋','宋诗','song-poetry','','[]','天意恢炎歷，星躔降昴精。',144,'全唐诗/poet.song.117000.json','["天意恢炎歷，星躔降昴精。", "典刑存大雅，領袖屬名卿。", "出入三朝舊，青冥萬里程。", "磨鉛周太史，視草漢承明。", "詞采今宗匠，艱危急老成。", "邃旒方側席，高纛尚專城。", "卜築鄱陽外，懸弧晉水清。", "先君桃李蔭，比屋袴襦聲。", "晝永黄堂夢，春晴綠野耕。", "日邊稽召節，幕下及稱觥。", "盛業期伊呂，脩齡頌老彭。", "一麾難久借，四海欲休兵。"]'),
('39c26564-e73e-48f2-9bf2-1ff75299c827','送鄭察推叔友罷官之潮陽二首  其一','黄公度','宋','宋诗','song-poetry','','[]','官達身何補，才名陸未沉。',48,'全唐诗/poet.song.117000.json','["官達身何補，才名陸未沉。", "不妨吾道在，休較吏文深。", "城郭春將暮，風雲晚更陰。", "相看炎海闊，魂斷欲分襟。"]'),
('fb0e1263-dd63-44be-a3bf-379266ab0fa1','送鄭察推叔友罷官之潮陽二首  其二','黄公度','宋','宋诗','song-poetry','','[]','春草故人去，落花離緒多。',48,'全唐诗/poet.song.117000.json','["春草故人去，落花離緒多。", "芙蓉少顔色，薏苡盡風波。", "塵土非長策，功名一醉歌。", "周南暫留滯，莫改歲寒柯。"]'),
('d9e1fea6-ec5b-4f16-9389-99ce4420a77f','和蔡司法南安之什','黄公度','宋','宋诗','song-poetry','','[]','一夜晴風吹曉霞，平明聯轡踏飛花。',64,'全唐诗/poet.song.117000.json','["一夜晴風吹曉霞，平明聯轡踏飛花。", "嵐光且對聖賢酒，世事僅同蠻觸蝸。", "簿領迷人春易老，漁樵滿地晝無譁。", "登臨未飽溪山興，歸路星星月照沙。"]'),
('0b3c8d5a-e010-4cc4-880d-fdd61840f51f','春雨中會西山佛迹','黄公度','宋','宋诗','song-poetry','','[]','自喜平生山水心，公餘猶及此登臨。',64,'全唐诗/poet.song.117000.json','["自喜平生山水心，公餘猶及此登臨。", "雲埋古寺鐘聲遠，花落空村烟雨深。", "是處芳尊追勝槩，幾人寒勒度踈林。", "都無春色一分在，况有塵寰萬慮侵。"]'),
('877f80dc-261f-4d5b-a315-0571bad22b98','陳晉江以壬戌四月上澣宴同僚于二公亭','黄公度','宋','宋诗','song-poetry','','[]','百年遺址俯郊坰，十里蒼波带古亭。',64,'全唐诗/poet.song.117000.json','["百年遺址俯郊坰，十里蒼波带古亭。", "隔岸樓臺春去遠，滿湖烟雨酒微醒。", "苔碑缺落庭松老，野鳥去來汀草青。", "風物不殊天竺路，扁舟髣髴舊曾經。"]'),
('947e4e12-eded-42fc-b032-795cfbac37b2','越十日陪使君汪內翰復來','黄公度','宋','宋诗','song-poetry','','[]','雅製初仍舊，佳名留至今。',48,'全唐诗/poet.song.117000.json','["雅製初仍舊，佳名留至今。", "城依刺桐古，亭入芰荷深。", "尊俎賓僚集，旌麾刺史臨。", "自公多暇日，及此豁塵襟。"]'),
('6fd48bbb-e452-4f11-86dd-c2befe58b2f9','再別鄭叔友兼寄方次雲','黄公度','宋','宋诗','song-poetry','','[]','鞍馬侵三伏，萍蓬寄一身。',48,'全唐诗/poet.song.117000.json','["鞍馬侵三伏，萍蓬寄一身。", "及秋歸計早，到日附書頻。", "炎嶺休長客，清漳有故人。", "過逢如問信，爲道各埃塵。"]'),
('87e9bf1d-d84c-4e99-b965-316fa3861891','三月三十日郊外即事','黄公度','宋','宋诗','song-poetry','','[]','雨積稻畦白，晴添麥壠黄。',48,'全唐诗/poet.song.117000.json','["雨積稻畦白，晴添麥壠黄。", "野橋排雁齒，山路轉羊腸。", "鳥語有時好，田家隨事忙。", "一年春盡日，身迹更他鄉。"]'),
('f683b0b9-48e1-4890-aded-d8fd899be326','夜坐梅樹下率爾','黄公度','宋','宋诗','song-poetry','','[]','羌吹宣重籥，胡床近小臺。',48,'全唐诗/poet.song.117000.json','["羌吹宣重籥，胡床近小臺。", "輕輕雲片度，淡淡月華開。", "壁暗雨留蘚，庭虛風落梅。", "納凉公宇邃，清夜興悠哉。"]'),
('2864aad0-0141-4307-8399-73b633c2789d','和汪端中陪府君遊東湖','黄公度','宋','宋诗','song-poetry','','[]','漢家虎璽重分銅，鑾坡厭直金蓮紅。',160,'全唐诗/poet.song.117000.json','["漢家虎璽重分銅，鑾坡厭直金蓮紅。", "海角瘡痍煩大手，循良不愧古人風。", "偃蹇霜風鈴閣寂，蒙茸春色圜扉空。", "爲郡風流見前輩，隙日車蓋飛城東。", "鰲首虛亭未泯滅，騷人古意無終窮。", "香風十里菰蒲外，喜氣一城尊俎中。", "中原景物久荆棘，南渡衣冠隨梗蓬。", "此地龜文符古讖，盛觀略與承平同。", "腐儒謬忝無雙裔，聲價遠慚吾祖童。", "青衫幕府困奔走，頼有新詩爲發聾。"]'),
('06288962-9f86-45d4-b506-814a28aa73cc','晚自東湖携藕花歸兒輩爭插盆池香艷不歇亦供兩日嗅翫因成','黄公度','宋','宋诗','song-poetry','','[]','怪底兒童無遠圖，埋盆注水插芙蕖。',32,'全唐诗/poet.song.117000.json','["怪底兒童無遠圖，埋盆注水插芙蕖。", "人心不作非真想，便覺東湖入座隅。"]'),
('0f1e9207-5e3b-4bba-9212-ff7fc5bf9cea','壬戌中秋沿檄行縣與龔實之同宿于琴泉軒','黄公度','宋','宋诗','song-poetry','','[]','摇落江城暮，招提訪舊遊。',48,'全唐诗/poet.song.117000.json','["摇落江城暮，招提訪舊遊。", "泉聲終夜雨，竹影一堂秋。", "露湛衣裳冷，山空枕簟幽。", "故人憐寂寞，抱被肯相投。"]'),
('78071acd-bac0-47d4-97ed-410d0163e80e','實之有詩復次其韻','黄公度','宋','宋诗','song-poetry','','[]','鞅掌從王事，招邀愧主人。',48,'全唐诗/poet.song.117000.json','["鞅掌從王事，招邀愧主人。", "彈琴秋葉落，聽雨夜床親。", "歲月何妨紀，詩篇莫厭頻。", "要令千載下，不但數姜秦。"]'),
('a010bc2d-dfc6-42b1-866e-cd75ab26dd0d','早發延福道間偶作錄呈','黄公度','宋','宋诗','song-poetry','','[]','夜宿姜峰寺，曉投劉店村。',48,'全唐诗/poet.song.117000.json','["夜宿姜峰寺，曉投劉店村。", "秋光隨杖屨，逸興滿郊原。", "短句時時得，何人細細論。", "鳳凰山下約，回首欲飛翻。"]'),
('7862ed6e-4733-4b7d-96fe-012d9ff2aeee','陪實之登姜峰絕頂鎸石','黄公度','宋','宋诗','song-poetry','','[]','抱琴歷高峰，拂石就晚陰。',24,'全唐诗/poet.song.117000.json','["抱琴歷高峰，拂石就晚陰。", "空山對摇落，懷哉千古心。"]'),
('e2f4268b-9dc2-4a00-8a07-dc7b5ce2e3ab','鄭山鋪用實之韻','黄公度','宋','宋诗','song-poetry','','[]','一溪清淺抱山根，山霧溪烟白晝昏。',32,'全唐诗/poet.song.117000.json','["一溪清淺抱山根，山霧溪烟白晝昏。", "負郭可能無五斗，肩輿何事走空村。"]'),
('8c534288-eeb0-4452-92aa-4a4ad0f3ef96','晚泊桃源驛奉懷幕府諸公','黄公度','宋','宋诗','song-poetry','','[]','鞍馬泊孤亭，人烟接古城。',48,'全唐诗/poet.song.117000.json','["鞍馬泊孤亭，人烟接古城。", "半村留晚照，萬壑送秋聲。", "風月思玄度，文章愧長卿。", "桃源何處在，山驛至今名。"]'),
('b63ce0ea-090d-43af-9255-5f306f56c413','秋旱熱甚尤苦登陟輿中戲成','黄公度','宋','宋诗','song-poetry','','[]','少皡不用事，八月猶苦熱。',240,'全唐诗/poet.song.117000.json','["少皡不用事，八月猶苦熱。", "南方本炎蒸，况乃甘澤闕。", "雨師弛厥職，旱魃逞餘孽。", "金石鑠欲流，汙池龜甲裂。", "稼穡亦已休，田家生理絕。", "敢意築場圃，漸聞罌瓶竭。", "租歛數有恒，不爲愆陽輟。", "州縣急錙銖，鞭箠動流血。", "吁嗟號帝閽，此語何由徹。", "空村巫覡舞，靈祠香火謁。", "水旱制於天，祈禳恐虛設。", "嘗聞桑林禱，爪犧亦清潔。", "萬國幾爲魚，堯德豈其劣。", "但令備先具，難必沴氣滅。", "江淮十萬兵，仰口資餽轍。", "太倉無宿儲，有司憂百結。", "腐儒從薄宦，籃輿走嵽嵲。", "王事有嚴程，亭午不得歇。", "林鳥呀無聲，僕夫屢告暍。", "馬得變玄冬，陰厓踏層雪。"]'),
('3cfbffa2-ad15-4ff2-a027-0210543b65bd','宿齊雲寺','黄公度','宋','宋诗','song-poetry','','[]','行李秋將老，停鞭日已西。',48,'全唐诗/poet.song.117000.json','["行李秋將老，停鞭日已西。", "深村見人少，孤寺與雲齊。", "試問霑微祿，何如返故棲。", "雞鳴不成寢，乘月下清溪。"]'),
('cf06d2a0-7f56-409f-a6c9-a2f11a6244d9','題鳳凰寺','黄公度','宋','宋诗','song-poetry','','[]','一代衣冠霸業休，半山金碧梵宮留。',64,'全唐诗/poet.song.117000.json','["一代衣冠霸業休，半山金碧梵宮留。", "傷心廢宅松榆老，滿目寒塘菡萏秋。", "馬鬣未平餘葬地，蛾眉不見但粧樓。", "憑高欲問豪華事，耆舊無人僧白頭。"]'),
('4d2e5c44-f533-4dab-8a60-2603475964db','鳳凰夜坐聯句','黄公度','宋','宋诗','song-poetry','','[]','月黑前村笛，風清俯檻琴。',120,'全唐诗/poet.song.117000.json','["月黑前村笛，風清俯檻琴。", "老苔虛殿閉，喬木故宮深。", "宿鳥依叢樹，踈鐘出斷林。", "夜堂留暑濕，秋谷半晴陰。", "事業惟欹枕，塵埃一散襟。", "勞生倦奔走，遠目寄登臨。", "割據當年事，英雄萬古心。", "青山空白骨，華屋漫黄金。", "酒薄何勞醉，詩成不廢吟。", "艱危多感慨，時序苦侵尋。"]'),
('0f3a41e5-39c2-4649-9d89-b41b048b87a5','題凉峰','黄公度','宋','宋诗','song-poetry','','[]','倚杖清秋遠，彈琴白晝長。',48,'全唐诗/poet.song.117000.json','["倚杖清秋遠，彈琴白晝長。", "笙簫離館廢，雲木晚風凉。", "往事空流水，巋心滿夕陽。", "相逢惜分手，珍重故人觴。"]'),
('16b89d25-d8b0-4042-9efc-97023e061b38','題雲臺寺','黄公度','宋','宋诗','song-poetry','','[]','西風城郭尚炎威，竟日琴尊歷翠微。',64,'全唐诗/poet.song.117000.json','["西風城郭尚炎威，竟日琴尊歷翠微。", "紅盡秋林楓正落，凉生晚寺雨初飛。", "相從歲月交情舊，此去塵埃會面稀。", "往事惟餘故侯塚，白楊衰草露霑衣。"]'),
('7b4f142b-2fe5-4145-9f70-f5c0bc4913a8','聞太母還輿喜極成歌','黄公度','宋','宋诗','song-poetry','','[]','嗚呼禍變稔前朝，都城千雉摧天驕。',128,'全唐诗/poet.song.117000.json','["嗚呼禍變稔前朝，都城千雉摧天驕。", "翠華北征沙漠遥，六宮萬里從翬褕。", "我皇龍飛守宗祧，周宣漢武見今朝。", "問安視膳阻夙宵，位極萬乘心何聊。", "大哉聖孝回天眷，萬類革心非革面。", "天邊驛騎急星電，傳報騩輿涉淮甸。", "小臣喜極手欲抃，朝坤一夜歡聲遍。", "遥想千官會星弁，拜舞稱觴長樂殿。"]'),
('dbb8c805-44a7-4858-a87a-8eeb7e49a455','題大盈驛壁','黄公度','宋','宋诗','song-poetry','','[]','西風落莫空館，暮色迷蒙遠巒。',28,'全唐诗/poet.song.117000.json','["西風落莫空館，暮色迷蒙遠巒。", "家近不妨酒盡，夜寒陡怯衣單。"]'),
('71f49fdd-d44c-4129-a2f5-7d2083df6cc1','和李元泰艷歌','黄公度','宋','宋诗','song-poetry','','[]','凉風愜人如故舊，客燕殘蟬度清晝。',64,'全唐诗/poet.song.117000.json','["凉風愜人如故舊，客燕殘蟬度清晝。", "摇落三秋楚澤悲，相思一夜東陽瘦。", "愁連黛入眉山重，猶憶去年和泪送。", "魚沉鴈斷消息稀，頻來惟有清宵夢。"]'),
('d6ad32ef-0b2f-4f98-9d40-9302121e5073','擬上張丞相','黄公度','宋','宋诗','song-poetry','','[]','五閏干戈極，炎暉歷數新。',288,'全唐诗/poet.song.117000.json','["五閏干戈極，炎暉歷數新。", "析圭綿六服，卜鼎邁千春。", "哀痛朝姦稔，夤緣國步屯。", "近畿橫彗孛，嚴禁失鈎陳。", "魏絳謀和敵，包胥日哭秦。", "翠華旋北狩，清蹕且南巡。", "霧塞紛銅馬，祥開表玉麟。", "官軍推大弟，耆老赴仁人。", "唐祚興靈武，昭王問水濱。", "悲纏刁斗急，警報羽書頻。", "關輔騰驕子，朝廷倚大臣。", "夢符巖肖說，天祐岳生申。", "濯濯襟靈邁，溫溫德業純。", "家聲真不墜，廟略信如神。", "行潔圭無玷，心堅竹有筠。", "蒼生出塗炭，黄屋待經綸。", "蘇峻稱兵日，姬公復辟辰。", "祚危旒在綴，主辱涕盈巾。", "諸將趨行殿，孤軍入帝闉。", "乾坤收逆氣，淮海霽妖塵。", "尊俎辭樞極，旌旄下蜀岷。", "霜稜函谷外，春色錦江瀕。", "流馬通飛漕，推鋒截要津。", "榮親萬鍾祿，許國百年身。"]'),
('9d413ca5-adbb-46b7-9f0c-23a2b6fd5f2d','惜別行送林梅卿赴闕','黄公度','宋','宋诗','song-poetry','','[]','刺桐城邊桐葉飛，刺桐城外行人稀。',128,'全唐诗/poet.song.117000.json','["刺桐城邊桐葉飛，刺桐城外行人稀。", "客來別我有所適，問客此去何當歸。", "林卿妙齡才秀發，胸中萬卷涌溟渤。", "家聲合沓蓋九州，里第嶙峋表雙闕。", "朅來試吏天南方，驥縶焉能騁所長。", "梅僊脫身東市卒，杜老落筆中書堂。", "傳道淮壖減豺虎，政須禮樂事明主。", "之子軒軒霄漢姿，好向春風刷毛羽。"]'),
('817604ef-4856-4fd7-be7c-fb935fa7775c','送汪內相移鎮宣城','黄公度','宋','宋诗','song-poetry','','[]','龍紀膺圖代，龜書出洛年。',288,'全唐诗/poet.song.117000.json','["龍紀膺圖代，龜書出洛年。", "人文初炳煥，神化共回旋。", "大雅藩籬缺，諸儒門戶專。", "天將扶古道，嶽始降名賢。", "派別軒皇遠，江回楚邑偏。", "英靈久蟠鬰，簪笏舊蟬聯。", "家學傳桑硯，詞場著祖鞭。", "風雲千載會，宇宙大名懸。", "行潔圭無玷，才長桷有梴。", "西都經術富，東閣道山連。", "蠹簡煩紬繹，羣書益貫穿。", "才超班馬上，道探老莊玄。", "近代風騷變，詞人霧縠鮮。", "俳優驚異體，輕薄竟相沿。", "作者今亡矣，明公獨勉旃。", "狂瀾資反正，墜緒得扶顛。", "內史趨欄藥，中書落筆椽。", "直詞批勑尾，清議列龜前。", "法駕南巡日，妖氛北刺天。", "新亭空涕泪，神汴一腥膻。", "慰將言彌切，徵兵檄屢宣。", "奉天憑陸贄，淮上困苻堅。", "素祕龍韜策，爰參虎旅權。", "精誠潛貫日，勳業合凌烟。"]'),
('ee8ac2f2-82c5-4c62-9d59-77fd5303af61','九日','黄公度','宋','宋诗','song-poetry','','[]','天涯霜露羈離久，海內風塵歸思賒。',64,'全唐诗/poet.song.117000.json','["天涯霜露羈離久，海內風塵歸思賒。", "萬里窮途雙白鬢，一尊濁酒對黄花。", "頻年奔走哀王粲，落日登臨憶孟嘉。", "絕塞歡娛易蕭瑟，悲來忍泪望京華。"]'),
('7576712b-bb1f-4a08-b145-a0319475c195','還家','黄公度','宋','宋诗','song-poetry','','[]','黎明呼羸僮，拄策渡野水。',96,'全唐诗/poet.song.117000.json','["黎明呼羸僮，拄策渡野水。", "輕嵐翳初日，古道步平砥。", "麥隴黄四出，松竹翠相倚。", "人間春告盡，巖色秀未已。", "眼入故鄉明，語還親舊喜。", "印非朱買臣，金無蘇季子。", "竊笑免妻孥，相過動隣里。", "富貴豈吾謀，薄游聊爾耳。"]'),
('fe7367cc-f6f3-44fb-af06-176b66554d09','早發東城迓憲車','黄公度','宋','宋诗','song-poetry','','[]','五更驅倦僕，發軔古城邊。',48,'全唐诗/poet.song.117000.json','["五更驅倦僕，發軔古城邊。", "月色潮初上，鐘聲人正眠。", "自憐筋力在，無補歲時遷。", "遠愧陶彭澤，歸心獨浩然。"]'),
('34c3383e-adb8-45c1-90d2-b8db921f48ca','暮春宴東園方良翰有詩入夏追和','黄公度','宋','宋诗','song-poetry','','[]','要洗襟懷萬斛埃，一尊相屬莫遲回。',64,'全唐诗/poet.song.117000.json','["要洗襟懷萬斛埃，一尊相屬莫遲回。", "顛狂柳絮將春去，排比荷花刺水開。", "懶矣宦情甘冗長，拙於句法强追陪。", "人生行樂須閒健，千古朱顔同一頹。"]'),
('eb74bd69-5a46-4f89-b2e7-b9dae8862e4a','自法石早歸','黄公度','宋','宋诗','song-poetry','','[]','避暑寓祇園，黎明度遠村。',48,'全唐诗/poet.song.117000.json','["避暑寓祇園，黎明度遠村。", "桑麻迷杜曲，雞犬散桃源。", "逕草細將合，溪流深不喧。", "幽懷未能愜，城郭已朝暾。"]'),
('d6211ce3-7c63-4487-aa48-6cf26a7d1eb4','和南安余宰題翠陰亭致爽軒二首  其一','黄公度','宋','宋诗','song-poetry','','[]','溪光山色兩幽深，更結新亭倚翠林。',64,'全唐诗/poet.song.117000.json','["溪光山色兩幽深，更結新亭倚翠林。", "老木參天烟漠漠，虛簷掛日影沉沉。", "三年此地留喬舄，六月凉風颯楚襟。", "趁取公餘急行樂，人生容易二毛侵。"]'),
('37c5c9b3-0d89-4c46-bdea-7df6cdcfbd3e','和南安余宰題翠陰亭致爽軒二首  其二','黄公度','宋','宋诗','song-poetry','','[]','面勢揖孤峙，交柯藏伯勞。',48,'全唐诗/poet.song.117000.json','["面勢揖孤峙，交柯藏伯勞。", "日臨公館寂，人與此軒高。", "對酒屢中聖，題詩應僕騷。", "喬林思舊隠，咫尺聽風號。"]'),
('74b0f962-8e31-45d8-9c2c-dcdce0ff7d7f','癸亥秋行縣夜寓下生院倦甚慨然有歸歟之興戲用壁間韻以盟泉石','黄公度','宋','宋诗','song-poetry','','[]','何須輪擁朱，不願佩懸玉。',92,'全唐诗/poet.song.117000.json','["何須輪擁朱，不願佩懸玉。", "青山得去且歸去，謀生待足何時足。", "林間招提金碧開，門外過客誰能來。", "桂花落盡無人問，古牆秋逕生青苔。", "舊山泉石故應好，菟裘不營亦可老。", "此身已與三徑期，未分淵明迹如掃。"]'),
('72cc4aca-90e3-4da3-a875-2a90d74fd36e','晚泊同安林明府携酒相過戲集杜陵句爲醉歌行','黄公度','宋','宋诗','song-poetry','','[]','疾風吹塵暗河縣，去馬來牛不復辨。',160,'全唐诗/poet.song.117000.json','["疾風吹塵暗河縣，去馬來牛不復辨。", "黄昏始扣主人門，置酒張燈促華饌。", "夜如何其初促膝，人生會合難再得。", "簿書何急來相仍，且將欵曲終今夕。", "腐儒衰晚謬通籍，射策君門期第一。", "天門日射黄金榜，自怪一日聲輝赫。", "三年奔走空皮骨，足繭荒山轉愁疾。", "未有涓埃答聖朝，途窮反遭俗眼白。", "懷抱何時得好開，生前相遇且銜杯。", "儒術於我何有哉，黄帽青鞋歸去來。"]'),
('24b514ce-fc9f-4b9f-95db-1aa8eab7f9bc','賀呂守用中','黄公度','宋','宋诗','song-poetry','','[]','紫帽山顛秋色高，刺桐城頭風怒號。',224,'全唐诗/poet.song.117000.json','["紫帽山顛秋色高，刺桐城頭風怒號。", "乾坤沖融忽異態，千里和氣生旌旄。", "昴星之精來瑞世，要令致主唐虞際。", "骨相誕鍾嵩嶽靈，風流不泯磻溪裔。", "懷香握蘭今幾春，瑣闥畫省曾彌綸。", "他年攬轡探禹穴，平反所活凡千人。", "南土分憂寬主顧，棠陰好在來何暮。", "儒風郁郁蜀文翁，德量汪汪黄叔度。", "相種由來多山東，蟬聯八葉屬我公。", "百年耆舊謳歌裏，萬里山河指顧中。", "聲名合沓蓋九州，人物中興第一流。", "風雲變化固有待，蒼虬寧許池中留。", "青衫腐儒趨幕府，香火祝公如衛武。", "夾輔皇家不計年，長將朽質入陶甄。"]'),
('510599b1-170a-41a6-ac34-912a806ec686','題定光寺','黄公度','宋','宋诗','song-poetry','','[]','爲憐山色好，百里赴幽期。',48,'全唐诗/poet.song.117000.json','["爲憐山色好，百里赴幽期。", "疊嶂生寒早，脩林出日遲。", "年華空晼晚，時事竟艱危。", "咫尺故園在，題詩有所思。"]'),
('1d509d38-6e5a-44b8-b1aa-c6f6348d117c','思歸','黄公度','宋','宋诗','song-poetry','','[]','醉眼乾坤大，歸心日夜長。',48,'全唐诗/poet.song.117000.json','["醉眼乾坤大，歸心日夜長。", "風霜歲云暮，塵土鬢成蒼。", "俗物猶能在，危機只自防。", "可無田種秫，三徑未宜荒。"]'),
('7b1b9d6b-131c-4e4b-8453-be81a611fd57','張雲翔采蘭堂','黄公度','宋','宋诗','song-poetry','','[]','丈夫貴成名，人子重養志。',216,'全唐诗/poet.song.117000.json','["丈夫貴成名，人子重養志。", "志養非鼎食，名成要身致。", "世上萬男兒，二者少稱遂。", "樂哉張公子，此事有餘地。", "昔我遊武林，始與張君值。", "津津紫芝眉，落落青雲器。", "驊騮步康衢，鵰鶚騰秋翅。", "一官天南州，艱難已嘗試。", "悠然望白雲，歸來爲隠吏。", "軒裳非吾心，菽水重親意。", "築堂九畹邊，遠取南陔義。", "膳羞務馨潔，晨夕必躬視。", "老人嗜國香，幽懷時一寄。", "春風敷柔絲，色與恩袍類。", "不效荆楚俗，紉之爲佩璲。", "不學會稽亭，徒然脩褉事。", "願言倚玉樹，同作庭階瑞。", "他年粉署握，永伴萊衣戲。"]'),
('8e32b78c-dabf-4c54-a523-fbbdbf9fda5e','次韻陳宜中携詩見訪','黄公度','宋','宋诗','song-poetry','','[]','朝來乾鵲啅簷牙，昨夜燈開送喜花。',64,'全唐诗/poet.song.117000.json','["朝來乾鵲啅簷牙，昨夜燈開送喜花。", "好事寧期貴公子，携詩肯訪野人家。", "客愁到此逢寒食，薄宦羈人屢歲華。", "載酒他年問奇字，故園歸去老桑麻。"]'),
('6da1dc15-3ea5-45f4-a80e-9d86fd9b7812','別方良翰','黄公度','宋','宋诗','song-poetry','','[]','海上曾聞屬國歸，歸來依舊壯心違。',64,'全唐诗/poet.song.117000.json','["海上曾聞屬國歸，歸來依舊壯心違。", "風塵萬里長爲客，管庫三年不救饑。", "尊酒欲謀良夜醉，庭花故就別時飛。", "看君好刷沖天翼，莫遣江城過鴈稀。"]'),
('62b9053f-8147-4411-bc8e-4c2916492711','題詩口鋪','黄公度','宋','宋诗','song-poetry','','[]','一水曳脩带，千山羅峻屏。',48,'全唐诗/poet.song.117000.json','["一水曳脩带，千山羅峻屏。", "客懷今古泪，人世短長亭。", "歲月身將老，功名夢未醒。", "長卿倦遊久，歸思滿巖扃。"]'),
('a182322f-f5bf-49f2-960f-59f36f44e153','過白衣莊','黄公度','宋','宋诗','song-poetry','','[]','草樹天邊碧，溪流雨外渾。',48,'全唐诗/poet.song.117000.json','["草樹天邊碧，溪流雨外渾。", "僕夫經燕岫，筋力盡龍門。", "斜日當幽徑，輕風度晚村。", "築場茅屋底，約畧似東屯。"]'),
('0cac043c-9120-43bd-97dc-720d4f642630','題化度寺竹間亭','黄公度','宋','宋诗','song-poetry','','[]','羸驂踏遍亂山青，薄宦羈人醉未醒。',32,'全唐诗/poet.song.117000.json','["羸驂踏遍亂山青，薄宦羈人醉未醒。", "破午停鞭得幽寺，眼明初見竹間亭。"]'),
('59886c4b-ca4c-47d4-80ad-3ec9ada484fa','行安溪道中','黄公度','宋','宋诗','song-poetry','','[]','雞豚殆盡官軍過，豺虎猶存野老愁。',32,'全唐诗/poet.song.117000.json','["雞豚殆盡官軍過，豺虎猶存野老愁。", "萬一皇恩更寬大，會令戈甲變耡耰。"]'),
('9af78890-07bc-418f-988f-7bb652e64c03','道間即事','黄公度','宋','宋诗','song-poetry','','[]','花枝已盡鶑將老，桑葉漸稀蠶欲眠。',64,'全唐诗/poet.song.117000.json','["花枝已盡鶑將老，桑葉漸稀蠶欲眠。", "半濕半晴梅雨道，乍寒乍暖麥秋天。", "村壚沽酒誰能擇，郵壁題詩盡偶然。", "方寸怡怡無一事，粗裘糲食地行僊。"]'),
('3ce808b9-030f-4632-a072-b9c7a1981567','別呂守三首  其一','黄公度','宋','宋诗','song-poetry','','[]','家世唐蕭瑀，風流晉謝安。',48,'全唐诗/poet.song.117000.json','["家世唐蕭瑀，風流晉謝安。", "胸中畜邱壑，筆下富波瀾。", "耆舊謳歌惜，賓僚禮數寬。", "龔黄初報政，飛詔忽江干。"]'),
('e28cf9ae-13ce-47dd-b518-80ee44839cd8','別呂守三首  其二','黄公度','宋','宋诗','song-poetry','','[]','自此調元去，人今卧轍同。',48,'全唐诗/poet.song.117000.json','["自此調元去，人今卧轍同。", "棠陰閩嶺外，星傳浙江東。", "四月黄梅雨，千山荔子風。", "離亭獨歸處，回首意無窮。"]'),
('e053a8ca-47a8-48b6-b39b-cbaa916723fc','別呂守三首  其三','黄公度','宋','宋诗','song-poetry','','[]','涉獵愧醇儒，南州入幕初。',48,'全唐诗/poet.song.117000.json','["涉獵愧醇儒，南州入幕初。", "力疲三尺法，塵滿一床書。", "不有劉寬恕，何堪阮籍踈。", "才微甘冗長，感激辱吹噓。"]'),
('6aec41f4-f681-4510-9dc4-28655573973e','白沙夜聞灘聲','黄公度','宋','宋诗','song-poetry','','[]','錯認松風萬壑傳，又如急雨碎池蓮。',32,'全唐诗/poet.song.117000.json','["錯認松風萬壑傳，又如急雨碎池蓮。", "青燈孤館元無寐，况復溪聲到枕邊。"]'),
('68b19d5f-85a3-49ef-b819-071555e2ea84','大水二首  其一','黄公度','宋','宋诗','song-poetry','','[]','巨浸滔天後，遺黎復業初。',48,'全唐诗/poet.song.117000.json','["巨浸滔天後，遺黎復業初。", "桑田皆變海，老稚半爲魚。", "鑿石開新道，行人問故廬。", "客愁那對此，搔首重欷歔。"]'),
('588457d1-1002-4b83-b281-1e49d0bc23f3','大水二首  其二','黄公度','宋','宋诗','song-poetry','','[]','洚水應垂儆，高穹豈不仁。',48,'全唐诗/poet.song.117000.json','["洚水應垂儆，高穹豈不仁。", "發陳遵故事，執咎定何人。", "岸落溪容改，山摧土色新。", "傷心問耆舊，誰與弔斯民。"]'),
('8d7682be-1320-4c91-a47d-aa233dca1810','題分水嶺兩絕  其一','黄公度','宋','宋诗','song-poetry','','[]','嗚咽泉流萬仞峯，斷腸從此各西東。',32,'全唐诗/poet.song.117000.json','["嗚咽泉流萬仞峯，斷腸從此各西東。", "誰知不作多時別，依舊相逢滄海中。"]'),
('8de7bf22-1b5a-45cc-ba21-4e287612f1d7','題分水嶺兩絕  其二','黄公度','宋','宋诗','song-poetry','','[]','閩越江南此地分，鮑娘詩句尚能存。',32,'全唐诗/poet.song.117000.json','["閩越江南此地分，鮑娘詩句尚能存。", "客懷未覺今宵好，家住壺山烟雨村。"]'),
('d01ade50-7d7f-400e-98b4-10973392a656','題崇安驛','黄公度','宋','宋诗','song-poetry','','[]','睡美生憎曉色催，丹心自愧未能灰。',64,'全唐诗/poet.song.117000.json','["睡美生憎曉色催，丹心自愧未能灰。", "塵埃汩汩歲將暮，霜霧濛濛晝不開。", "身外百端俱長物，時危萬事入羈懷。", "君恩早晚粗酬了，糲飯敝裘歸去來。"]'),
('de2534ab-4b2d-4c6f-8d53-5032cbc14c90','題紫溪驛','黄公度','宋','宋诗','song-poetry','','[]','離家一月斷家書，家在閩山深處居。',32,'全唐诗/poet.song.117000.json','["離家一月斷家書，家在閩山深處居。", "路入江南隔分水，山猶不見况吾廬。"]'),
('902a0b8c-251a-4c07-adfb-8ba79aebae2a','至日戲題天福寺','黄公度','宋','宋诗','song-poetry','','[]','去年至日老夫家，呼兒具酒對梅花。',65,'全唐诗/poet.song.117000.json','["去年至日老夫家，呼兒具酒對梅花。", "今年至日空奔走，豈止無花亦無酒。", "薄宦驅人無已時，客懷牢落强裁詩。", "君不見杜陵老詩伯，年年至日長爲客。"]'),
('f25c76fb-45cb-418d-8c7f-09ad8f36ac38','至日題江山驛','黄公度','宋','宋诗','song-poetry','','[]','客裏萍蓬愧此身，天涯風俗對茲辰。',64,'全唐诗/poet.song.117000.json','["客裏萍蓬愧此身，天涯風俗對茲辰。", "雲容山意商量雪，梅蕾葭灰漏洩春。", "歲晚旅懷元自惡，夜長歸夢爲誰頻。", "遥憐兒女團欒處，應念江山飄泊人。"]'),
('bf1123b0-072e-4ee6-908d-4627b5f0f9a7','上陸鹽生辰五首  其一','黄公度','宋','宋诗','song-poetry','','[]','拂拂秋風生桂枝，于門何日誕英奇。',32,'全唐诗/poet.song.117000.json','["拂拂秋風生桂枝，于門何日誕英奇。", "請看素魄初圓夜，正是奎星呈瑞時。"]'),
('5f1bdcef-d455-4d1f-93b7-8c7269d3ed69','上陸鹽生辰五首  其二','黄公度','宋','宋诗','song-poetry','','[]','高議曾匡馬上翁，聲名凜凜尉佗宮。',32,'全唐诗/poet.song.117000.json','["高議曾匡馬上翁，聲名凜凜尉佗宮。", "誰知千載經行地，猶有雲來紹祖風。"]'),
('b8470070-0eec-41ef-bca2-6b1ef0f5bce1','上陸鹽生辰五首  其三','黄公度','宋','宋诗','song-poetry','','[]','嘉謨合補三公衮，餘事聊分八使車。',32,'全唐诗/poet.song.117000.json','["嘉謨合補三公衮，餘事聊分八使車。", "想得忠勤徹旒冕，天涯洗眼看徵書。"]'),
('2b546cd6-7a9a-46e8-9b60-84b7a796e338','上陸鹽生辰五首  其四','黄公度','宋','宋诗','song-poetry','','[]','名家詩禮有諸郎，飛入南宮鴻雁行。',32,'全唐诗/poet.song.117000.json','["名家詩禮有諸郎，飛入南宮鴻雁行。", "不向人前稱閥閲，要須僊桂五枝芳。"]'),
('b888aad5-30e3-4e5d-b72b-cac7971ef156','上陸鹽生辰五首  其五','黄公度','宋','宋诗','song-poetry','','[]','可但人間五福全，飄飄真是地行僊。',32,'全唐诗/poet.song.117000.json','["可但人間五福全，飄飄真是地行僊。", "摩娑銅狄成追憶，游戲塵寰五百年。"]'),
('ea879ca2-fede-4833-8e36-dd44d7cdd02b','和泉上人','黄公度','宋','宋诗','song-poetry','','[]','芒鞋踏遍萬山松，得得歸來丈室中。',64,'全唐诗/poet.song.117000.json','["芒鞋踏遍萬山松，得得歸來丈室中。", "破祴一身在懸罄，清談對客似撞鐘。", "名家要看驚人舉，覓句何須效我窮。", "春雨地爐分半坐，便疑身住古禪叢。"]'),
('f65dffc0-ff59-4d6c-8775-486e82e9b5e4','進元會詩','黄公度','宋','宋诗','song-poetry','','[]','昭代干戈戢，炎輝歷數長。',240,'全唐诗/poet.song.117000.json','["昭代干戈戢，炎輝歷數長。", "蒼生久蘇息，寰海屢豐穰。", "社稷基新命，朝廷舉舊章。", "太平周禮樂，垂拱舜衣裳。", "拜壽先長樂，傳聲出未央。", "冕旒端黼座，儀物備明堂。", "閶闔星辰外，旂常日月旁。", "天顔春穆穆，雲物曉蒼蒼。", "雪色殘鳷鵲，韶音雜鳳凰。", "嚴宸分羽衛，荒服走梯航。", "人正今行夏，民心舊戴商。", "觀光環萬國，班朔首三陽。", "列辟鑾聲噦，羣工玉珮鏘。", "奉常陳雅奏，太史報殊祥。", "於穆前朝盛，丕承奕世昌。", "版圖還大禹，風俗再陶唐。", "已格無爲治，猶懷不敢康。", "幾年脩縟典，今日付吾皇。", "所願終寅畏，無忘每贊襄。", "明良相際會，長奉萬年觴。"]'),
('6680616f-73c5-4249-8942-598e323d7c75','除夜','黄公度','宋','宋诗','song-poetry','','[]','暮景流年速，寒燈照夜長。',48,'全唐诗/poet.song.117000.json','["暮景流年速，寒燈照夜長。", "艱危仍薄宦，時序更他鄉。", "雪暗吳宮下，春歸越嶠傍。", "明朝對佳節，無處覓椒觴。"]'),
('ffa000dc-4f36-4849-a5a9-362c4a25d166','元日次良翰韻','黄公度','宋','宋诗','song-poetry','','[]','老去低徊强北遊，春來消息望南州。',64,'全唐诗/poet.song.117000.json','["老去低徊强北遊，春來消息望南州。", "別離况復年華換，富貴難令少壯留。", "行李未知何處定，屠蘇還解憶人不。", "可堪一夜寒江雨，滴作羈懷萬斛愁。"]'),
('a828648c-553c-4bd9-9fa8-03f9f210a997','題方民瞻草堂','黄公度','宋','宋诗','song-poetry','','[]','結宇囂塵外，寓形天地間。',48,'全唐诗/poet.song.117000.json','["結宇囂塵外，寓形天地間。", "幽懷付松菊，高卧對雲山。", "門巷來人少，琴書竟日閒。", "可憐朝市客，名利老朱顔。"]'),
('cfa76276-23c6-4dd4-a96f-1c73c658fc9e','和詠陳賢良華表','黄公度','宋','宋诗','song-poetry','','[]','千年鶴表映溪濱，一代鴻文動至尊。',64,'全唐诗/poet.song.117000.json','["千年鶴表映溪濱，一代鴻文動至尊。", "仕路低徊唐老杜，才名合沓漢公孫。", "家風不減太丘令，盛事何如通德門。", "肯把浮榮衒流俗，欲遺典則到仍昆。"]'),
('6981d846-2c47-4206-ac5a-9047936075fa','試院中蒙相君惠茶和錢教授韻','黄公度','宋','宋诗','song-poetry','','["\u897f\u6e56"]','誤向文闈齒搢紳，相君分賜壑源春。',64,'全唐诗/poet.song.117000.json','["誤向文闈齒搢紳，相君分賜壑源春。", "窮搜千卷非吾事，滿引一杯如故人。", "無復睡魔能偃蹇，敢將詩律鬭清新。", "西湖好趁清明約，泉活涓涓火不陳。"]'),
('14f90433-2b39-4506-ae03-9cb83507ed08','將放榜用錢韻','黄公度','宋','宋诗','song-poetry','','["\u897f\u6e56"]','銀袍健筆落雲烟，入眼高文墨尚鮮。',64,'全唐诗/poet.song.117000.json','["銀袍健筆落雲烟，入眼高文墨尚鮮。", "隠隠蠶聲桑葉下，看看鵠立棘圖前。", "空階夜響催詩雨，平地雷轟造榜天。", "試問西湖好風景，何如華屋艷神僊。"]'),
('069f05be-f0ed-4a36-84a7-519af5d8bd1e','雨後陪省中諸公游竹閣','黄公度','宋','宋诗','song-poetry','','[]','紅盡桃初實，青濃柳欲花。',48,'全唐诗/poet.song.117000.json','["紅盡桃初實，青濃柳欲花。", "春歸人迹少，山遠市聲譁。", "空有前朝樹，難尋處士家。", "登臨多感慨，况復客天涯。"]'),
('5edad174-a8b9-4cbb-a7e5-1bef8d02b821','將歸','黄公度','宋','宋诗','song-poetry','','[]','北首寒猶淺，南轅暑正深。',48,'全唐诗/poet.song.117000.json','["北首寒猶淺，南轅暑正深。", "馬蹄長道路，鹿性本山林。", "客至能相勉，愁來可獨禁。", "功名竟何物，造化久冥心。"]'),
('8e298460-270d-4552-9343-18878009bc4f','離臨安','黄公度','宋','宋诗','song-poetry','','[]','細雨出江城，潮回江正清。',48,'全唐诗/poet.song.117000.json','["細雨出江城，潮回江正清。", "未能捐俗累，不敢憚嚴程。", "落日行人少，空山獨鳥鳴。", "離愁似春草，觸處便能生。"]'),
('752c66b0-8e9d-404b-a5ba-49fc93d610b0','題須江驛詩後','黄公度','宋','宋诗','song-poetry','','[]','歸來已負百花期，閒拂塵埃看舊詩。',32,'全唐诗/poet.song.117000.json','["歸來已負百花期，閒拂塵埃看舊詩。", "極目平蕪二千里，鄉心惟有杜鵑知。"]'),
('42842671-fc25-42f9-a170-26885a350045','題白沙鋪','黄公度','宋','宋诗','song-poetry','','[]','負郭可無三頃秫，蓋頭幸有兩間茅。',64,'全唐诗/poet.song.117000.json','["負郭可無三頃秫，蓋頭幸有兩間茅。", "還鄉且盡田家樂，舉世誰非市道交。", "村酒一杯澆磊塊，山程數驛更磽嶅。", "羸驂莫怪歸鞭急，心在輕紅荔子梢。"]'),
('59e9a983-6e51-4efe-8061-0fc8f7a24b38','和超然翁韻二首  其一','黄公度','宋','宋诗','song-poetry','','[]','才微祇合老荆扉，悞竊虛名及盛時。',64,'全唐诗/poet.song.117000.json','["才微祇合老荆扉，悞竊虛名及盛時。", "藜杖端須爲劉燭，匏竽聊復預齊吹。", "亨衢騰踔非吾事，客路逢迎仰己知。", "莫訝歸程秋向晚，也應去魯自遲遲。"]'),
('4d18695e-a7d7-4775-9ea2-12ed47fd56d1','和超然翁韻二首  其二','黄公度','宋','宋诗','song-poetry','','[]','西風回首故鄉情，何日爲園學邵平。',64,'全唐诗/poet.song.117000.json','["西風回首故鄉情，何日爲園學邵平。", "已辦孤帆衝夕浪，可堪萬壑更秋聲。", "折腰爲米追時輩，當面輸心愧老成。", "飲罷歸來未能寢，微吟擁鼻數寒更。"]'),
('725ac6cc-0bb0-428d-bc9f-652548a2eea3','不見','黄公度','宋','宋诗','song-poetry','','[]','碧湘幽夢秋帷冷，玉滴宵壺聲耿耿。',96,'全唐诗/poet.song.117000.json','["碧湘幽夢秋帷冷，玉滴宵壺聲耿耿。", "平生不作等閒愁，風月故人長引領。", "青樓花開歡正新，當時握手欲留春。", "樓空花落春竟去，惟有紗窗鎖暗塵。", "風流回首年華晚，愁與宮眉添宛轉。", "不堪翠袖裛殘香，六曲屏山爲誰展。"]'),
('1095175c-2e47-4943-8106-8a7445cc6a9b','御賜閣額二首  其一','黄公度','宋','宋诗','song-poetry','','[]','傑閣侵霄漢，宸章煥壁奎。',48,'全唐诗/poet.song.117000.json','["傑閣侵霄漢，宸章煥壁奎。", "內庭頒寶宴，中使揭璇題。", "信誓山河固，厖恩雨露低。", "寒儒倚天祿，目斷五雲西。"]'),
('7c730d2b-8790-4929-9dac-2d62f05b54b6','御賜閣額二首  其二','黄公度','宋','宋诗','song-poetry','','[]','功掩蕭何第，名超崔氏堂。',48,'全唐诗/poet.song.117000.json','["功掩蕭何第，名超崔氏堂。", "孤忠扶社稷，一德契穹蒼。", "金碧飛翬外，鸞虬結綺傍。", "落成紛賀燕，弱羽得高翔。"]'),
('a283df48-1b9a-45f2-a4f0-f3f6193bbd1c','西湖會同年和巫子先韻','黄公度','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一鸇獨立鳥羣空，寂寞誰憐漢閣雄。',64,'全唐诗/poet.song.117000.json','["一鸇獨立鳥羣空，寂寞誰憐漢閣雄。", "鴈塔他年曾接武，烏臺今日自生風。", "平湖入座摇寒碧，返照催人墮晚紅。", "目斷禁城驄馬客，何時譚笑一尊同。"]'),
('6b84389a-b072-44a0-a825-5a61908e7880','黄憲生朝三首  其一','黄公度','宋','宋诗','song-poetry','','[]','國勢巍巍盛，時髦衮衮生。',48,'全唐诗/poet.song.117000.json','["國勢巍巍盛，時髦衮衮生。", "雲師綿世胄，漢相舊家聲。", "學海波瀾闊，神峰冰雪清。", "天涯逢誕日，目極曲江城。"]'),
('f621a9ee-4b44-49e1-b370-d2fd070cc6ee','黄憲生朝三首  其二','黄公度','宋','宋诗','song-poetry','','[]','經術賢關望，訏謨帝席前。',48,'全唐诗/poet.song.117000.json','["經術賢關望，訏謨帝席前。", "詞場聲擲地，憲府力回天。", "金鑑風流在，炎陬雨露偏。", "慇懃理歸揖，早覲日華邊。"]'),
('dc2d062c-5761-43da-862b-b96a54436e32','黄憲生朝三首  其三','黄公度','宋','宋诗','song-poetry','','[]','陰德千人活，霜威五嶺寒。',48,'全唐诗/poet.song.117000.json','["陰德千人活，霜威五嶺寒。", "三持使者節，一著惠文冠。", "臺省班聯忝，賓僚禮數寬。", "微官慙束縛，稱壽阻門闌。"]'),
('7f5f6924-4077-40d3-8fae-02936b36ac59','送陳應求赴官','黄公度','宋','宋诗','song-poetry','','[]','莫辭酒，且聽歌，休被驪駒白玉珂。',245,'全唐诗/poet.song.117000.json','["莫辭酒，且聽歌，休被驪駒白玉珂。", "主人勸客終今夕，明日長亭可奈何。", "金風蕭蕭鏖餘熱，砌蟲唧唧助凄切。", "此時景物不勝愁，况是離人心欲折。", "陳侯陳侯，貌巖巖而俊整，才浩浩而清絕。", "有如壺山之萬仞巑岏，壽水之千尋瑩澈。", "青芝赤箭藥籠儲，金鐘大鏞廊廟須。", "天生奇才爲時出，容易棄擲天南隅。", "君不見馬賓王，新豐一逆旅。", "又不見公孫弘，菑川一老儒。", "逢辰立譚取卿相，至今文采照天衢。", "廣文官舍雖落莫，刀筆不與俗吏俱。", "公餘更勤五車讀，未必不是北門西掖之權輿。", "刺桐古城花欲燃，舊遊人物想依然。", "憑君到彼訪二陸，向道故人飽飯度殘年。"]'),
('20e7d9a2-0ec7-453f-80d4-7deb03bad6e7','送弟士季赴永春','黄公度','宋','宋诗','song-poetry','','[]','贈君以宣城秋兔之穎，佩君以嶧陽焦尾之琴。',204,'全唐诗/poet.song.117000.json','["贈君以宣城秋兔之穎，佩君以嶧陽焦尾之琴。", "餞君以顯父清壺之酒，送君以安仁金谷之吟。", "筆傳洙泗之正印，琴彈單父之遺音。", "酒以陶百里醇醲之化，詩以寫一時離別之心。", "門前車馬氣駸駸，黄葉飛飜秋正深。", "風雨對床連夜語，江山異地欲分襟。", "憶昔聯名唱行殿，一日聲華九垓遍。", "自知無用甘林泉，君亦何爲尚州縣。", "君今未用嘆滯留，丈夫勳業要晚收。", "信臣千載循吏傳，密令當年褒德侯。", "高才所蒞無全牛，民自不冤吏早休。", "倘免誅求急星火，行看寇盜盡鋤耰。"]'),
('56faeb02-4924-4e3e-be8b-9c1be91579c9','無題','黄公度','宋','宋诗','song-poetry','','[]','雞蟲底處覓得失，鳬鶴無心較短長。',32,'全唐诗/poet.song.117000.json','["雞蟲底處覓得失，鳬鶴無心較短長。", "醫國未能三折臂，憂時空費九回腸。"]'),
('f9cc01fe-8794-44f3-a56f-7f19f737dc43','送外兄方卿公美赴廣東憲十絕  其一','黄公度','宋','宋诗','song-poetry','','[]','九重仁聖不忘遠，庶獄哀矜軫慮深。',32,'全唐诗/poet.song.117000.json','["九重仁聖不忘遠，庶獄哀矜軫慮深。", "本恕定知黄霸用，無刑端契有虞心。"]'),
('88ee9796-2936-48d0-a3ac-98c60267c094','送外兄方卿公美赴廣東憲十絕  其二','黄公度','宋','宋诗','song-poetry','','[]','遐陬赤子困侵牟，跳弄潢池今幾秋。',32,'全唐诗/poet.song.117000.json','["遐陬赤子困侵牟，跳弄潢池今幾秋。", "從此聲威憺强梗，自然戈戟變鋤耰。"]'),
('bdecc265-a2bd-463b-b511-cf6e1383a38b','送外兄方卿公美赴廣東憲十絕  其三','黄公度','宋','宋诗','song-poetry','','[]','石門酌水賦新詩，舊事曾聞吳隠之。',32,'全唐诗/poet.song.117000.json','["石門酌水賦新詩，舊事曾聞吳隠之。", "習習清風化貪懦，不圖今見古齊夷。"]'),
('621be5ca-89df-4ce6-be31-02957073a761','送外兄方卿公美赴廣東憲十絕  其四','黄公度','宋','宋诗','song-poetry','','[]','親輿昔侍角方總，使節今持鬢未蒼。',32,'全唐诗/poet.song.117000.json','["親輿昔侍角方總，使節今持鬢未蒼。", "竹馬兒童半相識，分明遺愛在甘棠。"]'),
('f529c5fb-9c5b-40a5-8810-5ed05a3adb45','送外兄方卿公美赴廣東憲十絕  其五','黄公度','宋','宋诗','song-poetry','','[]','早晚芝函下九天，不容瓜戍更期年。',32,'全唐诗/poet.song.117000.json','["早晚芝函下九天，不容瓜戍更期年。", "蒼生屬望爲霖久，肯使炎方雨露偏。"]'),
('47361c30-6202-47c5-94e4-e3279987f2f7','送外兄方卿公美赴廣東憲十絕  其六','黄公度','宋','宋诗','song-poetry','','[]','聞道韶陽一畝宮，居民奉祀曲江公。',32,'全唐诗/poet.song.117000.json','["聞道韶陽一畝宮，居民奉祀曲江公。", "憑君到日酹尊酒，醖藉風流事事同。"]'),
('690c6872-8503-41c0-82ee-07356a473eeb','送外兄方卿公美赴廣東憲十絕  其七','黄公度','宋','宋诗','song-poetry','','[]','怪底青雲懶著鞭，年來餘事覺真詮。',32,'全唐诗/poet.song.117000.json','["怪底青雲懶著鞭，年來餘事覺真詮。", "圜扉晝闢庭無訟，時訪曹溪六祖禪。"]'),
('5031d5d4-081c-4999-af97-5ed7b8dcb474','送外兄方卿公美赴廣東憲十絕  其八','黄公度','宋','宋诗','song-poetry','','[]','千里江山一鴈聲，廣文官舍冷如冰。',32,'全唐诗/poet.song.117000.json','["千里江山一鴈聲，廣文官舍冷如冰。", "祁奚若未忘公舉，魏戊猶堪備內稱。"]'),
('3e23cda5-3ea5-4bb4-ac82-9e2c07a38a58','送外兄方卿公美赴廣東憲十絕  其九','黄公度','宋','宋诗','song-poetry','','[]','新息功名晚始收，送君今去跕鳶州。',32,'全唐诗/poet.song.117000.json','["新息功名晚始收，送君今去跕鳶州。", "男兒未上雲臺畫，莫念平生馬少游。"]'),
('ae02b00d-b47f-48d9-ab53-886b71d3556e','送外兄方卿公美赴廣東憲十絕  其一○','黄公度','宋','宋诗','song-poetry','','[]','十里紅旗擁使星，一杯綠蟻話長亭。',32,'全唐诗/poet.song.117000.json','["十里紅旗擁使星，一杯綠蟻話長亭。", "明朝車馬各南北，誰唱陽關且細聽。"]'),
('20a5a643-d917-4674-ac6d-9e023a3daf52','和宋永兄罷官還家途中見寄四絕  其一','黄公度','宋','宋诗','song-poetry','','[]','三年惠政留巖邑，千里歸舟犯惡灘。',32,'全唐诗/poet.song.117000.json','["三年惠政留巖邑，千里歸舟犯惡灘。", "烏鵲信傳知漸近，白鷗盟在未應寒。"]'),
('d5d0dc23-31c0-4d5d-a3de-1871e5db1538','和宋永兄罷官還家途中見寄四絕  其二','黄公度','宋','宋诗','song-poetry','','[]','流年忽忽雙蓬鬢，薄宦紛紛一旅亭。',32,'全唐诗/poet.song.117000.json','["流年忽忽雙蓬鬢，薄宦紛紛一旅亭。", "惟有長官衫色在，至今猶與眼俱青。"]'),
('b634fdb7-888a-4b17-b797-543cc78f25f4','和宋永兄罷官還家途中見寄四絕  其三','黄公度','宋','宋诗','song-poetry','','[]','知稼堂中一味閒，卷簾終日卧看山。',32,'全唐诗/poet.song.117000.json','["知稼堂中一味閒，卷簾終日卧看山。", "雖無微祿供貧病，幸有新詩伴往還。"]'),
('2bdc400a-2932-4f66-aed9-ccfe0a144e1c','和宋永兄罷官還家途中見寄四絕  其四','黄公度','宋','宋诗','song-poetry','','[]','不比人心驚歲移，且看鴈影逐春歸。',32,'全唐诗/poet.song.117000.json','["不比人心驚歲移，且看鴈影逐春歸。", "明朝已辦椒花頌，相對一尊忘是非。"]'),
('a9c6302b-b87f-436d-8e0f-4a2f3bf16267','送余子美歸淮上','黄公度','宋','宋诗','song-poetry','','[]','怪底窮途遭白眼，依然別酒對青春。',64,'全唐诗/poet.song.117000.json','["怪底窮途遭白眼，依然別酒對青春。", "百年甘旨爲貧計，千里羈棲有故人。", "道在不妨輕去魯，功成他日會歸秦。", "江淮若遇南飛翼，尺素無忘東海濱。"]'),
('f9f5ebaa-0582-4e2c-a0d8-49aee181f774','西郊步武地春將老矣不能一往朝吉姪今日爲遨頭澀雨大作非惟人心難并止或尼之枕上得小詩資宋永兄一噱因呈昔遊兄弟速尋舊盟勿爲天公所玩','黄公度','宋','宋诗','song-poetry','','[]','無復西郊訪綺羅，任教佳景去如梭。',64,'全唐诗/poet.song.117000.json','["無復西郊訪綺羅，任教佳景去如梭。", "殘杯冷炙何曾夢，亂絮飛花積漸多。", "舉世盡從忙裏過，幾人能共醉時歌。", "不辭作意營春事，急雨狂風可奈何。"]'),
('b50e01f4-e37e-4c86-9aec-607c00a33e8e','己巳九日陪陸使君宴共樂臺和莊倅韻','黄公度','宋','宋诗','song-poetry','','[]','一年秋色垂垂老，九日寒花處處同。',64,'全唐诗/poet.song.117000.json','["一年秋色垂垂老，九日寒花處處同。", "落帽何人羞短髮，危臺向晚易高風。", "黄雲萬頃峰巒下，白雪幾聲宵漢中。", "陌上行人盡回首，使君開宴在層空。"]'),
('83008f79-7e68-4367-a77b-0769215f3790','和宋去華愛日樓之什','黄公度','宋','宋诗','song-poetry','','[]','百里平疇一望間，綠蕪盡處見青山。',64,'全唐诗/poet.song.117000.json','["百里平疇一望間，綠蕪盡處見青山。", "孤雲自在開仍合，白鳥羣飛去復還。", "竟日茶瓜留客坐，滿床圖史伴君閒。", "携醪許我問奇字，剝啄何妨屢扣關。"]'),
('7e868f7f-1e38-4c6c-be3d-1952a5fbcd95','和宋永兄愛日樓見寄八首  其一','黄公度','宋','宋诗','song-poetry','','[]','畫圖展處千山雪，漁艇歸時一笛風。',32,'全唐诗/poet.song.117000.json','["畫圖展處千山雪，漁艇歸時一笛風。", "爲愛東溟日色好，側身樓外望壺公。"]'),
('afdd00d1-2d37-4c98-8340-4e844f7d892b','和宋永兄愛日樓見寄八首  其二','黄公度','宋','宋诗','song-poetry','','[]','陳樓高卧真佳士，陶徑歸來有古風。',32,'全唐诗/poet.song.117000.json','["陳樓高卧真佳士，陶徑歸來有古風。", "只恐功名不相放，驅人須作黑頭公。"]'),
('e3937edc-6f7b-4497-badf-344f31e16924','和宋永兄愛日樓見寄八首  其三','黄公度','宋','宋诗','song-poetry','','[]','野意樓前滿，秋聲樹杪回。',48,'全唐诗/poet.song.117000.json','["野意樓前滿，秋聲樹杪回。", "歲華行老矣，午夢思悠哉。", "碌碌甘捐棄，時時幸往來。", "不才詩有債，多病酒爲媒。"]'),
('cc3dccf7-4734-430a-9a9f-e3b7a71cc948','和宋永兄愛日樓見寄八首  其四','黄公度','宋','宋诗','song-poetry','','[]','醫手無三折，愁腸漫九回。',48,'全唐诗/poet.song.117000.json','["醫手無三折，愁腸漫九回。", "宦情聊復爾，世事轉艱哉。", "狂態未能免，新詩特地來。", "從今罷歌舞，焦尾聽無媒。"]'),
('c17ebe9e-2878-40e7-baec-33e48480543e','和宋永兄愛日樓見寄八首  其五','黄公度','宋','宋诗','song-poetry','','[]','軒組挽人力，萬中無一回。',48,'全唐诗/poet.song.117000.json','["軒組挽人力，萬中無一回。", "急流能退者，捨我有誰哉。", "此意何時遂，相携歸去來。", "東皋春雨足，荷鍤聽鳩媒。"]'),
('363922b2-cb94-4ba2-8320-fe2cd990778a','和宋永兄愛日樓見寄八首  其六','黄公度','宋','宋诗','song-poetry','','[]','齠齓携書冊，成名天上回。',48,'全唐诗/poet.song.117000.json','["齠齓携書冊，成名天上回。", "如公希世者，自古幾人哉。", "山藪詎宜去，功名看鼎來。", "人間無伯樂，相馬失龍媒。"]'),
('cd9815d6-4c89-4e49-80cd-90f99eac0c28','和宋永兄愛日樓見寄八首  其七','黄公度','宋','宋诗','song-poetry','','[]','秋心驚杵急，遠目見潮回。',48,'全唐诗/poet.song.117000.json','["秋心驚杵急，遠目見潮回。", "衰日可愛也，楚風真快哉。", "卷開前聖對，竹動故人來。", "去魯遲休怪，謀身恥自媒。"]'),
('83d1634f-6f6e-4856-8394-52172af1f6e0','和宋永兄愛日樓見寄八首  其八','黄公度','宋','宋诗','song-poetry','','[]','山林往不返，朝市去無回。',48,'全唐诗/poet.song.117000.json','["山林往不返，朝市去無回。", "能樂窮通者，真知出處哉。", "次山稱漫仕，彭澤賦歸來。", "堪笑脅肩子，相從不待媒。"]'),
('629e2b9a-7f05-4986-b068-488a01e327d0','和使君劭農之什','黄公度','宋','宋诗','song-poetry','','[]','交情自許膠投漆，賓主相輝璧與琨。',64,'全唐诗/poet.song.117000.json','["交情自許膠投漆，賓主相輝璧與琨。", "賣劍早書循吏傳，種瓜時問故侯園。", "百年耆舊須親訪，千里耕桑戴上恩。", "一郡風流古來少，筆端珠玉富歸軒。"]'),
('d24a2f81-a3ef-4c93-b605-25dd7eae635c','三瑞堂','黄公度','宋','宋诗','song-poetry','','[]','機雲二子才孤標，妙齡馳聲典午朝。',192,'全唐诗/poet.song.117000.json','["機雲二子才孤標，妙齡馳聲典午朝。", "今見遠孫來海嶠，儒雅雍容飾漢條。", "德化醇醲春有脚，天姿粹美玉不彫。", "無復犢牛充带佩，坐令襦袴成歌謠。", "藴藉斯人合臺閣，暫把一麾亦不惡。", "鈴閣正午槐陰清，訟庭無人鳥聲樂。", "政成瑞應一何多，天香國艷駢花蕚。", "可但漁陽頌麥岐，會見西京紀神爵。", "吾聞作善天降祥，拭目泥封下建章。", "一時文采七閩郡，千載風流三瑞堂。", "坤珍效祉來未央，九莖怒芽抽且長。", "胡不圖之獻天子，播在樂府歌芝房。"]'),
('87c5eb09-3cdd-49c4-b066-1d235c1fb8e8','庚午秋觀進士入試','黄公度','宋','宋诗','song-poetry','','[]','棘扉曉闢萬袍趨，鄒魯雖微士所都。',64,'全唐诗/poet.song.117000.json','["棘扉曉闢萬袍趨，鄒魯雖微士所都。", "三獻有人懷楚璞，濫吹何事試齊竽。", "要令廋語題韲臼，莫把元文覆醤瓿。", "袖手傍觀君勿怪，箇中曾是老於菟。"]'),
('9b5c6d5a-2758-47ed-acfc-bca2581b2b56','次韻宋永兄白髮','黄公度','宋','宋诗','song-poetry','','[]','銀鬢詎如許，金丹奈若何。',48,'全唐诗/poet.song.117000.json','["銀鬢詎如許，金丹奈若何。", "休垂髀肉涕，莫擊唾壺歌。", "世事奕棋局，人材在沚莪。", "未須相料理，大器晚成多。"]'),
('e5f5c60e-ebf1-4858-a56e-8dec4f447574','回文絕句','黄公度','宋','宋诗','song-poetry','','[]','歌闋一尊清晝長，曲池小景晚風凉。',32,'全唐诗/poet.song.117000.json','["歌闋一尊清晝長，曲池小景晚風凉。", "波微動處見魚戲，荷半開時過雨香。"]'),
('8914d97e-65a6-4e60-aa2e-660f34d86e98','贈炊僮','黄公度','宋','宋诗','song-poetry','','[]','雞唱度纔三，羸僮井臼探。',48,'全唐诗/poet.song.117000.json','["雞唱度纔三，羸僮井臼探。", "缺瓶分曉月，古竈湧晴嵐。", "口腹真吾累，庖厨頼爾堪。", "支離不耕者，對案敢無慙。"]'),
('9b9203e7-47c3-4c02-bef1-326559980cf8','和蘇伯承題恂恂軒','黄公度','宋','宋诗','song-poetry','','[]','可但溫恭九族敦，平生鄉黨更恂恂。',64,'全唐诗/poet.song.117000.json','["可但溫恭九族敦，平生鄉黨更恂恂。", "山林得趣身長健，門館無私物自春。", "一室琴尊對咸籍，百年膠漆付雷陳。", "共傳宅相工題品，未數東坡德有鄰。"]'),
('bb06086b-5551-4b00-b7d0-568da4981e31','春日書懷','黄公度','宋','宋诗','song-poetry','','[]','才薄難任家國憂，年衰未免稻粱謀。',64,'全唐诗/poet.song.117000.json','["才薄難任家國憂，年衰未免稻粱謀。", "權門雖好羞摇尾，世路多猜敢轉喉。", "是處溪山可藏拙，何人庭院許尋幽。", "便須火急營春事，九十韶光一半休。"]'),
('6b053afc-2a88-4b3b-bd73-ad85de233347','次韻宋永兄春日放言寄秉彝廣文兄','黄公度','宋','宋诗','song-poetry','','[]','君不見邊孝先，才得午枕一覺眠。',106,'全唐诗/poet.song.117000.json','["君不見邊孝先，才得午枕一覺眠。", "便遭弟子嘲便便，又不見馬季長。", "橫經高堂坐絳帳，背後女樂盈妖妍。", "青春一去少者老，白髮不分愚與賢。", "試看刻苦要稱天下士，何如落魄且作地行仙。", "東風來習習，新月照娟娟。", "若逢花解語，須用酒爲年。"]'),
('e0a1ca34-eec5-49c1-94e1-4b27e1e4c966','唱和盈軸而燕集未期小詩請廣文兄爲遨頭','黄公度','宋','宋诗','song-poetry','','[]','煩君管領東君手，收拾風光尊俎中。',64,'全唐诗/poet.song.117000.json','["煩君管領東君手，收拾風光尊俎中。", "與作遨頭共春燕，何須擁鼻學秋蟲。", "誰憐老子興不淺，自笑窮人詩轉工。", "趁取身閒酒價賤，明年此日又西東。"]'),
('e7da09d9-7fe6-4e86-94b5-e8b8f9e98411','宋永兄見和春懷再賦仍約秉彝兄尋春西郊','黄公度','宋','宋诗','song-poetry','','[]','朱轂常懷蹉跌憂，蓽門長苦斗升謀。',64,'全唐诗/poet.song.117000.json','["朱轂常懷蹉跌憂，蓽門長苦斗升謀。", "此生幸不貧到骨，未死何妨酒入喉。", "北里人隨春漸老，西郊地與興俱幽。", "憑君更語廣文叟，飯足還須醉始休。"]'),
('d51c667f-42c2-4b00-a26b-f936c4dc610e','宋永兄一訪青帝而黄婆作惡累日戲作小詩問安二首  其一','黄公度','宋','宋诗','song-poetry','','[]','鳴鐘伐鼓南山阿，傾城車馬相戛摩。',64,'全唐诗/poet.song.117000.json','["鳴鐘伐鼓南山阿，傾城車馬相戛摩。", "萬釭高下照朱碧，百堵往來紛綺羅。", "身入醉鄉頹紅玉，月明歸路湛金波。", "挽君一出卧三日，奈此陌上春光何。"]'),
('a9adb24a-cd81-4725-8f29-28cb4eb13946','宋永兄一訪青帝而黄婆作惡累日戲作小詩問安二首  其二','黄公度','宋','宋诗','song-poetry','','[]','陌上春光遽如許，花落花開任風雨。',64,'全唐诗/poet.song.117000.json','["陌上春光遽如許，花落花開任風雨。", "誰憐四印居士賢，苦遭造化小兒侮。", "古來醫手罕折肱，老去流年劇飛羽。", "無復當時倒載歸，羣童拍手山公舞。"]'),
('76bb45ae-de8f-46b1-968b-6f986801fd61','次韻宋永兄感舊五首  其一','黄公度','宋','宋诗','song-poetry','','[]','猶憶當年歌畫空，乘歡直欲舉千鍾。',64,'全唐诗/poet.song.117000.json','["猶憶當年歌畫空，乘歡直欲舉千鍾。", "韶光半老不相識，樂事一生能幾逢。", "戲蝶狂蜂隨意好，閑花蔓草向人濃。", "當壚春色今何在，病酒相如卧蜀邛。"]'),
('cac0ffce-c71c-4848-8330-7b1e81c46ef1','次韻宋永兄感舊五首  其二','黄公度','宋','宋诗','song-poetry','','[]','何用咄咄愁書空，何用鼎食鳴金鍾。',64,'全唐诗/poet.song.117000.json','["何用咄咄愁書空，何用鼎食鳴金鍾。", "流行坎止隨所值，穮蔉不憂年不逢。", "金釵困懶海棠睡，玉斚淋漓琥珀濃。", "安能辛勤鍊石髓，苦學成周人姓邛。"]'),
('cc7cd0e1-3bb4-42ff-ac8e-53fe46f99f70','次韻宋永兄感舊五首  其三','黄公度','宋','宋诗','song-poetry','','[]','齠齓談經動聖聰，山川英氣向來鍾。',64,'全唐诗/poet.song.117000.json','["齠齓談經動聖聰，山川英氣向來鍾。", "中書落筆萬人繞，天陛賜袍千載逢。", "利鎖名韁身半老，酒徒詩社意偏濃。", "莫欺犬子倦游久，得志猶能通筰卭。"]'),
('fc599ae4-2e51-482f-8eb3-425252d920e6','次韻宋永兄感舊五首  其四','黄公度','宋','宋诗','song-poetry','','[]','待價君方藏尺璧，知音誰解聽號鐘。',64,'全唐诗/poet.song.117000.json','["待價君方藏尺璧，知音誰解聽號鐘。", "渥漥天上非無種，伯樂人間那易逢。", "墨綬解來三歲改，白雲飛處寸心濃。", "鴟翔鸞伏古如此，直道不容非孔邛。"]'),
('edea2269-69cd-4577-a595-69c88ca78ff1','次韻宋永兄感舊五首  其五','黄公度','宋','宋诗','song-poetry','','[]','三分春色二分空，莫待春歸怨曉鐘。',64,'全唐诗/poet.song.117000.json','["三分春色二分空，莫待春歸怨曉鐘。", "詩句逼人何太甚，酒徒知己信難逢。", "百年夜永晝愁短，千樹紅踈綠漸濃。", "尊俎班荆元不惡，試張雲幕席苕邛。"]'),
('a3c73925-2334-46de-89be-5bb14062410f','雨後春遊','黄公度','宋','宋诗','song-poetry','','[]','鳴鳩乳燕報新晴，更被提壺苦勸人。',64,'全唐诗/poet.song.117000.json','["鳴鳩乳燕報新晴，更被提壺苦勸人。", "萬點桃花落紅雨，十分蕉葉負青春。", "醉鄉歸去疑無路，詩筆拈來似有神。", "莫惜千金買一笑，餘年樂事更關身。"]'),
('9d064970-89f9-43a7-b912-21a147faa60f','雨後行花圃','黄公度','宋','宋诗','song-poetry','','[]','習習春風軟，遲遲春日暄。',120,'全唐诗/poet.song.117000.json','["習習春風軟，遲遲春日暄。", "生意遍宇宙，盡托青皇恩。", "屏翳剛作惡，一夜如翻盆。", "奔流萬壑怒，比曉千山昏。", "鳴鳩喚我起，杖屨行中園。", "呼僮理僵仆，春事無半存。", "蓬蒿增意氣，蘭藥遭排根。", "雖無桃李妍，却有桑麻繁。", "萬化相除謝，此理誰明論。", "去去勿復辨，榮枯任乾坤。"]'),
('70d85fb2-b498-4627-bd5e-04ff4054de96','偶成','黄公度','宋','宋诗','song-poetry','','[]','野鳥春布穀，階蟲秋絡絲。',24,'全唐诗/poet.song.117000.json','["野鳥春布穀，階蟲秋絡絲。", "呶呶空過耳，終不救寒饑。"]'),
('b461fafb-28f2-4375-beb0-acf032434e6d','贈泉守趙表之二首  其一','黄公度','宋','宋诗','song-poetry','','[]','禪翁笑擁兩朱輪，麈尾蒲團付底人。',64,'全唐诗/poet.song.117000.json','["禪翁笑擁兩朱輪，麈尾蒲團付底人。", "千里謳吟真刺史，三朝出入老宗臣。", "春風半道旌旗轉，南國一番桃李新。", "莫把蹄涔留尺鯉，早令圖畫上麒麟。"]'),
('5accb52c-a813-4d0e-9e4f-f5d4b5330a4e','贈泉守趙表之二首  其二','黄公度','宋','宋诗','song-poetry','','[]','扁舟昔艤浙江邊，曾醉王孫玳瑁筵。',64,'全唐诗/poet.song.117000.json','["扁舟昔艤浙江邊，曾醉王孫玳瑁筵。", "竹杖芒鞵晚城上，金荷銀燭夜堂前。", "宦游我輩聊復爾，聚散人間亦偶然。", "誰料天涯今八載，青燈相對各華顛。"]'),
('83338422-3e31-4e38-a034-87182b4029d5','春日宴共樂臺','黄公度','宋','宋诗','song-poetry','','[]','畫棟朱甍插紫清，連山带水自紆縈。',64,'全唐诗/poet.song.117000.json','["畫棟朱甍插紫清，連山带水自紆縈。", "閭閻高下魚鱗比，田畝縱橫碁局平。", "花發鳥啼春耐事，夜闌客散月多情。", "寸陰自古千金重，一笑人間萬慮輕。"]'),
('811b7598-03ca-4cd6-9624-c8912f30b01d','秋夜獨酌','黄公度','宋','宋诗','song-poetry','','[]','溪山態足身無事，天地功深歲有秋。',64,'全唐诗/poet.song.117000.json','["溪山態足身無事，天地功深歲有秋。", "投老相從管城子，平生得意醉鄉侯。", "捲簾清坐月排闥，橫笛誰家風滿樓。", "可是離人更遺物，自緣身世兩無求。"]'),
('ac965f03-d12a-41cb-85e6-4ff9e58d7cfe','午睡起得富沙信','黄公度','宋','宋诗','song-poetry','','[]','閒處工夫要破除，茅堂一枕黑甜餘。',64,'全唐诗/poet.song.117000.json','["閒處工夫要破除，茅堂一枕黑甜餘。", "漆園栩栩看成蝶，邊笥便便舊貯書。", "掃盡機心還罔象，了無行迹便華胥。", "故人千里能知我，遠寄月團供燕居。"]'),
('4ee8088d-3ad1-4b73-a41c-7a5fbb565613','題順濟廟','黄公度','宋','宋诗','song-poetry','','[]','枯木肇靈滄海東，參差宮殿崒晴空。',64,'全唐诗/poet.song.117000.json','["枯木肇靈滄海東，參差宮殿崒晴空。", "平生不厭混巫媼，已死猶能效國功。", "萬戶牲醪無水旱，四時歌舞走兒童。", "傳聞利澤至今在，千里危檣一信風。"]'),
('ea565d86-4ba0-42a9-a44a-31d68b0ce015','冬日道間','黄公度','宋','宋诗','song-poetry','','[]','歲熟牛羊飽，村寒鳥獸呼。',48,'全唐诗/poet.song.117000.json','["歲熟牛羊飽，村寒鳥獸呼。", "霜餘山骨露，水落澗毛枯。", "歸艇收漁網，行人問酒壚。", "微軀任南北，未覺旅懷孤。"]'),
('910cf9e6-baee-40dc-9343-eac1406815e9','贈延福端老二絕  其一','黄公度','宋','宋诗','song-poetry','','[]','飄然瓶錫信行藏，偶駐姜峰古道場。',32,'全唐诗/poet.song.117000.json','["飄然瓶錫信行藏，偶駐姜峰古道場。", "欲識高人用心處，白雲堂下一爐香。"]'),
('d49baa33-2c45-457d-9705-3f6421e4738f','贈延福端老二絕  其二','黄公度','宋','宋诗','song-poetry','','[]','我來欲問小乘禪，慙愧塵埃未了緣。',32,'全唐诗/poet.song.117000.json','["我來欲問小乘禪，慙愧塵埃未了緣。", "忽憶去年秋夜話，共聽風雨不成眠。"]'),
('a738675d-ea4d-4923-8b4f-05f0ffcd9b4e','將赴高要官守書懷','黄公度','宋','宋诗','song-poetry','','[]','古來仕路多機穽，我復情田少町畦。',64,'全唐诗/poet.song.117000.json','["古來仕路多機穽，我復情田少町畦。", "回首壯圖猶拾瀋，驚心往事屢吹韲。", "不因昏嫁那能許，此去聲名敢厭低。", "但使安閒更强健，何妨流落在塗泥。"]'),
('c08f99aa-a946-4bbb-8e8b-9e00d3230360','題瘦牛嶺','黄公度','宋','宋诗','song-poetry','','[]','自笑年來爲食謀，扶携百指過南州。',32,'全唐诗/poet.song.117000.json','["自笑年來爲食謀，扶携百指過南州。", "時平四野皆青草，此地何曾解瘦牛。"]'),
('6851131a-eb01-4c35-8287-c245dfd6c9e1','中秋西江上','黄公度','宋','宋诗','song-poetry','','[]','月色今宵萬里，笛聲何處孤舟。',28,'全唐诗/poet.song.117000.json','["月色今宵萬里，笛聲何處孤舟。", "世事堪驚流水，鄉心不忍登樓。"]'),
('1c356b58-98e5-4d6d-b6c6-c2bc6b99e300','賀劉使君','黄公度','宋','宋诗','song-poetry','','[]','于門爲國産英賢，淮海鍾靈五百年。',128,'全唐诗/poet.song.117000.json','["于門爲國産英賢，淮海鍾靈五百年。", "松竹千尋森氣節，江湖萬頃渺情田。", "白頭未握封侯印，皂蓋猶分刺史天。", "俗變農桑皆犢佩，家傳愷悌只蒲鞭。", "歛容不動吏曹畏，清坐無言上意宣。", "四野歡聲豐歲裏，西山爽氣壽杯前。", "籬邊陶菊千苞折，階下堯蓂一葉鮮。", "香火祝公三入後，却來平地作飛僊。"]'),
('16c3ed3f-8560-48b1-902a-3e5fa733f0cc','南來苦熱戲作二首','黄公度','宋','宋诗','song-poetry','','[]','農夫烈日夏畦耕，僊家九轉丹竈成。',96,'全唐诗/poet.song.117000.json','["農夫烈日夏畦耕，僊家九轉丹竈成。", "阿奴投燭婢翻羹，飛蛾赴焰雞遭烹。", "湯爲池兮火爲城，未如三伏南州行。", "大旱赤地金將流，火炎崑岡玉石休。", "六月王師萬貔貅，叢坐氊帳襲重裘。", "鄰人延燒已焦頭，未如三伏行南州。"]'),
('4638d058-c24a-449a-9876-ed25d920ff6d','方帥務德生朝三首  其一','黄公度','宋','宋诗','song-poetry','','[]','一氣潛回萬物春，星躔降昴嶽生申。',64,'全唐诗/poet.song.117000.json','["一氣潛回萬物春，星躔降昴嶽生申。", "釣臺今古風流在，梅嶺東西雨露均。", "再擁朱轓專節制，久虛清禁待經綸。", "衮衣莫訝公歸晚，要使遐荒識鳳麟。"]'),
('6acfee86-bd34-4250-8312-37ff0e48277f','方帥務德生朝三首  其二','黄公度','宋','宋诗','song-poetry','','[]','一別帝城今幾秋，憂時不復爲身謀。',64,'全唐诗/poet.song.117000.json','["一別帝城今幾秋，憂時不復爲身謀。", "枌榆故國三千里，桃李新陰四十州。", "談笑折衝無鼠輩，平生推轂盡清流。", "急須整頓乾坤了，鳴玉槐庭要黑頭。"]'),
('441867de-1685-40c4-921a-5a3a19ad1599','方帥務德生朝三首  其三','黄公度','宋','宋诗','song-poetry','','[]','高門餘慶自綿綿，唾手功名不作難。',64,'全唐诗/poet.song.117000.json','["高門餘慶自綿綿，唾手功名不作難。", "况是胸中絕畦町，更於筆下富波瀾。", "家傳元老謀猷壯，人樂將軍禮數寬。", "香火祝公千百壽，姓名高並斗星寒。"]');
